insert into TOEFLWordBook values ('0', 'abnormal', '[æbˈnɔːrm(ə)l]', 'http://dict.youdao.com/dictvoice?audio=abnormal', '{adj.}++反常的，异常的，变态的；不规则的**{adj.}++not normal; not typical or usual or regular or conforming to a norm																										        													        													        													        				&quot;abnormal powers of concentration&quot;; &quot;abnormal amounts of rain&quot;; &quot;abnormal circumstances&quot;; &quot;an abnormal interest in food&quot;**{departing from the normal in e.}++g. intelligence and development																										        													        				&quot;they were heartbroken when they learned their child was abnormal&quot;; &quot;an abnormal personality&quot;**{adj.}++反常的，不规则的；变态的**', '');
insert into TOEFLWordBook values ('1', 'abroad', '[əˈbrɔːd]', 'http://dict.youdao.com/dictvoice?audio=abroad', '{adv.}++在国外，到国外；在室外，到室外； 广为流传，广为人知；行动自由； 未击中目标，出错**{n.}++外国**{adj.}++in a foreign country																										        				&quot;markets abroad&quot;															   	同义词：								                                  				    overseas**{adv.}++to or in a foreign country																										        				&quot;they had never travelled abroad&quot;**{n.}++海外；异国**', '');
insert into TOEFLWordBook values ('2', 'absent', '[ˈæbsənt]', 'http://dict.youdao.com/dictvoice?audio=absent', '{adj.}++缺勤的，缺席的；不存在的，缺乏的；心不在焉的，出神的；不与子女一起住的**{prep.}++缺乏，没有**{v.}++缺席，离开**{v.}++go away or leave																										        				&quot;He absented himself&quot;															   	同义词：								                                  				    remove**{adj.}++not in a specified place physically or mentally**{adj.}++缺席的；缺少的；心不在焉的；茫然的**', '');
insert into TOEFLWordBook values ('3', 'absorb', '[əbˈzɔːrb]', 'http://dict.youdao.com/dictvoice?audio=absorb', '{v.}++吸收；使并入，纳入；同化，汲取；消减，缓冲（外力、震动等）；理解，掌握（信息）；使全神贯注，使专心；承受（变革、影响等），承担（费用等）；花掉（大量金钱），耗费**{v.}++become imbued																										        				&quot;The liquids, light, and gases absorb&quot;**{vt.}++吸收；吸引；承受；理解；使…全神贯注**', '');
insert into TOEFLWordBook values ('4', 'abstract', '[ˈæbstrækt]', 'http://dict.youdao.com/dictvoice?audio=abstract', '{adj.}++抽象的，纯概念的；（艺术）抽象派的；理论上的，不切实际的**{n.}++摘要，梗概；抽象画，抽象派艺术作品；抽象的概念**{v.}++抽象化，从理论上（或孤立地）考虑；提取，使分离；写……的摘要；偷走，窃取；退出**{n.}++a concept or idea not associated with any specific instance																										        				&quot;he loved her only in the abstract--not in person&quot;															   	同义词：								                                  				    abstraction**{n.}++[图情]摘要；抽象；抽象的概念**{adj.}++抽象的；深奥的**{vt.}++[图情]摘要；提取；使……抽象化**', '');
insert into TOEFLWordBook values ('5', 'abundant', '[əˈbʌndənt]', 'http://dict.youdao.com/dictvoice?audio=abundant', '{adj.}++大量的，丰富的，充足的**{adj.}++present in great quantity																										        				&quot;an abundant supply of water&quot;**{adj.}++丰富的；充裕的；盛产**', '');
insert into TOEFLWordBook values ('6', 'abuse', '[əˈbjuːs]', 'http://dict.youdao.com/dictvoice?audio=abuse', '{v.}++虐待；滥用，辜负；辱骂；糟蹋（某物）；性侵犯**{n.}++虐待，凌辱；滥用，妄用；辱骂；舞弊，腐败；糟蹋；性侵犯；恶习，陋习**{n.}++cruel or inhumane treatment																					   	同义词：								                                  				    maltreatment				    				    				      				    				      				    				                                      				    ill-treatment				    				    				      				    				      				    				                                      				    ill-usage**{n.}++滥用；虐待；辱骂；弊端；恶习，陋习**{vt.}++滥用；虐待；辱骂**', '');
insert into TOEFLWordBook values ('7', 'academy', '[əˈkædəmi]', 'http://dict.youdao.com/dictvoice?audio=academy', '{n.}++专科院校；研究院，学会；（美国的）私立学校；（苏格兰的）中等学校**{n.}++a secondary school (usually private)**{n.}++学院；研究院；学会；专科院校**', '');
insert into TOEFLWordBook values ('8', 'access', '[ˈækses]', 'http://dict.youdao.com/dictvoice?audio=access', '{n.}++入口，通道；获得的机会，使用权；（对计算机存储器的）访问，存取；（情感）爆发，发作；探视权**{v.}++接近，进入；获取，访问（计算机信息）**{adj.}++（电视节目或时间等）对外公开的**{n.}++the right to enter																					   	同义词：								                                  				    entree				    				    				      				    				      				    				                                      				    accession				    				    				      				    				      				    				                                      				    admittance**{a code (a series of characters or digits) that must be entered in some way (typed or dialed or spoken) to get the use of something (a telephone line or a computer or a local area network etc.}++)																					   	同义词：								                                  				    access code**{vt.}++使用；[计]存取；接近**{n.}++进入；使用权；[电]通路**', '');
insert into TOEFLWordBook values ('9', 'accident', '[ˈæksɪdənt]', 'http://dict.youdao.com/dictvoice?audio=accident', '{n.}++交通事故，车祸；（不幸的）意外遭遇，不测事件；意外，偶然的事；运气，机遇；大便（或小便）失禁；（亚里士多德思想中的）非本质属性**{n.}++a mishap; especially one causing injury or death**{n.}++[安全]事故；意外；[法]意外事件；机遇**', '');
insert into TOEFLWordBook values ('10', 'acclaim', '[əˈkleɪm]', 'http://dict.youdao.com/dictvoice?audio=acclaim', '{v.}++赞扬，称赞，为……喝彩**{n.}++赞扬，称誉，高度评价**{n.}++enthusiastic approval																										        				&quot;the book met with modest acclaim&quot;															   	同义词：								                                  				    acclamation				    				    				      				    				      				    				                                      				    plaudits				    				    				      				    				      				    				                                      				    plaudit				    				    				      				    				      				    				                                      				    eclat**{v.}++praise vociferously																					   	同义词：								                                  				    hail				    				    				      				    				      				    				                                      				    herald**{vt.}++称赞；为…喝采，向…欢呼**{n.}++欢呼，喝彩；称赞**{vi.}++欢呼，喝采**', '');
insert into TOEFLWordBook values ('11', 'accommodate', '[əˈkɑːmədeɪt]', 'http://dict.youdao.com/dictvoice?audio=accommodate', '{v.}++为……提供住宿；容纳，提供空间；考虑到，顾及；顺应，适应；帮助（某人），向……施以援手；迎合，迁就；调解**{v.}++be agreeable or acceptable to																					   	同义词：								                                  				    suit				    				    				      				    				      				    				                                      				    fit**{vt.}++容纳；使适应；供应；调解**{vi.}++适应；调解**', '');
insert into TOEFLWordBook values ('12', 'accompany', '[əˈkʌmpəni]', 'http://dict.youdao.com/dictvoice?audio=accompany', '{v.}++陪伴，陪同；伴随，与……一起发生；为……伴奏（或伴唱）；附带，补充**{v.}++be associated with																					   	同义词：								                                  				    attach to				    				    				      				    				      				    				                                      				    come with				    				    				      				    				      				    				                                      				    go with**{vt.}++陪伴，伴随；伴奏**', '');
insert into TOEFLWordBook values ('13', 'accomplish', '[əˈkɑːmplɪʃ]', 'http://dict.youdao.com/dictvoice?audio=accomplish', '{v.}++完成，实现**{v.}++put in effect																					   	同义词：								                                  				    carry through				    				    				      				    				      				    				                                      				    execute				    				    				      				    				      				    				                                      				    carry out				    				    				      				    				      				    				                                      				    action				    				    				      				    				      				    				                                      				    fulfill				    				    				      				    				      				    				                                      				    fulfil**{vt.}++完成；实现；达到**', '');
insert into TOEFLWordBook values ('14', 'accord', '[əˈkɔːrd]', 'http://dict.youdao.com/dictvoice?audio=accord', '{n.}++协议，条约；符合，一致**{v.}++使受到，给予（某种待遇）；（与……）一致，符合**{n.}++harmony of peoples opinions or actions or characters																					   	同义词：								                                  				    agreement**{n.}++符合；一致；协议；自愿**{vt.}++使一致；给予**{vi.}++符合；一致**', '');
insert into TOEFLWordBook values ('15', 'accumulate', '[əˈkjuːmjəleɪt]', 'http://dict.youdao.com/dictvoice?audio=accumulate', '{v.}++积累，积攒**{v.}++get or gather together																					   	同义词：								                                  				    roll up				    				    				      				    				      				    				                                      				    collect				    				    				      				    				      				    				                                      				    pile up				    				    				      				    				      				    				                                      				    amass				    				    				      				    				      				    				                                      				    compile				    				    				      				    				      				    				                                      				    hoard**{vi.}++累积；积聚**{vt.}++积攒**', '');
insert into TOEFLWordBook values ('16', 'acoustic', '[əˈkuːstɪk]', 'http://dict.youdao.com/dictvoice?audio=acoustic', '{adj.}++声音的，听觉的；（乐器）原声的，不加电子设备传声的；（音乐）原声的，不经过电声设备放大的；（建筑材料）隔音的，修饰声音的；（装置，系统）利用声能运作的；（爆破性水雷或其他武器）能为声波引爆的**{n.}++（房间或建筑物的）音响效果，音质；声学（acoustics）；原声吉他（acoustic guitar）**{n.}++a remedy for hearing loss or deafness**{adj.}++of or relating to the science of acoustics																										        				&quot;acoustic properties of a hall&quot;															   	同义词：								                                  				    acoustical**{adj.}++声学的；[声]音响的；听觉的**', '');
insert into TOEFLWordBook values ('17', 'acquaint', '[əˈkweɪnt]', 'http://dict.youdao.com/dictvoice?audio=acquaint', '{v.}++使熟悉，使了解**{v.}++cause to come to know personally																										        				&quot;permit me to acquaint you with my son&quot;															   	同义词：								                                  				    introduce				    				    				      				    				      				    				                                      				    present**{vt.}++使熟悉；使认识**', '');
insert into TOEFLWordBook values ('18', 'adapt', '[əˈdæpt]', 'http://dict.youdao.com/dictvoice?audio=adapt', '{v.}++适应；调整，使适合；改编；改造，改装**{v.}++make fit for, or change to suit a new purpose																					   	同义词：								                                  				    accommodate**{vt.}++使适应；改编**{vi.}++适应**', '');
insert into TOEFLWordBook values ('19', 'address', '[əˈdres]', 'http://dict.youdao.com/dictvoice?audio=address', '{n.}++地址，住址；网址；电子邮箱地址；演讲，演说；（电子表格中某个单元格的）位置；（对他人的）谈吐；谦恭（或脉脉含情）的方式；机敏，迅速；位置存储编码**{v.}++演说，演讲；处理，设法解决；在（信封、包裹等）上写姓名和地址，致函； 向……讲话；称呼；（向某人）提出（陈述、投诉等）；（高尔夫）就位击（球）**{n.}++(computer science) the code that identifies where a piece of information is stored																					   	同义词：								                                  				    computer address**{vt.}++演说；从事；忙于；写姓名地址；向…致辞**{n.}++[计]地址；演讲；致辞；说话的技巧**', '');
insert into TOEFLWordBook values ('20', 'admission', '[ədˈmɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=admission', '{n.}++承认，供认；允许进入（加入），进入权；录取，录取人数；入场费；入院治疗（检查）；入场人数；入院病人**{n.}++the act of admitting someone to enter																										        				&quot;the surgery was performed on his second admission to the clinic&quot;															   	同义词：								                                  				    admittance**{n.}++承认；入场费；进入许可；坦白；录用**', '');
insert into TOEFLWordBook values ('21', 'admit', '[ædˈmɪt]', 'http://dict.youdao.com/dictvoice?audio=admit', '{v.}++（勉强）承认；招认，招供；准许进入（某处）；接纳，接收（入学）；收治，接收入院；承认……有效；容许，为……留有余地**{v.}++declare to be true or admit the existence or reality or truth of																										        				&quot;He admitted his errors&quot;															   	同义词：								                                  				    acknowledge**{vt.}++承认；准许进入；可容纳**{vi.}++承认；容许**', '');
insert into TOEFLWordBook values ('22', 'adolescent', '[ˌædəˈles(ə)nt]', 'http://dict.youdao.com/dictvoice?audio=adolescent', '{n.}++青少年**{adj.}++青春期的；不成熟的**{n.}++a juvenile between the onset of puberty and maturity																					   	同义词：								                                  				    stripling				    				    				      				    				      				    				                                      				    teenager				    				    				      				    				      				    				                                      				    teen**{adj.}++relating to or peculiar to or suggestive of an adolescent																										        				&quot;adolescent problems&quot;**{adj.}++青春期的；未成熟的**{n.}++[人类]青少年**', '');
insert into TOEFLWordBook values ('23', 'adverse', '[ədˈvɜːrs]', 'http://dict.youdao.com/dictvoice?audio=adverse', '{adj.}++不利的，有害的；相反的；敌对的**{adj.}++contrary to your interests or welfare																										        				&quot;adverse circumstances&quot;															   	同义词：								                                  				    harmful				    				    				      				    				      				    				                                      				    inauspicious				    				    				      				    				      				    				                                      				    untoward**{adj.}++不利的；相反的；[植]敌对的（名词adverseness，副词adversely）**', '');
insert into TOEFLWordBook values ('24', 'affair', '[əˈfer]', 'http://dict.youdao.com/dictvoice?audio=affair', '{n.}++公共事务，政治事务；事情，事件；个人的事，私事；私人业务；（尤指已婚男女的）私通，风流韵事；社交活动，喜庆事； 物件，东西；商务和金融交易**{n.}++a vaguely specified concern																										        				&quot;it is none of your affair&quot;															   	同义词：								                                  				    matter				    				    				      				    				      				    				                                      				    thing**{n.}++事情；事务；私事；（尤指关系不长久的）风流韵事**', '');
insert into TOEFLWordBook values ('25', 'aggressive', '[əˈɡresɪv]', 'http://dict.youdao.com/dictvoice?audio=aggressive', '{adj.}++好斗的，挑衅的；积极进取的；非常严重的；强烈的**{adj.}++having or showing determination and energetic pursuit of your ends																										        													        													        													        													        				&quot;an aggressive businessman&quot;; &quot;an aggressive basketball player&quot;; &quot;he was aggressive and imperious&quot;; &quot;positive in his convictions&quot;; &quot;aggressive drivers&quot;**{adj.}++侵略性的；好斗的；有进取心的；有闯劲的**', '');
insert into TOEFLWordBook values ('26', 'alarm', '[əˈlɑːrm]', 'http://dict.youdao.com/dictvoice?audio=alarm', '{n.}++警报；警报器；闹钟；惊恐，担忧**{v.}++使不安，使恐慌；给（门等）安装警报器**{n.}++fear resulting from the awareness of danger																					   	同义词：								                                  				    dismay				    				    				      				    				      				    				                                      				    consternation**{n.}++警报，[安全]警告器；惊慌**{vt.}++警告；使惊恐**', '');
insert into TOEFLWordBook values ('27', 'alien', '[ˈeɪliən]', 'http://dict.youdao.com/dictvoice?audio=alien', '{adj.}++陌生的；外国的，异域的；与外星人有关的，与地球外有关的；（植物或动物种类）外来的；不相容的，格格不入的 （alien to）**{n.}++外国人，侨民；外星人（或生物）；（植物或动物种类）外国引进品种**{v.}++让渡，转让**{n.}++a person who comes from a foreign country; someone who does not owe allegiance to your country																					   	同义词：								                                  				    foreigner				    				    				      				    				      				    				                                      				    noncitizen				    				    				      				    				      				    				                                      				    outlander**{adj.}++外国的；相异的，性质不同的；不相容的**{n.}++外国人，外侨；外星人**{vt.}++让渡，转让**', '');
insert into TOEFLWordBook values ('28', 'alternate', '[ˈɔːltərnət; ˈɔːltərneɪt]', 'http://dict.youdao.com/dictvoice?audio=alternate', '{adj.}++轮流的，交替的；间隔的；供选择的，备用的；（叶，芽）互生的；另类的**{v.}++（使）交替，（使）轮流**{n.}++替补者，候补者**{n.}++someone who takes the place of another person																					   	同义词：								                                  				    surrogate				    				    				      				    				      				    				                                      				    replacement**{v.}++go back and forth; swing back and forth between two states or conditions																					   	同义词：								                                  				    jump**{vi.}++交替；轮流**{vt.}++使交替；使轮流**{adj.}++[物]交替的；轮流的**{n.}++替换物**', '');
insert into TOEFLWordBook values ('29', 'amateur', '[ˈæmətər]', 'http://dict.youdao.com/dictvoice?audio=amateur', '{n.}++业余爱好者；生手，外行**{adj.}++非专业的，业余爱好的；不熟练的**{n.}++someone who pursues a study or sport as a pastime**{n.}++爱好者；业余爱好者；外行**{adj.}++业余的；外行的**', '');
insert into TOEFLWordBook values ('30', 'amazing', '[əˈmeɪzɪŋ]', 'http://dict.youdao.com/dictvoice?audio=amazing', '{adj.}++惊人的，了不起的；令人诧异的，令人惊愕的；令人高兴的**{v.}++使惊奇，使惊愕（amaze 的现在分词形式）**{adj.}++surprising greatly																										        				&quot;she does an amazing amount of work&quot;															   	同义词：								                                  				    astonishing**{adj.}++令人惊异的**', '');
insert into TOEFLWordBook values ('31', 'ambition', '[æmˈbɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=ambition', '{n.}++追求的目标，抱负；雄心，野心；干劲**{v.}++追求，有……野心**{n.}++a cherished desire																										        				&quot;his ambition is to own his own business&quot;															   	同义词：								                                  				    aspiration				    				    				      				    				      				    				                                      				    dream**{n.}++野心，雄心；抱负，志向**{vt.}++追求；有…野心**', '');
insert into TOEFLWordBook values ('32', 'amendment', '[əˈmendmənt]', 'http://dict.youdao.com/dictvoice?audio=amendment', '{n.}++修正，修订之处；美国宪法修正案（Amendment）；（土壤结构或肥力的）改善；（对文件或计划的）修改**{n.}++the act of amending or correcting**{a statement that is added to or revises or improves a proposal or document (a bill or constitution etc.}++)**{n.}++修正案；改善；改正**', '');
insert into TOEFLWordBook values ('33', 'ample', '[ˈæmp(ə)l]', 'http://dict.youdao.com/dictvoice?audio=ample', '{adj.}++充足的，充裕的；丰满的；宽敞的，巨大的**{adj.}++more than enough in size or scope or capacity																										        													        				&quot;had ample food for the party&quot;; &quot;an ample supply&quot;**{adj.}++丰富的；足够的；宽敞的**', '');
insert into TOEFLWordBook values ('34', 'analogy', '[əˈnælədʒi]', 'http://dict.youdao.com/dictvoice?audio=analogy', '{n.}++类比，比拟；用类比方法，进行比照；同功**{n.}++an inference that if things agree in some respects they probably agree in others**{n.}++类比；类推；类似**', '');
insert into TOEFLWordBook values ('35', 'analyze', '[ˈænəlaɪz]', 'http://dict.youdao.com/dictvoice?audio=analyze', '{vt.}++对……进行分析，分解（等于 analyse）**{v.}++consider in detail and subject to an analysis in order to discover essential features or meaning																										        													        													        				&quot;analyze a sonnet by Shakespeare&quot;; &quot;analyze the evidence in a criminal trial&quot;; &quot;analyze your real motives&quot;															   	同义词：								                                  				    analyse				    				    				      				    				      				    				                                      				    study				    				    				      				    				      				    				                                      				    examine				    				    				      				    				      				    				                                      				    canvass				    				    				      				    				      				    				                                      				    canvas**{vt.}++对…进行分析，分解（等于analyse）**', '');
