insert into TOEFLWordBook values ('37', 'angle', '[ˈæŋɡ(ə)l]', 'http://dict.youdao.com/dictvoice?audio=angle', '{n.}++角；倾斜，斜角；角度；视角，立场；不可告人的动机；诡计，狡猾的手段；角铁，角钢；鱼钩**{v.}++斜移，斜置；向（特定人群）提供资讯，定位于；博取，谋取；垂钓，钓鱼；（使）朝向，（使）转向**{n.}++the space between two lines or planes that intersect; the inclination of one line to another; measured in degrees or radians**{vi.}++钓鱼；谋取**{n.}++角度，[数]角**', '');
