insert into TOEFLWordBook values ('64', 'beam', '[biːm]', 'http://dict.youdao.com/dictvoice?audio=beam', '{n.}++梁，横梁；臀围；光线，光柱；喜色，笑容；（体操的）平衡木**{v.}++定向发出（无线电信号）；（光，光源）照耀；喜笑颜开，面露喜色**{n.}++a signal transmitted along a narrow path; guides pilots in darkness or bad weather																					   	同义词：								                                  				    radio beam**{long thick piece of wood or metal or concrete, etc.}++, used in construction**{n.}++[建]横梁；光线；电波；[船]船宽；[计量]秤杆**{vt.}++发送；以梁支撑；用…照射；流露**{vi.}++照射；堆满笑容**', '');
