insert into TOEFLWordBook values ('69', 'bend', '[bend]', 'http://dict.youdao.com/dictvoice?audio=bend', '{v.}++弯曲（身体关节）；（路）转弯；歪曲（事实）；篡改；屈从；系，缚（帆，缆绳）；使弯曲，弄弯**{n.}++（道路或河流的）拐弯，弯道；（身体的）弯曲（动作）；（尤指潜水员的）潜涵病，减压病（the bends）；绑结；（纹章盾形）左上方至右下方的对角斜纹**{n.}++a circular segment of a curve																										        				&quot;a bend in the road&quot;															   	同义词：								                                  				    crook				    				    				      				    				      				    				                                      				    twist				    				    				      				    				      				    				                                      				    turn**{curved segment (of a road or river or railroad track etc.}++)																					   	同义词：								                                  				    curve**{vt.}++使弯曲；使屈服；使致力；使朝向**{vi.}++弯曲，转弯；屈服；倾向；专心于**{n.}++弯曲**', '');
insert into TOEFLWordBook values ('70', 'beneficial', '[ˌbenɪˈfɪʃ(ə)l]', 'http://dict.youdao.com/dictvoice?audio=beneficial', '{adj.}++有益的，有利的；（与）权益（有关）的，有财产使用权的**{adj.}++promoting or enhancing well-being																										        													        				&quot;an arms limitation agreement beneficial to all countries&quot;; &quot;the beneficial effects of a temperate climate&quot;															   	同义词：								                                  				    good**{adj.}++有益的，有利的；可享利益的**', '');
insert into TOEFLWordBook values ('71', 'bind', '[baɪnd]', 'http://dict.youdao.com/dictvoice?audio=bind', '{v.}++捆绑，系；包扎；使紧密联系；迫使，使负有义务（或责任）；（使）凝结，（使）粘合；装订；给……镶边，给……滚边；（量词）适用于（给定的变量）；（规则，语法条件）决定（共指名词词组）之间的关系；（食物，药品）使便秘**{n.}++窘境，困境；令人不快的事情；法律约束；连结线；蔓，藤**{n.}++something that hinders as if with bonds**{v.}++stick to firmly																					   	同义词：								                                  				    adhere				    				    				      				    				      				    				                                      				    hold fast				    				    				      				    				      				    				                                      				    bond				    				    				      				    				      				    				                                      				    stick				    				    				      				    				      				    				                                      				    stick to**{vi.}++结合；装订；有约束力；过紧**{vt.}++绑；[法]约束；装订；包扎；凝固**{n.}++捆绑；困境；讨厌的事情；植物的藤蔓**', '');
insert into TOEFLWordBook values ('72', 'bite', '[baɪt]', 'http://dict.youdao.com/dictvoice?audio=bite', '{v.}++咬，咬伤；叮，蜇；卡紧，咬住；产生不良影响；接受，相信；咬饵，上钩；（酸）腐蚀；使生气，使烦恼；（物体）刺痛，勒痛；使伤心，使痛苦**{n.}++咬；一口的量；咬伤，叮伤；少量吃的东西，小吃；寒冷，刺骨；浓烈的味道；影响力，感染力；吞饵，上钩；咬合；简短的信息**{n.}++a wound resulting from biting by an animal or a person**{vt.}++咬；刺痛**{n.}++咬；一口；咬伤；刺痛**{vi.}++咬；刺痛**', '');
insert into TOEFLWordBook values ('73', 'blast', '[blæst]', 'http://dict.youdao.com/dictvoice?audio=blast', '{n.}++爆炸，爆破；冲击波；爆炸声，爆破声；强劲的（气或水）流，疾风；吹奏声，轰鸣；严厉的批评；狂欢，有趣的事；（球队或选手的）猛烈进攻；枪击；（公司、组织等发出的）群发电子邮件**{v.}++炸毁，爆破；轰开，炸开（通路）；向……射击，枪击；发出刺耳的高音；严厉批评，痛斥；由爆炸引起；用力踢，猛击；喷射（水流、气流等）；使枯萎；轻易击败；损坏，摧毁；开，炸开（通路）**{int.}++该死，讨厌**{n.}++a very long fly ball**{n.}++[力]爆炸；冲击波；一阵**{vi.}++猛攻**{vt.}++[力]爆炸；损害；使枯萎**', '');
insert into TOEFLWordBook values ('74', 'blazing', '[ˈbleɪzɪŋ]', 'http://dict.youdao.com/dictvoice?audio=blazing', '{adj.}++燃烧的；耀眼的，炽热的；（力量、速度等）强烈的；（争论）激烈的；极其愤怒的，情感强烈的**{adv.}++与火或热量相关地**{n.}++猛烈燃烧的火焰**{v.}++燃烧；闪耀；怒视；（愤怒等情绪）突然爆发；（枪或射击者）连续射击；（非正式）夺取，摘取；大力击（球）；（报纸）耸人听闻地报道，大肆宣扬（blaze 的现在分词）**{n.}++a strong flame that burns brightly																					   	同义词：								                                  				    blaze**{adj.}++shining intensely																										        				&quot;the blazing sun&quot;															   	同义词：								                                  				    blinding				    				    				      				    				      				    				                                      				    dazzling				    				    				      				    				      				    				                                      				    fulgent				    				    				      				    				      				    				                                      				    glaring				    				    				      				    				      				    				                                      				    glary**{adj.}++燃烧的；强烈的；闪耀的**{adv.}++非常**{v.}++燃烧；闪耀；迸发；公开（blaze的ing形式）**', '');
