insert into TOEFLWordBook values ('76', 'blow', '[bloʊ]', 'http://dict.youdao.com/dictvoice?audio=blow', '{v.}++（风）刮，吹；（用嘴）吹气；吹响，吹奏；毁掉，炸毁；（轮胎）爆开，爆裂；（保险丝）烧断，熔化；擤（鼻子）；浪费，挥霍（金钱）；出错，错失机会；泄露，暴露；迅速离开（某地）；用力投（球）；讨厌，糟糕；开花；（鲸鱼）喷水；吹制（玻璃）；（苍蝇）产卵于**{n.}++大风，强风；吹气，擤鼻子；猛击，一击；奋斗，努力；打击，挫折；开花，开花期；爵士乐演奏；大麻；（炼钢用语）吹炼**{n.}++a powerful stroke with the fist or a weapon																										        				&quot;a blow on the head&quot;**{n.}++吹；[机]打击；殴打**{vi.}++风吹；喘气**', '');
