insert into TOEFLWordBook values ('102', 'capture', '[ˈkæptʃər]', 'http://dict.youdao.com/dictvoice?audio=capture', '{v.}++俘获，捕获；夺取，占领；吸引，引起；记录，体现；拍摄，录制；吃掉（国际象棋棋子）；使（数据）保存于电脑中；俘获（原子，亚原子粒）；（河流）袭夺**{n.}++捕获，被捕获；被捕获的人（或物）；占领，攻占；夺取，抢占；（数据）存储**{n.}++the act of forcibly dispossessing an owner of property																					   	同义词：								                                  				    gaining control				    				    				      				    				      				    				                                      				    seizure**{vt.}++[物]俘获；夺得**{n.}++捕获；战利品，俘虏**', '');
