insert into TOEFLWordBook values ('110', 'cast', '[kæst]', 'http://dict.youdao.com/dictvoice?audio=cast', '{v.}++投射（光，影）；将（视线，目光）投向；浇铸，铸造；分配角色；扔，掷，抛；描述，描写；投票；使人怀疑；使（魔咒）生效，施法；抛（钓丝），撒（网）；（生长过程中）蜕（皮），脱（角）；（马）失（蹄铁）；用（星相）占卜；（乡村舞蹈中的）转向；（猎）（狗）四处探寻失踪的嗅迹；放开（猎狗）以探寻嗅迹；用绳子绊倒（动物，尤指母牛）**{n.}++演员阵容；铸型，模型；（固定断骨用的）石膏； 特性，外貌；（眼睛）斜视；掷，投，抛；浅淡的色调；（猎狗）探寻嗅迹；（蚯蚓钻洞时拱到地面的）小土堆；（鹰或猫头鹰的）颗粒状呕吐物；一群鹰，隼**{n.}++the actors in a play																					   	同义词：								                                  				    cast of characters				    				    				      				    				      				    				                                      				    dramatis personae**{vt.}++投，抛；计算；[印刷]浇铸；投射（光、影、视线等）**{n.}++投掷，抛；[机]铸件，[古生]铸型；演员阵容；脱落物**{vi.}++投，抛垂钓鱼钩；计算，把几个数字加起来**', '');
insert into TOEFLWordBook values ('111', 'casual', '[ˈkæʒuəl]', 'http://dict.youdao.com/dictvoice?audio=casual', '{adj.}++休闲的，便装的；随便的，非正式的；漫不经心的，随意的；临时的，短期的；碰巧的，偶然的；不认真的，马虎的；不定期的，偶尔的；感情不深的，疏远的**{n.}++便服，便装（casuals）；临时工；散漫青年；待命士兵**{adj.}++marked by blithe unconcern																										        													        				&quot;an ability to interest casual students&quot;; &quot;showed a casual disregard for cold weather&quot;															   	同义词：								                                  				    insouciant				    				    				      				    				      				    				                                      				    nonchalant**{adj.}++随便的；非正式的；临时的；偶然的**{n.}++便装；临时工人；待命士兵**', '');
