insert into TOEFLWordBook values ('127', 'circuit', '[ˈsɜːrkɪt]', 'http://dict.youdao.com/dictvoice?audio=circuit', '{n.}++电路，回路；巡回活动，巡回地；环道，环线；巡回赛；赛车道；（英国）巡回审判区，巡回上诉法院；（一套）体操动作；统一经营的连锁剧院（或影院）**{v.}++（绕……）环行**{n.}++an electrical device that provides a path for electrical current to flow																					   	同义词：								                                  				    electrical circuit				    				    				      				    				      				    				                                      				    electric circuit**{n.}++[电子]电路，回路；巡回；一圈；环道**{vi.}++环行**', '');
insert into TOEFLWordBook values ('128', 'circular', '[ˈsɜːrkjələr]', 'http://dict.youdao.com/dictvoice?audio=circular', '{adj.}++圆形的，环形的；循环的，绕圈的；循环论证的；传阅的**{n.}++（同时送达多人的）印刷品，宣传单**{n.}++an advertisement (usually printed on a page or in a leaflet) intended for wide distribution																										        				&quot;he mailed the circular to all subscribers&quot;															   	同义词：								                                  				    handbill				    				    				      				    				      				    				                                      				    bill				    				    				      				    				      				    				                                      				    broadside				    				    				      				    				      				    				                                      				    broadsheet				    				    				      				    				      				    				                                      				    flier				    				    				      				    				      				    				                                      				    flyer				    				    				      				    				      				    				                                      				    throwaway**{adj.}++having a circular shape																					   	同义词：								                                  				    round**{adj.}++循环的；[数]圆形的；间接的**{n.}++通知，传单**', '');
insert into TOEFLWordBook values ('129', 'circumstance', '[ˈsɜːrkəmstæns]', 'http://dict.youdao.com/dictvoice?audio=circumstance', '{n.}++条件，情况，环境；境况，经济状况；详情，原委；命运，境遇**{v.}++处于某种情况**{n.}++a condition that accompanies or influences some event or activity**{n.}++环境，情况；事件；境遇**', '');
insert into TOEFLWordBook values ('130', 'cite', '[saɪt]', 'http://dict.youdao.com/dictvoice?audio=cite', '{v.}++引用，援引；引证，引以为例；传唤，传讯；嘉奖，表彰**{n.}++引用，引文**{n.}++a short note recognizing a source of information or of a quoted passage																					   	同义词：								                                  				    citation				    				    				      				    				      				    				                                      				    acknowledgment				    				    				      				    				      				    				                                      				    credit				    				    				      				    				      				    				                                      				    reference				    				    				      				    				      				    				                                      				    mention				    				    				      				    				      				    				                                      				    quotation**{v.}++make reference to																					   	同义词：								                                  				    mention				    				    				      				    				      				    				                                      				    advert				    				    				      				    				      				    				                                      				    bring up				    				    				      				    				      				    				                                      				    name				    				    				      				    				      				    				                                      				    refer**{vt.}++引用；传讯；想起；表彰**', '');
