insert into TOEFLWordBook values ('133', 'classify', '[ˈklæsɪfaɪ]', 'http://dict.youdao.com/dictvoice?audio=classify', '{v.}++把……分类，把……分级；把（信息）归入保密级别**{v.}++arrange or order by classes or categories																										        				&quot;How would you classify these pottery shards--are they prehistoric?&quot;															   	同义词：								                                  				    class				    				    				      				    				      				    				                                      				    sort				    				    				      				    				      				    				                                      				    assort				    				    				      				    				      				    				                                      				    sort out				    				    				      				    				      				    				                                      				    separate**{vt.}++分类；分等**', '');
insert into TOEFLWordBook values ('134', 'clerk', '[klɜːrk]', 'http://dict.youdao.com/dictvoice?audio=clerk', '{n.}++办事员，职员；售货员，店员；（宾馆）接待员；（法庭、市政会等负责管理文书的）文书，书记员；（英国国教会的）牧师；读书识字的人，学者**{v.}++当职员（或文书、书记员）**{n.}++an employee who performs clerical work (e.g., keeps records or accounts)**{n.}++职员，办事员；[劳经]店员；书记；记帐员**', '');
insert into TOEFLWordBook values ('135', 'cling', '[klɪŋ]', 'http://dict.youdao.com/dictvoice?audio=cling', '{v.}++抓住，抱紧；黏附，粘住；依恋，依附；坚持，坚信；紧抓不放，坚守**{n.}++粘核桃**{n.}++fruit (especially peach) whose flesh adheres strongly to the pit																					   	同义词：								                                  				    clingstone**{v.}++come or be in close contact with; stick or hold together and resist separation																										        				&quot;The dress clings to her body&quot;															   	同义词：								                                  				    cleave				    				    				      				    				      				    				                                      				    adhere				    				    				      				    				      				    				                                      				    stick				    				    				      				    				      				    				                                      				    cohere**{to remain emotionally or intellectually attached																										        				&quot;He clings to the idea that she might still love him.}++&quot;**{vi.}++坚持，墨守；紧贴；附着**', '');
insert into TOEFLWordBook values ('136', 'clip', '[klɪp]', 'http://dict.youdao.com/dictvoice?audio=clip', '{n.}++夹子，别针；（电影、电视节目等的）片段；弹夹，弹匣；猛击，抽打；修剪；（行动）速度（尤指快速）；一次；（从羊或羊群）剪下的羊毛量**{v.}++修剪；剪下；减少，缩短；（意外地）斜撞，侧击；诈骗（某人），抢劫（某人）；截取（图像）；截取（信号）的标准振幅，限幅；夹住，固定住**{n.}++a metal frame or container holding cartridges; can be inserted into an automatic gun																					   	同义词：								                                  				    cartridge holder				    				    				      				    				      				    				                                      				    cartridge clip				    				    				      				    				      				    				                                      				    magazine**{vt.}++[园艺]修剪；夹牢；痛打**{vi.}++[园艺]修剪**{n.}++[园艺]修剪；夹子；回形针**', '');
