insert into TOEFLWordBook values ('138', 'clumsy', '[ˈklʌmzi]', 'http://dict.youdao.com/dictvoice?audio=clumsy', '{adj.}++笨拙的，不灵活的；不得体的；难处理的，难使用的；难以移动的**{adj.}++lacking grace in movement or posture																										        				&quot;clumsy fingers&quot;															   	同义词：								                                  				    gawky				    				    				      				    				      				    				                                      				    clunky				    				    				      				    				      				    				                                      				    ungainly				    				    				      				    				      				    				                                      				    unwieldy**{adj.}++笨拙的**', '');
insert into TOEFLWordBook values ('139', 'coach', '[koʊtʃ]', 'http://dict.youdao.com/dictvoice?audio=coach', '{n.}++教练；私人教师；长途客车，长途汽车；火车车厢；四轮大马车；（飞机）经济舱，（火车）普通车厢；（体育队的）领队；（棒球运动中的）跑垒指挥员；教练**{v.}++训练，指导；（尤指私人）辅导；指示，专门传授；乘火车（或汽车、马车）旅行**{adv.}++乘（飞机、火车的）经济舱地**{n.}++(sports) someone in charge of training an athlete or a team																					   	同义词：								                                  				    manager				    				    				      				    				      				    				                                      				    handler**{n.}++教练；旅客车厢；[车辆]长途公车；四轮大马车**{vt.}++训练；指导**', '');
