insert into TOEFLWordBook values ('142', 'colony', '[ˈkɑːləni]', 'http://dict.youdao.com/dictvoice?audio=colony', '{n.}++殖民地；殖民团，移民队；聚集人群，聚居地（区）；群体，群落；（统称）英属殖民地；（美国独立前的）北美十三州**{n.}++a body of people who settle far from home but maintain ties with their homeland; inhabitants remain nationals of their home state but are not literally under the home states system of government																					   	同义词：								                                  				    settlement**{n.}++殖民地；移民队**', '');
