insert into TOEFLWordBook values ('150', 'compose', '[kəmˈpoʊz]', 'http://dict.youdao.com/dictvoice?audio=compose', '{v.}++组成，构成；作曲；撰写（信、诗或演讲稿）；使镇静，使平静；为（照片、图像）构图；排版，排稿**{v.}++form the substance of																										        				&quot;Greed and ambition composed his personality&quot;**{vt.}++构成；写作；使平静；排…的版**{vi.}++组成；作曲；排字**', '');
insert into TOEFLWordBook values ('151', 'comprehensive', '[ˌkɑːmprɪˈhensɪv]', 'http://dict.youdao.com/dictvoice?audio=comprehensive', '{adj.}++综合性的，全面的；有理解力的**{n.}++综合中学；专业综合测验**{n.}++an intensive examination testing a students proficiency in some special field of knowledge																					   	同义词：								                                  				    comprehensive examination				    				    				      				    				      				    				                                      				    comp**{adj.}++including all or everything																										        													        													        													        				&quot;comprehensive coverage&quot;; &quot;a comprehensive history of the revolution&quot;; &quot;a comprehensive survey&quot;; &quot;a comprehensive education&quot;**{adj.}++综合的；广泛的；有理解力的**', '');
insert into TOEFLWordBook values ('152', 'compress', '[kəmˈpres]', 'http://dict.youdao.com/dictvoice?audio=compress', '{v.}++（使）压紧，压缩；精简，浓缩；压缩（文件）；缩短（时间）**{n.}++（止血、减痛等的）敷布，压布**{n.}++a cloth pad or dressing (with or without medication) applied firmly to some part of the body (to relieve discomfort or reduce fever)**{v.}++make more compact by or as if by pressing																										        				&quot;compress the data&quot;															   	同义词：								                                  				    compact				    				    				      				    				      				    				                                      				    pack together**{vt.}++压缩，压紧；精简**', '');
