insert into TOEFLWordBook values ('154', 'concerning', '[kənˈsɜːrnɪŋ]', 'http://dict.youdao.com/dictvoice?audio=concerning', '{prep.}++关于，涉及**{adj.}++让人不安的，令人担忧的**{v.}++有关，关于；影响；使担心（concern 的现在分词形式）**{n.}++something that interests you because it is important or affects you																										        				&quot;the safety of the ship is the captains concern&quot;**{prep.}++关于；就…而言**{v.}++涉及；使关心（concern的ing形式）；忧虑**', '');
