insert into TOEFLWordBook values ('156', 'concrete', '[ˈkɑːnkriːt]', 'http://dict.youdao.com/dictvoice?audio=concrete', '{adj.}++确实的，具体的；实在的，有形的；混凝土的；物质的**{n.}++混凝土**{v.}++用混凝土覆盖（或做成）；（使）凝固，（使）凝结；使真实（化），使具体（化）**{n.}++a strong hard building material composed of sand and gravel and cement and water**{v.}++cover with cement																										        				&quot;concrete the walls&quot;**{adj.}++[建]混凝土的；实在的，具体的；有形的**{vi.}++凝结**{n.}++具体物；凝结物**', '');
