insert into TOEFLWordBook values ('160', 'conflict', '[ˈkɑːnflɪkt]', 'http://dict.youdao.com/dictvoice?audio=conflict', '{n.}++争执，争论，分歧；战斗，战争；抵触，矛盾**{v.}++冲突，抵触**{n.}++an open clash between two opposing groups (or individuals)																										        				&quot;the harder the conflict the more glorious the triumph&quot;															   	同义词：								                                  				    struggle				    				    				      				    				      				    				                                      				    battle**{n.}++冲突，矛盾；斗争；争执**{vi.}++冲突，抵触；争执；战斗**', '');
