insert into TOEFLWordBook values ('162', 'confront', '[kənˈfrʌnt]', 'http://dict.youdao.com/dictvoice?audio=confront', '{v.}++面对，面临；正视，处理；对峙，对抗；对质，当面对证**{v.}++oppose, as in hostility or a competition																										        													        				&quot;You must confront your opponent&quot;; &quot;The two enemies finally confronted each other&quot;															   	同义词：								                                  				    face**{vt.}++面对；遭遇；比较**', '');
