insert into TOEFLWordBook values ('164', 'conjunction', '[kənˈdʒʌŋkʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=conjunction', '{n.}++结合，同时发生；连词；（占星术中两个天体的）相合**{n.}++the temporal property of two things happening at the same time																					   	同义词：								                                  				    concurrence				    				    				      				    				      				    				                                      				    coincidence				    				    				      				    				      				    				                                      				    co-occurrence**{n.}++结合；[语]连接词；同时发生**', '');
insert into TOEFLWordBook values ('165', 'conquer', '[ˈkɑːŋkər]', 'http://dict.youdao.com/dictvoice?audio=conquer', '{v.}++占领，攻克，征服；击败，战胜；克服（恐惧），解决（问题）；成功攀登；在……很受欢迎，在……取得成功**{v.}++to put down by force or authority																										        				&quot;conquer ones desires&quot;															   	同义词：								                                  				    suppress				    				    				      				    				      				    				                                      				    stamp down				    				    				      				    				      				    				                                      				    inhibit				    				    				      				    				      				    				                                      				    subdue				    				    				      				    				      				    				                                      				    curb**{vt.}++战胜，征服；攻克，攻取**{vi.}++胜利；得胜**', '');
insert into TOEFLWordBook values ('166', 'consecutive', '[kənˈsekjətɪv]', 'http://dict.youdao.com/dictvoice?audio=consecutive', '{adj.}++连续的，不间断的**{adj.}++in regular succession without gaps																					   	同义词：								                                  				    sequent				    				    				      				    				      				    				                                      				    sequential				    				    				      				    				      				    				                                      				    serial				    				    				      				    				      				    				                                      				    successive**{adj.}++连贯的；连续不断的**', '');
