insert into TOEFLWordBook values ('206', 'dairy', '[ˈderi]', 'http://dict.youdao.com/dictvoice?audio=dairy', '{adj.}++奶制的，乳品的；乳品业的，生产乳品的**{n.}++乳品公司，乳品店；乳制品；牛奶场，乳品场；地方小店；乳牛**{n.}++a farm where dairy products are produced																					   	同义词：								                                  				    dairy farm**{n.}++奶制品；乳牛；制酪场；[食品]乳品店；牛奶及乳品业**{adj.}++[食品]乳品的；牛奶的；牛奶制的；产乳的**', '');
