insert into TOEFLWordBook values ('214', 'decorate', '[ˈdekəreɪt]', 'http://dict.youdao.com/dictvoice?audio=decorate', '{v.}++装饰，装点；粉刷，装修；授予（某人）勋章**{v.}++make more attractive by adding ornament, colour, etc.																					   	同义词：								                                  				    adorn				    				    				      				    				      				    				                                      				    grace				    				    				      				    				      				    				                                      				    ornament				    				    				      				    				      				    				                                      				    embellish				    				    				      				    				      				    				                                      				    beautify**{vt.}++装饰；布置；授勋给**{vi.}++装饰；布置**', '');
insert into TOEFLWordBook values ('215', 'dedicate', '[ˈdedɪkeɪt]', 'http://dict.youdao.com/dictvoice?audio=dedicate', '{v.}++致力于，献身于；把（书、戏剧、音乐作品等）献给；为（建筑物或教堂）举行奉献（或落成）典礼**{v.}++give entirely to a specific person, activity, or cause																					   	同义词：								                                  				    give				    				    				      				    				      				    				                                      				    consecrate				    				    				      				    				      				    				                                      				    commit				    				    				      				    				      				    				                                      				    devote**{vt.}++致力；献身；题献**', '');
insert into TOEFLWordBook values ('216', 'defeat', '[dɪˈfiːt]', 'http://dict.youdao.com/dictvoice?audio=defeat', '{v.}++击败，战胜；困惑，难住；使失败，阻挠；反对（动议或提议）**{n.}++失败，战败；战胜，击败**{n.}++an unsuccessful ending to a struggle or contest																										        													        				&quot;it was a narrow defeat&quot;; &quot;the armys only defeat&quot;															   	同义词：								                                  				    licking**{vt.}++击败，战胜；挫败；使…失败**{n.}++失败；战胜**', '');
insert into TOEFLWordBook values ('217', 'defend', '[dɪˈfend]', 'http://dict.youdao.com/dictvoice?audio=defend', '{v.}++保卫，防御；捍卫，维护；（在比赛中）防守，防卫；参加卫冕赛，蝉联；做……的辩护律师，为……辩解**{v.}++argue or speak in defense of																					   	同义词：								                                  				    support				    				    				      				    				      				    				                                      				    fend for**{be the defense counsel for someone in a trial																										        				&quot;Ms.}++Smith will represent the defendant&quot;															   	同义词：								                                  				    represent**{vt.}++[法]辩护；防护**{vi.}++保卫；防守**', '');
insert into TOEFLWordBook values ('218', 'deficient', '[dɪˈfɪʃ(ə)nt]', 'http://dict.youdao.com/dictvoice?audio=deficient', '{adj.}++缺乏的，不足的；有缺点的，有缺陷的**{adj.}++inadequate in amount or degree																										        													        				&quot;a deficient education&quot;; &quot;deficient in common sense&quot;															   	同义词：								                                  				    lacking(p)				    				    				      				    				      				    				                                      				    wanting(p)**{adj.}++不足的；有缺陷的；不充分的**', '');
insert into TOEFLWordBook values ('219', 'definite', '[ˈdefɪnət]', 'http://dict.youdao.com/dictvoice?audio=definite', '{adj.}++清晰的，明晰的；确定的，不会改变的；肯定的，一定的**{n.}++确定之事**{adj.}++precise; explicit and clearly defined																										        													        													        													        													        													        				&quot;I want a definite answer&quot;; &quot;a definite statement of the terms of the will&quot;; &quot;a definite amount&quot;; &quot;definite restrictions on the sale of alcohol&quot;; &quot;the wedding date is now definite&quot;; &quot;a definite drop in attendance&quot;**', '');
insert into TOEFLWordBook values ('220', 'degrade', '[dɪˈɡreɪd]', 'http://dict.youdao.com/dictvoice?audio=degrade', '{v.}++侮辱，贬低；降低，削弱（尤指质量）；降解，分解；使降级，贬黜；使（岩石）陵削；使（能量）衰变**{v.}++reduce the level of land, as by erosion**{vt.}++贬低；使……丢脸；使……降级；使……降解**{vi.}++降级，降低；退化**', '');
