insert into TOEFLWordBook values ('222', 'delicate', '[ˈdelɪkət]', 'http://dict.youdao.com/dictvoice?audio=delicate', '{adj.}++柔和的，清淡的；虚弱的，纤弱的；脆弱的，易碎的；小巧玲珑的，纤细的；微妙的，棘手的；精致的，精巧的；灵巧的，熟练的；（仪器）灵敏的**{n.}++精美的衣物**{adj.}++exquisitely fine and subtle and pleasing; susceptible to injury																										        													        													        													        				&quot;a delicate violin passage&quot;; &quot;delicate china&quot;; &quot;a delicate flavor&quot;; &quot;the delicate wing of a butterfly&quot;**{adj.}++微妙的；精美的，雅致的；柔和的；易碎的；纤弱的；清淡可口的**', '');
