insert into TOEFLWordBook values ('244', 'discern', '[dɪˈsɜːrn]', 'http://dict.youdao.com/dictvoice?audio=discern', '{v.}++（艰难地或努力地）看出，觉察出；了解，认识**{v.}++detect with the senses																					   	同义词：								                                  				    recognize				    				    				      				    				      				    				                                      				    recognise				    				    				      				    				      				    				                                      				    distinguish				    				    				      				    				      				    				                                      				    pick out				    				    				      				    				      				    				                                      				    make out				    				    				      				    				      				    				                                      				    tell apart**{vt.}++识别；领悟，认识**{vi.}++看清楚，辨别**', '');
insert into TOEFLWordBook values ('245', 'discipline', '[ˈdɪsəplɪn]', 'http://dict.youdao.com/dictvoice?audio=discipline', '{n.}++纪律，风纪；惩罚，处分；训导，管教；训练，锻炼；自制力，自律能力；（尤指大学的）科目，学科**{v.}++惩罚，处分；训练，管教**{n.}++a branch of knowledge																										        				&quot;in what discipline is his doctorate?&quot;															   	同义词：								                                  				    subject				    				    				      				    				      				    				                                      				    subject area				    				    				      				    				      				    				                                      				    subject field				    				    				      				    				      				    				                                      				    field				    				    				      				    				      				    				                                      				    field of study				    				    				      				    				      				    				                                      				    study				    				    				      				    				      				    				                                      				    bailiwick				    				    				      				    				      				    				                                      				    branch of knowledge**{n.}++学科；[管理]纪律；训练；惩罚**{vt.}++训练，训导；惩戒**', '');
