insert into TOEFLWordBook values ('247', 'disperse', '[dɪˈspɜːrs]', 'http://dict.youdao.com/dictvoice?audio=disperse', '{v.}++分散，散布；疏散，驱散；使（光）色散**{adj.}++分散的**{v.}++distribute loosely																					   	同义词：								                                  				    scatter				    				    				      				    				      				    				                                      				    sprinkle				    				    				      				    				      				    				                                      				    dot				    				    				      				    				      				    				                                      				    dust**{vt.}++分散；使散开；传播**{vi.}++分散**{adj.}++分散的**', '');
insert into TOEFLWordBook values ('248', 'dispute', '[dɪˈspjuːt]', 'http://dict.youdao.com/dictvoice?audio=dispute', '{n.}++争论，辩论，纠纷**{v.}++对……提出质疑，否认；争论，辩论；争夺，竞争；阻止（着陆），抵抗（进攻）**{n.}++a disagreement or argument about something important																										        				&quot;he had a dispute with his wife&quot;															   	同义词：								                                  				    difference				    				    				      				    				      				    				                                      				    difference of opinion				    				    				      				    				      				    				                                      				    conflict**{vt.}++辩论；怀疑；阻止；抗拒**{vi.}++争论**{n.}++辩论；争吵**', '');
