insert into TOEFLWordBook values ('250', 'disseminate', '[dɪˈsemɪneɪt]', 'http://dict.youdao.com/dictvoice?audio=disseminate', '{v.}++散布，传播（信息、知识等）**{v.}++cause to become widely known																					   	同义词：								                                  				    circulate				    				    				      				    				      				    				                                      				    circularize				    				    				      				    				      				    				                                      				    circularise				    				    				      				    				      				    				                                      				    distribute				    				    				      				    				      				    				                                      				    propagate				    				    				      				    				      				    				                                      				    broadcast				    				    				      				    				      				    				                                      				    spread				    				    				      				    				      				    				                                      				    diffuse				    				    				      				    				      				    				                                      				    disperse				    				    				      				    				      				    				                                      				    pass around**{vt.}++宣传，传播；散布**{vi.}++散布；广为传播**', '');
insert into TOEFLWordBook values ('251', 'dissolve', '[dɪˈzɑːlv]', 'http://dict.youdao.com/dictvoice?audio=dissolve', '{v.}++解散，解除；消失；（以化学手段）除去，分散；（使）溶解**{n.}++（电影中）（画面的）叠化，淡入淡出**{n.}++(film) a gradual transition from one scene to the next; the next scene is gradually superimposed as the former scene fades out**{v.}++cause to go into a solution																										        				&quot;The recipe says that we should dissolve a cup of sugar in two cups of water&quot;															   	同义词：								                                  				    resolve				    				    				      				    				      				    				                                      				    break up**{vt.}++使溶解；使分解；使液化**{vi.}++溶解；解散；消失**', '');
insert into TOEFLWordBook values ('252', 'distant', '[ˈdɪstənt]', 'http://dict.youdao.com/dictvoice?audio=distant', '{adj.}++遥远的，久远的；冷淡的；心不在焉的；远亲的；不相似的，不同的**{adj.}++separated in space or coming from or going to a distance																										        													        													        													        				&quot;distant villages&quot;; &quot;the sound of distant traffic&quot;; &quot;a distant sound&quot;; &quot;a distant telephone call&quot;**{adj.}++遥远的；冷漠的；远隔的**', '');
insert into TOEFLWordBook values ('253', 'distinct', '[dɪˈstɪŋkt]', 'http://dict.youdao.com/dictvoice?audio=distinct', '{adj.}++不同的，有区别的；清楚的，明显的；确切的**{adj.}++easy to perceive; especially clearly outlined																										        													        													        													        													        				&quot;a distinct flavor&quot;; &quot;a distinct odor of turpentine&quot;; &quot;a distinct outline&quot;; &quot;the ship appeared as a distinct silhouette&quot;; &quot;distinct fingerprints&quot;**{clearly or sharply defined to the mind																										        													        				&quot;Claudius was the first to invade Britain with distinct.}++..intentions of conquest&quot;; &quot;trenchant distinctions between right and wrong&quot;															   	同义词：								                                  				    clear-cut				    				    				      				    				      				    				                                      				    trenchant**{adj.}++明显的；独特的；清楚的；有区别的**', '');
insert into TOEFLWordBook values ('254', 'distinguish', '[dɪˈstɪŋɡwɪʃ]', 'http://dict.youdao.com/dictvoice?audio=distinguish', '{v.}++使有别于；看清，认出；区别，分清**{v.}++mark as different																										        				&quot;We distinguish several kinds of maple&quot;															   	同义词：								                                  				    separate				    				    				      				    				      				    				                                      				    differentiate				    				    				      				    				      				    				                                      				    secern				    				    				      				    				      				    				                                      				    secernate				    				    				      				    				      				    				                                      				    severalize				    				    				      				    				      				    				                                      				    severalise				    				    				      				    				      				    				                                      				    tell				    				    				      				    				      				    				                                      				    tell apart**{vt.}++区分；辨别；使杰出，使表现突出**{vi.}++区别，区分；辨别**', '');
insert into TOEFLWordBook values ('255', 'distort', '[dɪˈstɔːrt]', 'http://dict.youdao.com/dictvoice?audio=distort', '{v.}++扭曲，使失真；歪曲，曲解**{v.}++make false by mutilation or addition; as of a message or story																					   	同义词：								                                  				    falsify				    				    				      				    				      				    				                                      				    garble				    				    				      				    				      				    				                                      				    warp**{vt.}++扭曲；使失真；曲解**{vi.}++扭曲；变形**', '');
insert into TOEFLWordBook values ('256', 'distract', '[dɪˈstrækt]', 'http://dict.youdao.com/dictvoice?audio=distract', '{v.}++使分心，使转移注意力；使困惑，使迷惑**{v.}++draw someones attention away from something																										        				&quot;The thief distracted the bystanders&quot;															   	同义词：								                                  				    deflect**{vt.}++转移；分心**', '');
insert into TOEFLWordBook values ('257', 'district', '[ˈdɪstrɪkt]', 'http://dict.youdao.com/dictvoice?audio=district', '{n.}++地区，区域；行政区，辖区；（郡或区以下的）选区**{v.}++把……划分成区**{n.}++a region marked off for administrative or other purposes																					   	同义词：								                                  				    territory				    				    				      				    				      				    				                                      				    territorial dominion				    				    				      				    				      				    				                                      				    dominion**{v.}++regulate housing in; of certain areas of towns																					   	同义词：								                                  				    zone**{n.}++[地理]区域；地方；行政区**', '');
insert into TOEFLWordBook values ('258', 'disturb', '[dɪˈstɜːrb]', 'http://dict.youdao.com/dictvoice?audio=disturb', '{v.}++打扰，妨碍；使焦虑，使烦恼；移动，弄乱**{v.}++move deeply																					   	同义词：								                                  				    upset				    				    				      				    				      				    				                                      				    trouble**{vt.}++打扰；妨碍；使不安；弄乱；使恼怒**{vi.}++打扰；妨碍**', '');
insert into TOEFLWordBook values ('259', 'dive', '[daɪv]', 'http://dict.youdao.com/dictvoice?audio=dive', '{v.}++跳水；潜水；突然大幅贬值，暴跌；下降，下潜；扑向，冲向；（飞机，鸟）俯冲；热情投身于；快速伸入（包、口袋等）；（对方阻截时）假摔**{n.}++跳水；潜水；俯冲；突降，暴跌；冲，扑；（遇到阻截时的）假摔；低级的餐馆（或酒吧、娱乐场所）**{n.}++a cheap disreputable nightclub or dance hall																					   	同义词：								                                  				    honkytonk**{vi.}++[水运]潜水；跳水；[航]俯冲；急剧下降**{n.}++[水运]潜水；跳水；[航]俯冲；扑**', '');
insert into TOEFLWordBook values ('260', 'diverse', '[daɪˈvɜːrs]', 'http://dict.youdao.com/dictvoice?audio=diverse', '{adj.}++不同的，各式各样的**{adj.}++many and different																										        				&quot;a person of diverse talents&quot;															   	同义词：								                                  				    divers(a)**{adj.}++不同的；多种多样的；变化多的**', '');
insert into TOEFLWordBook values ('261', 'divert', '[daɪˈvɜːrt]', 'http://dict.youdao.com/dictvoice?audio=divert', '{v.}++使转向，使绕道；分散，转移；娱乐，供消遣；转接（电话）；改变（资金、材料等）的用途**{v.}++turn aside; turn away from																					   	同义词：								                                  				    deviate**{vt.}++转移；使…欢娱；使…转向**{vi.}++转移**', '');
insert into TOEFLWordBook values ('262', 'doctrine', '[ˈdɑːktrɪn]', 'http://dict.youdao.com/dictvoice?audio=doctrine', '{n.}++教义，主义，信条；（政府政策的）正式声明**{n.}++a belief (or system of beliefs) accepted as authoritative by some group or school																					   	同义词：								                                  				    philosophy				    				    				      				    				      				    				                                      				    philosophical system				    				    				      				    				      				    				                                      				    school of thought				    				    				      				    				      				    				                                      				    ism**{n.}++主义；学说；教义；信条**', '');
insert into TOEFLWordBook values ('263', 'domain', '[doʊˈmeɪn]', 'http://dict.youdao.com/dictvoice?audio=domain', '{n.}++领域，范围；领土，势力范围；（因特网上的）域；（函数的）定义域；地产**{n.}++a particular environment or walk of life																					   	同义词：								                                  				    sphere				    				    				      				    				      				    				                                      				    area				    				    				      				    				      				    				                                      				    orbit				    				    				      				    				      				    				                                      				    field				    				    				      				    				      				    				                                      				    arena**{n.}++领域；域名；产业；地产**', '');
insert into TOEFLWordBook values ('264', 'domestic', '[dəˈmestɪk]', 'http://dict.youdao.com/dictvoice?audio=domestic', '{adj.}++国内的，本国的；家用的，家庭的；喜爱家庭生活的，乐于操持家务的；非野生的，驯养的**{n.}++家庭纠纷，家庭矛盾；佣人，家仆；国货，本地产品**{n.}++a servant who is paid to perform menial tasks around the household																					   	同义词：								                                  				    domestic help				    				    				      				    				      				    				                                      				    house servant**{adj.}++of concern to or concerning the internal affairs of a nation																										        				&quot;domestic issues such as tax rate and highway construction&quot;**{adj.}++国内的；家庭的；驯养的；一心只管家务的**{n.}++国货；佣人**', '');
insert into TOEFLWordBook values ('265', 'dominate', '[ˈdɑːmɪneɪt]', 'http://dict.youdao.com/dictvoice?audio=dominate', '{v.}++统治，支配；在……中占首要地位；俯视，高耸于；占绝对优势**{v.}++be larger in number, quantity, power, status or importance																										        				&quot;Hispanics predominate in this neighborhood&quot;															   	同义词：								                                  				    predominate				    				    				      				    				      				    				                                      				    rule				    				    				      				    				      				    				                                      				    reign				    				    				      				    				      				    				                                      				    prevail**{vt.}++控制；支配；占优势；在…中占主要地位**{vi.}++占优势；处于支配地位**', '');
insert into TOEFLWordBook values ('266', 'dot', '[dɑːt]', 'http://dict.youdao.com/dictvoice?audio=dot', '{n.}++点，小圆点，点状物；顿音记号；（摩尔斯电码、因特网或电子邮件地址中的）点；嫁妆**{v.}++加点；散布于，遍布；给音符加附点；击打**{n.}++a very small circular shape																										        				&quot;draw lines between the dots&quot;															   	同义词：								                                  				    point**{n.}++[数]点，圆点；嫁妆**', '');
insert into TOEFLWordBook values ('267', 'draft', '[dræft]', 'http://dict.youdao.com/dictvoice?audio=draft', '{n.}++草稿，草案；汇票；通风气流，穿堂风（=draught）；征兵；（职业球队的）选拔队员制**{v.}++起草，草拟；选派，派遣；征召，征召……入伍；挑选，选拔（运动员）；作草图，绘样**{adj.}++（动物）驮重物的，负重的；（啤酒）散装的；草拟的**{n.}++a document ordering the payment of money; drawn by one person or bank on another																					   	同义词：								                                  				    bill of exchange				    				    				      				    				      				    				                                      				    order of payment**', '');
insert into TOEFLWordBook values ('268', 'drain', '[dreɪn]', 'http://dict.youdao.com/dictvoice?audio=drain', '{v.}++（使）排出，滤干；喝光，喝干；使劳累，使疲惫；（使）逐渐消失；使降低，消耗；（通常指因惊吓或疾病而脸色）变苍白；漂亮地完成（投篮、射门等）；将（球）轻击入穴**{n.}++下水道，排水管；流失，消耗；（将体内液体排走的）导管，引流管；（场效应晶体管的）漏极；使人疲倦的事物，负担**{n.}++emptying something accomplished by allowing liquid to run out of it																					   	同义词：								                                  				    drainage**{vi.}++排水；流干**{vt.}++喝光，耗尽；使流出；排掉水**{n.}++排水；下水道，[建]排水管；消耗**', '');
insert into TOEFLWordBook values ('269', 'drift', '[drɪft]', 'http://dict.youdao.com/dictvoice?audio=drift', '{v.}++飘移，漂流；任其自然地（或不知不觉地）进入（某种状态）；流浪，漂泊；缓慢移动；传出；吹积**{n.}++流动，趋势；吹积物，雪堆；主旨，大意；偏航；不作为，优柔寡断；丛生的植物；冰碛；水平巷道**{n.}++a force that moves something along																					   	同义词：								                                  				    impetus				    				    				      				    				      				    				                                      				    impulsion**{n.}++漂流，[电子]漂移；趋势；漂流物**{vi.}++漂流，[电子]漂移；漂泊**', '');
insert into TOEFLWordBook values ('270', 'drip', '[drɪp]', 'http://dict.youdao.com/dictvoice?audio=drip', '{v.}++滴下，滴出；含有，充满**{n.}++水滴，滴液；滴水声，滴落；（医用）滴注器；笨蛋，懦夫，平庸乏味者**{n.}++flowing in drops; the formation and falling of drops of liquid																										        				&quot;theres a drip through the roof&quot;															   	同义词：								                                  				    trickle				    				    				      				    				      				    				                                      				    dribble**{vi.}++滴下；充满；漏下**{n.}++水滴，[建]滴水声；静脉滴注；使人厌烦的人**{vt.}++使滴下；溢出，发出**', '');
insert into TOEFLWordBook values ('271', 'droplet', '[ˈdrɑːplət]', 'http://dict.youdao.com/dictvoice?audio=droplet', '{n.}++小滴，微滴**{n.}++a tiny drop**{n.}++小滴，[气象]微滴**', '');
insert into TOEFLWordBook values ('272', 'dull', '[dʌl]', 'http://dict.youdao.com/dictvoice?audio=dull', '{adj.}++枯燥无聊的；无精打采的；不明亮的；（声音）不清晰的；阴沉的；不明显的，隐隐的；钝的；迟钝的，愚笨的；萧条的**{v.}++减轻，缓解；使迟钝；（使）变模糊，变暗淡；（使刀或刀片等）变钝；（兴趣、痛苦等）减少**{v.}++make dull in appearance																										        				&quot;Age had dulled the surface&quot;**{adj.}++钝的；迟钝的；无趣的；呆滞的；阴暗的**{vt.}++使迟钝；使阴暗；缓和**{vi.}++减少；变迟钝**', '');
insert into TOEFLWordBook values ('273', 'dumb', '[dʌm]', 'http://dict.youdao.com/dictvoice?audio=dumb', '{adj.}++哑的，不能说话的；一时说不出话的，不肯开口的；愚蠢的；（计算机终端）简易的**{v.}++使通俗化；使变哑，使沉默**{adj.}++slow to learn or understand; lacking intellectual acuity																										        				&quot;dumb officials make some really dumb decisions&quot;															   	同义词：								                                  				    dense				    				    				      				    				      				    				                                      				    dim				    				    				      				    				      				    				                                      				    dull				    				    				      				    				      				    				                                      				    obtuse				    				    				      				    				      				    				                                      				    slow**{adj.}++哑的，无说话能力的；不说话的，无声音的**', '');
