insert into TOEFLWordBook values ('275', 'dye', '[daɪ]', 'http://dict.youdao.com/dictvoice?audio=dye', '{v.}++给……染色**{n.}++染料，染液**{n.}++a usually soluble substance for staining or coloring e.g. fabrics or hair																					   	同义词：								                                  				    dyestuff**{v.}++color with dye																										        				&quot;Please dye these shoes&quot;**{n.}++[染料]染料；染色**{vt.}++染；把…染上颜色**', '');
insert into TOEFLWordBook values ('276', 'dynamic', '[daɪˈnæmɪk]', 'http://dict.youdao.com/dictvoice?audio=dynamic', '{adj.}++充满活力的，精力充沛的；动态的，发展变化的；力的，动力的**{n.}++动力，活力；相互作用，动态；动力学**{n.}++an efficient incentive																										        				&quot;they hoped it would act as a spiritual dynamic on all churches&quot;															   	同义词：								                                  				    moral force**{adj.}++characterized by action or forcefulness or force of personality																										        													        													        				&quot;a dynamic market&quot;; &quot;a dynamic speaker&quot;; &quot;the dynamic president of the firm&quot;															   	同义词：								                                  				    dynamical**{expressing action rather than a state of being; used of verbs (e.}++g. `to run) and participial adjectives (e.g. `running in `running water)																					   	同义词：								                                  				    active**{adj.}++[力]动态的；动力的；动力学的；有活力的**{n.}++动态；[力]动力**', '');
insert into TOEFLWordBook values ('277', 'eager', '[ˈiːɡər]', 'http://dict.youdao.com/dictvoice?audio=eager', '{adj.}++热切的，渴望的，渴求的**{n.}++a high wave (often dangerous) caused by tidal flow (as by colliding tidal currents or in a narrow estuary)																					   	同义词：								                                  				    tidal bore				    				    				      				    				      				    				                                      				    bore				    				    				      				    				      				    				                                      				    eagre				    				    				      				    				      				    				                                      				    aegir**{adj.}++having or showing keen interest or intense desire or impatient expectancy																										        													        													        													        													        				&quot;eager to learn&quot;; &quot;eager to travel abroad&quot;; &quot;eager for success&quot;; &quot;eager helpers&quot;; &quot;an eager look&quot;**{adj.}++渴望的；热切的；热心的**', '');
insert into TOEFLWordBook values ('278', 'earnest', '[ˈɜːrnɪst]', 'http://dict.youdao.com/dictvoice?audio=earnest', '{adj.}++认真的，诚挚的，真诚的**{n.}++预示，象征；严肃，认真（in earnest）**{n.}++something of value given by one person to another to bind a contract**{adj.}++characterized by a firm and humorless belief in the validity of your opinions																										        				&quot;both sides were deeply in earnest, even passionate&quot;															   	同义词：								                                  				    sincere				    				    				      				    				      				    				                                      				    solemn**{adj.}++认真的，热心的；重要的**{n.}++认真；[贸易]定金；诚挚**', '');
