insert into TOEFLWordBook values ('280', 'echo', '[ˈekoʊ]', 'http://dict.youdao.com/dictvoice?audio=echo', '{n.}++回声，回音，余音绕梁；重复，附和，共鸣；相似之处，再现；回声插入；（话语结构和内容的）重复；（桥牌）回声信号**{v.}++回响，发出回声；重复，附和**{n.}++the persistence of a sound after its source has stopped																					   	同义词：								                                  				    reverberation				    				    				      				    				      				    				                                      				    sound reflection				    				    				      				    				      				    				                                      				    replication**{vt.}++反射；重复**{n.}++回音；效仿**', '');
