insert into TOEFLWordBook values ('282', 'elaborate', '[ɪˈlæbərət]', 'http://dict.youdao.com/dictvoice?audio=elaborate', '{adj.}++复杂的，详尽的；精心制作的**{v.}++详细说明，详尽阐述；精心制作**{v.}++add details, as to an account or idea; clarify the meaning of and discourse in a learned way, usually in writing																										        				&quot;She elaborated on the main ideas in her dissertation&quot;															   	同义词：								                                  				    lucubrate				    				    				      				    				      				    				                                      				    expatiate				    				    				      				    				      				    				                                      				    exposit				    				    				      				    				      				    				                                      				    enlarge				    				    				      				    				      				    				                                      				    flesh out				    				    				      				    				      				    				                                      				    expand				    				    				      				    				      				    				                                      				    expound				    				    				      				    				      				    				                                      				    dilate**{adj.}++精心制作的；详尽的；煞费苦心的**{vt.}++精心制作；详细阐述；从简单成分合成（复杂有机物）**{vi.}++详细描述；变复杂**', '');
