insert into TOEFLWordBook values ('291', 'emerge', '[ɪˈmɜːrdʒ]', 'http://dict.youdao.com/dictvoice?audio=emerge', '{v.}++浮现，出现；显露，知悉；恢复过来，幸存下来；形成，兴起**{v.}++come out into view, as from concealment																										        				&quot;Suddenly, the proprietor emerged from his office&quot;**{vi.}++浮现；摆脱；暴露**', '');
insert into TOEFLWordBook values ('292', 'emit', '[iˈmɪt]', 'http://dict.youdao.com/dictvoice?audio=emit', '{v.}++排放，散发（尤指气体、辐射物）；发出（声音或噪音）；发行，发表**{v.}++expel (gases or odors)																					   	同义词：								                                  				    breathe				    				    				      				    				      				    				                                      				    pass off**{give off, send forth, or discharge; as of light, heat, or radiation, vapor, etc.}++&quot;The ozone layer blocks some harmful rays which the sun emits&quot;															   	同义词：								                                  				    give out				    				    				      				    				      				    				                                      				    give off**{vt.}++发出，放射；发行；发表**', '');
insert into TOEFLWordBook values ('293', 'emphasize', '[ˈemfəsaɪz]', 'http://dict.youdao.com/dictvoice?audio=emphasize', '{v.}++强调，着重；重读（单词或短语）；使突出（或明显）**{v.}++to stress, single out as important																										        				&quot;Dr. Jones emphasizes exercise in addition to a change in diet&quot;															   	同义词：								                                  				    stress				    				    				      				    				      				    				                                      				    emphasise				    				    				      				    				      				    				                                      				    punctuate				    				    				      				    				      				    				                                      				    accent				    				    				      				    				      				    				                                      				    accentuate**{vt.}++强调，着重**', '');
insert into TOEFLWordBook values ('294', 'enclose', '[ɪnˈkloʊz]', 'http://dict.youdao.com/dictvoice?audio=enclose', '{v.}++包围，围住；随信附上，随信装入**{v.}++enclose or enfold completely with or as if with a covering																					   	同义词：								                                  				    envelop				    				    				      				    				      				    				                                      				    enfold				    				    				      				    				      				    				                                      				    enwrap				    				    				      				    				      				    				                                      				    wrap**{vt.}++围绕；装入；放入封套**', '');
insert into TOEFLWordBook values ('295', 'encompass', '[ɪnˈkʌmpəs]', 'http://dict.youdao.com/dictvoice?audio=encompass', '{v.}++包含，包括；包围，环绕；促成，实现**{v.}++include in scope; include as part of something broader; have as ones sphere or territory																										        				&quot;This group encompasses a wide range of people from different backgrounds&quot;															   	同义词：								                                  				    embrace				    				    				      				    				      				    				                                      				    comprehend				    				    				      				    				      				    				                                      				    cover**{vt.}++包含；包围，环绕；完成**', '');
insert into TOEFLWordBook values ('296', 'encounter', '[ɪnˈkaʊntər]', 'http://dict.youdao.com/dictvoice?audio=encounter', '{v.}++遭遇；偶遇，邂逅**{n.}++偶遇，邂逅；经历，体验；冲突；比赛，交锋**{n.}++a minor short-term fight																					   	同义词：								                                  				    brush				    				    				      				    				      				    				                                      				    clash				    				    				      				    				      				    				                                      				    skirmish**{vt.}++遭遇，邂逅；遇到**{n.}++遭遇，偶然碰见**{vi.}++遭遇；偶然相遇**', '');
insert into TOEFLWordBook values ('297', 'endangered', '[ɪnˈdeɪndʒərd]', 'http://dict.youdao.com/dictvoice?audio=endangered', '{adj.}++（动植物）濒危的**{adj.}++(of flora or fauna) in imminent danger of extinction																										        				&quot;an endangered species&quot;**', '');
insert into TOEFLWordBook values ('298', 'endeavor', '[ɪnˈdevər]', 'http://dict.youdao.com/dictvoice?audio=endeavor', '{n.}++努力；尽力（等于 endeavour）**{vi.}++努力；尽力（等于 endeavour）**{vt.}++努力；尽力（等于 endeavour）**{n.}++a purposeful or industrious undertaking (especially one that requires effort or boldness)																					   	同义词：								                                  				    enterprise				    				    				      				    				      				    				                                      				    endeavour**{n.}++努力；尽力（等于endeavour）**{vi.}++努力；尽力（等于endeavour）**{vt.}++努力；尽力（等于endeavour）**', '');
insert into TOEFLWordBook values ('299', 'endure', '[ɪnˈdʊr]', 'http://dict.youdao.com/dictvoice?audio=endure', '{v.}++持续存在，持久；忍受，忍耐**{v.}++put up with something or somebody unpleasant																										        				&quot;The new secretary had to endure a lot of unprofessional remarks&quot;															   	同义词：								                                  				    digest				    				    				      				    				      				    				                                      				    stick out				    				    				      				    				      				    				                                      				    stomach				    				    				      				    				      				    				                                      				    bear				    				    				      				    				      				    				                                      				    stand				    				    				      				    				      				    				                                      				    tolerate				    				    				      				    				      				    				                                      				    support				    				    				      				    				      				    				                                      				    brook				    				    				      				    				      				    				                                      				    abide				    				    				      				    				      				    				                                      				    suffer				    				    				      				    				      				    				                                      				    put up**{vt.}++忍耐；容忍**{vi.}++忍耐；持续**', '');
insert into TOEFLWordBook values ('300', 'energetic', '[ˌenərˈdʒetɪk]', 'http://dict.youdao.com/dictvoice?audio=energetic', '{adj.}++精力充沛的，充满活力的；积极的；（活动）剧烈的，费力气的；高能的**{adj.}++possessing or exerting or displaying energy																										        													        													        				&quot;an energetic fund raiser for the college&quot;; &quot;an energetic group of hikers&quot;; &quot;it caused an energetic chemical reaction&quot;**{adj.}++精力充沛的；积极的；有力的**', '');
insert into TOEFLWordBook values ('301', 'engage', '[ɪnˈɡeɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=engage', '{v.}++雇用，聘请；参加，从事；吸引，引起；与……交战，开战；（使）（机器）啮合，接合；预定（膳食，地方等）；适应，与……有密切关系；允诺，签约保证；（运动员或击剑手）使（兵器）交结在一起；占用**{v.}++carry out or participate in an activity; be involved in																										        				&quot;They engaged in a discussion&quot;															   	同义词：								                                  				    prosecute				    				    				      				    				      				    				                                      				    pursue**{vt.}++吸引，占用；使参加；雇佣；使订婚；预定**{vi.}++从事；答应，保证；交战；啮合**', '');
insert into TOEFLWordBook values ('302', 'engrave', '[ɪnˈɡreɪv]', 'http://dict.youdao.com/dictvoice?audio=engrave', '{v.}++雕刻（文字，图案）；铭刻在（记忆，脑海）中（be engraved on/in）**{v.}++carve, cut, or etch into a material or surface																										        													        				&quot;engrave a pen&quot;; &quot;engraved the winners name onto the trophy cup&quot;															   	同义词：								                                  				    scratch				    				    				      				    				      				    				                                      				    grave				    				    				      				    				      				    				                                      				    inscribe**{vt.}++雕刻；铭记**', '');
insert into TOEFLWordBook values ('303', 'enhance', '[ɪnˈhæns]', 'http://dict.youdao.com/dictvoice?audio=enhance', '{v.}++增强，提高，改善**{v.}++increase																										        				&quot;This will enhance your enjoyment&quot;															   	同义词：								                                  				    heighten				    				    				      				    				      				    				                                      				    raise**{vt.}++提高；加强；增加**', '');
insert into TOEFLWordBook values ('304', 'enormous', '[ɪˈnɔːrməs]', 'http://dict.youdao.com/dictvoice?audio=enormous', '{adj.}++巨大的，极大的；凶暴的，极恶的**{adj.}++extraordinarily large in size or extent or amount or power or degree																										        													        				&quot;an enormous boulder&quot;; &quot;enormous expenses&quot;															   	同义词：								                                  				    tremendous**{adj.}++庞大的，巨大的；凶暴的，极恶的**', '');
insert into TOEFLWordBook values ('305', 'enroll', '[ɪnˈroʊl]', 'http://dict.youdao.com/dictvoice?audio=enroll', '{vt.}++登记；使加入；把……记入名册；使入伍**{vi.}++参加；登记；注册；记入名册**{v.}++register formally as a participant or member																					   	同义词：								                                  				    inscribe				    				    				      				    				      				    				                                      				    enter				    				    				      				    				      				    				                                      				    enrol				    				    				      				    				      				    				                                      				    recruit**{vt.}++登记；使加入；把...记入名册；使入伍**{vi.}++参加；登记；注册；记入名册**', '');
