insert into TOEFLWordBook values ('307', 'enterprise', '[ˈentərpraɪz]', 'http://dict.youdao.com/dictvoice?audio=enterprise', '{n.}++企业，事业单位；事业心，进取心；事业；创业，企业经营**{n.}++a purposeful or industrious undertaking (especially one that requires effort or boldness)																										        				&quot;he had doubts about the whole enterprise&quot;															   	同义词：								                                  				    endeavor				    				    				      				    				      				    				                                      				    endeavour**{n.}++[经]企业；事业；进取心；事业心**', '');
