insert into TOEFLWordBook values ('310', 'entrance', '[ˈentrəns]', 'http://dict.youdao.com/dictvoice?audio=entrance', '{n.}++入口，进口；进入，进门；（演员的）登台，登场；进入权，进入许可；卷入，参与；着手，开始；就任，就职**{v.}++使入迷，使狂喜**{n.}++something that provides access (to get in or get out)																										        				&quot;they waited at the entrance to the garden&quot;															   	同义词：								                                  				    entranceway				    				    				      				    				      				    				                                      				    entryway				    				    				      				    				      				    				                                      				    entry				    				    				      				    				      				    				                                      				    entree**{n.}++[建]入口；进入**', '');
