insert into TOEFLWordBook values ('312', 'entry', '[ˈentri]', 'http://dict.youdao.com/dictvoice?audio=entry', '{n.}++进入，加入；出场，莅临；门，入口；进入权，进入许可；参赛；参赛作品，竞赛答题；参赛人数，报名人数；登记，录入；条目，账目，记录**{n.}++an item inserted in a written record**{something (manuscripts or architectural plans and models or estimates or works of art of all genres etc.}++) submitted for the judgment of others (as in a competition)																					   	同义词：								                                  				    submission**{n.}++进入；入口；条目；登记；报关手续；对土地的侵占**', '');
insert into TOEFLWordBook values ('313', 'epoch', '[ˈepək]', 'http://dict.youdao.com/dictvoice?audio=epoch', '{n.}++时代，纪元；值得纪念的事件（或日期）；世（地质年代，纪下分世）；历元**{n.}++a period marked by distinctive character or reckoned from a fixed point or event																					   	同义词：								                                  				    era**{n.}++[地质]世；新纪元；新时代；时间上的一点**', '');
insert into TOEFLWordBook values ('314', 'equip', '[ɪˈkwɪp]', 'http://dict.youdao.com/dictvoice?audio=equip', '{v.}++装备，配备；使有所准备，使能够胜任**{v.}++provide with (something) usually for a specific purpose																										        				&quot;The expedition was equipped with proper clothing, food, and other necessities&quot;															   	同义词：								                                  				    fit				    				    				      				    				      				    				                                      				    fit out				    				    				      				    				      				    				                                      				    outfit**{vt.}++装备，配备**', '');
insert into TOEFLWordBook values ('315', 'equivalent', '[ɪˈkwɪvələnt]', 'http://dict.youdao.com/dictvoice?audio=equivalent', '{adj.}++等同的，等效的**{n.}++对等的人（或事物），对应的人（或事物）；当量（equivalent weight）**{n.}++a person or thing equal to another in value or measure or force or effect or significance etc																										        				&quot;send two dollars or the equivalent in stamps&quot;**{adj.}++[物价][化学][数]等价的，相等的；同意义的**{n.}++[物价][化学]等价物，相等物**', '');
