insert into TOEFLWordBook values ('317', 'erect', '[ɪˈrekt]', 'http://dict.youdao.com/dictvoice?audio=erect', '{v.}++搭建，建造；使竖立，竖起；创立，建立；安装，装配；（使）勃起**{adj.}++竖直的，直立的；竖起的；勃起的，坚挺的**{v.}++construct, build, or erect																					   	同义词：								                                  				    raise				    				    				      				    				      				    				                                      				    rear				    				    				      				    				      				    				                                      				    set up				    				    				      				    				      				    				                                      				    put up**{vt.}++使竖立；建造；安装**{adj.}++竖立的；笔直的；因性刺激而勃起的**{vi.}++直立；勃起**', '');
insert into TOEFLWordBook values ('318', 'escape', '[ɪˈskeɪp]', 'http://dict.youdao.com/dictvoice?audio=escape', '{v.}++逃跑，逃脱；逃避，摆脱；避开，避免（疾病或受伤等）；泄露，逸出；不自觉地说出；被遗忘，被忽略；去度假；退出**{n.}++逃跑，逃离；逃避现实，暂时解脱；漏出，逸出；Esc退出键；度假；逃跑工具，逃跑方法；野化的植物（或宠物）**{n.}++the act of escaping physically																										        													        				&quot;he made his escape from the mental hospital&quot;; &quot;the canary escaped from its cage&quot;															   	同义词：								                                  				    flight**{vt.}++逃避，避免；被忘掉**{vi.}++逃脱；避开；溜走**{n.}++逃跑；逃亡**', '');
insert into TOEFLWordBook values ('319', 'essence', '[ˈes(ə)ns]', 'http://dict.youdao.com/dictvoice?audio=essence', '{n.}++本质，要素；香精，香料**{n.}++the choicest or most essential or most vital part of some idea or experience																					   	同义词：								                                  				    kernel				    				    				      				    				      				    				                                      				    substance				    				    				      				    				      				    				                                      				    core				    				    				      				    				      				    				                                      				    center				    				    				      				    				      				    				                                      				    gist				    				    				      				    				      				    				                                      				    heart				    				    				      				    				      				    				                                      				    heart and soul				    				    				      				    				      				    				                                      				    inwardness				    				    				      				    				      				    				                                      				    marrow				    				    				      				    				      				    				                                      				    meat				    				    				      				    				      				    				                                      				    nub				    				    				      				    				      				    				                                      				    pith				    				    				      				    				      				    				                                      				    sum				    				    				      				    				      				    				                                      				    nitty-gritty**{n.}++本质，实质；精华；[化工]香精**', '');
insert into TOEFLWordBook values ('320', 'estimate', '[ˈestɪmət; ˈestɪmeɪt]', 'http://dict.youdao.com/dictvoice?audio=estimate', '{v.}++估计；判断，评价**{n.}++估计，估价；估价单；看法，判断**{n.}++an approximate calculation of quantity or degree or worth																										        				&quot;an estimate of what it would cost&quot;															   	同义词：								                                  				    estimation				    				    				      				    				      				    				                                      				    approximation				    				    				      				    				      				    				                                      				    idea**{vi.}++估计，估价**{n.}++估计，估价；判断，看法**{vt.}++估计，[数]估量；判断，评价**', '');
insert into TOEFLWordBook values ('321', 'ethic', '[ˈeθɪk]', 'http://dict.youdao.com/dictvoice?audio=ethic', '{n.}++行为准则，道德规范，伦理标准；信仰**{adj.}++（与）道德规范（有关）的，（与）伦理（有关）的（=ethical）**{n.}++the principles of right and wrong that are accepted by an individual or a social group																										        				&quot;the Puritan ethic&quot;															   	同义词：								                                  				    moral principle				    				    				      				    				      				    				                                      				    value-system				    				    				      				    				      				    				                                      				    value orientation**{n.}++伦理；道德规范**{adj.}++伦理的；道德的（等于ethical）**', '');
insert into TOEFLWordBook values ('322', 'evaporate', '[ɪˈvæpəreɪt]', 'http://dict.youdao.com/dictvoice?audio=evaporate', '{v.}++（使）蒸发，挥发；消失，消散**{v.}++lose or cause to lose liquid by vaporization leaving a more concentrated residue																										        				&quot;evaporate milk&quot;															   	同义词：								                                  				    vaporize				    				    				      				    				      				    				                                      				    vaporise**{vt.}++使……蒸发；使……脱水；使……消失**{vi.}++蒸发，挥发；消失，失踪**', '');
insert into TOEFLWordBook values ('323', 'evoke', '[ɪˈvoʊk]', 'http://dict.youdao.com/dictvoice?audio=evoke', '{v.}++引起，唤起（感情、记忆或形象）；召（魂），唤（神）**{v.}++call forth (emotions, feelings, and responses)																										        				&quot;evoke sympathy&quot;															   	同义词：								                                  				    arouse				    				    				      				    				      				    				                                      				    elicit				    				    				      				    				      				    				                                      				    enkindle				    				    				      				    				      				    				                                      				    kindle				    				    				      				    				      				    				                                      				    fire				    				    				      				    				      				    				                                      				    raise				    				    				      				    				      				    				                                      				    provoke**{vt.}++引起，唤起；博得**', '');
insert into TOEFLWordBook values ('324', 'evolve', '[ɪˈvɑːlv]', 'http://dict.youdao.com/dictvoice?audio=evolve', '{v.}++进化，演化；逐步发展，逐渐演变**{v.}++work out																					   	同义词：								                                  				    germinate				    				    				      				    				      				    				                                      				    develop**{vt.}++发展，进化；进化；使逐步形成；推断出**{vi.}++发展，进展；进化；逐步形成**', '');
insert into TOEFLWordBook values ('325', 'exaggerate', '[ɪɡˈzædʒəreɪt]', 'http://dict.youdao.com/dictvoice?audio=exaggerate', '{v.}++夸大，言过其实；使扩大**{v.}++to enlarge beyond bounds or the truth																										        				&quot;tended to romanticize and exaggerate this `gracious Old South imagery&quot;															   	同义词：								                                  				    overstate				    				    				      				    				      				    				                                      				    overdraw				    				    				      				    				      				    				                                      				    hyperbolize				    				    				      				    				      				    				                                      				    hyerbolise				    				    				      				    				      				    				                                      				    magnify				    				    				      				    				      				    				                                      				    amplify**{vt.}++使扩大；使增大**{vi.}++夸大；夸张**', '');
insert into TOEFLWordBook values ('326', 'execute', '[ˈeksɪkjuːt]', 'http://dict.youdao.com/dictvoice?audio=execute', '{v.}++执行，实施；处决；完成，表演（高难度动作）；制作（艺术作品）；（计算机）执行指令（或程序）**{v.}++kill as a means of socially sanctioned punishment																										        				&quot;In some states, criminals are executed&quot;															   	同义词：								                                  				    put to death**{vt.}++实行；执行；处死**', '');
