insert into TOEFLWordBook values ('329', 'exhibit', '[ɪɡˈzɪbɪt]', 'http://dict.youdao.com/dictvoice?audio=exhibit', '{v.}++表现出；卖弄，炫耀；提出（证据等）；展览，展出**{n.}++展品；（法庭上出示的）证物；展览，展出**{n.}++an object or statement produced before a court of law and referred to while giving evidence**{vt.}++展览；显示；提出（证据等）**{n.}++[贸易]展览品；证据；展示会**', '');
insert into TOEFLWordBook values ('330', 'exotic', '[ɪɡˈzɑːtɪk]', 'http://dict.youdao.com/dictvoice?audio=exotic', '{adj.}++奇异的，异国风情的**{n.}++外来植物，外来动物**{adj.}++being or from or characteristic of another place or part of the world																										        													        				&quot;exotic plants in a greenhouse&quot;; &quot;exotic cuisine&quot;															   	同义词：								                                  				    alien**{adj.}++[物]异国的；[语]外来的；异国情调的**', '');
