insert into TOEFLWordBook values ('332', 'explode', '[ɪkˈsploʊd]', 'http://dict.youdao.com/dictvoice?audio=explode', '{v.}++（使）爆炸，（使）爆破；急剧扩大，激增；（情感）迸发，爆发；推翻，破除；爆响，发出巨响；迅速移动**{v.}++cause to burst with a violent release of energy																										        				&quot;We exploded the nuclear bomb&quot;															   	同义词：								                                  				    detonate				    				    				      				    				      				    				                                      				    blow up				    				    				      				    				      				    				                                      				    set off**{vi.}++爆炸，爆发；激增**{vt.}++使爆炸；爆炸；推翻**', '');
insert into TOEFLWordBook values ('333', 'expose', '[ɪkˈspoʊz]', 'http://dict.youdao.com/dictvoice?audio=expose', '{v.}++暴露，使显露；使面临，使遭受（危险或不快）；揭露，揭发；接触，体验；露出，显露（感情）；使（胶卷）曝光；弃（婴孩）于户外让其死去**{n.}++揭露，曝光**{n.}++the exposure of an impostor or a fraud																										        				&quot;he published an expose of the graft and corruption in city government&quot;															   	同义词：								                                  				    unmasking**{v.}++expose or make accessible to some action or influence																										        				&quot;expose the blanket to sunshine&quot;**{vt.}++揭露，揭发；使曝光；显示**', '');
insert into TOEFLWordBook values ('334', 'expressive', '[ɪkˈspresɪv]', 'http://dict.youdao.com/dictvoice?audio=expressive', '{adj.}++富于表情的，富于表现力的；表现的，表达的**{adj.}++characterized by expression																										        				&quot;a very expressive face&quot;**', '');
insert into TOEFLWordBook values ('335', 'extend', '[ɪkˈstend]', 'http://dict.youdao.com/dictvoice?audio=extend', '{v.}++延伸；扩大，延长；持续；包括，波及；提供，表示；伸出；使竭尽全力；对……估价；继承（面向对象语言中的一种概念）**{v.}++extend in scope or range or area																										        				&quot;The law was extended to all citizens&quot;															   	同义词：								                                  				    widen				    				    				      				    				      				    				                                      				    broaden**{vt.}++延伸；扩大；推广；伸出；给予；使竭尽全力；对…估价**{vi.}++延伸；扩大；伸展；使疏开**', '');
insert into TOEFLWordBook values ('336', 'extent', '[ɪkˈstent]', 'http://dict.youdao.com/dictvoice?audio=extent', '{n.}++程度；范围，长度**{n.}++the point or degree to which something extends																										        													        													        				&quot;the extent of the damage&quot;; &quot;the full extent of the law&quot;; &quot;to a certain extent she was right&quot;**{n.}++程度；范围；[计量]长度**', '');
insert into TOEFLWordBook values ('337', 'external', '[ɪkˈstɜːrn(ə)l]', 'http://dict.youdao.com/dictvoice?audio=external', '{adj.}++外部的，外面的；对外的，与外国有关的；外来的，外聘的；（药品等类似物质）外用的**{n.}++外表，外部特征**{n.}++outward features																										        				&quot;he enjoyed the solemn externals of religion&quot;**{adj.}++happening or arising or located outside or beyond some limits or especially surface																										        													        				&quot;the external auditory canal&quot;; &quot;external pressures&quot;**{adj.}++[药][动]外部的；表面的；外用的；外国的；外面的**{n.}++外部；外观；外面**', '');
insert into TOEFLWordBook values ('338', 'extinct', '[ɪkˈstɪŋkt]', 'http://dict.youdao.com/dictvoice?audio=extinct', '{adj.}++灭绝的；消亡的；（火山）死的；（贵族称号）无合法继承人的；熄灭了的**{adj.}++no longer in existence; lost or especially having died out leaving no living representatives																										        													        													        				&quot;an extinct species of fish&quot;; &quot;an extinct royal family&quot;; &quot;extinct laws and customs&quot;															   	同义词：								                                  				    nonextant**{(of e.}++g. volcanos) permanently inactive																										        				&quot;an extinct volcano&quot;**{vt.}++使熄灭**', '');
insert into TOEFLWordBook values ('339', 'extraordinary', '[ɪkˈstrɔːrdəneri]', 'http://dict.youdao.com/dictvoice?audio=extraordinary', '{adj.}++异乎寻常的，令人惊奇的；非凡的，卓越的；特别的，临时的；特大（或多）的；特派的，特命的**{n.}++（公司正常业务活动之外的）非常账目，特支款项**{adj.}++beyond what is ordinary or usual; highly unusual or exceptional or remarkable																										        													        													        													        													        													        				&quot;extraordinary authority&quot;; &quot;an extraordinary achievement&quot;; &quot;her extraordinary beauty&quot;; &quot;enjoyed extraordinary popularity&quot;; &quot;an extraordinary capacity for work&quot;; &quot;an extraordinary session of the legislature&quot;**{adj.}++非凡的；特别的；离奇的；临时的；特派的**', '');
insert into TOEFLWordBook values ('340', 'faint', '[feɪnt]', 'http://dict.youdao.com/dictvoice?audio=faint', '{adj.}++模糊的，微弱的；微小的，可能性不大的；虚弱的，头晕目眩的；不热情的**{n.}++晕倒，昏厥**{v.}++昏厥；变得微弱，衰落；变得没有气力**{n.}++a spontaneous loss of consciousness caused by insufficient blood to the brain																					   	同义词：								                                  				    swoon				    				    				      				    				      				    				                                      				    syncope				    				    				      				    				      				    				                                      				    deliquium**{v.}++pass out from weakness, physical or emotional distress due to a loss of blood supply to the brain																					   	同义词：								                                  				    conk				    				    				      				    				      				    				                                      				    swoon				    				    				      				    				      				    				                                      				    pass out**{adj.}++deficient in magnitude; barely perceptible; lacking clarity or brightness or loudness etc																										        													        													        													        													        				&quot;a faint outline&quot;; &quot;the wan sun cast faint shadows&quot;; &quot;the faint light of a distant candle&quot;; &quot;a faint hissing sound&quot;; &quot;a faint aroma&quot;															   	同义词：								                                  				    weak**{adj.}++模糊的；头晕的；[医]虚弱的；衰弱的**{vi.}++昏倒；变得微弱；变得没气力**{n.}++[中医]昏厥，昏倒**', '');
insert into TOEFLWordBook values ('341', 'fairly', '[ˈferli]', 'http://dict.youdao.com/dictvoice?audio=fairly', '{adv.}++相当地，颇；公平地，公正地；（用以强调）完全，简直；令人愉快地，让人喜欢地**{adv.}++to a moderately sufficient extent or degree																										        				&quot;he is fairly clever with computers&quot;															   	同义词：								                                  				    reasonably				    				    				      				    				      				    				                                      				    moderately				    				    				      				    				      				    				                                      				    within reason				    				    				      				    				      				    				                                      				    somewhat				    				    				      				    				      				    				                                      				    middling				    				    				      				    				      				    				                                      				    passably**{adv.}++相当地；公平地；简直**', '');
insert into TOEFLWordBook values ('342', 'faith', '[feɪθ]', 'http://dict.youdao.com/dictvoice?audio=faith', '{n.}++信任，信心，信念；宗教；宗教信仰；忠诚**{int.}++用以表示惊讶或强调千真万确**{n.}++a strong belief in a supernatural power or powers that control human destiny																										        				&quot;he lost his faith but not his morality&quot;															   	同义词：								                                  				    religion				    				    				      				    				      				    				                                      				    religious belief**{n.}++信仰；信念；信任；忠实**', '');
insert into TOEFLWordBook values ('343', 'fame', '[feɪm]', 'http://dict.youdao.com/dictvoice?audio=fame', '{n.}++名誉，名气**{v.}++使闻名，使有名望**{n.}++the state or quality of being widely honored and acclaimed																					   	同义词：								                                  				    celebrity				    				    				      				    				      				    				                                      				    renown**{n.}++名声，名望；传闻，传说**', '');
insert into TOEFLWordBook values ('344', 'fantasy', '[ˈfæntəsi]', 'http://dict.youdao.com/dictvoice?audio=fantasy', '{n.}++幻想，想象；想象产物，幻想作品；虚拟比赛（游戏）；幻想曲，集成曲；期望**{v.}++想象，幻想**{n.}++imagination unrestricted by reality																										        				&quot;a schoolgirl fantasy&quot;															   	同义词：								                                  				    phantasy**{n.}++[心理]幻想；白日梦；幻觉**{adj.}++虚幻的**{vt.}++空想；想像**{vi.}++耽于幻想；奏幻想曲（等于phantasy）**', '');
