insert into TOEFLWordBook values ('347', 'fatigue', '[fəˈtiːɡ]', 'http://dict.youdao.com/dictvoice?audio=fatigue', '{n.}++疲乏，厌倦；（金属部件的）疲劳；（士兵穿的）工作服；士兵杂役（尤指作为惩罚,如做打扫、帮厨）**{v.}++使疲劳，使劳累**{adj.}++疲劳的**{n.}++temporary loss of strength and energy resulting from hard physical or mental work																										        													        				&quot;he was hospitalized for extreme fatigue&quot;; &quot;growing fatigue was apparent from the decline in the execution of their athletic skills&quot;															   	同义词：								                                  				    weariness				    				    				      				    				      				    				                                      				    tiredness**{n.}++[生理][心理][力]疲劳，疲乏；杂役**{vt.}++[生理][心理][力]使疲劳；使心智衰弱**{vi.}++[生理][心理][力]疲劳**', '');
