insert into TOEFLWordBook values ('353', 'flap', '[flæp]', 'http://dict.youdao.com/dictvoice?audio=flap', '{n.}++片状悬垂物；拍打，拍动；（飞机的）襟翼；混乱，激动；群众愤怒，大众批评**{v.}++激动，紧张；摆动，拍打**{n.}++any broad thin and limber covering attached at one edge; hangs loose or projects freely																										        				&quot;he wrote on the flap of the envelope&quot;**{n.}++拍打，拍打声；[航]副翼**{vi.}++拍动；鼓翼而飞；（帽边等）垂下**{vt.}++拍打；扔；拉下帽边；飘动**', '');
insert into TOEFLWordBook values ('354', 'flash', '[flæʃ]', 'http://dict.youdao.com/dictvoice?audio=flash', '{v.}++闪光，闪亮；（快速）出示，显示；飞驰，掠过；闪现；迅速播出，传送（信息）；突然显露（强烈情感）；当众暴露（性器官）；（为引人注目而）展示，炫耀；（尤指用无线电或光波）通信，联络**{n.}++闪光；闪光灯；闪现；（军装上的）肩章；网站动画程序；花哨，噱头；突然理解，顿悟；（感情的）突发；炫耀财富，夸富；（产品包装上用来吸引顾客眼光的）色带，突显区域；（模塑过程中的）溢料，溢边；（尤指为帮助行船而从堰闸里放出的）水流；飞快的一瞥；（模塑过程中的）溢料，溢边**{adj.}++阔气的，爱显摆的；突然而短暂的；非常有才能的，杰出的**{n.}++a sudden intense burst of radiant energy**{vt.}++使闪光；反射**{n.}++闪光，闪现；一瞬间**{vi.}++闪光，闪现；反射**{adj.}++闪光的，火速的**', '');
insert into TOEFLWordBook values ('355', 'flat', '[flæt]', 'http://dict.youdao.com/dictvoice?audio=flat', '{adj.}++平的，水平的；平坦的；（水面）平静的，波澜不兴的；平滑的；平放的，平躺的，平卧的；足弓平坦的；扁平的；（鞋）平跟的，低跟的；断然的，直截了当的；（费率、价格等）统一的，固定的；（市场、价格等）疲软的，萧条的；枯燥的，无趣的，缺乏热情的；（饮品）走了气的；（轮胎）没气的，瘪的；（电池）电力不足的，没电的；平淡的，无变化的；（音符）降半音的；音调偏低的；色彩单调的，无反差的，无景深的；无光泽的；（图表上的线）平的，无变化的；（组织或系统）内部层次不多的；（关于）无障碍平地赛马的；（面包）未发酵的**{adv.}++水平地；平整地；平贴着；正好；完全地，彻底地；音调偏低地**{n.}++公寓，单元房；（通常指近水的）浅滩，洼地；（某物的）平面部份；（音符的）降半音；降半音符号；浅箱，浅苗床；平底鞋，低跟鞋（flats）；漏气轮胎；平板列车，敞车，平台货车；平面布景，布景屏；无障碍平地赛马季节（the Flat）**{v.}++住公寓，伙住公寓；（乐）把（音调）降半音**{n.}++a level tract of land																										        				&quot;the salt flats of Utah&quot;**{adj.}++平坦的；扁平的；浅的；单调的**{adv.}++平直地；断然地**{n.}++平地；平面；公寓**{vi.}++变平**', '');
