insert into TOEFLWordBook values ('360', 'float', '[floʊt]', 'http://dict.youdao.com/dictvoice?audio=float', '{v.}++（使）漂浮，（使）浮动；轻盈走动，飘然移动；提出（想法或计划）；发行（股票）上市；使（货币汇率）自由浮动**{n.}++彩车；鱼漂，浮子；（学游泳用的）浮板；顶端加冰激凌的饮料；（商店的）备用零钱；（公司股票）上市，开始发行**{n.}++the time interval between the deposit of a check in a bank and its payment**{vt.}++使漂浮；实行**{vi.}++浮动；飘动，散播；摇摆；付诸实施**{n.}++彩车，花车；漂流物；浮舟；浮萍**', '');
