insert into TOEFLWordBook values ('364', 'folk', '[foʊk]', 'http://dict.youdao.com/dictvoice?audio=folk', '{n.}++人们；家人，双亲；民间音乐；诸位，大伙儿**{adj.}++民俗的，传统的；流传民间的，普通百姓的**{n.}++people in general (often used in the plural)																										        													        				&quot;theyre just country folk&quot;; &quot;folks around here drink moonshine&quot;															   	同义词：								                                  				    folks				    				    				      				    				      				    				                                      				    common people**{n.}++民族；人们；亲属（复数）**{adj.}++民间的**', '');
