insert into TOEFLWordBook values ('371', 'frame', '[freɪm]', 'http://dict.youdao.com/dictvoice?audio=frame', '{n.}++框架，边框；（家具、建筑物、车辆等的）构架，支架；体格，骨架；眼镜框；（系统、概念或文章的）基本框架；镜头，画面；（连环漫画中的）一幅画；（网页的）一个区域；（斯诺克或保龄球的）一局；（玻璃或塑料的箱式）轻便温床；（纺织、编结或刺绣用的）框；替换框架；（计算机或通信）帧，影格**{v.}++装框架；勾勒出；围绕；陷害，诬陷；制定，拟订；（措词谨慎地）表达**{adj.}++有木架的**{n.}++a structure supporting or containing something																					   	同义词：								                                  				    framework				    				    				      				    				      				    				                                      				    framing**{n.}++[建][计]框架；结构；[电影]画面**{vt.}++设计；建造；陷害；使…适合**', '');
