insert into TOEFLWordBook values ('374', 'frustrate', '[ˈfrʌstreɪt]', 'http://dict.youdao.com/dictvoice?audio=frustrate', '{v.}++使懊恼，使沮丧；挫败，阻挠；受挫**{adj.}++痛苦的，受挫的**{v.}++hinder or prevent (the efforts, plans, or desires) of																										        				&quot;What ultimately frustrated every challenger was Ruths amazing September surge&quot;															   	同义词：								                                  				    thwart				    				    				      				    				      				    				                                      				    queer				    				    				      				    				      				    				                                      				    spoil				    				    				      				    				      				    				                                      				    scotch				    				    				      				    				      				    				                                      				    foil				    				    				      				    				      				    				                                      				    cross				    				    				      				    				      				    				                                      				    baffle				    				    				      				    				      				    				                                      				    bilk**{vt.}++挫败；阻挠；使感到灰心**{vi.}++失败；受挫**{adj.}++挫败的；无益的**', '');
