insert into TOEFLWordBook values ('376', 'fur', '[fɜːr]', 'http://dict.youdao.com/dictvoice?audio=fur', '{n.}++（某些动物的）软毛，柔毛；毛皮，裘皮；毛皮衣服，皮草； 水垢，水碱；舌苔**{v.}++积垢，生苔；通过插木条使（地板，墙面木料）齐平；用某种毛皮覆盖（或制成）的**{n.}++the dressed hairy coat of a mammal																					   	同义词：								                                  				    pelt**{dense coat of fine silky hairs on mammals (e.}++g., cat or seal or weasel)**{n.}++皮，皮子；[皮革]毛皮；软毛**', '');
