insert into TOEFLWordBook values ('378', 'gallery', '[ˈɡæləri]', 'http://dict.youdao.com/dictvoice?audio=gallery', '{n.}++美术馆，画廊；（大厅的）楼座，楼上旁听席；（剧场中的）顶层楼座；阳台，露台；一群（相似的人或物）；长廊，走廊；（矿井下的）巷道；观众**{n.}++spectators at a golf or tennis match**{n.}++画廊；走廊；旁听席；地道**', '');
insert into TOEFLWordBook values ('379', 'garbage', '[ˈɡɑːrbɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=garbage', '{n.}++垃圾，废物；垃圾箱；废话，无聊的东西；无用信息**{n.}++food that is discarded (as from a kitchen)																					   	同义词：								                                  				    refuse				    				    				      				    				      				    				                                      				    food waste				    				    				      				    				      				    				                                      				    scraps**{n.}++[环境]垃圾；废物**', '');
insert into TOEFLWordBook values ('380', 'gear', '[ɡɪr]', 'http://dict.youdao.com/dictvoice?audio=gear', '{n.}++排挡，齿轮；（用于特定目的的）装备，服装；（做事的）速度，努力；（特定用途的）器械，装置；毒品；所有物，财物**{v.}++使变速，使调挡**{n.}++a toothed wheel that engages another toothed mechanism in order to change the speed or direction of transmitted motion																					   	同义词：								                                  				    gear wheel				    				    				      				    				      				    				                                      				    geared wheel				    				    				      				    				      				    				                                      				    cogwheel**{equipment consisting of miscellaneous articles needed for a particular operation or sport etc.}++同义词：								                                  				    paraphernalia				    				    				      				    				      				    				                                      				    appurtenance**{n.}++[机]齿轮；装置，工具；传动装置**{vi.}++适合；搭上齿轮；开始工作**{vt.}++开动；搭上齿轮；使……适合；使……准备好**', '');
insert into TOEFLWordBook values ('381', 'generalization', '[ˌdʒen(ə)rələˈzeɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=generalization', '{n.}++（依据不足的）概括，泛论（=generalisation）**{n.}++the process of formulating general concepts by abstracting common properties of instances																					   	同义词：								                                  				    abstraction				    				    				      				    				      				    				                                      				    generalisation**{n.}++概括；普遍化；一般化**', '');
insert into TOEFLWordBook values ('382', 'generate', '[ˈdʒenəreɪt]', 'http://dict.youdao.com/dictvoice?audio=generate', '{v.}++产生，引起**{v.}++bring into existence																										        													        				&quot;The new manager generated a lot of problems&quot;; &quot;The computer bug generated chaos in the office&quot;															   	同义词：								                                  				    bring forth**{vt.}++使形成；发生；[生物]生殖**', '');
insert into TOEFLWordBook values ('383', 'generous', '[ˈdʒenərəs]', 'http://dict.youdao.com/dictvoice?audio=generous', '{adj.}++慷慨的，大方的；大量的，丰富的；宽宏大量的**{adj.}++willing to give and share unstintingly																										        				&quot;a generous donation&quot;**{adj.}++慷慨的，大方的；宽宏大量的；有雅量的**', '');
insert into TOEFLWordBook values ('384', 'genetic', '[dʒəˈnetɪk]', 'http://dict.youdao.com/dictvoice?audio=genetic', '{adj.}++基因的，遗传学的；有共同起源的**{adj.}++tending to occur among members of a family usually by heredity																										        				&quot;genetically transmitted features&quot;															   	同义词：								                                  				    familial				    				    				      				    				      				    				                                      				    hereditary				    				    				      				    				      				    				                                      				    inherited				    				    				      				    				      				    				                                      				    transmitted				    				    				      				    				      				    				                                      				    transmissible**{adj.}++遗传的；基因的；起源的**', '');
insert into TOEFLWordBook values ('385', 'genius', '[ˈdʒiːniəs]', 'http://dict.youdao.com/dictvoice?audio=genius', '{n.}++天赋，天资；天才，智商很高的人；（擅长做某事的）高手；精华，精髓；对某人有很大好（或坏）影响的人；（神话中某个人、地方或机构的）守护神；（民族或时代的）普遍特征**{adj.}++天才的**{n.}++someone who has exceptional intellectual ability and originality																										        				&quot;Mozart was a child genius&quot;															   	同义词：								                                  				    mastermind				    				    				      				    				      				    				                                      				    brain				    				    				      				    				      				    				                                      				    brainiac				    				    				      				    				      				    				                                      				    Einstein**{n.}++天才，天赋；精神**', '');
