insert into TOEFLWordBook values ('387', 'gentle', '[ˈdʒent(ə)l]', 'http://dict.youdao.com/dictvoice?audio=gentle', '{adj.}++文静的，温柔的；（动作）轻柔的，徐缓的；（坡度）平缓的，不陡的；微热的；出身高贵的，品格高尚的**{v.}++使（或变）温柔，（使）平静；使驯服**{n.}++蛆，饵**{v.}++cause to be more favorably inclined; gain the good will of																					   	同义词：								                                  				    pacify				    				    				      				    				      				    				                                      				    lenify				    				    				      				    				      				    				                                      				    conciliate				    				    				      				    				      				    				                                      				    assuage				    				    				      				    				      				    				                                      				    appease				    				    				      				    				      				    				                                      				    mollify				    				    				      				    				      				    				                                      				    placate				    				    				      				    				      				    				                                      				    gruntle**{adj.}++温和的；文雅的**{vt.}++使温和，使驯服**{n.}++蛆，饵**', '');
insert into TOEFLWordBook values ('388', 'genuine', '[ˈdʒenjuɪn]', 'http://dict.youdao.com/dictvoice?audio=genuine', '{adj.}++真正的，非伪造的；真诚的，真心的**{adj.}++not fake or counterfeit																										        													        				&quot;a genuine Picasso&quot;; &quot;genuine leather&quot;															   	同义词：								                                  				    echt**{adj.}++真实的，真正的；诚恳的**', '');
