insert into TOEFLWordBook values ('390', 'giant', '[ˈdʒaɪənt]', 'http://dict.youdao.com/dictvoice?audio=giant', '{n.}++（传说中的）巨人；高大健壮的人；巨兽，巨型植物；大公司，大国；卓越人物，伟人；（天文）巨星**{adj.}++巨大的，伟大的**{n.}++any creature of exceptional size**{n.}++巨人；伟人；[植][动]巨大的动物**{adj.}++[动]巨大的；巨人般的**', '');
insert into TOEFLWordBook values ('391', 'gifted', '[ˈɡɪftɪd]', 'http://dict.youdao.com/dictvoice?audio=gifted', '{adj.}++有天赋的，有才华的；聪慧的，有特长的**{v.}++赠送；（无意中）让（对手）获得（gift 的过去式和过去分词形式）**{adj.}++endowed with talent or talents																										        				&quot;a gifted writer&quot;															   	同义词：								                                  				    talented**{adj.}++有天赋的；有才华的**{v.}++给予（gift的过去分词）**', '');
