insert into TOEFLWordBook values ('394', 'gravity', '[ˈɡrævəti]', 'http://dict.youdao.com/dictvoice?audio=gravity', '{n.}++重力，地心引力；严重性；严肃，庄严；重（量）**{n.}++(physics) the force of attraction between all masses in the universe; especially the attraction of the earths mass for bodies near its surface																										        				&quot;the more remote the body the less the gravity&quot;															   	同义词：								                                  				    gravitation				    				    				      				    				      				    				                                      				    gravitational attraction				    				    				      				    				      				    				                                      				    gravitational force**{n.}++[力]重力，地心引力；严重性；庄严**', '');
