insert into TOEFLWordBook values ('396', 'guarantee', '[ˌɡærənˈtiː]', 'http://dict.youdao.com/dictvoice?audio=guarantee', '{v.}++确保，保证；担保，为……作保；保修，包换**{n.}++保证，担保；保修单，质量保证书；担保金，抵押品**{n.}++a written assurance that some product or service will be provided or will meet certain specifications																					   	同义词：								                                  				    warrant				    				    				      				    				      				    				                                      				    warrantee				    				    				      				    				      				    				                                      				    warranty**{n.}++[金融]保证；[法]担保；保证人；保证书；[经]抵押品**{vt.}++[金融]保证；[法]担保**', '');
insert into TOEFLWordBook values ('397', 'habitat', '[ˈhæbɪtæt]', 'http://dict.youdao.com/dictvoice?audio=habitat', '{n.}++（动植物的）生活环境，栖息地**{n.}++the type of environment in which an organism or group normally lives or occurs																										        				&quot;a marine habitat&quot;															   	同义词：								                                  				    home ground**{n.}++[生态]栖息地，[经]产地**', '');
insert into TOEFLWordBook values ('398', 'hall', '[hɔːl]', 'http://dict.youdao.com/dictvoice?audio=hall', '{n.}++礼堂，大厅；门厅；走廊，过道；（大学的）学生宿舍；府邸，庄园**{n.}++an interior passage or corridor onto which rooms open																										        				&quot;the elevators were at the end of the hall&quot;															   	同义词：								                                  				    hallway**{United States child psychologist whose theories of child psychology strongly influenced educational psychology (1844-1924)																					   	同义词：								                                  				    G.}++Stanley Hall				    				    				      				    				      				    				                                      				    Granville Stanley Hall**{n.}++门厅，走廊；[建]会堂；食堂；学生宿舍**', '');
insert into TOEFLWordBook values ('399', 'hallmark', '[ˈhɔːlmɑːrk]', 'http://dict.youdao.com/dictvoice?audio=hallmark', '{n.}++特点，特征；（金银制品上标明纯度及制作时间、地点的）印记**{v.}++给……打金银纯度印记；使具有……特征**{n.}++a distinctive characteristic or attribute																					   	同义词：								                                  				    trademark				    				    				      				    				      				    				                                      				    earmark				    				    				      				    				      				    				                                      				    stylemark**{n.}++特点；品质证明**', '');
insert into TOEFLWordBook values ('400', 'halt', '[hɔːlt]', 'http://dict.youdao.com/dictvoice?audio=halt', '{v.}++（使）停止行进；阻止，中断；（口令）立定；跛行；（尤指逻辑或诗韵）有缺陷；踌躇，犹豫**{n.}++停止，中止；乡间小火车站（只有站台）；跛，瘸； 跛，瘸；（口令）立定**{adj.}++跛的，瘸的**{n.}++the state of inactivity following an interruption																										        				&quot;during the halt he got some lunch&quot;															   	同义词：								                                  				    arrest				    				    				      				    				      				    				                                      				    check				    				    				      				    				      				    				                                      				    hitch				    				    				      				    				      				    				                                      				    stay				    				    				      				    				      				    				                                      				    stop				    				    				      				    				      				    				                                      				    stoppage**{vi.}++停止；立定；踌躇，犹豫**{n.}++停止；立定；休息**{vt.}++使停止；使立定**', '');
insert into TOEFLWordBook values ('401', 'hammer', '[ˈhæmər]', 'http://dict.youdao.com/dictvoice?audio=hammer', '{n.}++锤子，榔头；（拍卖用的）木槌；链球；击铁；音槌；锣锤**{v.}++（用锤子）敲击；用力敲打，猛踢；强行灌输，反复强调；（在体育比赛中）使惨败，大败；使（企业）受到打击；严厉批评，指责；（心脏）剧烈跳动；压低（某股票）的价格**{n.}++the part of a gunlock that strikes the percussion cap when the trigger is pulled																					   	同义词：								                                  				    cock**{vi.}++锤击；敲打；重复**{n.}++铁锤；链球；[解剖]锤骨；音锤**', '');
insert into TOEFLWordBook values ('402', 'handcrafted', '[ˌhændˈkræftɪd]', 'http://dict.youdao.com/dictvoice?audio=handcrafted', '{adj.}++手工制作的，手工艺的**{n.}++a work produced by hand labor																					   	同义词：								                                  				    handicraft				    				    				      				    				      				    				                                      				    handiwork				    				    				      				    				      				    				                                      				    handwork**{v.}++make something by hand																										        				&quot;We handcraft all our paper&quot;**', '');
insert into TOEFLWordBook values ('403', 'handful', '[ˈhændfʊl]', 'http://dict.youdao.com/dictvoice?audio=handful', '{n.}++一把；少数，少量； 难以控制的人（或事物）**{n.}++a small number or amount																										        				&quot;only a handful of responses were received&quot;															   	同义词：								                                  				    smattering**{n.}++少数；一把；棘手事**', '');
insert into TOEFLWordBook values ('404', 'handle', '[ˈhænd(ə)l]', 'http://dict.youdao.com/dictvoice?audio=handle', '{v.}++拿；处理，应付；操纵；触（球）；经营，管理**{n.}++把手，拉手；柄，提手；（理解、解决问题的）方法，途径；（尤指奇怪的）名字，名称；（织物等的）手感；赌注总额**{comb.}++有……个柄的，有……柄的**{n.}++the appendage to an object that is designed to be held in order to use or move it																										        				&quot;he grabbed the hammer by the handle&quot;															   	同义词：								                                  				    grip				    				    				      				    				      				    				                                      				    handgrip				    				    				      				    				      				    				                                      				    hold**{v.}++be in charge of, act on, or dispose of																										        				&quot;This blender cant handle nuts&quot;															   	同义词：								                                  				    manage				    				    				      				    				      				    				                                      				    deal				    				    				      				    				      				    				                                      				    care**{show and train																										        				&quot;The prize-winning poodle was handled by Mrs.}++Priscilla Prescott&quot;**{n.}++[建]把手；柄；手感；口实**{vt.}++处理；操作；运用；买卖；触摸**', '');
insert into TOEFLWordBook values ('405', 'hang', '[hæŋ]', 'http://dict.youdao.com/dictvoice?audio=hang', '{v.}++悬挂，吊；（使）挂在墙上；垂下，垂落；悬浮；绞死；贴，糊（墙纸）；安装（门）；（决定）未做出；逗留，徘徊；投曲线球失败；（尤指驾车时）拐弯；（使）死机**{n.}++悬挂方式；下垂，低垂；（画展中画作的）陈列，布局**{n.}++a special way of doing something																										        				&quot;he couldnt get the hang of it&quot;															   	同义词：								                                  				    bent				    				    				      				    				      				    				                                      				    knack**{vt.}++悬挂，垂下；装饰；绞死；使悬而未决**{vi.}++悬着，垂下；被绞死；悬而不决**{n.}++悬挂；暂停，中止**', '');
insert into TOEFLWordBook values ('406', 'harden', '[ˈhɑːrdn]', 'http://dict.youdao.com/dictvoice?audio=harden', '{v.}++（使）变硬，坚固；（使）更坚定，更强硬；使变得冷酷无情，使麻木不仁；（使声音，面孔等）更严肃，更严厉；变明确；（价格、经济）变得更稳定；（股票、商品价格等）升水（上涨并保持高价位）**{v.}++become hard or harder																										        				&quot;The wax hardened&quot;															   	同义词：								                                  				    indurate**{vi.}++变硬，变坚固；变坚强；变冷酷**', '');
