insert into TOEFLWordBook values ('410', 'harm', '[hɑːrm]', 'http://dict.youdao.com/dictvoice?audio=harm', '{n.}++伤害，损害**{v.}++危害，损害（某事物）；伤害（人或动物）**{n.}++any physical damage to the body caused by violence or accident or fracture etc.																					   	同义词：								                                  				    injury				    				    				      				    				      				    				                                      				    hurt				    				    				      				    				      				    				                                      				    trauma**{n.}++伤害；损害**{vt.}++伤害；危害；损害**', '');
