insert into TOEFLWordBook values ('412', 'harness', '[ˈhɑːrnɪs]', 'http://dict.youdao.com/dictvoice?audio=harness', '{v.}++控制并利用；（把动物）拴在一起（或拴到某物上）；给（马）套上挽具；连接，串联**{n.}++（马的）挽具，马具；系带，吊带；日常工作**{n.}++a support consisting of an arrangement of straps for holding something to the body (especially one supporting a person suspended from a parachute)**{vt.}++治理；套；驾驭；披上甲胄**{n.}++马具；甲胄；挽具状带子；降落伞背带**', '');
insert into TOEFLWordBook values ('413', 'harsh', '[hɑːrʃ]', 'http://dict.youdao.com/dictvoice?audio=harsh', '{adj.}++（环境）恶劣的，艰苦的；严厉的，残酷的；刺耳的，难听的；刺眼的，耀眼的；丑陋的；刺激性强的，太强力的**{adj.}++unpleasantly stern																										        				&quot;wild and harsh country full of hot sand and cactus&quot;															   	同义词：								                                  				    rough**{adj.}++严厉的；严酷的；[声]刺耳的；粗糙的；刺目的**', '');
insert into TOEFLWordBook values ('414', 'haunt', '[hɔːnt]', 'http://dict.youdao.com/dictvoice?audio=haunt', '{v.}++（鬼魂）出没；萦绕在……心头；（长期）困扰；常去（某地）**{n.}++常去的地方；栖息地**{n.}++a frequently visited place																					   	同义词：								                                  				    hangout				    				    				      				    				      				    				                                      				    resort				    				    				      				    				      				    				                                      				    repair				    				    				      				    				      				    				                                      				    stamping ground**{v.}++follow stealthily or recur constantly and spontaneously to																										        				&quot;the ghost of her mother haunted her&quot;															   	同义词：								                                  				    stalk**{n.}++栖息地；常去的地方**', '');
insert into TOEFLWordBook values ('415', 'hazard', '[ˈhæzərd]', 'http://dict.youdao.com/dictvoice?audio=hazard', '{n.}++危险，危害；（不可避免的）风险；（高尔夫球道）障碍物（如池塘或沙地）；机会，机遇；双骰子游戏；（网球）可得分区域；（台球）使球触他球后落入袋中的一击**{v.}++冒失地提出，冒险猜测；使遭危险，使处于危险**{n.}++a source of danger; a possibility of incurring loss or misfortune																										        				&quot;drinking alcohol is a health hazard&quot;															   	同义词：								                                  				    jeopardy				    				    				      				    				      				    				                                      				    peril				    				    				      				    				      				    				                                      				    risk				    				    				      				    				      				    				                                      				    endangerment**{vt.}++赌运气；冒…的危险，使遭受危险**{n.}++[安全]危险，冒险；冒险的事**', '');
insert into TOEFLWordBook values ('416', 'heal', '[hiːl]', 'http://dict.youdao.com/dictvoice?audio=heal', '{v.}++痊愈，康复；（感情创伤）愈合，（情感）恢复常态；（使）（裂痕、创伤）弥合，（使）和好；止息（争斗），调停；修复（对土地的破坏）；减轻（痛苦）**{v.}++heal or recover																					   	同义词：								                                  				    mend**', '');
insert into TOEFLWordBook values ('417', 'heed', '[hiːd]', 'http://dict.youdao.com/dictvoice?audio=heed', '{v.}++注意，留心**{n.}++注意，留心**{n.}++paying particular notice (as to children or helpless people)																										        				&quot;he spends without heed to the consequences&quot;															   	同义词：								                                  				    attentiveness				    				    				      				    				      				    				                                      				    regard				    				    				      				    				      				    				                                      				    paying attention**{v.}++pay close attention to; give heed to																					   	同义词：								                                  				    mind				    				    				      				    				      				    				                                      				    listen**{vi.}++注意，留心**{vt.}++注意，留心**', '');
