insert into TOEFLWordBook values ('419', 'hence', '[hens]', 'http://dict.youdao.com/dictvoice?audio=hence', '{adv.}++因此；之后**{adv.}++(used to introduce a logical conclusion) from that fact or reason or as a result																										        													        				&quot;the eggs were fresh and hence satisfactory&quot;; &quot;we were young and thence optimistic&quot;															   	同义词：								                                  				    therefore				    				    				      				    				      				    				                                      				    thence				    				    				      				    				      				    				                                      				    thus**{adv.}++因此；今后**', '');
