insert into TOEFLWordBook values ('423', 'highlight', '[ˈhaɪlaɪt]', 'http://dict.youdao.com/dictvoice?audio=highlight', '{v.}++突出，强调；用亮色突出；挑染**{n.}++最好（或最精彩、最激动人心）的部分；挑染的头发；强光部分**{n.}++the most interesting or memorable part																										        				&quot;the highlight of the tour was our visit to the Vatican&quot;															   	同义词：								                                  				    high spot**{vt.}++突出；强调；使显著；加亮**{n.}++最精彩的部分；最重要的事情；[电子]加亮区**', '');
