insert into TOEFLWordBook values ('425', 'hollow', '[ˈhɑːloʊ]', 'http://dict.youdao.com/dictvoice?audio=hollow', '{adj.}++空的，空心的；凹的，凹陷的；虚伪的，不真诚的；无用的，无价值的；（声音）沉闷回荡的；空腹的；沉闷回荡的**{v.}++使凹陷，使下陷；挖洞（成某物）；形成空洞**{n.}++凹陷处，坑洼处；坑，洞；山谷**{n.}++a cavity or space in something																										        				&quot;hunger had caused the hollows in their cheeks&quot;**{adj.}++空的；中空的，空腹的；凹的；虚伪的**{n.}++洞；山谷；窟窿**{vi.}++形成空洞**{adv.}++彻底地；无用地**', '');
insert into TOEFLWordBook values ('426', 'honor', '[ˈɑːnər]', 'http://dict.youdao.com/dictvoice?audio=honor', '{n.}++荣誉；信用；头衔**{vt.}++尊敬（等于 honour）；给……以荣誉**{n.}++a tangible symbol signifying approval or distinction																					   	同义词：								                                  				    award				    				    				      				    				      				    				                                      				    accolade				    				    				      				    				      				    				                                      				    honour				    				    				      				    				      				    				                                      				    laurels**{n.}++荣誉；信用；头衔**{vt.}++尊敬（等于honour）；给…以荣誉**', '');
insert into TOEFLWordBook values ('427', 'hook', '[hʊk]', 'http://dict.youdao.com/dictvoice?audio=hook', '{n.}++钩，挂钩；勾拳；曲线球；吸引人的东西；使（投手）下场；（尤指用于收割、剪羊毛）弧形切割工具；弯曲的笔画；弧形岬（或沙嘴）**{v.}++钩住，挂住；（用手臂等身体部位）箍住；钓鱼；打曲线球；弯成钩状；吸引；偷窃；卖淫；把……连接到（某设备）**{n.}++a catch for locking a door**{n.}++挂钩，[机]吊钩**{vt.}++钩住；[口腔]引上钩**', '');
