insert into TOEFLWordBook values ('430', 'hostile', '[ˈhɑːst(ə)l]', 'http://dict.youdao.com/dictvoice?audio=hostile', '{adj.}++敌对的，怀敌意的；强烈反对的；敌人的，敌方的；艰苦的，不利的；不受（被购公司）欢迎的**{n.}++敌对分子**{adj.}++characterized by enmity or ill will																										        													        													        				&quot;a hostile nation&quot;; &quot;a hostile remark&quot;; &quot;hostile actions&quot;**{adj.}++敌对的，敌方的；怀敌意的**{n.}++敌对**', '');
