insert into TOEFLWordBook values ('435', 'identify', '[aɪˈdentɪfaɪ]', 'http://dict.youdao.com/dictvoice?audio=identify', '{v.}++认出，识别；查明，确认；发现；证明（身份），表明；认同，理解；认为……和……一致；和（某人）打成一片**{v.}++recognize as being; establish the identity of someone or something																					   	同义词：								                                  				    place**{vt.}++确定；[计]识别；使参与；把…看成一样**{vi.}++确定；认同；一致**', '');
