insert into TOEFLWordBook values ('437', 'ignorant', '[ˈɪɡnərənt]', 'http://dict.youdao.com/dictvoice?audio=ignorant', '{adj.}++无知的，（对某事物）不了解的；无礼的，粗鲁的；暴躁的，易怒的**{adj.}++uneducated in general; lacking knowledge or sophistication																										        				&quot;an ignorant man&quot;															   	同义词：								                                  				    nescient				    				    				      				    				      				    				                                      				    unenlightened				    				    				      				    				      				    				                                      				    unlearned				    				    				      				    				      				    				                                      				    unlettered**{adj.}++无知的；愚昧的**', '');
