insert into TOEFLWordBook values ('442', 'immediate', '[ɪˈmiːdiət]', 'http://dict.youdao.com/dictvoice?audio=immediate', '{adj.}++立刻的，即时的；目前的，紧迫的；附近的，紧接的；（关系或级别）最接近的，直系的；（两者间）直接的；（感知，反应）直觉的**{adj.}++very close or connected in space or time																										        													        													        				&quot;immediate contact&quot;; &quot;the immediate vicinity&quot;; &quot;the immediate past&quot;															   	同义词：								                                  				    contiguous**{adj.}++立即的；直接的；最接近的**', '');
