insert into TOEFLWordBook values ('445', 'immortal', '[ɪˈmɔːrt(ə)l]', 'http://dict.youdao.com/dictvoice?audio=immortal', '{adj.}++不死的，永存的；不朽的，流芳百世的，永垂千古的**{n.}++神，永生不灭者；永垂不朽的人物；法国科学院院士（Immortal）；古波斯皇家护卫（Immortals）**{n.}++a person (such as an author) of enduring fame																										        				&quot;Shakespeare is one of the immortals&quot;**{adj.}++不朽的；神仙的；长生的**{n.}++神仙；不朽人物**', '');
