insert into TOEFLWordBook values ('449', 'impose', '[ɪmˈpoʊz]', 'http://dict.youdao.com/dictvoice?audio=impose', '{v.}++强制推行，强制实行；把（自己的观点、信仰等）强加于；打扰，麻烦；把（活字页）拼版；欺骗**{v.}++compel to behave in a certain way																										        				&quot;Social relations impose courtesy&quot;															   	同义词：								                                  				    enforce**{vi.}++利用；欺骗；施加影响**{vt.}++强加；征税；以…欺骗**', '');
insert into TOEFLWordBook values ('450', 'impulse', '[ˈɪmpʌls]', 'http://dict.youdao.com/dictvoice?audio=impulse', '{n.}++冲动；脉冲；推动力**{adj.}++一时兴起的，随兴的**{v.}++推动**{n.}++an instinctive motive																										        				&quot;profound religious impulses&quot;															   	同义词：								                                  				    urge**{n.}++[心理]冲动；[电子]脉冲；刺激；神经冲动；推动力**{vt.}++推动**', '');
