insert into TOEFLWordBook values ('453', 'infant', '[ˈɪnfənt]', 'http://dict.youdao.com/dictvoice?audio=infant', '{n.}++婴儿，幼儿；（英国学校里四至七岁的）学童；未成年人**{adj.}++供婴幼儿用的；初期的，初创期的；四岁至七岁幼儿的**{n.}++a very young child (birth to 1 year) who has not yet begun to walk or talk																					   	同义词：								                                  				    baby				    				    				      				    				      				    				                                      				    babe**{n.}++婴儿；幼儿；未成年人**{adj.}++婴儿的；幼稚的；初期的；未成年的**', '');
