insert into TOEFLWordBook values ('456', 'ingenious', '[ɪnˈdʒiːniəs]', 'http://dict.youdao.com/dictvoice?audio=ingenious', '{adj.}++灵巧的，有独创性的；精巧的，巧妙的**{adj.}++(used of persons or artifacts) marked by independence and creativity in thought or action																										        													        				&quot;the invention of the knitting frame by another ingenious English clergyman&quot;; &quot;an ingenious device&quot;															   	同义词：								                                  				    imaginative				    				    				      				    				      				    				                                      				    inventive**{adj.}++有独创性的；机灵的，精制的；心灵手巧的**', '');
insert into TOEFLWordBook values ('457', 'inherent', '[ɪnˈherənt]', 'http://dict.youdao.com/dictvoice?audio=inherent', '{adj.}++内在的，固有的；（权利，特权）固定属于（某人）的；（形容词）作定语和表语时意义相同的**{adj.}++existing as an essential constituent or characteristic																					   	同义词：								                                  				    built-in				    				    				      				    				      				    				                                      				    constitutional				    				    				      				    				      				    				                                      				    inbuilt				    				    				      				    				      				    				                                      				    integral**{adj.}++内在的；固有的；与生俱来的**', '');
insert into TOEFLWordBook values ('458', 'inherit', '[ɪnˈherɪt]', 'http://dict.youdao.com/dictvoice?audio=inherit', '{v.}++继承（遗产）；经遗传获得（品质、身体特征等）；接手，承担；接收（前所有者的事物）；（尤作圣经翻译和典故用语）得到**{v.}++obtain from someone after their death																										        				&quot;I inherited a castle from my French grandparents&quot;															   	同义词：								                                  				    come into**{vt.}++继承；遗传而得**', '');
