insert into TOEFLWordBook values ('460', 'initial', '[ɪˈnɪʃ(ə)l]', 'http://dict.youdao.com/dictvoice?audio=initial', '{adj.}++开始的，最初的；（字母）位于词首的**{n.}++（姓名的）首字母**{v.}++用姓名的首字母作标记（或签名）于**{n.}++the first letter of a word (especially a persons name)																										        				&quot;he refused to put the initials FRS after his name&quot;**{v.}++mark with ones initials**{adj.}++occurring at the beginning																										        				&quot;took the initial step toward reconciliation&quot;**{adj.}++[数]最初的；字首的**', '');
insert into TOEFLWordBook values ('461', 'inject', '[ɪnˈdʒekt]', 'http://dict.youdao.com/dictvoice?audio=inject', '{v.}++注射；（给……）添加，增加（某品质）；投入（金钱或资源）；（往物质、装置中）注入或射入（电流、粒子束等）；将（宇宙飞船等）射入轨道（或弹道）**{v.}++give an injection to																										        				&quot;We injected the glucose into the patients vein&quot;															   	同义词：								                                  				    shoot**{vt.}++注入；注射**', '');
