insert into TOEFLWordBook values ('463', 'inland', '[ˈɪnlənd]', 'http://dict.youdao.com/dictvoice?audio=inland', '{adv.}++在内地，向内陆**{adj.}++内陆的，内地的；国内的**{n.}++内陆，内地**{adj.}++situated away from an areas coast or border**{adv.}++towards or into the interior of a region																										        				&quot;the town is five miles inland&quot;**{n.}++内地；[地理]内陆**{adj.}++[地理]内陆的；内地的；国内的**{adv.}++在内地；向内地；[地理]向内陆；在内陆**', '');
insert into TOEFLWordBook values ('464', 'inner', '[ˈɪnər]', 'http://dict.youdao.com/dictvoice?audio=inner', '{adj.}++内部的，靠近中心的；内心的，未表达出来的；存在于性格中的，骨子里的；隐蔽的，内在的**{n.}++内部，内里；靶子内圈；命中靶子内圈的一发**{adj.}++located inward																										        				&quot;Beethovens manuscript looks like a bloody record of a tremendous inner battle&quot;															   	同义词：								                                  				    interior				    				    				      				    				      				    				                                      				    internal**{adj.}++内部的；内心的；精神的**{n.}++内部**', '');
insert into TOEFLWordBook values ('465', 'innocent', '[ˈɪnəs(ə)nt]', 'http://dict.youdao.com/dictvoice?audio=innocent', '{adj.}++天真的，幼稚的；清白的，无罪的；无辜受害的；没有恶意的，无冒犯之意的**{n.}++天真无邪的人，幼稚的人；无辜的受害者（尤指犯罪或战争的受害者）**{n.}++a person who lacks knowledge of evil																					   	同义词：								                                  				    inexperienced person**{adj.}++free from evil or guilt																										        													        				&quot;an innocent child&quot;; &quot;the principle that one is innocent until proved guilty&quot;															   	同义词：								                                  				    guiltless				    				    				      				    				      				    				                                      				    clean-handed**{adj.}++[法]无辜的；无罪的；无知的**{n.}++天真的人；笨蛋**', '');
insert into TOEFLWordBook values ('466', 'innumerable', '[ɪˈnuːmərəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=innumerable', '{adj.}++无数的，数不清的**{adj.}++too numerous to be counted																										        				&quot;innumerable difficulties&quot;															   	同义词：								                                  				    countless				    				    				      				    				      				    				                                      				    infinite				    				    				      				    				      				    				                                      				    innumerous				    				    				      				    				      				    				                                      				    multitudinous				    				    				      				    				      				    				                                      				    myriad				    				    				      				    				      				    				                                      				    numberless				    				    				      				    				      				    				                                      				    uncounted				    				    				      				    				      				    				                                      				    unnumberable				    				    				      				    				      				    				                                      				    unnumbered				    				    				      				    				      				    				                                      				    unnumerable**{adj.}++无数的，数不清的**', '');
insert into TOEFLWordBook values ('467', 'insert', '[ɪnˈsɜːrt]', 'http://dict.youdao.com/dictvoice?audio=insert', '{v.}++插入，嵌入；（在文章中）添加，加插；使参与（活动）；（肌肉或其他器官）附着于（尤指移动部分）**{n.}++插入物；（尤指）插页，附加页；（电影等的）插入镜头**{n.}++a folded section placed between the leaves of another publication**{vt.}++插入；[建]嵌入**{n.}++[建]插入物**', '');
