insert into TOEFLWordBook values ('470', 'inspire', '[ɪnˈspaɪər]', 'http://dict.youdao.com/dictvoice?audio=inspire', '{v.}++激励，鼓舞；赋予灵感，激发（想法）；使产生（感觉或情感）；引起，导致；吸气，吸入**{v.}++heighten or intensify																					   	同义词：								                                  				    animate				    				    				      				    				      				    				                                      				    invigorate				    				    				      				    				      				    				                                      				    enliven				    				    				      				    				      				    				                                      				    exalt**{vt.}++激发；鼓舞；启示；产生；使生灵感**', '');
insert into TOEFLWordBook values ('471', 'install', '[ɪnˈstɔːl]', 'http://dict.youdao.com/dictvoice?audio=install', '{v.}++安装，设置；（计算机）安装（新软件）；正式任命，使正式就职；安顿，安置**{v.}++set up for use																										        				&quot;install the washer and dryer&quot;															   	同义词：								                                  				    instal				    				    				      				    				      				    				                                      				    put in				    				    				      				    				      				    				                                      				    set up**{vt.}++安装；任命；安顿**', '');
insert into TOEFLWordBook values ('472', 'instant', '[ˈɪnstənt]', 'http://dict.youdao.com/dictvoice?audio=instant', '{adj.}++立刻的，马上的；速食的，即食的；紧急的，紧迫的；（商业信函用语）本月的；此刻的，现时的**{n.}++瞬间，片刻；当时，那一刻；速溶咖啡**{n.}++a very short time (as the time it takes the eye blink or the heart to beat)																					   	同义词：								                                  				    blink of an eye				    				    				      				    				      				    				                                      				    flash				    				    				      				    				      				    				                                      				    heartbeat				    				    				      				    				      				    				                                      				    jiffy				    				    				      				    				      				    				                                      				    split second				    				    				      				    				      				    				                                      				    trice				    				    				      				    				      				    				                                      				    twinkling				    				    				      				    				      				    				                                      				    wink				    				    				      				    				      				    				                                      				    New York minute**{adj.}++立即的；紧急的；紧迫的**{n.}++瞬间；立即；片刻**', '');
insert into TOEFLWordBook values ('473', 'instinct', '[ˈɪnstɪŋkt]', 'http://dict.youdao.com/dictvoice?audio=instinct', '{n.}++本能，天性；直觉；天分，天赋**{adj.}++充满（某种品质，尤指好品质）的**{n.}++inborn pattern of behavior often responsive to specific stimuli																										        													        				&quot;the spawning instinct in salmon&quot;; &quot;altruistic instincts in social animals&quot;															   	同义词：								                                  				    inherent aptitude**{adj.}++(followed by `with)deeply filled or permeated																										        				&quot;words instinct with love&quot;															   	同义词：								                                  				    replete(p)**{n.}++[生物]本能，直觉；[心理]天性**{adj.}++充满着的**', '');
insert into TOEFLWordBook values ('474', 'institute', '[ˈɪnstɪtuːt]', 'http://dict.youdao.com/dictvoice?audio=institute', '{n.}++研究所，学院，协会；（尤指与法律相关的）注释，论述**{v.}++制定（制度、规则等）；提出（诉讼）；任命，授予……职位（尤指圣职）**{n.}++an association organized to promote art or science or education**{v.}++set up or lay the groundwork for																					   	同义词：								                                  				    establish				    				    				      				    				      				    				                                      				    found				    				    				      				    				      				    				                                      				    plant				    				    				      				    				      				    				                                      				    constitute**{vt.}++开始（调查）；制定；创立；提起（诉讼）**{n.}++学会，协会；学院**', '');
insert into TOEFLWordBook values ('475', 'institution', '[ˌɪnstɪˈtuːʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=institution', '{n.}++机构，团体；社会收容机构；制度，习俗；建立，制定；知名的人（或事物）**{n.}++an organization founded and united for a specific purpose																					   	同义词：								                                  				    establishment**{n.}++[管理]制度；建立；（社会或宗教等）公共机构；习俗**', '');
insert into TOEFLWordBook values ('476', 'instruct', '[ɪnˈstrʌkt]', 'http://dict.youdao.com/dictvoice?audio=instruct', '{v.}++指示，吩咐；教授，指导；聘请（律师），托办；通知；（法官向陪审团）建议，作说明**{v.}++impart skills or knowledge to																										        				&quot;He instructed me in building a boat&quot;															   	同义词：								                                  				    teach				    				    				      				    				      				    				                                      				    learn**{vt.}++指导；通知；命令；教授**', '');
insert into TOEFLWordBook values ('477', 'instrument', '[ˈɪnstrəmənt]', 'http://dict.youdao.com/dictvoice?audio=instrument', '{n.}++器械；乐器；仪器；促成某事的人（或事物），手段；受利用（或控制）的人，工具；文据，正式法律文件**{v.}++给……装备测量仪器**{n.}++a device that requires skill for proper use**{n.}++[仪]仪器；[机]工具；乐器；手段；器械**', '');
