insert into TOEFLWordBook values ('479', 'interfere', '[ˌɪntərˈfɪr]', 'http://dict.youdao.com/dictvoice?audio=interfere', '{v.}++干涉，干扰；阻碍，妨害；（未经允许）摆弄，（尤指）弄坏；（光或其他电磁波）相互作用，相互干扰；（指马）碰踝，绊脚**{v.}++come between so as to be hindrance or obstacle																										        				&quot;Your talking interferes with my work!&quot;**{vi.}++干涉；妨碍；打扰**{vt.}++冲突；介入**', '');
insert into TOEFLWordBook values ('480', 'interior', '[ɪnˈtɪriər]', 'http://dict.youdao.com/dictvoice?audio=interior', '{adj.}++内部的，里面的；国内的，内政的；内心的，本质的；内陆的，腹地的**{n.}++内部，里面；内陆，腹地；（本国的）内政，内务；（建筑物或房间内的）内景；内心，本质**{n.}++the region that is inside of something																					   	同义词：								                                  				    inside**{n.}++内部；本质**{adj.}++内部的；国内的；本质的**', '');
insert into TOEFLWordBook values ('481', 'interpret', '[ɪnˈtɜːrprət]', 'http://dict.youdao.com/dictvoice?audio=interpret', '{v.}++解释，说明；口译；把……理解为；演绎**{v.}++make sense of; assign a meaning to																										        				&quot;How do you interpret his behavior?&quot;															   	同义词：								                                  				    construe				    				    				      				    				      				    				                                      				    see**{vt.}++说明；口译**{vi.}++解释；翻译**', '');
insert into TOEFLWordBook values ('482', 'interrupt', '[ˌɪntəˈrʌpt]', 'http://dict.youdao.com/dictvoice?audio=interrupt', '{v.}++打断，打扰；使暂停，使中断；阻断，遮挡**{n.}++a signal that temporarily stops the execution of a program so that another procedure can be carried out**{v.}++make a break in																										        				&quot;We interrupt the program for the following messages&quot;															   	同义词：								                                  				    disrupt				    				    				      				    				      				    				                                      				    break up				    				    				      				    				      				    				                                      				    cut off**{vt.}++中断；打断；插嘴；妨碍**{vi.}++打断；打扰**{n.}++中断**', '');
insert into TOEFLWordBook values ('483', 'intimate', '[ˈɪntɪmət]', 'http://dict.youdao.com/dictvoice?audio=intimate', '{adj.}++亲密的；个人的，隐私的；温馨的，幽静舒适的；详尽的，精通的；密切的，紧密的；有性关系的，暧昧的**{v.}++透露，暗示；宣布，通告**{n.}++密友，知己**{n.}++someone to whom private matters are confided																					   	同义词：								                                  				    confidant**{v.}++give to understand																					   	同义词：								                                  				    adumbrate				    				    				      				    				      				    				                                      				    insinuate**{adj.}++亲密的；私人的；精通的；有性关系的**{n.}++知己；至交**{vt.}++暗示；通知；宣布**', '');
insert into TOEFLWordBook values ('484', 'intrinsic', '[ɪnˈtrɪnzɪk]', 'http://dict.youdao.com/dictvoice?audio=intrinsic', '{adj.}++内在的，固有的**{adj.}++belonging to a thing by its very nature																										        				&quot;form was treated as something intrinsic, as the very essence of the thing&quot;															   	同义词：								                                  				    intrinsical**{adj.}++[物][生物]本质的，固有的**', '');
insert into TOEFLWordBook values ('485', 'invariable', '[ɪnˈveriəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=invariable', '{adj.}++永远不变的，始终如一的；（屈折变化语言的名词）单复数同形的；（数）（数量） 不变的**{n.}++常数；不变的东西**{n.}++a quantity that does not vary																					   	同义词：								                                  				    constant				    				    				      				    				      				    				                                      				    constant quantity**{adj.}++not liable to or capable of change																										        													        													        				&quot;an invariable temperature&quot;; &quot;an invariable rule&quot;; &quot;his invariable courtesy&quot;**{adj.}++不变的；常数的**{n.}++常数；不变的东西**', '');
insert into TOEFLWordBook values ('486', 'investigate', '[ɪnˈvestɪɡeɪt]', 'http://dict.youdao.com/dictvoice?audio=investigate', '{v.}++侦察（某事）；调查（某人）；研究**{v.}++investigate scientifically																										        				&quot;Lets investigate the syntax of Chinese&quot;															   	同义词：								                                  				    look into**{v.}++调查；研究**', '');
insert into TOEFLWordBook values ('487', 'involve', '[ɪnˈvɑːlv]', 'http://dict.youdao.com/dictvoice?audio=involve', '{v.}++牵涉，涉及；包含，需要；使陷入，使卷入；（使）参加，加入；使承担，使面对**{v.}++connect closely and often incriminatingly																					   	同义词：								                                  				    affect				    				    				      				    				      				    				                                      				    regard**{vt.}++包含；牵涉；使陷于；潜心于**', '');
insert into TOEFLWordBook values ('488', 'irony', '[ˈaɪrəni]', 'http://dict.youdao.com/dictvoice?audio=irony', '{n.}++（出乎意料的）奇异可笑之处，具有讽刺意味的情况；反语，讽刺**{adj.}++铁的；含铁的；似铁的**{n.}++witty language used to convey insults or scorn																										        				&quot;irony is wasted on the stupid&quot;															   	同义词：								                                  				    sarcasm				    				    				      				    				      				    				                                      				    satire				    				    				      				    				      				    				                                      				    caustic remark**{n.}++讽刺；反语；具有讽刺意味的事**{adj.}++铁的；似铁的**', '');
