insert into TOEFLWordBook values ('492', 'isolate', '[ˈaɪsəleɪt]', 'http://dict.youdao.com/dictvoice?audio=isolate', '{v.}++孤立，分离；隔离；单独考虑，区别看待；使（某物质、细胞等）分离**{n.}++被隔离的人（或物）；（用于研究的）分离菌，隔离群**{adj.}++孤独的，孤立的**{v.}++place or set apart																										        				&quot;They isolated the political prisoners from the other inmates&quot;															   	同义词：								                                  				    insulate**{vt.}++[生物]使隔离；使孤立；使绝缘**{vi.}++[生物]隔离；孤立**{adj.}++[生物]隔离的；孤立的**', '');
