insert into TOEFLWordBook values ('496', 'keen', '[kiːn]', 'http://dict.youdao.com/dictvoice?audio=keen', '{adj.}++渴望的，热衷的；喜爱的，着迷的；热情的，热心的；（兴趣或感情）浓厚的，强烈的；思维敏捷的，敏锐的；（目光或听觉）灵敏的；（战斗或竞争）激烈的，紧张的；（价格）低廉的，有竞争力的；寒冷刺骨的；锋利的，锐利的；（气味、光或声音）有穿透力的，强烈的，明净的**{v.}++（为死者）恸哭，哀号**{n.}++痛哭，挽歌**{n.}++a funeral lament sung with loud wailing**{v.}++express grief verbally																					   	同义词：								                                  				    lament**{adj.}++having or demonstrating ability to recognize or draw fine distinctions																					   	同义词：								                                  				    acute				    				    				      				    				      				    				                                      				    discriminating				    				    				      				    				      				    				                                      				    incisive				    				    				      				    				      				    				                                      				    knifelike				    				    				      				    				      				    				                                      				    penetrating				    				    				      				    				      				    				                                      				    penetrative				    				    				      				    				      				    				                                      				    piercing				    				    				      				    				      				    				                                      				    sharp**{adj.}++敏锐的，敏捷的；渴望的；强烈的；热心的；锐利的**{n.}++痛哭，挽歌**', '');
