insert into TOEFLWordBook values ('503', 'lash', '[læʃ]', 'http://dict.youdao.com/dictvoice?audio=lash', '{v.}++猛击，狠打；鞭打，抽打；怒斥，抨击；捆绑，捆扎；煽动，激励；（动物）用力甩动（尾巴）**{n.}++睫毛；鞭打（尤作为惩罚）；突然（猛烈）的一甩；责骂，讽刺；鞭梢**{n.}++any of the short curved hairs that grow from the edges of the eyelids																					   	同义词：								                                  				    eyelash				    				    				      				    				      				    				                                      				    cilium**{vt.}++鞭打；冲击；摆动；扎捆；煽动；讽刺**{vi.}++鞭打；猛击；急速甩动**{n.}++鞭打；睫毛；鞭子；责骂；讽刺**', '');
insert into TOEFLWordBook values ('504', 'latter', '[ˈlætər]', 'http://dict.youdao.com/dictvoice?audio=latter', '{adj.}++（两者之中的）后者的；末期的，后期的**{n.}++（两者之间的）后者（the latter）**{n.}++the second of two or the second mentioned of two																										        				&quot;Tom and Dick were both heroes but only the latter is remembered today&quot;**{adj.}++referring to the second of two things or persons mentioned (or the last one or ones of several)																										        				&quot;in the latter case&quot;**{adj.}++后者的；近来的；后面的；较后的**', '');
