insert into TOEFLWordBook values ('517', 'limb', '[lɪm]', 'http://dict.youdao.com/dictvoice?audio=limb', '{n.}++肢；大树枝；（某物的）突出部，延伸部分；十字形四个分支中的一个；弓把的上部（或下部）；（日月等天体的）边缘；冠檐，萼檐；（管状花的）瓣片；（四分仪等科学仪器上测量角度的）分度弧**{v.}++切断……的手足；从……上截下树枝**{n.}++one of the jointed appendages of an animal used for locomotion or grasping: arm; leg; wing; flipper**{n.}++肢，臂；分支；枝干**', '');
