insert into TOEFLWordBook values ('544', 'massive', '[ˈmæsɪv]', 'http://dict.youdao.com/dictvoice?audio=massive', '{adj.}++大而重的，结实的；非常严重的；大量的，大规模的；特别成功的，非常有影响的；（岩石或地层）均匀构造的，大块的；（矿物）外观非晶质的；极好的，非常妙的**{n.}++（某一地区的年轻人群体）嬉蹦音乐迷（或丛林爵士音乐迷）**{adj.}++imposing in size or bulk or solidity																										        													        				&quot;massive oak doors&quot;; &quot;Moores massive sculptures&quot;															   	同义词：								                                  				    monolithic				    				    				      				    				      				    				                                      				    monumental**{adj.}++大量的；巨大的，厚重的；魁伟的**', '');
