insert into TOEFLWordBook values ('553', 'medium', '[ˈmiːdiəm]', 'http://dict.youdao.com/dictvoice?audio=medium', '{n.}++媒介，媒体；方法，手段；（艺术创作）材料，素材；灵媒，巫师；培养基；环境；中等，中号；存储（或打印）介质；（颜料）溶剂（如油或水）；（品质、状态）中等，中庸**{adj.}++中等的，中间的，适中的；五分熟的，半熟的；（程度、强度或数量）平均的；（颜色）不深不浅的，适中的；（投球，投球手）中速的**{n.}++a means or instrumentality for storing or communicating information**{adj.}++中间的，中等的；半生熟的**{n.}++方法；媒体；媒介；中间物**', '');
