insert into TOEFLWordBook values ('556', 'merchant', '[ˈmɜːrtʃənt]', 'http://dict.youdao.com/dictvoice?audio=merchant', '{n.}++商人，（尤指外贸）批发商；商店老板；对（令人讨厌之事）入迷的人**{adj.}++海上货运的；商业的，商人的**{n.}++a businessperson engaged in retail trade																					   	同义词：								                                  				    merchandiser**{n.}++[贸易]商人，批发商；店主**{adj.}++商业的，[贸易]商人的**', '');
insert into TOEFLWordBook values ('557', 'mention', '[ˈmenʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=mention', '{v.}++提到，谈到；提名，推荐；传令嘉奖，提名表扬**{n.}++提及，说起，写上一笔；提名表扬**{n.}++a remark that calls attention to something or someone																										        													        				&quot;she made frequent mention of her promotion&quot;; &quot;there was no mention of it&quot;															   	同义词：								                                  				    reference**{vt.}++提到，谈到；提及，论及；说起**{n.}++提及，说起**', '');
insert into TOEFLWordBook values ('558', 'merciless', '[ˈmɜːrsɪləs]', 'http://dict.youdao.com/dictvoice?audio=merciless', '{adj.}++残忍的；无慈悲心的**{adj.}++having or showing no mercy																										        													        													        				&quot;the merciless enemy&quot;; &quot;a merciless critic&quot;; &quot;gave him a merciless beating&quot;															   	同义词：								                                  				    unmerciful**{adj.}++残忍的；无慈悲心的**', '');
insert into TOEFLWordBook values ('559', 'mere', '[mɪr]', 'http://dict.youdao.com/dictvoice?audio=mere', '{adj.}++仅仅，只不过；只凭……就足以**{n.}++小湖，池塘；（尤指毛利人用绿岩制的武器）石棒**{n.}++a small pond of standing water**{adj.}++being nothing more than specified																										        				&quot;a mere child&quot;**{n.}++小湖；池塘**', '');
