insert into TOEFLWordBook values ('562', 'migrate', '[ˈmaɪɡreɪt]', 'http://dict.youdao.com/dictvoice?audio=migrate', '{v.}++（候鸟或动物）迁徙；（尤指为找工作）移居，迁移；转移（从一个部位移到另一部位）；把（程序，硬件）从一系统转移到另一系统；改用操作系统**{v.}++move from one country or region to another and settle there																										        													        				&quot;Many Germans migrated to South America in the mid-19th century&quot;; &quot;This tribe transmigrated many times over the centuries&quot;															   	同义词：								                                  				    transmigrate**{vi.}++移动；随季节而移居；移往**{vt.}++使移居；使移植**', '');
insert into TOEFLWordBook values ('563', 'mild', '[maɪld]', 'http://dict.youdao.com/dictvoice?audio=mild', '{adj.}++（伤病）不严重的，轻微的；（感觉或表情）不强烈的，微弱的；（惩罚或批评）不严厉的；轻的，不过度的；（味道）清淡的，不刺激的；（药物、化妆品等）柔和的，无副作用的；（肥皂、洗涤液）温和的，不伤皮肤的；（天气）和煦的，温暖的；（人或其行为）和善的，随和的**{n.}++淡味黑啤**{adj.}++moderate in type or degree or effect or force; far from extreme																										        													        													        													        													        				&quot;a mild winter storm&quot;; &quot;a mild fever&quot;; &quot;fortunately the pain was mild&quot;; &quot;a mild rebuke&quot;; &quot;mild criticism&quot;**{adj.}++温和的；轻微的；淡味的；文雅的；不含有害物质的的**', '');
insert into TOEFLWordBook values ('564', 'military', '[ˈmɪləteri]', 'http://dict.youdao.com/dictvoice?audio=military', '{adj.}++军事的，军队的；陆军的；军人般的，军人作风的**{n.}++军人，军方**{n.}++the military forces of a nation																										        													        				&quot;their military is the largest in the region&quot;; &quot;the military machine is the same one we faced in 1991 but now it is weaker&quot;															   	同义词：								                                  				    armed forces				    				    				      				    				      				    				                                      				    armed services				    				    				      				    				      				    				                                      				    military machine				    				    				      				    				      				    				                                      				    war machine**{adj.}++of or relating to the study of the principles of warfare																										        				&quot;military law&quot;**{adj.}++军事的；军人的；适于战争的**{n.}++军队；军人**', '');
insert into TOEFLWordBook values ('565', 'mill', '[mɪl]', 'http://dict.youdao.com/dictvoice?audio=mill', '{n.}++磨坊，磨粉厂；工厂，制造厂； 一百万；磨粉机，磨麪机；密尔，厘；机器，铣床；引擎；一百万**{v.}++（用磨粉机）碾碎，磨成粉；（一大群人）闲逛，转悠；碾（轧，铣）（金属）；轧出（硬币的）边纹；使（羊毛或其他动物纤维）缩绒（或缩呢）**{n.}++a plant consisting of one or more buildings with facilities for manufacturing																					   	同义词：								                                  				    factory				    				    				      				    				      				    				                                      				    manufacturing plant				    				    				      				    				      				    				                                      				    manufactory**{n.}++[工经]工厂；磨坊；[化工][粮食][机]磨粉机；制造厂；压榨机**{vt.}++搅拌；[机]碾磨；磨细；使乱转**', '');
insert into TOEFLWordBook values ('566', 'millennium', '[mɪˈleniəm]', 'http://dict.youdao.com/dictvoice?audio=millennium', '{n.}++一千年；千周年纪念日，千禧年（the millennium）；世界末日前基督治理世界的一千年（the millennium）；（作为乌托邦的）美满时期，太平盛世（the millennium）**{n.}++a span of 1000 years																					   	同义词：								                                  				    millenary**{(New Testament) in Revelations it is foretold that those faithful to Jesus will reign with Jesus over the earth for a thousand years; the meaning of these words have been much debated; some denominations (e.}++g. Jehovahs Witnesses) expect it to be a thousand years of justice and peace and happiness**{n.}++千年期，千禧年；一千年，千年纪念；太平盛世，黄金时代**', '');
insert into TOEFLWordBook values ('567', 'mimic', '[ˈmɪmɪk]', 'http://dict.youdao.com/dictvoice?audio=mimic', '{v.}++模仿（人的言行举止）；模拟（外观或效果）；模拟（另一种植物或动物）；（药）模拟（另一物质）的生理作用；（疾病）表现出（另一疾病）的症状**{n.}++善于模仿的人；会模拟的动物（或植物）**{adj.}++模拟的，演习的**{n.}++someone who mimics (especially an actor or actress)																					   	同义词：								                                  				    mimicker**{v.}++imitate (a person or manner), especially for satirical effect																										        				&quot;The actor mimicked the President very accurately&quot;															   	同义词：								                                  				    mime**{adj.}++constituting an imitation																										        				&quot;the mimic warfare of the opera stage&quot;**{vt.}++模仿，摹拟**{n.}++效颦者，模仿者；仿制品；小丑**{adj.}++模仿的，模拟的；假装的**', '');
insert into TOEFLWordBook values ('568', 'miniature', '[ˈmɪnətʃər]', 'http://dict.youdao.com/dictvoice?audio=miniature', '{adj.}++微型的，小型的**{n.}++缩微模型，微型复制品；微型画，小画像；小瓶装酒；小种植物（或动物）；（华美装饰手稿上的）画饰，花字**{n.}++painting or drawing included in a book (especially in illuminated medieval manuscripts)																					   	同义词：								                                  				    illumination**{adj.}++微型的，小规模的**{n.}++缩图；微型画；微型图画绘画术**', '');
insert into TOEFLWordBook values ('569', 'ministry', '[ˈmɪnɪstri]', 'http://dict.youdao.com/dictvoice?audio=ministry', '{n.}++（政府的）部，部办公楼；（全体）牧师；神职，神职任期；一任首相的执政期；照料，服务**{n.}++religious ministers collectively (especially Presbyterian)**{n.}++（政府的）部门**', '');
insert into TOEFLWordBook values ('570', 'mission', '[ˈmɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=mission', '{n.}++（尤指赴他国的）使命，重要任务；职责，天职；（军用飞机或航天火箭的）飞行任务；军事行动；（一个组织的）目的，宗旨；外交使团，代表团；驻外机构，使馆；（尤指在海外的）传教，布道；传教团，布道团；布道所，传教所**{vi.}++作艰苦的长途旅行（尤指去许多地方）；派遣；向……传教**{n.}++an organization of missionaries in a foreign land sent to carry on religious work																					   	同义词：								                                  				    missionary post				    				    				      				    				      				    				                                      				    missionary station				    				    				      				    				      				    				                                      				    foreign mission**{n.}++使命，任务；代表团；布道**{vt.}++派遣；向……传教**', '');
