insert into TOEFLWordBook values ('572', 'mock', '[mɑːk]', 'http://dict.youdao.com/dictvoice?audio=mock', '{v.}++嘲笑，（模仿）嘲弄；使显得徒劳，使显得可笑；（照原尺寸）模仿，仿制 （mock sth. up）**{adj.}++假装的，假的；仿真的；（考试、作战等）模拟的，演习的**{n.}++模拟考试（mocks）；嘲笑对象，笑柄；嘲笑；模仿，仿造（品）**{adv.}++虚假地，不诚实地**{n.}++the act of mocking or ridiculing																										        				&quot;they made a mock of him&quot;**{v.}++treat with contempt																										        				&quot;The new constitution mocks all democratic principles&quot;															   	同义词：								                                  				    bemock**{vt.}++嘲弄；模仿；使…失望；使…无效**{vi.}++嘲弄，嘲笑**{n.}++嘲弄；仿制品；嘲笑对象**{adj.}++模拟的；假装的；伪造的**{adv.}++虚伪地**', '');
insert into TOEFLWordBook values ('573', 'mode', '[moʊd]', 'http://dict.youdao.com/dictvoice?audio=mode', '{n.}++方式，做法；（机器、设备的）运行方式，状态；（衣着、艺术等的）形式，风格；（思想、情感或行为的）状态，状况；（音乐的）调式；众数（一组数字中出现次数最多的数）；（逻）（模态命题的）式，形式；（物理）模（式），波型；（模态命题的）式，形式**{n.}++how something is done or how it happens																										        				&quot;their nomadic mode of existence&quot;															   	同义词：								                                  				    manner				    				    				      				    				      				    				                                      				    style				    				    				      				    				      				    				                                      				    way				    				    				      				    				      				    				                                      				    fashion**{n.}++模式；方式；风格；时尚**', '');
insert into TOEFLWordBook values ('574', 'modem', '[ˈmoʊdəm]', 'http://dict.youdao.com/dictvoice?audio=modem', '{n.}++调制解调器（等于 modulator-demodulator）**{n.}++(from a combination of MOdulate and DEModulate) electronic equipment consisting of a device used to connect computers by a telephone line**{n.}++调制解调器（等于modulator-demodulator）**', '');
insert into TOEFLWordBook values ('575', 'moderate', '[ˈmɑːdərət]', 'http://dict.youdao.com/dictvoice?audio=moderate', '{adj.}++普通的，中等的；不偏激的，温和的；有节制的，不过分的；（变化）不大的，有限的**{v.}++缓和，使适中；主持（讨论或会议）；审核评分（查看不同阅卷人所打分数是否公平一致）；（物理）使（中子）减速**{n.}++持温和政见者**{n.}++a person who takes a position in the political center																					   	同义词：								                                  				    centrist				    				    				      				    				      				    				                                      				    middle of the roader				    				    				      				    				      				    				                                      				    moderationist**{v.}++preside over																										        				&quot;John moderated the discussion&quot;															   	同义词：								                                  				    chair				    				    				      				    				      				    				                                      				    lead**{adj.}++稳健的，温和的；适度的，中等的；有节制的**{vi.}++变缓和，变弱**{vt.}++节制；减轻**', '');
insert into TOEFLWordBook values ('576', 'modest', '[ˈmɑːdɪst]', 'http://dict.youdao.com/dictvoice?audio=modest', '{adj.}++不太多的，适中的；谦虚的，谦逊的；保守的，端庄的；不错的；（服装）不显身材的；羞怯的，腼腆的**{adj.}++marked by simplicity; having a humble opinion of yourself																										        													        				&quot;a modest apartment&quot;; &quot;too modest to wear his medals&quot;**{adj.}++谦虚的，谦逊的；适度的；端庄的；羞怯的**', '');
