insert into TOEFLWordBook values ('578', 'mold', '[moʊld]', 'http://dict.youdao.com/dictvoice?audio=mold', '{n.}++模具；铸模；模制品；类型，个性，风格；框架；体型，模样；霉，霉菌；耕作土壤；松软沃土**{v.}++浇铸，塑造；用模子制作；对……影响重大；将……塑造成；使）紧贴于，吻合；轮廓相符；使发霉**{n.}++（Mold）（美、英、奥地利）莫尔德（人名）**{n.}++the distinctive form in which a thing is made																					   	同义词：								                                  				    cast				    				    				      				    				      				    				                                      				    stamp**{vt.}++塑造；使发霉；用模子制作**{vi.}++发霉**{n.}++霉菌；模子**', '');
insert into TOEFLWordBook values ('579', 'moment', '[ˈmoʊmənt]', 'http://dict.youdao.com/dictvoice?audio=moment', '{n.}++片刻，瞬间；某一时刻；现在，目前；时机，机会；（事物发展的）关头，转折点；重大，重要；力矩；矩，动差**{n.}++a particular point in time																										        				&quot;the moment he arrived the party began&quot;															   	同义词：								                                  				    minute				    				    				      				    				      				    				                                      				    second				    				    				      				    				      				    				                                      				    instant**{n.}++重要，契机；瞬间；重要时刻；指定时刻**', '');
insert into TOEFLWordBook values ('580', 'monetary', '[ˈmɑːnɪteri]', 'http://dict.youdao.com/dictvoice?audio=monetary', '{adj.}++货币的，金融的；能用金钱衡量的**{adj.}++relating to or involving money																										        				&quot;monetary rewards&quot;															   	同义词：								                                  				    pecuniary**{adj.}++货币的；财政的**', '');
insert into TOEFLWordBook values ('581', 'monster', '[ˈmɑːnstər]', 'http://dict.youdao.com/dictvoice?audio=monster', '{n.}++怪兽，怪物；残忍的人，恶魔；小恶棍，捣蛋鬼；巨大的东西，庞然大物；难以驾驭的人，难以掌控的事物；畸形动物（或植物）**{adj.}++很受欢迎的；庞大的，巨大的**{v.}++严厉批评，斥责**{n.}++an imaginary creature usually having various human and animal parts**{n.}++怪物；巨人，巨兽；残忍的人**{adj.}++巨大的，庞大的**', '');
insert into TOEFLWordBook values ('582', 'monument', '[ˈmɑːnjumənt]', 'http://dict.youdao.com/dictvoice?audio=monument', '{n.}++纪念碑，纪念馆，纪念物；遗址，名胜古迹；典范；塑像，墓碑；有永久价值的作品**{v.}++为……树碑**{n.}++a structure erected to commemorate persons or events																					   	同义词：								                                  				    memorial**{n.}++纪念碑；历史遗迹；不朽的作品**', '');
insert into TOEFLWordBook values ('583', 'mood', '[muːd]', 'http://dict.youdao.com/dictvoice?audio=mood', '{n.}++心境，情绪；气氛，情感基调；心情不好，坏脾气；想（做某事），有兴致（做某事）；（尤指音乐）激发……情感的，暗示……心境的；（群体的）态度，意愿；表达语气的动词屈折变化；（语法的）式，语气； 想（做某事），有兴致（做某事）**{n.}++a characteristic (habitual or relatively temporary) state of feeling																					   	同义词：								                                  				    temper				    				    				      				    				      				    				                                      				    humor				    				    				      				    				      				    				                                      				    humour**{n.}++情绪，语气；心境；气氛**', '');
insert into TOEFLWordBook values ('584', 'moral', '[ˈmɔːrəl]', 'http://dict.youdao.com/dictvoice?audio=moral', '{adj.}++有关道德的；基于道德的，道义上的；品行端正的，有道德的；伦理的；能辨别是非的**{n.}++道德准则（标准）；寓意，道德上的教训**{n.}++the significance of a story or event																										        				&quot;the moral of the story is to love thy neighbor&quot;															   	同义词：								                                  				    lesson**{adj.}++relating to principles of right and wrong; i.e. to morals or ethics																										        				&quot;moral philosophy&quot;**{adj.}++道德的；精神上的；品性端正的**{n.}++道德；寓意**', '');
insert into TOEFLWordBook values ('585', 'mud', '[mʌd]', 'http://dict.youdao.com/dictvoice?audio=mud', '{n.}++泥，淤泥，泥浆；（多指与腐化有关的）侮蔑，诽谤**{n.}++water soaked soil; soft wet earth																					   	同义词：								                                  				    clay**{vt.}++弄脏；用泥涂**{n.}++[地质]泥；诽谤的话；无价值的东西**', '');
insert into TOEFLWordBook values ('586', 'multiple', '[ˈmʌltɪp(ə)l]', 'http://dict.youdao.com/dictvoice?audio=multiple', '{adj.}++多个的，多种的；多人共有的；影响身体许多部位的**{n.}++倍数；连锁商店；（电信）复联，复接**{n.}++the product of a quantity by an integer																										        				&quot;36 is a multiple of 9&quot;**{adj.}++having or involving or consisting of more than one part or entity or individual																										        													        													        													        													        													        				&quot;multiple birth&quot;; &quot;multiple ownership&quot;; &quot;made multiple copies of the speech&quot;; &quot;his multiple achievements in public life&quot;; &quot;her multiple personalities&quot;; &quot;a pineapple is a multiple fruit&quot;**{adj.}++多重的；多样的；许多的**{n.}++[数]倍数；[电]并联**', '');
insert into TOEFLWordBook values ('587', 'mutual', '[ˈmjuːtʃuəl]', 'http://dict.youdao.com/dictvoice?audio=mutual', '{adj.}++相互的，彼此的；共同的，共有的；（保险公司、建筑协会等）互助的**{n.}++互助公司**{adj.}++common to or shared by two or more parties																										        				&quot;the mutual interests of management and labor&quot;															   	同义词：								                                  				    common**{adj.}++共同的；相互的，彼此的**', '');
insert into TOEFLWordBook values ('588', 'mystery', '[ˈmɪstəri]', 'http://dict.youdao.com/dictvoice?audio=mystery', '{n.}++难以理解（或解释）的事物，奥秘；神秘的人（或事物）；不可思议；疑案小说（或电影、戏剧）；（宗教信仰的）奥义，真谛；圣餐礼**{adj.}++神秘的，身份不明的**{n.}++something that baffles understanding and cannot be explained																										        				&quot;how it got out is a mystery&quot;															   	同义词：								                                  				    enigma				    				    				      				    				      				    				                                      				    secret				    				    				      				    				      				    				                                      				    closed book**{n.}++神秘，秘密；奥秘；神秘的事物**', '');
insert into TOEFLWordBook values ('589', 'myth', '[mɪθ]', 'http://dict.youdao.com/dictvoice?audio=myth', '{n.}++错误的观点，荒诞的说法；神话，神话故事；虚构的人（或事），想象中的人（或事）**{n.}++a traditional story accepted as history; serves to explain the world view of a people**{n.}++神话；虚构的人，虚构的事**', '');
insert into TOEFLWordBook values ('590', 'nail', '[neɪl]', 'http://dict.youdao.com/dictvoice?audio=nail', '{n.}++钉子；指甲，趾甲；（一些软喙鸟类）上喙的硬甲壳；纳尔（布匹长度单位）**{v.}++（用钉子）钉住，钉牢；抓住，证明……有罪；戳穿，揭露；（尤指体育运动中）获得，赢得；（选手）锁定（胜局）；用力击打；完美地完成，漂亮地做；(棒球)（外场手）把（跑垒者）杀出局；（选手）击败（或智胜）（对手）；（男性）与……性交；（外场手）把（跑垒者）杀出局**{n.}++horny plate covering and protecting part of the dorsal surface of the digits**{vt.}++钉；使固定；揭露**{n.}++[解剖]指甲；[五金]钉子**', '');
insert into TOEFLWordBook values ('591', 'naked', '[ˈneɪkɪd]', 'http://dict.youdao.com/dictvoice?audio=naked', '{adj.}++裸露的，无遮盖的；肉眼的；裸体的，不穿衣服的；露骨的，明显的；缺乏保护的，无力自卫的；（动物）没有皮毛的，没有羽毛的；公然的**{adj.}++completely unclothed																										        				&quot;naked from the waist up&quot;															   	同义词：								                                  				    bare				    				    				      				    				      				    				                                      				    au naturel(p)				    				    				      				    				      				    				                                      				    nude**{(of the eye or ear e.}++g.) without the aid of an optical or acoustical device or instrument																										        				&quot;visible to the naked eye&quot;**{adj.}++[生物]裸体的；无装饰的；无证据的；直率的**', '');
insert into TOEFLWordBook values ('592', 'narration', '[nəˈreɪʃnˌnæˈreɪʃn]', 'http://dict.youdao.com/dictvoice?audio=narration', '{n.}++叙述，讲故事；（电影、戏剧等中的）旁白，解说**{n.}++a message that tells the particulars of an act or occurrence or course of events; presented in writing or drama or cinema or as a radio or television program																					   	同义词：								                                  				    narrative				    				    				      				    				      				    				                                      				    story				    				    				      				    				      				    				                                      				    tale**{n.}++叙述，讲述；故事**', '');
insert into TOEFLWordBook values ('593', 'narrow', '[ˈnæroʊ]', 'http://dict.youdao.com/dictvoice?audio=narrow', '{adj.}++狭窄的，狭小的；（想法、态度或信仰）狭隘的；勉强的，（成败）差距很小的；（种类或数目）有限的，范围小的；严格的，精确的；（标音）严式的；（语音）窄的**{v.}++（人的眼睛）眯起来；使缩小，压缩；使变窄，变窄**{n.}++海峡；狭窄部分**{n.}++a narrow strait connecting two bodies of water**{v.}++make or become more narrow or restricted																										        													        				&quot;The selection was narrowed&quot;; &quot;The road narrowed&quot;															   	同义词：								                                  				    contract**{adj.}++狭窄的，有限的；勉强的；精密的；度量小的**{n.}++海峡；狭窄部分，隘路**{vi.}++变窄**', '');
insert into TOEFLWordBook values ('594', 'nationwide', '[ˌneɪʃ(ə)nˈwaɪd]', 'http://dict.youdao.com/dictvoice?audio=nationwide', '{adj.}++全国性的，全国各地的**{adv.}++在全国**{adj.}++occurring or extending throughout a country or nation																										        				&quot;the event aroused nationwide interest&quot;															   	同义词：								                                  				    countrywide**{adv.}++extending throughout an entire nation																										        				&quot;it was broadcast nationwide&quot;															   	同义词：								                                  				    nationally				    				    				      				    				      				    				                                      				    across the nation				    				    				      				    				      				    				                                      				    across the country**{adj.}++全国范围的；全国性的**', '');
insert into TOEFLWordBook values ('595', 'navigate', '[ˈnævɪɡeɪt]', 'http://dict.youdao.com/dictvoice?audio=navigate', '{v.}++导航，引路；航行于，横渡；穿过，穿越；驾驶，操纵；浏览；（有效地）处理；(鱼、动物或昆虫)找到正确的行动方向；绕过**{v.}++travel by boat propelled by wind or by other means																					   	同义词：								                                  				    voyage				    				    				      				    				      				    				                                      				    sail**{vt.}++驾驶，操纵；使通过；航行于**{vi.}++航行，航空**', '');
insert into TOEFLWordBook values ('596', 'necessity', '[nəˈsesəti]', 'http://dict.youdao.com/dictvoice?audio=necessity', '{n.}++必需品，必需的事物；必要，需要；必然性，不可避免的情况**{n.}++the condition of being essential or indispensable**{n.}++需要；[数]必然性；[经]必需品**', '');
insert into TOEFLWordBook values ('597', 'neck', '[nek]', 'http://dict.youdao.com/dictvoice?audio=neck', '{n.}++颈项，脖子；衣领，领口；（物体的）细长部分，颈部；狭长地带，狭长水域；（动物的）颈肉；（赛马）以微弱优势（获胜），险（胜）；在这一带，在某人的地区；受到惩罚（批评）；（喻）（对责任或过失的）背负；（剖）颈；（蕨、苔藓或菌类的）茎部**{v.}++搂着脖子亲吻，相拥互吻；一口喝下（某物，尤指酒）；（因拉伸而）变狭，变细**{n.}++the part of an organism that connects the head to the rest of the body																										        				&quot;he admired her long graceful neck&quot;															   	同义词：								                                  				    cervix**{n.}++脖子；衣领；海峡**', '');
insert into TOEFLWordBook values ('598', 'neglect', '[nɪˈɡlekt]', 'http://dict.youdao.com/dictvoice?audio=neglect', '{v.}++疏于照顾，未予看管；不予重视，忽视；漏做**{n.}++忽略，忽视，未被重视**{n.}++lack of attention and due care																					   	同义词：								                                  				    disregard**{vt.}++疏忽，忽视；忽略**{n.}++疏忽，忽视；怠慢**', '');
insert into TOEFLWordBook values ('599', 'negotiate', '[nɪˈɡoʊʃieɪt]', 'http://dict.youdao.com/dictvoice?audio=negotiate', '{v.}++（尤指在商业或政治上）谈判，磋商，洽谈；商定，达成协议；顺利通过，成功越过；解决（难题）；议付，洽兑；转让（支票、汇票或票据）**{v.}++discuss the terms of an arrangement																										        				&quot;They negotiated the sale of the house&quot;															   	同义词：								                                  				    negociate				    				    				      				    				      				    				                                      				    talk terms**{vt.}++谈判，商议；转让；越过**{vi.}++谈判，交涉**', '');
insert into TOEFLWordBook values ('600', 'neighbor', '[ˈneɪbər]', 'http://dict.youdao.com/dictvoice?audio=neighbor', '{n.}++邻居**{adj.}++邻近的**{vi.}++友好；毗邻而居**{vt.}++邻接**{n.}++（Neighbor）人名；（英）内伯**{n.}++a person who lives (or is located) near another																					   	同义词：								                                  				    neighbour**{n.}++邻居**{adj.}++邻近的**{vi.}++友好；毗邻而居**{vt.}++邻接**', '');
