insert into TOEFLWordBook values ('602', 'net', '[net]', 'http://dict.youdao.com/dictvoice?audio=net', '{n.}++网，网状物；因特网；球网，球门网；广播网，通讯网；安全网；捕鱼总量；净赚，纯利；（板球）练球场；（板球）一次练球；网眼织物；陷阱；候选人的选择面**{adj.}++净得的；净重的；最后的，最终的**{v.}++净赚，净得；设法获得，巧妙地做；（用网）捕捉；（篮球或足球）得分，进（球）；用网覆盖；（计算时）扣除……（以得出净额）**{adv.}++净赚地**{n.}++a computer network consisting of a worldwide network of computer networks that use the TCP/IP network protocols to facilitate data transmission and exchange																					   	同义词：								                                  				    internet				    				    				      				    				      				    				                                      				    cyberspace**{n.}++网；网络；净利；实价**{vt.}++得到；净赚；用网捕**{adj.}++纯粹的；净余的**', '');
insert into TOEFLWordBook values ('603', 'neutral', '[ˈnuːtrəl]', 'http://dict.youdao.com/dictvoice?audio=neutral', '{adj.}++中立的，不偏不倚的；中性的，不带感情色彩的；暗淡的，素净的；（化学中）中性的，非酸非碱的；不带电的**{n.}++（车辆排挡的）空挡；中立者，中立国；素净色，中和色；不活动，停滞；不带电的接触点**{n.}++one who does not side with any party in a war or dispute**{adj.}++neither moral nor immoral; neither good nor evil, right nor wrong**{adj.}++中立的，[生物]中性的；中立国的；非彩色的**{n.}++中立国；中立者；非彩色；齿轮的空档**', '');
insert into TOEFLWordBook values ('604', 'nickname', '[ˈnɪkneɪm]', 'http://dict.youdao.com/dictvoice?audio=nickname', '{n.}++绰号，外号**{v.}++给……起绰号；叫错名字**{n.}++a familiar name for a person (often a shortened version of a persons given name)																										        													        				&quot;Joes mother would not use his nickname and always called him Joseph&quot;; &quot;Henrys nickname was Slim&quot;															   	同义词：								                                  				    moniker				    				    				      				    				      				    				                                      				    cognomen				    				    				      				    				      				    				                                      				    sobriquet				    				    				      				    				      				    				                                      				    soubriquet				    				    				      				    				      				    				                                      				    byname**{a descriptive name for a place or thing																										        				&quot;the nickname for the U.}++S. Constitution is `Old Ironsides&quot;**{n.}++绰号；昵称**', '');
insert into TOEFLWordBook values ('605', 'nonetheless', '[ˌnʌnðəˈles]', 'http://dict.youdao.com/dictvoice?audio=nonetheless', '{adv.}++然而，尽管如此**{adv.}++despite anything to the contrary (usually following a concession)																					   	同义词：								                                  				    however				    				    				      				    				      				    				                                      				    nevertheless				    				    				      				    				      				    				                                      				    withal				    				    				      				    				      				    				                                      				    still				    				    				      				    				      				    				                                      				    yet				    				    				      				    				      				    				                                      				    all the same				    				    				      				    				      				    				                                      				    even so				    				    				      				    				      				    				                                      				    notwithstanding**{adv.}++尽管如此，但是**{conj.}++尽管如此，但是**', '');
insert into TOEFLWordBook values ('606', 'nonsense', '[ˈnɑːnsens]', 'http://dict.youdao.com/dictvoice?audio=nonsense', '{n.}++荒谬的想法（看法），胡说；愚蠢的行为，胡闹；无意义的话（字句）**{adj.}++无意义的，荒谬的**{int.}++胡说，废话**{n.}++a message that seems to convey no meaning																					   	同义词：								                                  				    bunk				    				    				      				    				      				    				                                      				    nonsensicality				    				    				      				    				      				    				                                      				    meaninglessness				    				    				      				    				      				    				                                      				    hokum**{n.}++胡说；废话**{adj.}++荒谬的**', '');
insert into TOEFLWordBook values ('607', 'normal', '[ˈnɔːrm(ə)l]', 'http://dict.youdao.com/dictvoice?audio=normal', '{adj.}++正常的，标准的；（身心）健康的，（人）普通的；（线或线性特征）正交的，垂直的；（盐溶液）与血液的盐浓度相同的；正（断层）的；平常的，通常的**{n.}++常态，通常标准；正常人，循规蹈矩者；法线，正交**{n.}++something regarded as a normative example																					   	同义词：								                                  				    convention				    				    				      				    				      				    				                                      				    pattern				    				    				      				    				      				    				                                      				    rule				    				    				      				    				      				    				                                      				    formula**{adj.}++conforming with or constituting a norm or standard or level or type or social norm; not abnormal																										        													        													        													        													        													        				&quot;serve wine at normal room temperature&quot;; &quot;normal diplomatic relations&quot;; &quot;normal working hours&quot;; &quot;normal word order&quot;; &quot;normal curiosity&quot;; &quot;the normal course of events&quot;**{being approximately average or within certain limits in e.}++g. intelligence and development																										        													        													        				&quot;a perfectly normal child&quot;; &quot;of normal intelligence&quot;; &quot;the most normal person Ive ever met&quot;**{adj.}++[数]正常的；正规的，标准的**{n.}++正常；标准；常态**', '');
insert into TOEFLWordBook values ('608', 'notable', '[ˈnoʊtəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=notable', '{adj.}++显要的，值得注意的；非常成功的，令人尊敬的**{n.}++显要人物，名流**{n.}++a celebrity who is an inspiration to others																					   	同义词：								                                  				    luminary				    				    				      				    				      				    				                                      				    leading light				    				    				      				    				      				    				                                      				    guiding light				    				    				      				    				      				    				                                      				    notability**{adj.}++worthy of notice																					   	同义词：								                                  				    noteworthy**{adj.}++值得注意的，显著的；著名的**{n.}++名人，显要人物**', '');
insert into TOEFLWordBook values ('609', 'notion', '[ˈnoʊʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=notion', '{n.}++概念，想法；缝纫用品；一时的念头，突发的奇想**{n.}++a vague idea in which some confidence is placed																					   	同义词：								                                  				    impression				    				    				      				    				      				    				                                      				    feeling				    				    				      				    				      				    				                                      				    belief				    				    				      				    				      				    				                                      				    opinion**{n.}++概念；见解；打算**', '');
insert into TOEFLWordBook values ('610', 'nourishing', '[ˈnɜːrɪʃɪŋ]', 'http://dict.youdao.com/dictvoice?audio=nourishing', '{adj.}++有营养的；滋养多的**{v.}++滋养；养育（nourish 的 ing 形式）**{adj.}++of or providing nourishment																										        				&quot;good nourishing stew&quot;															   	同义词：								                                  				    alimentary				    				    				      				    				      				    				                                      				    alimental				    				    				      				    				      				    				                                      				    nutrient				    				    				      				    				      				    				                                      				    nutritious				    				    				      				    				      				    				                                      				    nutritive**{adj.}++有营养的；滋养多的**{v.}++滋养；养育（nourish的ing形式）**', '');
insert into TOEFLWordBook values ('611', 'nuclear', '[ˈnuːkliər]', 'http://dict.youdao.com/dictvoice?audio=nuclear', '{adj.}++核子的，原子核的；核武器的；原子能的，核能的；核心的，中心的；细胞核的，构成细胞核的**{adj.}++(weapons) deriving destructive energy from the release of atomic energy																										        													        				&quot;nuclear war&quot;; &quot;nuclear weapons&quot;															   	同义词：								                                  				    atomic**{adj.}++原子能的；[细胞]细胞核的；中心的；原子核的**', '');
insert into TOEFLWordBook values ('612', 'numerical', '[nuːˈmerɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=numerical', '{adj.}++数字的，用数字表示的**{adj.}++measured or expressed in numbers																										        													        				&quot;numerical value&quot;; &quot;the numerical superiority of the enemy&quot;															   	同义词：								                                  				    numeric**{adj.}++[数]数值的；数字的；用数字表示的（等于numeric）**', '');
insert into TOEFLWordBook values ('613', 'nurse', '[nɜːrs]', 'http://dict.youdao.com/dictvoice?audio=nurse', '{n.}++护士；保姆，奶妈；保育虫；（保护其他作物的）防护作物；沙锥齿鲨**{v.}++看护，照料；细心打理；调养，调治；喂奶，哺乳；吃奶；怀有；慢慢地喝；爱惜地搂抱；（在某种特定条件下）被抚养长大；（台球，斯诺克）聚球，使球互相靠拢**{n.}++one skilled in caring for young children or the sick (usually under the supervision of a physician)**{vt.}++看护，护理；照顾；培养；给…喂奶**{vi.}++照料，护理；喂奶；当保姆**{n.}++[医]护士；奶妈，保姆**', '');
insert into TOEFLWordBook values ('614', 'nutrition', '[nuˈtrɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=nutrition', '{n.}++营养，滋养；营养学；食物，营养物**{n.}++(physiology) the organic process of nourishing or being nourished; the processes by which an organism assimilates food and uses it for growth and maintenance**{n.}++[生物]营养，营养学；营养品**', '');
insert into TOEFLWordBook values ('615', 'objective', '[əbˈdʒektɪv]', 'http://dict.youdao.com/dictvoice?audio=objective', '{n.}++目的，目标；出击目标（尤指在军事攻击中)；（望远镜或显微镜中的）物镜；出击目标（尤指在军事攻击中）；宾格**{adj.}++客观的，不带个人情感的；客观存在的；宾格的；目标的**{n.}++the goal intended to be attained (and which is believed to be attainable)																					   	同义词：								                                  				    aim				    				    				      				    				      				    				                                      				    object				    				    				      				    				      				    				                                      				    target**{adj.}++[医]客观的；目标的；[语]宾格的**{n.}++目的；目标；[光]物镜；[语]宾格**', '');
insert into TOEFLWordBook values ('616', 'obscure', '[əbˈskjʊr]', 'http://dict.youdao.com/dictvoice?audio=obscure', '{adj.}++难以说清楚的，模糊的；鲜为人知的，默默无闻的；未被查实的，不确定的；费解的，晦涩的**{v.}++遮掩，遮蔽；使费解**{n.}++某种模糊的或不清楚的东西**{v.}++make less visible or unclear																										        				&quot;The stars are obscured by the clouds&quot;															   	同义词：								                                  				    befog				    				    				      				    				      				    				                                      				    becloud				    				    				      				    				      				    				                                      				    obnubilate				    				    				      				    				      				    				                                      				    haze over				    				    				      				    				      				    				                                      				    fog				    				    				      				    				      				    				                                      				    cloud				    				    				      				    				      				    				                                      				    mist**{adj.}++模糊的；晦涩的；[光]昏暗的**{vt.}++遮掩；使变暗；使难理解**', '');
insert into TOEFLWordBook values ('617', 'obstacle', '[ˈɑːbstək(ə)l]', 'http://dict.youdao.com/dictvoice?audio=obstacle', '{n.}++障碍，阻碍；障碍物**{n.}++something immaterial that stands in the way and must be circumvented or surmounted																										        													        				&quot;lack of imagination is an obstacle to ones advancement&quot;; &quot;the poverty of a district is an obstacle to good education&quot;															   	同义词：								                                  				    obstruction**{n.}++障碍，干扰；妨害物**', '');
insert into TOEFLWordBook values ('618', 'occupy', '[ˈɑːkjupaɪ]', 'http://dict.youdao.com/dictvoice?audio=occupy', '{v.}++使用（房屋、建筑），居住；占据（空间，时间）；使忙于（做某事）；使一直在想；（军事）占领，占据；（尤指为表示抗议而）非法强占（建筑物）；任职，位居**{v.}++be present in; be inside of																					   	同义词：								                                  				    inhabit**{vt.}++占据，占领；居住；使忙碌**', '');
insert into TOEFLWordBook values ('619', 'occurrence', '[əˈkɜːrəns]', 'http://dict.youdao.com/dictvoice?audio=occurrence', '{n.}++发生的事，事件；发生，出现（尤指意外且令人不快的事）**{n.}++an event that happens																					   	同义词：								                                  				    happening				    				    				      				    				      				    				                                      				    occurrent				    				    				      				    				      				    				                                      				    natural event**{n.}++发生；出现；事件；发现**', '');
insert into TOEFLWordBook values ('620', 'odd', '[ɑːd]', 'http://dict.youdao.com/dictvoice?audio=odd', '{adj.}++奇怪的，反常的；偶然出现的，偶尔发生的；奇形怪状的，各种各样的；不成对的，不同类的；奇数的；可得到的，可用的；少量的，不重要的；（尤指在双方至少各进一球的情况下）一球险胜的**{adv.}++（用于数字后）大约，左右**{adj.}++not divisible by two**{of the remaining member of a pair, of socks e.}++g.																					   	同义词：								                                  				    unmatched				    				    				      				    				      				    				                                      				    unmated				    				    				      				    				      				    				                                      				    unpaired**{adj.}++[数]奇数的；古怪的；剩余的；临时的；零散的**{n.}++[数]奇数；怪人；奇特的事物**', '');
insert into TOEFLWordBook values ('621', 'offensive', '[əˈfensɪv]', 'http://dict.youdao.com/dictvoice?audio=offensive', '{adj.}++无礼的，冒犯的；令人不快（讨厌）的；攻击的，进攻性的； （体育比赛中）进攻的，攻势的**{n.}++（军事）进攻，攻势；  （引人注意的）系列行动，攻势**{n.}++the action of attacking an enemy																					   	同义词：								                                  				    offense				    				    				      				    				      				    				                                      				    offence**{adj.}++violating or tending to violate or offend against																										        				&quot;considered such depravity offensive against all laws of humanity&quot;															   	同义词：								                                  				    violative**{adj.}++攻击的；冒犯的；无礼的；讨厌的**{n.}++攻势；攻击**', '');
insert into TOEFLWordBook values ('622', 'official', '[əˈfɪʃ(ə)l]', 'http://dict.youdao.com/dictvoice?audio=official', '{adj.}++正式的，官方的，官方授权的；公务的，公职的；据官方的，公开宣称的（但可能并非事实）；官方场合的，（常指）正式公开的；被正式选用的**{n.}++官员，高级职员；（体育比赛中的）执法人，裁判员；（大主教法庭，主教法庭或会吏总法庭的）主持法官**{n.}++a worker who holds or is invested with an office																					   	同义词：								                                  				    functionary**{adj.}++官方的；正式的；公务的**{n.}++官员；公务员**', '');
