insert into TOEFLWordBook values ('625', 'operate', '[ˈɑːpəreɪt]', 'http://dict.youdao.com/dictvoice?audio=operate', '{v.}++操纵，操作（机器或设备）；（机器等）运转，运行 ；管理，经营（企业、部门等）；（组织或公司）运营；（使）运行，（使）工作；起作用，发生影响；（以某种方式）行事；开刀，动手术；（士兵或警察在某地区）行动，执行公务**{v.}++direct or control; projects, businesses, etc.																					   	同义词：								                                  				    run**{vi.}++运转；动手术；起作用**{vt.}++操作；经营；引起；对…开刀**', '');
insert into TOEFLWordBook values ('626', 'opinion', '[əˈpɪnjən]', 'http://dict.youdao.com/dictvoice?audio=opinion', '{n.}++意见，看法；（群体的）观点，信仰；专家意见，专业意见；（对某人的）评价，印象；（法官或法院说明判决理由的）判决意见书**{n.}++a personal belief or judgment that is not founded on proof or certainty																										        				&quot;my opinion differs from yours&quot;															   	同义词：								                                  				    sentiment				    				    				      				    				      				    				                                      				    persuasion				    				    				      				    				      				    				                                      				    view				    				    				      				    				      				    				                                      				    thought**{n.}++意见；主张**', '');
