insert into TOEFLWordBook values ('630', 'oral', '[ˈɔːrəl]', 'http://dict.youdao.com/dictvoice?audio=oral', '{adj.}++口头的，口述的；口的，口腔的；（药物）口服的；（语音）口腔发声的；（社会）没有文字的；（心理分析）口欲的，口唇的**{n.}++（尤指外语）口试；（大学里的）口试**{n.}++an examination conducted by word of mouth																					   	同义词：								                                  				    oral exam				    				    				      				    				      				    				                                      				    oral examination				    				    				      				    				      				    				                                      				    viva voce				    				    				      				    				      				    				                                      				    viva**{adj.}++using speech rather than writing																										        													        				&quot;an oral tradition&quot;; &quot;an oral agreement&quot;															   	同义词：								                                  				    unwritten**{adj.}++[药][解剖]口头的，口述的**{n.}++口试**', '');
insert into TOEFLWordBook values ('631', 'orbit', '[ˈɔːrbɪt]', 'http://dict.youdao.com/dictvoice?audio=orbit', '{n.}++（环绕地球、太阳等运行的）轨道；势力范围，影响范围；眼眶，眼窝**{v.}++沿轨道运行，环绕……运行；使（卫星）进入轨道**{n.}++the (usually elliptical) path described by one celestial body in its revolution about another																										        				&quot;he plotted the orbit of the moon&quot;															   	同义词：								                                  				    celestial orbit**{n.}++[天][航]轨道；[昆]眼眶；势力范围；生活常规**{vi.}++盘旋；绕轨道运行**', '');
