insert into TOEFLWordBook values ('633', 'orderly', '[ˈɔːrdərli]', 'http://dict.youdao.com/dictvoice?audio=orderly', '{adj.}++有条理的，整齐的；守秩序的；传达命令的，值班的**{n.}++（医院）护理员，勤杂工；传令兵，勤务兵**{adv.}++有秩序地**{n.}++a soldier who serves as an attendant to a superior officer																										        				&quot;the orderly laid out the generals uniform&quot;**{adj.}++有秩序的；整齐的；值班的**{n.}++勤务兵；传令兵；护理员**{adv.}++顺序地；依次地**', '');
