insert into TOEFLWordBook values ('636', 'ornament', '[ˈɔːrnəmənt]', 'http://dict.youdao.com/dictvoice?audio=ornament', '{n.}++装饰品，点缀品；装饰，摆设；首饰，饰物； 为……增添光彩的人（或事物）（ornament to sth.）；（乐）装饰音（ornaments） ；（基督教）（圣坛、圣餐杯和圣器等）礼拜用品，典礼用品**{v.}++装饰，点缀**{n.}++something used to beautify																					   	同义词：								                                  				    decoration				    				    				      				    				      				    				                                      				    ornamentation**{v.}++make more attractive by adding ornament, colour, etc.																					   	同义词：								                                  				    decorate				    				    				      				    				      				    				                                      				    adorn				    				    				      				    				      				    				                                      				    grace				    				    				      				    				      				    				                                      				    embellish				    				    				      				    				      				    				                                      				    beautify**{n.}++[建][服装]装饰；装饰物；教堂用品**{vt.}++[建][服装]装饰，修饰**', '');
