insert into TOEFLWordBook values ('638', 'outgoing', '[ˈaʊtɡoʊɪŋ]', 'http://dict.youdao.com/dictvoice?audio=outgoing', '{adj.}++爱交际的，外向的；即将离职的；往外去的，离去的**{n.}++外出，离开物；日常支出，开销（outgoings）**{v.}++超过，优于（outgo 的现在分词形式）**{adj.}++leaving a place or a position																										        													        				&quot;an outgoing steamship&quot;; &quot;the outgoing president&quot;**{adj.}++外出的；即将离职的；乐于助人的**{n.}++外出；流出；开支**{v.}++超过；优于（outgo的ing形式）**', '');
