insert into TOEFLWordBook values ('640', 'outward', '[ˈaʊtwərd]', 'http://dict.youdao.com/dictvoice?audio=outward', '{adj.}++外表的，表面的；（特定方面）可见的，外部的；朝外的，向外的；（旅程）往外地的，外出的**{adv.}++向外，朝外；自身之外；明显地，公然地**{n.}++外表，外面；外部世界，物质世界**{adj.}++relating to physical reality rather than with thoughts or the mind																										        				&quot;a concern with outward beauty rather than with inward reflections&quot;**{adj.}++向外的；外面的；公开的；外服的；肉体的**{adv.}++向外（等于outwards）；在外；显而易见地**{n.}++外表；外面；物质世界**', '');
