insert into TOEFLWordBook values ('642', 'overall', '[ˌoʊvərˈɔːl]', 'http://dict.youdao.com/dictvoice?audio=overall', '{adj.}++总的，全面的；所有的，包括一切的**{adv.}++全部，总共； 总的说来，大体上**{n.}++（工作时穿的）罩衣；（上下连身的）工作服，防护服（overalls）；背带工装裤（overalls）；骑马裤，紧身制服裤（overalls）**{n.}++(usually plural) work clothing consisting of denim trousers (usually with a bib and shoulder straps)**{adj.}++全部的；全体的；一切在内的**{adv.}++全部地；总的说来**{n.}++工装裤；罩衫**', '');
insert into TOEFLWordBook values ('643', 'overcome', '[ˌoʊvərˈkʌm]', 'http://dict.youdao.com/dictvoice?audio=overcome', '{v.}++克服，解决；征服，战胜；使受不了，使无法行动（或思考）**{v.}++win a victory over																										        				&quot;You must overcome all difficulties&quot;															   	同义词：								                                  				    get the better of				    				    				      				    				      				    				                                      				    defeat**{vt.}++克服；胜过**{vi.}++克服；得胜**', '');
insert into TOEFLWordBook values ('644', 'overturn', '[ˌoʊvərˈtɜːrn]', 'http://dict.youdao.com/dictvoice?audio=overturn', '{v.}++（使）翻倒，（使）倾覆；推翻，撤销（判决等）；颠覆，破坏（政府或体系）；在英国大选中因获得多数席位而获胜**{n.}++颠覆，革命；（尤指水温分层的湖水每年两次的）湖水对流**{n.}++the act of upsetting something																					   	同义词：								                                  				    upset				    				    				      				    				      				    				                                      				    turnover**{vt.}++推翻；倾覆；破坏**{vi.}++推翻；倾覆**{n.}++倾覆；周转；破灭**', '');
insert into TOEFLWordBook values ('645', 'overwhelm', '[ˌoʊvərˈwelm]', 'http://dict.youdao.com/dictvoice?audio=overwhelm', '{v.}++（感情上）使受不了，使不知所措；使大吃一惊；压垮，使应接不暇；打败，击垮； （水）漫过，淹没；压倒，制服**{v.}++overcome, as with emotions or perceptual stimuli																					   	同义词：								                                  				    overpower				    				    				      				    				      				    				                                      				    sweep over				    				    				      				    				      				    				                                      				    whelm				    				    				      				    				      				    				                                      				    overcome				    				    				      				    				      				    				                                      				    overtake**{vt.}++压倒；淹没；受打击**', '');
insert into TOEFLWordBook values ('646', 'pack', '[pæk]', 'http://dict.youdao.com/dictvoice?audio=pack', '{v.}++（把……）打包，收拾（行李）；包装，装箱；（用柔软材料）把……裹（包）起来；在（容器中的食物）上覆盖物质（以防止腐烂）；可折叠运输（或存放）；挤进，塞满；聚集；把……盖上，填封；把……大量放进，装满；（把……）压实，（使）堆积；在（委员会或会议）中安插（支持者、利己的人或事物）；具有，能产生（强大之物或能量）；携带（武器）；（橄榄球）形成对阵争球**{n.}++包，包裹，捆；（尤指士兵或野外徒步者的）背包；（一般为纸质的）小盒，小包；一副纸牌；（一起生活猎食的）兽群（尤指狼群）；（尤指不受人喜欢的）一帮，一伙；（比赛或竞赛中的）集群，集团；（放在伤口上止血或消肿的）裹布，敷料；（美容用的）面膜，贴膜；一队（男或女幼童军）；（军事交通工具，尤指飞机或潜水艇的）一组，一队；（英橄）全体前锋；（极地海洋中的）流冰群，浮冰群**{n.}++a large indefinite number																					   	同义词：								                                  				    battalion				    				    				      				    				      				    				                                      				    large number				    				    				      				    				      				    				                                      				    multitude				    				    				      				    				      				    				                                      				    plurality**{n.}++[包装]包装；一群；背包；[临床]包裹；一副**{vt.}++[包装]包装；压紧；捆扎；挑选；塞满**{vi.}++挤；包装货物；[包装]被包装；群集**', '');
insert into TOEFLWordBook values ('647', 'pale', '[peɪl]', 'http://dict.youdao.com/dictvoice?audio=pale', '{adj.}++（脸色）苍白的；（颜色）浅的，淡的；（光线）暗淡的，微弱的；较差的，逊色的**{v.}++（脸色）变苍白；（颜色）变淡，变浅；使褪色；显得逊色，相形见绌；用板条围**{n.}++（做桩篱用的）板条，尖桩；（喻）界限，范围；（纹章）（盾形中部的）垂直宽条；（俄国）犹太人居住区**{n.}++a wooden strip forming part of a fence																					   	同义词：								                                  				    picket**{v.}++turn pale, as if in fear																					   	同义词：								                                  				    blanch				    				    				      				    				      				    				                                      				    blench**{adj.}++very light colored; highly diluted with white																										        													        				&quot;pale seagreen&quot;; &quot;pale blue eyes&quot;**{adj.}++苍白的；无力的；暗淡的**{n.}++前哨；栅栏；范围**{vt.}++使失色；使变苍白；用栅栏围**{vi.}++失色；变苍白；变得暗淡**', '');
insert into TOEFLWordBook values ('648', 'pamphlet', '[ˈpæmflət]', 'http://dict.youdao.com/dictvoice?audio=pamphlet', '{n.}++小册子，活页**{v.}++向……散发小册子**{n.}++a small book usually having a paper cover																					   	同义词：								                                  				    booklet				    				    				      				    				      				    				                                      				    brochure				    				    				      				    				      				    				                                      				    folder				    				    				      				    				      				    				                                      				    leaflet**{n.}++小册子**', '');
insert into TOEFLWordBook values ('649', 'paradox', '[ˈpærədɑːks]', 'http://dict.youdao.com/dictvoice?audio=paradox', '{n.}++矛盾的人（或事物、情况）；似非而是的隽语，悖论；悖论修辞**{n.}++(logic) a statement that contradicts itself																										        				&quot;`I always lie is a paradox because if it is true it must be false&quot;**', '');
