insert into TOEFLWordBook values ('653', 'particle', '[ˈpɑːrtɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=particle', '{n.}++微粒；极少量；粒子（原子的极微小成分，如电子、质子或中子）；（数）质点；（语法中的）小品词**{n.}++(nontechnical usage) a tiny piece of anything																					   	同义词：								                                  				    atom				    				    				      				    				      				    				                                      				    molecule				    				    				      				    				      				    				                                      				    corpuscle				    				    				      				    				      				    				                                      				    mote				    				    				      				    				      				    				                                      				    speck**{n.}++颗粒；[物]质点；极小量；小品词**', '');
insert into TOEFLWordBook values ('654', 'passage', '[ˈpæsɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=passage', '{n.}++过道，走廊；（人体的）管道；段落，章节；通道，通路；通行权，通行许可；经过，穿过；（时间的）流逝；（法案的）通过；航程，船票；过渡，转变；（候鸟的）迁徙；（微生物的）传代；巴沙基（盛装舞步和古典骑术的高抬腿舞步）**{v.}++使（微生物）继代移种**{n.}++the act of passing from one state or place to the next																					   	同义词：								                                  				    transition**{n.}++一段（文章）；走廊；通路**', '');
insert into TOEFLWordBook values ('655', 'passion', '[ˈpæʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=passion', '{n.}++爱恋，情欲；激情，热情；酷爱，热衷的爱好（或活动等）；盛怒，激愤；耶稣的受难（the Passion）**{n.}++strong feeling or emotion																					   	同义词：								                                  				    passionateness**{n.}++激情；热情；酷爱；盛怒**', '');
insert into TOEFLWordBook values ('656', 'patch', '[pætʃ]', 'http://dict.youdao.com/dictvoice?audio=patch', '{n.}++补丁，补片；（保护受伤眼睛的）眼罩；（衣服上的）徽章，标识；药膏，胶布；（与周围部分不同的）斑，小块；小片，碎片；（尤指园艺用的）一小块地；熟悉的地方，家乡； 属地，管辖地；一段时间；（尤指17、18世纪妇女装饰用的）饰颜片，美人斑；（软件的）补丁程序；（电气或电话的）临时连接（线）；（电子乐器，尤指合成乐器中的）预设配置（或声音）数据文件，配音**{vt.}++修补，缝补；使出现斑块；临时连接，临时接入（通信系统）；（计算机）（用补丁对程序进行）修正，打补丁；解决；拼凑，匆匆制成**{n.}++a small contrasting part of something																										        													        				&quot;a patch of clouds&quot;; &quot;patches of thin ice&quot;															   	同义词：								                                  				    spot				    				    				      				    				      				    				                                      				    speckle				    				    				      				    				      				    				                                      				    dapple				    				    				      				    				      				    				                                      				    fleck				    				    				      				    				      				    				                                      				    maculation**{n.}++眼罩；斑点；碎片；小块土地**{vt.}++修补；解决；掩饰**', '');
insert into TOEFLWordBook values ('657', 'patent', '[ˈpæt(ə)nt]', 'http://dict.youdao.com/dictvoice?audio=patent', '{n.}++专利（权），专利证书；专利发明**{adj.}++受专利保护的，专利的；专利生产的，专利经销的；显而易见的，赤裸裸的；（寄生虫感染）明显的，显著的；（脉管、导管或孔）开放的，不闭合的**{v.}++获得……的专利权；授予专利**{n.}++a document granting an inventor sole rights to an invention																					   	同义词：								                                  				    patent of invention**{adj.}++[专利]专利的；新奇的；显然的**{n.}++[专利]专利权；执照；专利品**', '');
insert into TOEFLWordBook values ('658', 'patience', '[ˈpeɪʃ(ə)ns]', 'http://dict.youdao.com/dictvoice?audio=patience', '{n.}++耐心；耐性；忍耐力；考验某人的耐心；单人纸牌游戏**{n.}++good-natured tolerance of delay or incompetence																					   	同义词：								                                  				    forbearance				    				    				      				    				      				    				                                      				    longanimity**{n.}++耐性，耐心；忍耐，容忍**', '');
