insert into TOEFLWordBook values ('661', 'pearl', '[pɜːrl]', 'http://dict.youdao.com/dictvoice?audio=pearl', '{n.}++珍珠；珍珠母；珠状物；极其优秀的人，珍贵的东西；人造珍珠；珠灰色；珍珠项链，珍珠首饰（pearls）**{v.}++成珠状滴；使呈珠灰色，使呈蓝灰色；（潜水）采珍珠；用珍珠装饰**{adj.}++珍珠般的；镶珍珠的**{n.}++a smooth lustrous round structure inside the shell of a clam or oyster; much valued as a jewel**{n.}++[水产]珍珠；珍珠色；杰出者；珍品**{adj.}++镶珍珠的；珍珠状的**{vt.}++使成珠状；用珍珠装饰；使呈珍珠色**', '');
insert into TOEFLWordBook values ('662', 'percentage', '[pərˈsentɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=percentage', '{n.}++百分比，百分率；部分，比例；利润分成，提成；利益，好处**{n.}++a proportion multiplied by 100																					   	同义词：								                                  				    percent				    				    				      				    				      				    				                                      				    per centum				    				    				      				    				      				    				                                      				    pct**{n.}++[数]百分比；百分率，百分数**', '');
insert into TOEFLWordBook values ('663', 'performance', '[pərˈfɔːrməns]', 'http://dict.youdao.com/dictvoice?audio=performance', '{n.}++表演，演出；工作情况，表现；（投资的）业绩；执行，履行；麻烦，苦差事（a performance）；艺术上的表现，演技；（汽车的）性能；（语言学）语言表现，言语行为**{adj.}++性能卓越的，高性能的**{n.}++a dramatic or musical entertainment																										        													        													        				&quot;they listened to ten different performances&quot;; &quot;the play ran for 100 performances&quot;; &quot;the frequent performances of the symphony testify to its popularity&quot;															   	同义词：								                                  				    public presentation**{n.}++性能；绩效；表演；执行**', '');
insert into TOEFLWordBook values ('664', 'periodic', '[ˌpɪriˈɑːdɪk]', 'http://dict.youdao.com/dictvoice?audio=periodic', '{adj.}++阶段性的，定期的；（化学）元素周期表的；（修辞）完整句的**{adj.}++happening or recurring at regular intervals																					   	同义词：								                                  				    periodical**{adj.}++周期的；定期的**', '');
insert into TOEFLWordBook values ('665', 'permanent', '[ˈpɜːrmənənt]', 'http://dict.youdao.com/dictvoice?audio=permanent', '{adj.}++永久的，永恒的；（尤指问题或困难）不断出现的，一直存在的；（员工）终生的，长期的；（家庭住址）固定的**{n.}++烫发**{n.}++a series of waves in the hair made by applying heat and chemicals																					   	同义词：								                                  				    permanent wave				    				    				      				    				      				    				                                      				    perm**{adj.}++continuing or enduring without marked change in status or condition or place																										        													        													        				&quot;permanent secretary to the president&quot;; &quot;permanent address&quot;; &quot;literature of permanent value&quot;															   	同义词：								                                  				    lasting**{adj.}++永久的，永恒的；不变的**', '');
insert into TOEFLWordBook values ('666', 'perpetuate', '[pərˈpetʃueɪt]', 'http://dict.youdao.com/dictvoice?audio=perpetuate', '{v.}++使持续，使长久（尤指不好的事物）**{v.}++cause to continue or prevail																										        				&quot;perpetuate a myth&quot;**{vt.}++使不朽；保持**', '');
insert into TOEFLWordBook values ('667', 'petroleum', '[pəˈtroʊliəm]', 'http://dict.youdao.com/dictvoice?audio=petroleum', '{n.}++石油，原油**{n.}++a dark oil consisting mainly of hydrocarbons																					   	同义词：								                                  				    crude oil				    				    				      				    				      				    				                                      				    crude				    				    				      				    				      				    				                                      				    rock oil				    				    				      				    				      				    				                                      				    fossil oil**{n.}++[油气]石油**', '');
insert into TOEFLWordBook values ('668', 'phase', '[feɪz]', 'http://dict.youdao.com/dictvoice?audio=phase', '{n.}++（发展或变化的）阶段，时期；做出某种行为的短时期；（动物生活周期或年周期的）阶段，期；（月亮的）位相，盈亏；同步，协调；（化）相；（动）（由遗传或季节引起的）动物颜色变化（期）；（物理）相位，相角；（线圈的）匝，（多相电机或电路的）连接；（语言学）（系统语法用语）相（指链接动词与后续动词的关系）；相结构（含有链接动词和后续动词的结构）**{v.}++分阶段进行；（物理）使相位同步，使定相**{n.}++(physical chemistry) a distinct state of matter in a system; matter that is identical in chemical composition and physical state and separated from other material by the phase boundary																										        				&quot;the reaction occurs in the liquid phase of the system&quot;															   	同义词：								                                  				    form**{n.}++[物]相；阶段；[天]位相**', '');
insert into TOEFLWordBook values ('669', 'phenomenon', '[fəˈnɑːmɪnən]', 'http://dict.youdao.com/dictvoice?audio=phenomenon', '{n.}++现象；杰出的人，非凡的人（或事物）；（哲学）现象**{n.}++any state or process known through the senses rather than by intuition or reasoning**{n.}++[物]现象；奇迹；杰出的人才**', '');
insert into TOEFLWordBook values ('670', 'photograph', '[ˈfoʊtəɡræf]', 'http://dict.youdao.com/dictvoice?audio=photograph', '{n.}++照片，相片**{v.}++拍照，照相；在照片上显出某种样子**{n.}++a picture of a person or scene in the form of a print or transparent slide; recorded by a camera on light-sensitive material																					   	同义词：								                                  				    photo				    				    				      				    				      				    				                                      				    exposure				    				    				      				    				      				    				                                      				    pic**{v.}++record on photographic film																										        				&quot;I photographed the scene of the accident&quot;															   	同义词：								                                  				    snap				    				    				      				    				      				    				                                      				    shoot**{vi.}++拍照；在照片上显得**{n.}++照片，[摄]相片**', '');
insert into TOEFLWordBook values ('671', 'phrase', '[freɪz]', 'http://dict.youdao.com/dictvoice?audio=phrase', '{n.}++短语，词组；惯用语，习语；乐句；（芭蕾）舞句**{v.}++用……方式表达，以……措辞表达；把（乐曲）分成短句**{n.}++an expression consisting of one or more words forming a grammatical constituent of a sentence**{n.}++成语；习语；措词**', '');
insert into TOEFLWordBook values ('672', 'pilot', '[ˈpaɪlət]', 'http://dict.youdao.com/dictvoice?audio=pilot', '{n.}++飞行员；领航员；（船只的）领航员；（电视）试播节目；常燃小火；航海手册；职业骑师；向导；（火车头前端的）排障器**{adj.}++试点的；（电信）控制引导信号**{v.}++驾驶（飞行器）；领航；试验，试行；使（新法律）顺利通过；带领，指引**{n.}++someone who is licensed to operate an aircraft in flight																					   	同义词：								                                  				    airplane pilot**{n.}++[航]飞行员；[水运]领航员**{v.}++[航]驾驶；[水运]领航；试用**', '');
insert into TOEFLWordBook values ('673', 'plantation', '[plænˈteɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=plantation', '{n.}++（尤指热带的）种植地，农园；人工林场，苗木场；殖民地，新开垦地；普兰泰申市（美国佛罗里达州城市名）**{n.}++an estate where cash crops are grown on a large scale (especially in tropical areas)**{n.}++栽植；殖民；大农场**', '');
insert into TOEFLWordBook values ('674', 'plastic', '[ˈplæstɪk]', 'http://dict.youdao.com/dictvoice?audio=plastic', '{n.}++塑料；信用卡；塑胶制造业（plastics）；塑料学（plastics）**{adj.}++塑料制的；人造的，不自然的；可塑的；（艺术用语）造型的，塑造的；（科技用语）范性的，塑性的；适应环境多样性的**{n.}++generic name for certain synthetic or semisynthetic materials that can be molded or extruded into objects or films or filaments or used for making e.g. coatings and adhesives**{adj.}++capable of being molded or modeled (especially of earth or clay or other soft material)																										        				&quot;plastic substances such as wax or clay&quot;															   	同义词：								                                  				    fictile				    				    				      				    				      				    				                                      				    moldable**{adj.}++[塑料][力]塑料的；（外科）造型的；可塑的**{n.}++[塑料]塑料制品；整形；[力]可塑体**', '');
