insert into TOEFLWordBook values ('687', 'potent', '[ˈpoʊt(ə)nt]', 'http://dict.youdao.com/dictvoice?audio=potent', '{adj.}++强大的，有力的；（毒品、药品或化学品）药效强的，强效的；（男子）有性功能的；由T字形构成的，（尤指十字架）有T形端的；（纹章装饰）有交错T形拼花毛皮的；有说服力的**{n.}++有交错T形拼花的毛皮**{adj.}++having great influence																					   	同义词：								                                  				    powerful**{adj.}++有效的；强有力的，有权势的；有说服力的**', '');
