insert into TOEFLWordBook values ('689', 'powder', '[ˈpaʊdər]', 'http://dict.youdao.com/dictvoice?audio=powder', '{n.}++粉，粉末；扑面粉，美容粉；细雪，粉状雪；火药，炸药**{v.}++往（脸或身体）上搽粉；撒粉（状物）于（表面），以粉（状物）覆盖；使（某物）成粉状；变成粉末**{n.}++a solid substance in the form of tiny loose particles; a solid that has been pulverized																					   	同义词：								                                  				    pulverization				    				    				      				    				      				    				                                      				    pulverisation**{n.}++[材]粉；粉末；[化工][军]火药；尘土**{vt.}++使成粉末；撒粉；搽粉于**', '');
insert into TOEFLWordBook values ('690', 'practical', '[ˈpræktɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=practical', '{adj.}++真实的，实际的；（计划、方法等）切实有效的，切实可行的；（人）明智的，务实的；合适的，适用的；心灵手巧的，善于制作（或修补）的；几乎完全的，实际上的**{n.}++（科学、烹饪等的）实践课，实用知识考试**{adj.}++concerned with actual use or practice																										        													        													        													        				&quot;he is a very practical person&quot;; &quot;the idea had no practical application&quot;; &quot;a practical knowledge of Japanese&quot;; &quot;woodworking is a practical art&quot;**{adj.}++实际的；实用性的**', '');
