insert into TOEFLWordBook values ('692', 'precede', '[prɪˈsiːd]', 'http://dict.youdao.com/dictvoice?audio=precede', '{v.}++处在……之前，先于；在……之前做（或说）；比……更重要，比……（级别）更高**{v.}++be earlier in time; go back further																										        				&quot;Stone tools precede bronze tools&quot;															   	同义词：								                                  				    predate				    				    				      				    				      				    				                                      				    forego				    				    				      				    				      				    				                                      				    forgo				    				    				      				    				      				    				                                      				    antecede				    				    				      				    				      				    				                                      				    antedate**{vt.}++领先，在…之前；优于，高于**{vi.}++领先，在前面**', '');
insert into TOEFLWordBook values ('693', 'precious', '[ˈpreʃəs]', 'http://dict.youdao.com/dictvoice?audio=precious', '{adj.}++宝贵的，珍贵的；珍视的，重要的；珍稀的，珍奇的；（表示气愤）宝贝似的；（言行）矫揉造作的，过分讲究的；可爱的，讨人喜欢的**{n.}++（用作称呼）宝贝，亲爱的**{adv.}++非常，极其**{adj.}++characterized by feeling or showing fond affection for																										        				&quot;children are precious&quot;															   	同义词：								                                  				    cherished				    				    				      				    				      				    				                                      				    treasured				    				    				      				    				      				    				                                      				    wanted**{adj.}++宝贵的；珍贵的；矫揉造作的**', '');
insert into TOEFLWordBook values ('694', 'precise', '[prɪˈsaɪs]', 'http://dict.youdao.com/dictvoice?audio=precise', '{adj.}++精确的，准确的；恰好的，确切的；（人）严格的，一丝不苟的**{adj.}++sharply exact or accurate or delimited																										        													        													        				&quot;a precise mind&quot;; &quot;specified a precise amount&quot;; &quot;arrived at the precise moment&quot;**{adj.}++精确的；明确的；严格的**', '');
insert into TOEFLWordBook values ('695', 'precursor', '[priˈkɜːrsər]', 'http://dict.youdao.com/dictvoice?audio=precursor', '{n.}++（事物）先驱，先兆；（尤指经新陈代谢形成另一种物质的）前体，前质**{n.}++a substance from which another substance is formed (especially by a metabolic reaction)**{n.}++先驱，前导**', '');
