insert into TOEFLWordBook values ('700', 'presence', '[ˈprez(ə)ns]', 'http://dict.youdao.com/dictvoice?audio=presence', '{n.}++出席，存在；（某人的）所在地方；感觉中的存在物（如鬼魂）；驻扎部队，驻扎的警力；风度，气质；（公司在某地的）工人（或产品），势力**{n.}++the state of being present; current existence																										        				&quot;he tested for the presence of radon&quot;**{n.}++[植]存在；出席；参加；风度；仪态**', '');
