insert into TOEFLWordBook values ('703', 'prey', '[preɪ]', 'http://dict.youdao.com/dictvoice?audio=prey', '{n.}++猎物，捕获物；受害者，受骗者；掠夺品**{v.}++捕食；欺凌，坑害（尤指弱者）；不断困扰，折磨**{n.}++a person who is the aim of an attack (especially a victim of ridicule or exploitation) by some hostile person or influence																										        				&quot;he fell prey to muggers&quot;															   	同义词：								                                  				    quarry				    				    				      				    				      				    				                                      				    target				    				    				      				    				      				    				                                      				    fair game**{vi.}++捕食；掠夺；折磨**{n.}++捕食；牺牲者；被捕食的动物**', '');
insert into TOEFLWordBook values ('704', 'pride', '[praɪd]', 'http://dict.youdao.com/dictvoice?audio=pride', '{n.}++自豪（感）；自尊（心）；傲慢，自负；最佳状态，全盛期；狮群；引以为傲的人（或事物）**{v.}++以……自豪（pride oneself on/upon）**{n.}++a feeling of self-respect and personal worth																					   	同义词：								                                  				    pridefulness**{n.}++自豪；骄傲；自尊心**{vt.}++使得意，以…自豪**{vi.}++自豪**', '');
