insert into TOEFLWordBook values ('706', 'private', '[ˈpraɪvət]', 'http://dict.youdao.com/dictvoice?audio=private', '{adj.}++私有的，自用的；（服务，行业）私营的，民营的；没有股票上市的；私下的，秘密的；（交易未涉及商业机构的）私下里的；（想法、感觉）私密的；未担任公职的，无官职的；与官职（或工作）无关的；安静的，不受打扰的；（人）内敛的，不喜欢谈论私事的；（尤指两人）单独的；私下辅导的；（教育，医疗）私立的；只有自己人明白的**{n.}++（美、英陆军或美国海军陆战队）二等兵； 私处，阴部（privates）**{n.}++an enlisted man of the lowest rank																										        				&quot;our prisoner was just a private and knew nothing of value&quot;															   	同义词：								                                  				    buck private				    				    				      				    				      				    				                                      				    common soldier**{adj.}++confined to particular persons or groups or providing privacy																										        													        													        													        													        													        													        													        				&quot;a private place&quot;; &quot;private discussions&quot;; &quot;private lessons&quot;; &quot;a private club&quot;; &quot;a private secretary&quot;; &quot;private property&quot;; &quot;the former President is now a private citizen&quot;; &quot;public figures struggle to maintain a private life&quot;**{adj.}++私人的；私有的；私下的**{n.}++列兵；二等兵**', '');
insert into TOEFLWordBook values ('707', 'procedure', '[prəˈsiːdʒər]', 'http://dict.youdao.com/dictvoice?audio=procedure', '{n.}++手续，步骤；（商业、法律或政治上的）程序；外科手术；（电脑的）应用程式**{n.}++a particular course of action intended to achieve a result																										        				&quot;the procedure of obtaining a drivers license&quot;															   	同义词：								                                  				    process**{n.}++程序，[管理]手续；步骤**', '');
insert into TOEFLWordBook values ('708', 'proceed', '[proʊˈsiːd]', 'http://dict.youdao.com/dictvoice?audio=proceed', '{v.}++开始行动，开展；继续做（或从事、进行）；（完成其他事后）继续做某事；行进，前往；起诉某人；来自，出自**{n.}++（某个事件或活动的）收入，收益**{v.}++continue talking																					   	同义词：								                                  				    continue				    				    				      				    				      				    				                                      				    go on				    				    				      				    				      				    				                                      				    carry on**{vi.}++开始；继续进行；发生；行进**', '');
insert into TOEFLWordBook values ('709', 'profession', '[prəˈfeʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=profession', '{n.}++（尤指需要长期训练和正规资格的）职业；（某）职业界同行，同业；（统称，指需要较高教育水平的）职业（the professions）；（信念、观点或感情的）公开表示，表白；入教誓言，修道誓约；入教仪式，入教**{n.}++the body of people in a learned occupation																					   	同义词：								                                  				    community**{n.}++职业，专业；声明，宣布，表白**', '');
insert into TOEFLWordBook values ('710', 'proficiency', '[prəˈfɪʃ(ə)nsi]', 'http://dict.youdao.com/dictvoice?audio=proficiency', '{n.}++熟练，精通**{n.}++the quality of having great facility and competence**{n.}++精通，熟练**', '');
insert into TOEFLWordBook values ('711', 'profit', '[ˈprɑːfɪt]', 'http://dict.youdao.com/dictvoice?audio=profit', '{n.}++利润，盈利； 利益，好处**{v.}++获益，得益（于）；赢利，获利**{n.}++the excess of revenues over outlays in a given period of time (including depreciation and other non-cash expenses)																					   	同义词：								                                  				    net income				    				    				      				    				      				    				                                      				    net				    				    				      				    				      				    				                                      				    net profit				    				    				      				    				      				    				                                      				    lucre				    				    				      				    				      				    				                                      				    profits				    				    				      				    				      				    				                                      				    earnings**{n.}++[会计]利润；利益**{vi.}++获利；有益**{vt.}++有益于**', '');
insert into TOEFLWordBook values ('712', 'profound', '[prəˈfaʊnd]', 'http://dict.youdao.com/dictvoice?audio=profound', '{adj.}++（影响）深刻的，极大的；（感情）强烈的，深切的；（思想）深邃的，（见解）深刻的；深的，深处的；完全的；艰深的，玄奥的；（疾病，残疾）严重的**{adj.}++showing intellectual penetration or emotional depths; from the depths of your being																										        													        													        													        													        													        				&quot;the differences are profound&quot;; &quot;a profound insight&quot;; &quot;a profound book&quot;; &quot;a profound mind&quot;; &quot;profound contempt&quot;; &quot;profound regret&quot;**{adj.}++深厚的；意义深远的；渊博的**', '');
insert into TOEFLWordBook values ('713', 'progress', '[ˈprɑːɡres]', 'http://dict.youdao.com/dictvoice?audio=progress', '{n.}++进步，进展；前进，行进；（社会的）进步**{v.}++进步，进展；使（任务，事业）取得持续进展；（时间）推移，流逝；缓慢行进；（占星）计算行星（或星象图各星及坐标）的位置**{n.}++gradual improvement or growth or development																										        				&quot;great progress in the arts&quot;															   	同义词：								                                  				    advancement**{n.}++进步，发展；前进**{vi.}++前进，进步；进行**', '');
insert into TOEFLWordBook values ('714', 'promise', '[ˈprɑːmɪs]', 'http://dict.youdao.com/dictvoice?audio=promise', '{v.}++承诺，保证；使很可能，预示；指望，期待（promise oneself）；把（某人，尤指女人）许配给；有指望，有前途**{n.}++承诺，诺言；前途，指望；迹象，预示**{n.}++a verbal commitment by one person to another agreeing to do (or not to do) something in the future**{n.}++许诺，允诺；希望**{vt.}++允诺，许诺；给人以…的指望或希望**', '');
insert into TOEFLWordBook values ('715', 'promote', '[prəˈmoʊt]', 'http://dict.youdao.com/dictvoice?audio=promote', '{v.}++促进，提倡；升职，晋升；促销，推广； 将（运动队）晋级；使（学生）升年级；负责筹办，主办（大型活动，如音乐会或体育比赛）；促使（议会私法议案）通过；使（卒）升格为（尤指后等）；（先打大牌）使（小牌）赢得一墩；使（催化剂）更活泼**{v.}++contribute to the progress or growth of																					   	同义词：								                                  				    advance				    				    				      				    				      				    				                                      				    boost				    				    				      				    				      				    				                                      				    further				    				    				      				    				      				    				                                      				    encourage**{vt.}++促进；提升；推销；发扬**', '');
insert into TOEFLWordBook values ('716', 'prompt', '[prɑːmpt]', 'http://dict.youdao.com/dictvoice?audio=prompt', '{v.}++促使，导致；鼓励，提示（说话者）；（计算机上）提示；（给演员）提词，提白**{n.}++（给演员的）提词；（计算机屏幕上显示准备接受指令的）提示； 鼓励，催促；（付款通知单上的）付款期限**{adj.}++迅速的，立刻的；（人）利索的，敏捷的；及时的，准时的；（商品）即期要送的，即期要付的**{adv.}++准时地**{n.}++a cue given to a performer (usually the beginning of the next line to be spoken)																										        				&quot;the audience could hear his prompting&quot;															   	同义词：								                                  				    prompting**{adj.}++敏捷的，迅速的；立刻的**{vt.}++[计]提示；促进；激起；（给演员）提白**{n.}++[计]提示；付款期限；DOS命令：改变DOS系统提示符的风格**{adv.}++准时地**', '');
insert into TOEFLWordBook values ('717', 'propel', '[prəˈpel]', 'http://dict.youdao.com/dictvoice?audio=propel', '{v.}++推进，驱动；推搡（某人走向特定方向）； 驱使，促使**{v.}++cause to move forward with force																										        				&quot;Steam propels this ship&quot;															   	同义词：								                                  				    impel**{vt.}++推进；驱使；激励；驱策**', '');
insert into TOEFLWordBook values ('718', 'province', '[ˈprɑːvɪns]', 'http://dict.youdao.com/dictvoice?audio=province', '{n.}++（知识、兴趣、责任的）范围，领域；省；（由大主教负责管辖的）教省；外省，外地（the provinces）； 北爱尔兰（the Province）；（古罗马总督统治的意大利境外的）行省**{n.}++the territory occupied by one of the constituent administrative districts of a nation																					   	同义词：								                                  				    state**{n.}++省；领域；职权**', '');
insert into TOEFLWordBook values ('719', 'provision', '[prəˈvɪʒ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=provision', '{n.}++提供，供应；准备，预备；（尤指为旅行准备的）食物，必需品（provisions）；条款，规定；赡养，供养；（机构账户上为已知负债，尤指坏账或资产价值缩减，从利润中留出的）准备金；神职委任（尤指教皇对尚未缺额神职的预先委任）**{v.}++为……提供所需物品（尤指食物）；（为已知债务）留出准备金**{n.}++a stipulated condition																										        				&quot;he accepted subject to one provision&quot;															   	同义词：								                                  				    proviso**{n.}++规定；条款；准备；[经]供应品**', '');
insert into TOEFLWordBook values ('720', 'provoke', '[prəˈvoʊk]', 'http://dict.youdao.com/dictvoice?audio=provoke', '{v.}++激起，引起；激励，刺激；挑衅，激怒**{v.}++call forth (emotions, feelings, and responses)																					   	同义词：								                                  				    arouse				    				    				      				    				      				    				                                      				    elicit				    				    				      				    				      				    				                                      				    enkindle				    				    				      				    				      				    				                                      				    kindle				    				    				      				    				      				    				                                      				    evoke				    				    				      				    				      				    				                                      				    fire				    				    				      				    				      				    				                                      				    raise**{vt.}++驱使；激怒；煽动；惹起**', '');
insert into TOEFLWordBook values ('721', 'pry', '[praɪ]', 'http://dict.youdao.com/dictvoice?audio=pry', '{vt.}++撬动，撬开**{vi.}++刺探，探查**{n.}++窥探；杠杆**{n.}++a heavy iron lever with one end forged into a wedge																					   	同义词：								                                  				    crowbar				    				    				      				    				      				    				                                      				    wrecking bar				    				    				      				    				      				    				                                      				    pry bar**{v.}++to move or force, especially in an effort to get something open																										        				&quot;Raccoons managed to pry the lid off the garbage pail&quot;															   	同义词：								                                  				    prise				    				    				      				    				      				    				                                      				    prize				    				    				      				    				      				    				                                      				    lever				    				    				      				    				      				    				                                      				    jimmy**{vt.}++撬动，撬开**{vi.}++刺探，探查**{n.}++窥探；[机]杠杆**', '');
