insert into TOEFLWordBook values ('724', 'pull', '[pʊl]', 'http://dict.youdao.com/dictvoice?audio=pull', '{v.}++拉，拽；拖动，移走；拔出，抽出；挪动，挣脱；拉开，拉上；牵引（车辆）；吃力地运转；（使车辆）打斜；划（船），划动；（迅速地）穿脱衣服；拉伤，扭伤；扳动，拉（开关）；犯下（罪行），使出（诡计）；吸引，影响；吸引异性；鼓励，为……打气；（把车）停在某处；拆开，拆散；从酒桶中取酒；取消，撤销；深吸烟斗（或烟）（pull at/on）；举止像（某人）；逮捕，拘留；控制（马）的速度；把（球）从前方场地打向外场；（把球）击向左侧（右侧）；打印（草样，校样）；（计算机）拉式检索（数据）；（美橄）侧翼迂回阻挡**{n.}++拉，拽；力，引力；吸引力，影响；（对他人的）影响力；艰难攀登；拉伤，扭伤；深吸，大口喝；拉手，拉绳，拉环；性引诱；向左侧（右侧）的一击；草样，校样；null**{n.}++the act of pulling; applying force to move something toward or with you																										        													        				&quot;the pull up the hill had him breathing harder&quot;; &quot;his strenuous pulling strained his back&quot;															   	同义词：								                                  				    pulling**{vt.}++拉；拔；拖**{vi.}++拉，拖；拔**{n.}++拉，拉绳；拉力，[交]牵引力；拖**', '');
insert into TOEFLWordBook values ('725', 'pulse', '[pʌls]', 'http://dict.youdao.com/dictvoice?audio=pulse', '{n.}++脉搏，脉率； 强劲的音乐节拍，律动；（声波、光波或电流的）脉冲；（生化）（供细胞培养的）冲量； 冲动；共有立场，心态；（喻）（活力或组织的）核心；（可食用的）豆子**{v.}++（有节奏地）搏动，跳动；产生节奏；洋溢着，充满（激情等）；用脉冲调制（波，光束）；应用脉冲信号于（装置）；（生化）用同位素脉冲标记（培养中的细胞）（pulse-label 的简称）；有节奏地驱动（食物搅拌机）**{n.}++(electronics) a sharp transient wave in the normal electrical state (or a series of such transients)																					   	同义词：								                                  				    pulsation				    				    				      				    				      				    				                                      				    pulsing				    				    				      				    				      				    				                                      				    impulse**{edible seeds of various pod-bearing plants (peas or beans or lentils etc.}++)**{n.}++[电子]脉冲；[生理]脉搏**{vi.}++跳动，脉跳**', '');
insert into TOEFLWordBook values ('726', 'pump', '[pʌmp]', 'http://dict.youdao.com/dictvoice?audio=pump', '{n.}++泵，抽水机；平底鞋，轻软舞鞋；高跟无带女鞋；抽吸，泵送；（生理）泵（指特定离子逆浓度梯度进行的跨膜主动运输机制）**{v.}++用泵（或泵样器官等）输送；快速上下（或内外）运动；涌出，涌流； 盘问，套问； 让某人使用大量药物； 举重（pump iron）；给......洗胃； 不断制造（pump out）；大量增加（pump up）；接连发射**{n.}++a mechanical device that moves fluid or gas by pressure or suction**{vt.}++打气；用抽水机抽…**{n.}++[机]泵，抽水机；打气筒**', '');
insert into TOEFLWordBook values ('727', 'purchase', '[ˈpɜːrtʃəs]', 'http://dict.youdao.com/dictvoice?audio=purchase', '{n.}++购买，采购；购买的东西；（非继承性的）财产置得；紧握，牢牢抓住；（移动重物的）滑轮（或类似装置）**{v.}++购买，采购；（努力或艰难地）获得，得到；（航海）（用滑轮或杠杆）升起，举起（绳，索，锚）**{n.}++the acquisition of something for payment																										        				&quot;they closed the purchase with a handshake&quot;**{n.}++[贸易]购买；紧握；起重装置**{vt.}++[贸易]购买；赢得**', '');
insert into TOEFLWordBook values ('728', 'pure', '[pjʊr]', 'http://dict.youdao.com/dictvoice?audio=pure', '{adj.}++纯的，不掺杂质的；血统纯的，纯种的；纯真的，贞洁的；干净的，不含有害物质的；无杂色的，清晰而优美的；完全的，纯粹的；（科学或研究）纯理论的，抽象的；（元音）单音的，纯音的**{adj.}++free of extraneous elements of any kind																										        													        													        													        													        													        				&quot;pure air and water&quot;; &quot;pure gold&quot;; &quot;pure primary colors&quot;; &quot;the violins pure and lovely song&quot;; &quot;pure tones&quot;; &quot;pure oxygen&quot;**{adj.}++纯的；纯粹的；纯洁的；清白的；纯理论的**', '');
insert into TOEFLWordBook values ('729', 'puzzle', '[ˈpʌz(ə)l]', 'http://dict.youdao.com/dictvoice?audio=puzzle', '{v.}++使困惑，使迷惑；（因迷惑而）苦思，冥思苦想；（通过苦苦思索）解决（或弄清楚），理出头绪（puzzle sth. out）**{n.}++测验智力（或知识）的游戏（或玩具，问题）；拼图游戏，拼图玩具；令人费解的人（或事物），难题**{n.}++a particularly baffling problem that is said to have a correct solution																										        													        				&quot;he loved to solve chessmate puzzles&quot;; &quot;thats a real puzzler&quot;															   	同义词：								                                  				    puzzler				    				    				      				    				      				    				                                      				    mystifier				    				    				      				    				      				    				                                      				    teaser**{vt.}++使…困惑；使…为难；苦思而得出**{vi.}++迷惑；冥思苦想**{n.}++谜；难题；迷惑**', '');
insert into TOEFLWordBook values ('730', 'pyramid', '[ˈpɪrəmɪd]', 'http://dict.youdao.com/dictvoice?audio=pyramid', '{n.}++金字塔；金字塔形的物体（或一堆东西）；角锥体，棱锥体；（解剖）锥体；金字塔式组织（体系）；金字塔式台球（pyramids）；金字塔式控股；金字塔式骗局（pyramid scheme）**{v.}++把……堆成尖塔（或角锥）形；在（小投资）上获得丰厚的收益；渐增，上涨；（使）渐增，（使）上涨**{n.}++a polyhedron having a polygonal base and triangular sides with a common vertex**{vi.}++渐增；上涨；[建]成金字塔状**', '');
insert into TOEFLWordBook values ('731', 'qualify', '[ˈkwɑːlɪfaɪ]', 'http://dict.youdao.com/dictvoice?audio=qualify', '{v.}++（使）有权去做；取得资格，达到标准；获得参赛资格；使合格，胜任；符合，可算作；具体说明，使语气缓和；修饰，限定**{v.}++prove capable or fit; meet requirements																					   	同义词：								                                  				    measure up**{vt.}++限制；使具有资格；证明…合格**{vi.}++取得资格，有资格**', '');
insert into TOEFLWordBook values ('732', 'quarry', '[ˈkwɑːri]', 'http://dict.youdao.com/dictvoice?audio=quarry', '{n.}++采石场；猎物；来源**{vi.}++费力地找**{vt.}++挖出；努力挖掘**{n.}++（Quarry）人名；（英）夸里**{n.}++a person who is the aim of an attack (especially a victim of ridicule or exploitation) by some hostile person or influence																					   	同义词：								                                  				    prey				    				    				      				    				      				    				                                      				    target				    				    				      				    				      				    				                                      				    fair game**{n.}++[矿业]采石场；猎物；来源**{vt.}++挖出；努力挖掘**', '');
insert into TOEFLWordBook values ('733', 'quotation', '[kwoʊˈteɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=quotation', '{n.}++引语，引文；音乐（或艺术品）片段的引用；引用，引述；报价单，估价；（股票）报价，牌价；（股票）上市许可登记**{n.}++a short note recognizing a source of information or of a quoted passage																					   	同义词：								                                  				    citation				    				    				      				    				      				    				                                      				    cite				    				    				      				    				      				    				                                      				    acknowledgment				    				    				      				    				      				    				                                      				    credit				    				    				      				    				      				    				                                      				    reference				    				    				      				    				      				    				                                      				    mention**{the practice of quoting from books or plays etc.}++&quot;since he lacks originality he must rely on quotation&quot;**{n.}++[贸易]报价单；引用语；引证**', '');
insert into TOEFLWordBook values ('734', 'race', '[reɪs]', 'http://dict.youdao.com/dictvoice?audio=race', '{n.}++赛跑，速度竞赛；竞争，角逐；赛马会（the races）；人种，种族；民族；（动植物）种，属；（具有共同特征的）一群（或一批）人（或物）；急流；沟槽，通道；血统，门第**{v.}++（和……）比赛，参加比赛；使（动物或车辆）参赛参赛；（使）快速移动，快速运转；疾走，全速行进；竞相，赶（时间）；（因害怕、兴奋而）急速跳动，快速转动；（发动机）猛转**{n.}++any competition																										        				&quot;the race for the presidency&quot;**{n.}++属，种；[人类]种族，人种；家庭，门弟**', '');
insert into TOEFLWordBook values ('735', 'radar', '[ˈreɪdɑːr]', 'http://dict.youdao.com/dictvoice?audio=radar', '{n.}++雷达，无线电探测系统；（人的）直觉感知能力，（对因素或潮流等的）敏感性**{n.}++measuring instrument in which the echo of a pulse of microwave radiation is used to detect and locate distant objects																					   	同义词：								                                  				    microwave radar				    				    				      				    				      				    				                                      				    radio detection and ranging				    				    				      				    				      				    				                                      				    radiolocation**', '');
insert into TOEFLWordBook values ('736', 'radiate', '[ˈreɪdieɪt]', 'http://dict.youdao.com/dictvoice?audio=radiate', '{v.}++（使品质或情感）显出，流露；辐射，发射；自中心辐射出，向周围伸展；（动物或植物群）辐射形进化**{adj.}++辐射（状）的，光芒四射的**{v.}++send out rays or waves																										        				&quot;The sun radiates heat&quot;**{vt.}++[物]辐射；传播；流露；发射；广播**{vi.}++[物]辐射；流露；发光；从中心向各方伸展**{adj.}++[物]辐射状的，有射线的**', '');
insert into TOEFLWordBook values ('737', 'radiation', '[ˌreɪdiˈeɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=radiation', '{n.}++辐射，放射线；辐射的热（或能量等）；放射疗法；辐射形进化，发散状分化**{n.}++energy that is radiated or transmitted in the form of rays or waves or particles**{syndrome resulting from exposure to ionizing radiation (e.}++g., exposure to radioactive chemicals or to nuclear explosions); low doses cause diarrhea and nausea and vomiting and sometimes loss of hair; greater exposure can cause sterility and cataracts and some forms of cancer and other diseases; severe exposure can cause death within hours																										        				&quot;he was suffering from radiation&quot;															   	同义词：								                                  				    radiation sickness				    				    				      				    				      				    				                                      				    radiation syndrome**{n.}++[物]辐射；发光；放射物**', '');
insert into TOEFLWordBook values ('738', 'radical', '[ˈrædɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=radical', '{adj.}++根本的，彻底的；激进的，极端的；全新的，不同凡响的；（增减）急剧的，大幅度的；（人，物）原本的，与生俱来的；顶呱呱的；（外科，医疗）根治的；（19世纪）自由党激进派的；（数）根式的，根号的；词根的；（植）根生的**{n.}++激进分子； 游离基，自由基；词根；（汉字）偏旁，部首；（数）根式；根号**{n.}++(chemistry) two or more atoms bound together as a single unit and forming part of a molecule																					   	同义词：								                                  				    group				    				    				      				    				      				    				                                      				    chemical group**{adj.}++激进的；根本的；彻底的**{n.}++基础；激进分子；[物化]原子团；[数]根数**', '');
insert into TOEFLWordBook values ('739', 'raft', '[ræft]', 'http://dict.youdao.com/dictvoice?audio=raft', '{n.}++木排，木筏； 橡皮艇，充气船；（游泳、跳水的）浮台；大量，许多；（树木、草木或冰块等一堆）漂浮物；大群游动的水鸟（或哺乳动物）；浮筏基础，格床基础**{v.}++乘坐筏子（度河），用筏子运送；（浮冰）随浮冰流淌；将（船或其他物体）并排连为一体**{n.}++a flat float (usually made of logs or planks) that can be used for transport or as a platform for swimmers**{n.}++筏；救生艇；（美）大量**', '');
insert into TOEFLWordBook values ('740', 'rage', '[reɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=rage', '{n.}++盛怒，狂怒；粗暴的举动，愤怒的行为；（喻）（自然事物的）狂暴，凶猛；风靡一时，非常流行；强烈的欲望，激情；（尤指预示的、诗意的或武力的）狂热； 欢乐聚会，热闹的活动**{v.}++发脾气，大怒；（战斗、争论）激烈进行，（暴风雨）肆虐；（火灾、疾病）迅速蔓延，快速扩散；（感情）强烈表现，变得强烈；狂欢，出去作乐**{n.}++a feeling of intense anger																										        				&quot;his face turned red with rage&quot;															   	同义词：								                                  				    fury				    				    				      				    				      				    				                                      				    madness**{n.}++愤怒；狂暴，肆虐；情绪激动**{vi.}++大怒，发怒；流行，风行**', '');
insert into TOEFLWordBook values ('741', 'ragged', '[ˈræɡɪd]', 'http://dict.youdao.com/dictvoice?audio=ragged', '{adj.}++（衣服）破旧的；（人）衣衫褴褛的；高低不平的，参差不齐的；不流畅的，不规则的；精疲力竭的；不熟练的，蹩脚的；（尤指右边距）未对齐的**{adj.}++being or dressed in clothes that are worn or torn																										        													        				&quot;clothes as ragged as a scarecrows&quot;; &quot;a ragged tramp&quot;**{adj.}++衣衫褴褛的；粗糙的；参差不齐的；锯齿状的；刺耳的；不规则的**', '');
