insert into TOEFLWordBook values ('743', 'rank', '[ræŋk]', 'http://dict.youdao.com/dictvoice?audio=rank', '{n.}++军衔，军阶；（社会、团体中的）地位，等级；（尤指较高的）地位；（警察、士兵等的）队列，行列；排，列；横排，棋盘横格；组织（或机构等）中的全体人员（ranks）；普通士兵（the ranks）；出租车候车站（=taxi rank）；（数）秩；（统计）次序排列；（系统语法用语）（一个或一组语言单位的）阶，级**{v.}++把……分等级，属于某等级；级别高于，地位高于；排列，使排成行**{adj.}++（植被）茂密的，芜生蔓长的；难闻的，恶臭的；（强调质量、状况等）极端的，糟糕的**{n.}++a row or line of people (especially soldiers or police) standing abreast of one another																										        				&quot;the entrance was guarded by ranks of policemen&quot;**{n.}++排；等级；[军]军衔；队列**{adj.}++讨厌的；恶臭的；繁茂的**{vt.}++排列；把…分等**{vi.}++列为；列队**', '');
insert into TOEFLWordBook values ('744', 'rat', '[ræt]', 'http://dict.youdao.com/dictvoice?audio=rat', '{n.}++老鼠；卑鄙小人（尤指欺诈或变节者）； 常客，常待在某处的人；（为头发定型做出饱满效果的）女用发垫**{v.}++捕（捉）老鼠，灭鼠； 告发，告密； 背信弃义，食言；用发垫给（头发）定型**{int.}++（rats） 胡说，去你的（用以表示轻度烦恼，恼怒）**{n.}++any of various long-tailed rodents similar to but larger than a mouse**{n.}++[脊椎]鼠；卑鄙小人，叛徒**{vi.}++捕鼠；背叛，告密**', '');
insert into TOEFLWordBook values ('745', 'rational', '[ˈræʃ(ə)nəl]', 'http://dict.youdao.com/dictvoice?audio=rational', '{adj.}++（想法、决定等）合理的，基于理性的；（人）理性的，理智的；富有理性的；（数）有理的，有理数的**{n.}++有理数**{n.}++an integer or a fraction																					   	同义词：								                                  				    rational number**{adj.}++consistent with or based on or using reason																										        													        													        				&quot;rational behavior&quot;; &quot;a process of rational inference&quot;; &quot;rational thought&quot;**', '');
insert into TOEFLWordBook values ('746', 'raven', '[ˈreɪv(ə)n]', 'http://dict.youdao.com/dictvoice?audio=raven', '{n.}++掠夺，劫掠；大乌鸦**{adj.}++乌黑的**{vt.}++掠夺；狼吞虎咽**{vi.}++掠夺；狼吞虎咽**{n.}++（Raven）人名；（英）雷文；（德）拉文**{n.}++large black bird with a straight bill and long wedge-shaped tail																					   	同义词：								                                  				    Corvus corax**{v.}++obtain or seize by violence**{n.}++掠夺，劫掠；大乌鸦**{adj.}++乌黑的**{vt.}++掠夺；狼吞虎咽**{vi.}++掠夺；狼吞虎咽**', '');
