insert into TOEFLWordBook values ('748', 'realize', '[ˈriːəlaɪz]', 'http://dict.youdao.com/dictvoice?audio=realize', '{v.}++了解，意识到；（所担心的事）发生，产生（be realized）；实现（目标、梦想等）；（充分）发挥出自己的潜力； 把（概念等）具体表现出来；用（语言特征）表达；对（记谱不全的乐曲）做完整兑谱改编；获得（金钱，利润）；变现，变卖（资产）**{v.}++be fully aware or cognizant of																					   	同义词：								                                  				    recognize				    				    				      				    				      				    				                                      				    recognise				    				    				      				    				      				    				                                      				    realise				    				    				      				    				      				    				                                      				    agnize				    				    				      				    				      				    				                                      				    agnise**{vt.}++实现；认识到；了解；将某物卖得**', '');
insert into TOEFLWordBook values ('749', 'realm', '[relm]', 'http://dict.youdao.com/dictvoice?audio=realm', '{n.}++（知识、活动、思想的）领域，范围；王国；（动物学）界（对地球表面所作的最主要的生物地理划分）**{n.}++a domain in which something is dominant																										        				&quot;the rise of the realm of cotton in the south&quot;															   	同义词：								                                  				    kingdom				    				    				      				    				      				    				                                      				    land**{n.}++领域，范围；王国**', '');
insert into TOEFLWordBook values ('750', 'rear', '[rɪr]', 'http://dict.youdao.com/dictvoice?audio=rear', '{n.}++（尤指建筑物或车辆等的）后部，背部（the rear）；（队列的）后方，后尾部队（或舰队）；臀部，屁股（=rear end）**{adj.}++后方的，背部的**{v.}++养育，饲养；栽种，培植；（动物）用后腿直立；（建筑、山等）高耸；（人）发火，暴跳（rear up）**{adv.}++向后，在后面**{n.}++the back of a military formation or procession																										        				&quot;infantrymen were in the rear&quot;**{vt.}++培养；树立；栽种**{vi.}++暴跳；高耸**{adv.}++向后；在后面**{adj.}++[军]后方的；后面的；背面的**{n.}++后面；屁股；后方部队**', '');
