insert into TOEFLWordBook values ('752', 'rebel', '[ˈreb(ə)l; rɪˈbel]', 'http://dict.youdao.com/dictvoice?audio=rebel', '{n.}++造反者，反抗者；反抗权威者；叛逆者，不守规矩者**{v.}++反叛，造反；违抗，不服从（权威）；反对，反抗（规定、行为规范等）；（胃、腿、头脑等）不听使唤**{adj.}++造反的；反抗的**{n.}++`Johnny was applied as a nickname for Confederate soldiers by the Federal soldiers in the American Civil War; `greyback derived from their grey Confederate uniforms																					   	同义词：								                                  				    Reb				    				    				      				    				      				    				                                      				    Johnny Reb				    				    				      				    				      				    				                                      				    Johnny				    				    				      				    				      				    				                                      				    greyback**{vi.}++反叛；反抗；造反**{n.}++反叛者；叛徒**{adj.}++反抗的；造反的**', '');
insert into TOEFLWordBook values ('753', 'rebuild', '[ˌriːˈbɪld]', 'http://dict.youdao.com/dictvoice?audio=rebuild', '{v.}++重建，重造； 使复原，使恢复**{n.}++（尤指车辆等机器的）重新组装；（尤指车辆等）改装的机器**{v.}++build again																										        				&quot;The house was rebuild after it was hit by a bomb&quot;															   	同义词：								                                  				    reconstruct**{vt.}++重建；改造，重新组装；复原**', '');
insert into TOEFLWordBook values ('754', 'recall', '[rɪˈkɔːl]', 'http://dict.youdao.com/dictvoice?audio=recall', '{v.}++记起，回想起；使想起，使想到；召回，叫回（某人）；召回（运动员），使归队； 收回（有问题的产品）；检索，调用（计算机储存的数据）； 罢免；使重新集中注意力； 撤销，废止（行动，决定）**{n.}++记忆力，记性；召回；（因产品有问题的）收回；（将运动员的）召回归队；（请愿后经投票对政府官员的）罢免；回索率，检索率；撤销**{n.}++a request by the manufacturer of a defective product to return the product (as for replacement or repair)																					   	同义词：								                                  				    callback**{vt.}++召回；回想起，记起；取消**{n.}++召回；回忆；撤消**', '');
insert into TOEFLWordBook values ('755', 'receiver', '[rɪˈsiːvər]', 'http://dict.youdao.com/dictvoice?audio=receiver', '{n.}++（电话）听筒；（无线电或电视）接收器，接收机；（法庭指定的）破产接管人；收受者，收件人；买卖赃物者，收赃人；接球手，外接手；接受罐，聚集器；（安置枪栓并与枪管等部件相连接的）机闸**{n.}++set that receives radio or tv signals																					   	同义词：								                                  				    receiving system**{n.}++接收器；接受者；收信机；收款员，接待者**', '');
insert into TOEFLWordBook values ('756', 'reception', '[rɪˈsepʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=reception', '{n.}++接待处，服务台；欢迎会，招待会；欢迎，反响；（收音机或电视信号）接收效果，接收质量；接收，接待；（美橄）接球；（幼儿学校的）小班，学前班**{n.}++the manner in which something is greeted																										        				&quot;she did not expect the cold reception she received from her superiors&quot;															   	同义词：								                                  				    response**{n.}++接待；接收；招待会；感受；反应**', '');
insert into TOEFLWordBook values ('757', 'recognition', '[ˌrekəɡˈnɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=recognition', '{n.}++承认，接受；表彰，赞誉；认出，识别；（政府对他国的）外交认可**{n.}++the state or quality of being recognized or acknowledged																										        													        				&quot;the partners were delighted with the recognition of their work&quot;; &quot;she seems to avoid much in the way of recognition or acknowledgement of feminist work prior to her own&quot;															   	同义词：								                                  				    acknowledgment				    				    				      				    				      				    				                                      				    acknowledgement**{n.}++[计][免疫]识别；承认，认出；重视；赞誉；公认**', '');
