insert into TOEFLWordBook values ('759', 'recording', '[rɪˈkɔːrdɪŋ]', 'http://dict.youdao.com/dictvoice?audio=recording', '{n.}++录音，录像；录制；（正式的）记录，记载**{v.}++记录，记载；录制；（仪器）显示，标示；（尤指体育上）获得（好成绩）（record 的现在分词）**{n.}++signal encoding something (e.g., picture or sound) that has been recorded**{n.}++录音；唱片**{adj.}++记录的；记录用的**{v.}++录音；记录；录像（record的ing形式）**', '');
insert into TOEFLWordBook values ('760', 'recover', '[rɪˈkʌvər]', 'http://dict.youdao.com/dictvoice?audio=recover', '{v.}++恢复（健康，精神，体力）；康复，复原（be recovered）；（从不愉快的经历中）恢复；（从弱势或困境中）好转，扭转；重新获得，寻回；收回（开支、投资等）；恢复（意识、神志或身体状态）；挽回（地位），弥补（时间损失）；提取（能源或化工品等），回收利用； 给……换上新面**{n.}++（军事操练）枪还原，收枪（the recover）**{v.}++get or find back; recover the use of																					   	同义词：								                                  				    retrieve				    				    				      				    				      				    				                                      				    find				    				    				      				    				      				    				                                      				    regain**{regain a former condition after a financial loss																										        				&quot;We expect the stocks to recover to $2.}++90&quot;															   	同义词：								                                  				    go back				    				    				      				    				      				    				                                      				    recuperate**{vt.}++恢复；弥补；重新获得**{vi.}++恢复；胜诉；重新得球**', '');
insert into TOEFLWordBook values ('761', 'recreation', '[ˌriːkriˈeɪʃn; ˌrekriˈeɪʃən]', 'http://dict.youdao.com/dictvoice?audio=recreation', '{n.}++娱乐（活动），消遣（活动）；重现，重建**{n.}++an activity that diverts or amuses or stimulates																										        													        				&quot;for recreation he wrote poetry and solved crossword puzzles&quot;; &quot;drug abuse is often regarded as a form of recreation&quot;															   	同义词：								                                  				    diversion**{n.}++娱乐；消遣；休养**', '');
insert into TOEFLWordBook values ('762', 'recycle', '[ˌriːˈsaɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=recycle', '{v.}++回收利用，再利用；（将可回收物品）送入回收加工厂；使再循环；再次应用，重新使用（观念、文章等）**{n.}++回收利用，循环使用**{v.}++cause to repeat a cycle**{n.}++再生；再循环；重复利用**', '');
insert into TOEFLWordBook values ('763', 'reddish', '[ˈredɪʃ]', 'http://dict.youdao.com/dictvoice?audio=reddish', '{adj.}++微红的；略带红色的**{n.}++（Reddish）人名；（英）雷迪什**{adj.}++of a color at the end of the color spectrum (next to orange); resembling the color of blood or cherries or tomatoes or rubies																					   	同义词：								                                  				    red				    				    				      				    				      				    				                                      				    ruddy				    				    				      				    				      				    				                                      				    blood-red				    				    				      				    				      				    				                                      				    carmine				    				    				      				    				      				    				                                      				    cerise				    				    				      				    				      				    				                                      				    cherry				    				    				      				    				      				    				                                      				    cherry-red				    				    				      				    				      				    				                                      				    crimson				    				    				      				    				      				    				                                      				    ruby				    				    				      				    				      				    				                                      				    ruby-red				    				    				      				    				      				    				                                      				    scarlet**', '');
insert into TOEFLWordBook values ('764', 'reel', '[riːl]', 'http://dict.youdao.com/dictvoice?audio=reel', '{n.}++卷轴，线轴；（钓竿上的）卷线轮；一卷，一盘；（影片的）一本；里尔舞（一种轻快的苏格兰或爱尔兰舞蹈），里尔舞曲；蹒跚（或摇晃）的动作**{v.}++震惊，困惑；（尤指被打或震惊而）踉跄着后退；蹒跚，踉跄；（感觉）晕眩，天旋地转；卷，绕（reel sth. in）；跳里尔舞**{n.}++a roll of photographic film holding a series of frames to be projected by a movie projector**{vi.}++卷；眩晕；蹒跚地走；退缩**{vt.}++卷；使旋转**{n.}++蹒跚；眩晕；旋转**', '');
insert into TOEFLWordBook values ('765', 'refer', '[rɪˈfɜːr]', 'http://dict.youdao.com/dictvoice?audio=refer', '{v.}++提到，谈及（refer to）；描述，涉及（refer to）；查阅，参考（refer to）；将……送交给（以求获得帮助等）；让（某人）注意；把……归因于；（考试中）淘汰（应试者）**{v.}++make reference to																					   	同义词：								                                  				    mention				    				    				      				    				      				    				                                      				    advert				    				    				      				    				      				    				                                      				    bring up				    				    				      				    				      				    				                                      				    cite				    				    				      				    				      				    				                                      				    name**{vi.}++参考；涉及；提到；查阅**{vt.}++涉及；委托；归诸于；使…求助于**', '');
