insert into TOEFLWordBook values ('767', 'reflection', '[rɪˈflekʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=reflection', '{n.}++（光、热或声音的）反射；反射光，反射热，回声；（反射出来的）影像，倒影；深思，反省；（尤指见诸语言的）想法，意见；表现，反映；坏的印象；（数）镜射，反射**{n.}++a calm lengthy intent consideration																					   	同义词：								                                  				    contemplation				    				    				      				    				      				    				                                      				    reflexion				    				    				      				    				      				    				                                      				    rumination				    				    				      				    				      				    				                                      				    musing				    				    				      				    				      				    				                                      				    thoughtfulness**{n.}++[热][光][物]反射；沉思；映象**', '');
insert into TOEFLWordBook values ('768', 'reform', '[rɪˈfɔːrm]', 'http://dict.youdao.com/dictvoice?audio=reform', '{v.}++改革，革新；改邪归正，改造；（石油炼制）重整**{n.}++改革，改良**{adj.}++犹太教改革（仅保留犹太教部分的传统信条和习俗）（Reform）**{n.}++a change for the better as a result of correcting abuses																										        				&quot;justice was for sale before the reform of the law courts&quot;**{n.}++改革，改良；改正**{vt.}++改革，革新；重新组成**{vi.}++重组；改过**', '');
