insert into TOEFLWordBook values ('770', 'refuse', '[rɪˈfjuːz]', 'http://dict.youdao.com/dictvoice?audio=refuse', '{v.}++拒绝，回绝（做某事）；不接受，拒绝（别人给的东西）；拒绝给（所需之物）；（物体）未应要求起作用； 不接受（某人的）求婚；（马）拒绝（跨栏或其他障碍物）**{n.}++垃圾，废弃物**{adj.}++废弃的**{n.}++food that is discarded (as from a kitchen)																					   	同义词：								                                  				    garbage				    				    				      				    				      				    				                                      				    food waste				    				    				      				    				      				    				                                      				    scraps**{v.}++show unwillingness towards																					   	同义词：								                                  				    decline**{n.}++垃圾；[环境]废物**{vt.}++拒绝；不愿；抵制**{vi.}++拒绝**', '');
insert into TOEFLWordBook values ('771', 'regard', '[rɪˈɡɑːrd]', 'http://dict.youdao.com/dictvoice?audio=regard', '{v.}++认为，把……看作；（尤指以某种方式）注视，凝视；注意，留心；与……有关，涉及**{n.}++尊重，敬佩； 关心，关注；注视，凝视；（用于信函结尾或转达问候）致意，问候（regards）**{n.}++(usually preceded by `in) a detail or point																					   	同义词：								                                  				    respect**{n.}++注意；尊重；问候；凝视**{vt.}++注重，考虑；看待；尊敬；把…看作；与…有关**{vi.}++注意，注重；注视**', '');
insert into TOEFLWordBook values ('772', 'regional', '[ˈriːdʒən(ə)l]', 'http://dict.youdao.com/dictvoice?audio=regional', '{adj.}++地区的，区域的；（与）首都以外各地（有关）的**{n.}++（邮票、报纸等）地方版；地区性体育竞赛**{adj.}++characteristic of a region																										        				&quot;regional flora&quot;**{adj.}++地区的；局部的；整个地区的**', '');
insert into TOEFLWordBook values ('773', 'regular', '[ˈreɡjələr]', 'http://dict.youdao.com/dictvoice?audio=regular', '{adj.}++定期的，规律的；经常的，频繁的；惯常的，通常的；持久的，固定的；标准尺寸的，中号的；普通的，平凡的；常备军的，正规军的；（动词）规则的；（人）正常通便的，月经正常的；完全的，彻底的；均匀的，端正的；正规的，正当的；（冲浪等）左腿在前的**{n.}++常客，老主顾；主演，主力队员；正规军人，职业军人；普通产品，普通装；（区别于世俗教士的）修道者，教士**{n.}++a regular patron																					   	同义词：								                                  				    habitue				    				    				      				    				      				    				                                      				    fixture**{adj.}++定期的；有规律的；合格的；[植]整齐的**{n.}++常客；正式队员；中坚分子**{adv.}++定期地；经常地**', '');
insert into TOEFLWordBook values ('774', 'regulate', '[ˈreɡjuleɪt]', 'http://dict.youdao.com/dictvoice?audio=regulate', '{v.}++（用规则条例）控制，管理；调节，调整；监控，监管；校准，对准（时钟或其他仪器）**{v.}++fix or adjust the time, amount, degree, or rate of																										        				&quot;regulate the temperature&quot;															   	同义词：								                                  				    modulate**{vt.}++调节，规定；控制；校准；有系统的管理**', '');
