insert into TOEFLWordBook values ('776', 'release', '[rɪˈliːs]', 'http://dict.youdao.com/dictvoice?audio=release', '{v.}++释放，放走；放开，松开；公布，发布；发行，上映；发泄，宣泄；排放（物质）；免除，解雇；放弃，让予；放松，使松弛**{n.}++释放，获释；排放，泄漏；释放装置；表达，宣泄；解脱，轻松感；新发行的东西；发表，发布；（责任等的）免除； 放弃，让予； 传球；（设备的）松开**{n.}++merchandise issued for sale or public showing (especially a record or film)																										        				&quot;a new release from the London Symphony Orchestra&quot;**{vt.}++释放；发射；让与；允许发表**{n.}++释放；发布；让与**', '');
