insert into TOEFLWordBook values ('778', 'reliable', '[rɪˈlaɪəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=reliable', '{adj.}++可靠的，可信赖的；真实可信的，确凿的；（汽车、设备、系统等）耐用的，性能稳定的**{n.}++可靠的人（或物）**{adj.}++worthy of reliance or trust																										        				&quot;a reliable source of information&quot;															   	同义词：								                                  				    dependable**{adj.}++可靠的；可信赖的**{n.}++可靠的人**', '');
insert into TOEFLWordBook values ('779', 'remark', '[rɪˈmɑːrk]', 'http://dict.youdao.com/dictvoice?audio=remark', '{n.}++言论，评述；（正式演讲时的）言论（remarks）； 引人注目，显耀**{v.}++谈论，说起；注意到**{n.}++a statement that expresses a personal opinion or belief																					   	同义词：								                                  				    comment**{n.}++注意；言辞**{vt.}++评论；觉察**{vi.}++谈论**', '');
