insert into TOEFLWordBook values ('781', 'remote', '[rɪˈmoʊt]', 'http://dict.youdao.com/dictvoice?audio=remote', '{adj.}++边远的，偏僻的；（距离或空间上）遥远的；（时间上）久远的；（机会或可能性）渺茫的；差别很大的，很不相同的；不友好的，冷漠的；远亲关系的；（电子设备）遥控的；（计算机）远程的，远程连接的**{n.}++遥控装置，遥控器**{n.}++a device that can be used to control a machine or apparatus from a distance																										        				&quot;he lost the remote for his TV&quot;															   	同义词：								                                  				    remote control**{adj.}++apart in space																										        				&quot;remote stars&quot;															   	同义词：								                                  				    distant**{adj.}++遥远的；偏僻的；疏远的**', '');
insert into TOEFLWordBook values ('782', 'Renaissance', '[ˈrenəsɑːns]', 'http://dict.youdao.com/dictvoice?audio=Renaissance', '{n.}++文艺复兴（欧洲14至17世纪）**{n.}++the period of European history at the close of the Middle Ages and the rise of the modern world; a cultural rebirth from the 14th through the middle of the 17th centuries																					   	同义词：								                                  				    Renascence**{n.}++文艺复兴（欧洲14至16世纪）**', '');
insert into TOEFLWordBook values ('783', 'render', '[ˈrendər]', 'http://dict.youdao.com/dictvoice?audio=render', '{v.}++使成为，使处于某种状态；给予，提供；（以某种方式）表达，表现；粉刷，往（墙上）抹灰；将（脂肪）熬成油，使熔化；正式宣布（判决或决定）；（供审查，考虑）提交，呈报；放弃，献出；演奏，演唱；翻译；绘制（指用色彩和明暗使轮廓图像具立体感）；秘密引渡（外国罪犯、恐怖嫌疑犯）；从（动物身体）提取（蛋白质、脂肪及其他可用部分）**{n.}++底灰，底泥；交纳**{n.}++a substance similar to stucco but exclusively applied to masonry walls**{v.}++cause to become																										        				&quot;The shot rendered her immobile&quot;**{vt.}++致使；提出；实施；着色；以…回报**{n.}++打底；交纳；粉刷**', '');
insert into TOEFLWordBook values ('784', 'renew', '[rɪˈnuː]', 'http://dict.youdao.com/dictvoice?audio=renew', '{v.}++重新开始，中止后继续；恢复，重新建立（关系）；使（受到损毁或丢失后）重获新生；更换，更新；重申，重复强调；延长（执照、合同等）的有效期，使续签**{v.}++reestablish on a new, usually improved, basis or make new or like new																										        													        				&quot;We renewed our friendship after a hiatus of twenty years&quot;; &quot;They renewed their membership&quot;															   	同义词：								                                  				    regenerate**{vt.}++使更新；续借；复兴；重申**{vi.}++更新；重新开始**', '');
insert into TOEFLWordBook values ('785', 'rental', '[ˈrent(ə)l]', 'http://dict.youdao.com/dictvoice?audio=rental', '{n.}++租费，租金；出租，租赁；租用物（尤指房屋或车辆）**{adj.}++（与）租借（有关）的，可供租用的**{n.}++property that is leased or rented out or let																					   	同义词：								                                  				    lease				    				    				      				    				      				    				                                      				    letting**{n.}++租金收入，租金；租赁**{adj.}++租赁的；收取租金的**', '');
insert into TOEFLWordBook values ('786', 'repair', '[rɪˈper]', 'http://dict.youdao.com/dictvoice?audio=repair', '{v.}++修理，修补；补救，挽救（关系或声誉）；（结伴）去，赴（repair to）**{n.}++修理，补救；修补过的地方；维修状态，保养情况； 常去；常去的场所**{n.}++the act of putting something in working order again																					   	同义词：								                                  				    fix				    				    				      				    				      				    				                                      				    fixing				    				    				      				    				      				    				                                      				    fixture				    				    				      				    				      				    				                                      				    mend				    				    				      				    				      				    				                                      				    mending				    				    				      				    				      				    				                                      				    reparation**{vi.}++修理；修复**{vt.}++修理；恢复；补救，纠正**{n.}++修理，修补；修补部位**', '');
insert into TOEFLWordBook values ('787', 'repeat', '[rɪˈpiːt]', 'http://dict.youdao.com/dictvoice?audio=repeat', '{v.}++重复，重说；复述，跟读（尤指为学习）；转述，转告；（强调说过的话）再说一遍；重新做，使再次发生；重播；重读，重修；（选举中违法）重复投票；再次成功，两连冠；（吃下的食物因打嗝或消化不良）在口中留下余味；（钟表按要求）连打**{n.}++（事件的）重演，重现；重播节目；（同类货物的）再次运送；重复装饰图案；（乐谱的）反复符号，重复段**{n.}++an event that repeats																										        				&quot;the events today were a repeat of yesterdays&quot;															   	同义词：								                                  				    repetition**{v.}++to say, state, or perform again																					   	同义词：								                                  				    reiterate				    				    				      				    				      				    				                                      				    ingeminate				    				    				      				    				      				    				                                      				    iterate				    				    				      				    				      				    				                                      				    restate				    				    				      				    				      				    				                                      				    retell**{vt.}++重复；复制；背诵**{n.}++重复；副本**{vi.}++重做；重复发生**', '');
