insert into TOEFLWordBook values ('794', 'request', '[rɪˈkwest]', 'http://dict.youdao.com/dictvoice?audio=request', '{n.}++要求，请求；要求的事，点播的歌曲；（要求计算机提供信息或执行另一任务的）指令**{v.}++请求，要求；要求（某人）做……，请求（某人）做……；点播（乐曲）**{n.}++a formal message requesting something that is submitted to an authority																					   	同义词：								                                  				    petition				    				    				      				    				      				    				                                      				    postulation**{n.}++[计]请求；需要**{vt.}++要求，[计]请求**', '');
insert into TOEFLWordBook values ('795', 'requirement', '[rɪˈkwaɪərmənt]', 'http://dict.youdao.com/dictvoice?audio=requirement', '{n.}++要求，必要条件；需要（要求）的事物**{n.}++required activity																										        				&quot;the requirements of his work affected his health&quot;															   	同义词：								                                  				    demand**{n.}++要求；必要条件；必需品**', '');
insert into TOEFLWordBook values ('796', 'reserve', '[rɪˈzɜːrv]', 'http://dict.youdao.com/dictvoice?audio=reserve', '{v.}++预订；保留，预留；拥有，保留（某种权利）；留作，用于（特定场合）；保留（意见），推迟作出（决定或判断）；贮存，贮藏；（教会用语）弥撒仪式后保留部分圣餐**{n.}++储备（量），储藏（量）；含蓄，寡言；保留意见，异议；（野生生物）保护区；替补队员，后备队员；后备队，替补队（the reserves）；预备役部队，后备部队；（尤指拍卖时的）底价，最低价；（美洲土著居民的）居留地；（陶瓷装饰或纺织品印染中保留原色的）防染本色区；（陶瓷装饰或纺织品印染中保留原色的）防染本色区**{n.}++formality and propriety of manner																					   	同义词：								                                  				    modesty**{n.}++[贸易][金融]储备，储存；自然保护区；[军][林]预备队；储备金**{vt.}++[贸易][金融]储备；保留；预约**{vi.}++预订**', '');
insert into TOEFLWordBook values ('797', 'reshape', '[ˌriːˈʃeɪp]', 'http://dict.youdao.com/dictvoice?audio=reshape', '{vt.}++改造；再成形**{v.}++shape anew or differently																										        				&quot;The new foreign minister reshaped the foreign policy of his country&quot;**{vt.}++改造；再成形**', '');
insert into TOEFLWordBook values ('798', 'resist', '[rɪˈzɪst]', 'http://dict.youdao.com/dictvoice?audio=resist', '{v.}++阻挡，抵制；抵抗，回击；耐得住，抵挡；使不受……的伤害，抗（伤害）**{n.}++保护涂层（防染色、着釉等），防染材料**{v.}++elude, especially in a baffling way																					   	同义词：								                                  				    defy				    				    				      				    				      				    				                                      				    refuse**{vi.}++抵抗，[法]抗拒；忍耐**{vt.}++抵抗；忍耐，忍住**{n.}++[助剂]抗蚀剂；防染剂**', '');
insert into TOEFLWordBook values ('799', 'resolution', '[ˌrezəˈluːʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=resolution', '{n.}++决议，正式决定；（冲突、问题等的）解决，解决办法；决心，决定；坚决，果断；（电视、照相机、显微镜等的）清晰度，分辨率；（故事中主要矛盾的）冲突解开；（乐）解决（指和声中不协和音向协和音的进行）；（医）（炎症或其他症状的）消散，消退；（化）分解；（物理）（力或其他矢量的）分解**{n.}++a formal expression by a meeting; agreed to by a vote																					   	同义词：								                                  				    declaration				    				    				      				    				      				    				                                      				    resolve**{n.}++[物][电子][光]分辨率；决议；解决；决心**', '');
insert into TOEFLWordBook values ('800', 'resort', '[rɪˈzɔːrt]', 'http://dict.youdao.com/dictvoice?audio=resort', '{n.}++旅游胜地，度假胜地；求助的方法，采用的手段；采用，诉诸，求助**{v.}++诉诸，求助于；常去，（成群结队地）去**{n.}++a hotel located in a resort area																					   	同义词：								                                  				    resort hotel				    				    				      				    				      				    				                                      				    holiday resort**{n.}++凭借，手段；度假胜地；常去之地**{vi.}++求助，诉诸；常去；采取某手段或方法**', '');
insert into TOEFLWordBook values ('801', 'respect', '[rɪˈspekt]', 'http://dict.youdao.com/dictvoice?audio=respect', '{n.}++尊敬，敬重；重视，尊重；方面，着眼点；问候，敬意（respects）**{v.}++尊敬，敬佩；慎重对待，尊重；遵守；避免破坏（或干扰）**{int.}++真了不起（因敬重或赞同而发出的感叹）**{n.}++(usually preceded by `in) a detail or point																										        				&quot;it differs in that respect&quot;															   	同义词：								                                  				    regard**{n.}++尊敬，尊重；方面；敬意**{vt.}++尊敬，尊重；遵守**', '');
insert into TOEFLWordBook values ('802', 'respond', '[rɪˈspɑːnd]', 'http://dict.youdao.com/dictvoice?audio=respond', '{v.}++（口头或书面）回答，回应；作出反应，回应；（对某种治疗）有良好反应；（桥牌）（对同伴的叫牌）作应叫；（会众对牧师）应答，唱和；承担责任**{n.}++（教堂用语）应答，唱和；（建筑）壁联（与墙相连支承拱的半柱或半墩，尤指在拱廊两端）**{v.}++show a response or a reaction to something																					   	同义词：								                                  				    react**{vi.}++回答；作出反应；承担责任**{n.}++应答；唱和**', '');
insert into TOEFLWordBook values ('803', 'responsible', '[rɪˈspɑːnsəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=responsible', '{adj.}++（对某人、某事）负责的；（对事故、错误、罪行等）负有责任的，应承担责任的；（工作或职位）重要的，责任重大的；可靠的，负责任的；作为缘由的，应受归咎的；向......负责的，向......汇报的**{adj.}++worthy of or requiring responsibility or trust; or held accountable																										        													        													        													        													        				&quot;a responsible adult&quot;; &quot;responsible journalism&quot;; &quot;a responsible position&quot;; &quot;the captain is responsible for the ships safety&quot;; &quot;the cabinet is responsible to the parliament&quot;**{adj.}++[法]负责的，可靠的；有责任的**', '');
insert into TOEFLWordBook values ('804', 'restore', '[rɪˈstɔːr]', 'http://dict.youdao.com/dictvoice?audio=restore', '{v.}++恢复（某种情况或感受）；使复原，使复位；修复，整修；重新采用，恢复使用；归还**{v.}++return to its original or usable and functioning condition																										        				&quot;restore the forest to its original pristine condition&quot;															   	同义词：								                                  				    reconstruct**{vt.}++恢复；修复；归还**{vi.}++恢复；还原**', '');
insert into TOEFLWordBook values ('805', 'restrict', '[rɪˈstrɪkt]', 'http://dict.youdao.com/dictvoice?audio=restrict', '{v.}++限制，控制（大小、数量、范围）；限制（活动或行为），妨碍；约束，管束；（以法规）限制；封锁（消息）**{v.}++place restrictions on																					   	同义词：								                                  				    curtail				    				    				      				    				      				    				                                      				    curb				    				    				      				    				      				    				                                      				    cut back**{vt.}++限制；约束；限定**', '');
insert into TOEFLWordBook values ('806', 'resume', '[rɪˈzuːm]', 'http://dict.youdao.com/dictvoice?audio=resume', '{v.}++恢复（职位），回到（座位）；继续说，接着说；概述；（中断后）重新开始，继续**{n.}++梗概，摘要（résumé或resumé）；简历，履历（résumé或resumé）**{n.}++short descriptive summary (of events)																					   	同义词：								                                  				    sketch				    				    				      				    				      				    				                                      				    survey**{n.}++[管理]履历；个人简历；摘要**{vt.}++重新开始；重新获得**', '');
insert into TOEFLWordBook values ('807', 'retreat', '[rɪˈtriːt]', 'http://dict.youdao.com/dictvoice?audio=retreat', '{v.}++（军队）撤退；后退，离开；（水、雪或土地）范围缩小；隐退，躲避；悔棋；改变意见，改变看法；（股价）下挫，下跌；向后倾**{n.}++撤军，撤兵；后退，离开；退隐处，静居处；（主意、观点、决定的）改变；（股票）贬值；静修期间（或活动）**{n.}++a place of privacy; a place affording peace and quiet**{n.}++撤退；休息寓所；撤退**{vi.}++撤退；退避；向后倾**', '');
insert into TOEFLWordBook values ('808', 'retrieve', '[rɪˈtriːv]', 'http://dict.youdao.com/dictvoice?audio=retrieve', '{v.}++找回，收回；检索（储存于计算机的信息）；（狗等）衔回（物品、猎物）；挽救，挽回；回忆，追忆；收绕钓鱼线**{n.}++（尤指中枪猎物的）找回；收绕钓鱼线； 恢复的可能性；检索**{v.}++get or find back; recover the use of																					   	同义词：								                                  				    recover				    				    				      				    				      				    				                                      				    find				    				    				      				    				      				    				                                      				    regain**{vt.}++[计]检索；恢复；重新得到**{n.}++[计]检索；恢复，取回**', '');
insert into TOEFLWordBook values ('809', 'reverse', '[rɪˈvɜːrs]', 'http://dict.youdao.com/dictvoice?audio=reverse', '{v.}++逆转，彻底改变（决定、政策、趋势等）；撤销，推翻（法庭判决）；颠倒，反转；交换，互换（位置、功能）；承认错误，放弃（立场）；倒（车）；（发动机）反向运转；打对方付费的电话；使（铅字，图案）印成白或浅色**{n.}++相对，相反（the reverse）；逆向，逆转；倒车挡；失败，挫折；反面，背面；（翻开的书）左手页，（活页文件的）背面；（硬币或奖牌）反面图案（或刻字）；（美式橄榄球）反向传球，变位传球**{adj.}++相反的，反向的；背面的，反面的；（半导体结的外加电压）反向的；（地层）逆断的，冲断的；反身的**{n.}++a relation of direct opposition																										        				&quot;we thought Sue was older than Bill but just the reverse was true&quot;															   	同义词：								                                  				    contrary				    				    				      				    				      				    				                                      				    opposite**{n.}++相反；背面；倒退；失败**{vt.}++颠倒；倒转**{adj.}++反面的；颠倒的**{vi.}++倒退；逆叫**', '');
insert into TOEFLWordBook values ('810', 'review', '[rɪˈvjuː]', 'http://dict.youdao.com/dictvoice?audio=review', '{n.}++审查，检查；评论，评论文章；（时事、艺术等的）评论期刊；述评，回顾；复习，温习；（一门课程的）材料，练习；阅兵，阅兵式；中止快速倒带（或卷带）重放装置**{v.}++仔细研究，审视；给（书、戏剧、电影等）写评论；回顾，反思；（为考试而）复习，温习；校阅，审核；复查（病人）；检阅（军队）；将（判决、案件等）提交上级法院（或权力机构）复审**{n.}++a new appraisal or evaluation																					   	同义词：								                                  				    reappraisal				    				    				      				    				      				    				                                      				    revaluation				    				    				      				    				      				    				                                      				    reassessment**{n.}++回顾；复习；评论；检讨；检阅**{vt.}++回顾；检查；复审**{vi.}++回顾；复习功课；写评论**', '');
insert into TOEFLWordBook values ('811', 'revival', '[rɪˈvaɪv(ə)l]', 'http://dict.youdao.com/dictvoice?audio=revival', '{n.}++复兴，复苏；再流行；（旧剧的）重新上演；（复兴基督教信仰的）奋兴布道会；（体力或活力的）重振**{n.}++bringing again into activity and prominence																										        													        													        				&quot;the revival of trade&quot;; &quot;a revival of a neglected play by Moliere&quot;; &quot;the Gothic revival in architecture&quot;															   	同义词：								                                  				    resurgence				    				    				      				    				      				    				                                      				    revitalization				    				    				      				    				      				    				                                      				    revitalisation				    				    				      				    				      				    				                                      				    revivification**{n.}++复兴；复活；苏醒；恢复精神；再生效**', '');
insert into TOEFLWordBook values ('812', 'revolutionary', '[ˌrevəˈluːʃəneri]', 'http://dict.youdao.com/dictvoice?audio=revolutionary', '{adj.}++革命的；革命性的，突破性的**{n.}++革命者，革命家**{n.}++a radical supporter of political or social revolution																					   	同义词：								                                  				    revolutionist				    				    				      				    				      				    				                                      				    subversive				    				    				      				    				      				    				                                      				    subverter**{adj.}++markedly new or introducing radical change																										        				&quot;a revolutionary discovery&quot;															   	同义词：								                                  				    radical**{adj.}++革命的；旋转的；大变革的**', '');
insert into TOEFLWordBook values ('813', 'reward', '[rɪˈwɔːrd]', 'http://dict.youdao.com/dictvoice?audio=reward', '{n.}++奖励，回报；赏格，悬赏金；报偿，报应**{v.}++酬谢，奖赏；奖励（行动，品质）；（理所当然地）获得，赢得（be rewarded）；值得（付出时间或精力）**{n.}++a recompense for worthy acts or retribution for wrongdoing																										        				&quot;virtue is its own reward&quot;															   	同义词：								                                  				    wages				    				    				      				    				      				    				                                      				    payoff**{n.}++[劳经]报酬；报答；酬谢**{vt.}++[劳经]奖励；奖赏**', '');
insert into TOEFLWordBook values ('814', 'ribbon', '[ˈrɪbən]', 'http://dict.youdao.com/dictvoice?audio=ribbon', '{n.}++丝带，绸带；（表示军功的）绶带，勋带；（作为比赛奖品的）绶带；（表明支持某一组织、原则或目标而配带的）饰带；带状物，狭长的东西；（打字机用的）色带；碎片（ribbons）；奖品，荣誉**{v.}++成带状延伸（或运动）；把…撕成条带；用缎带装饰**{n.}++any long object resembling a thin line																										        													        				&quot;a mere ribbon of land&quot;; &quot;the lighted ribbon of traffic&quot;															   	同义词：								                                  				    thread**{n.}++带；缎带；（勋章等的）绶带；带状物；勋表**', '');
insert into TOEFLWordBook values ('815', 'rid', '[rɪd]', 'http://dict.youdao.com/dictvoice?audio=rid', '{v.}++使……去掉，使……去除；摆脱，消除**{adj.}++得到解脱的**{v.}++relieve from																					   	同义词：								                                  				    free				    				    				      				    				      				    				                                      				    disembarrass**{vt.}++使摆脱；使去掉**', '');
insert into TOEFLWordBook values ('816', 'rifle', '[ˈraɪf(ə)l]', 'http://dict.youdao.com/dictvoice?audio=rifle', '{n.}++步枪，来复枪；步枪队（rifles）**{v.}++快速搜寻，匆忙翻找；偷窃，盗取；用力掷，猛踢（球）；为（枪、枪管或内膛）凿制来复线**{n.}++a shoulder firearm with a long barrel and a rifled bore																										        				&quot;he lifted the rifle to his shoulder and fired&quot;**{v.}++steal goods; take as spoils																					   	同义词：								                                  				    plunder				    				    				      				    				      				    				                                      				    despoil				    				    				      				    				      				    				                                      				    loot				    				    				      				    				      				    				                                      				    reave				    				    				      				    				      				    				                                      				    strip				    				    				      				    				      				    				                                      				    ransack				    				    				      				    				      				    				                                      				    pillage				    				    				      				    				      				    				                                      				    foray**{n.}++[军]步枪；来复枪**{vt.}++用步枪射击；抢夺；偷走**', '');
insert into TOEFLWordBook values ('817', 'rigid', '[ˈrɪdʒɪd]', 'http://dict.youdao.com/dictvoice?audio=rigid', '{adj.}++（方法、体制等）严格死板的，僵化的；（人）顽固的，不通融的；刚硬的，不易弯曲的；（因强烈的感情而）僵硬的，僵直的；精确的**{n.}++未铰接的货车**{adj.}++incapable of or resistant to bending																										        													        				&quot;a rigid strip of metal&quot;; &quot;a table made of rigid plastic&quot;															   	同义词：								                                  				    stiff**{adj.}++严格的；僵硬的，死板的；坚硬的；精确的**', '');
insert into TOEFLWordBook values ('818', 'ring', '[rɪŋ]', 'http://dict.youdao.com/dictvoice?audio=ring', '{n.}++戒指，指环；环状物，圈形物；圆圈；圆形表演场（或竞技场）；围成一圈的人（或物）；团伙，帮派；铃声，钟声，按铃，敲钟；（说法、讨论、辩论等的）特性；圆形灶盘，炉头；肛门；（化）环；（数）环**{v.}++包围；绕……画圆，把……圈起来；（尤指在动物身上）套环；敲钟，按铃；（给……）打电话；嗡嗡作响；回响；充满；非法将（汽车）改头换面**{n.}++a characteristic sound																										        				&quot;it has the ring of sincerity&quot;**{vi.}++按铃；敲钟；回响；成环形**{n.}++戒指；铃声，钟声；拳击场；环形物**{vt.}++按铃；包围；敲钟；套住**', '');
insert into TOEFLWordBook values ('819', 'risk', '[rɪsk]', 'http://dict.youdao.com/dictvoice?audio=risk', '{n.}++危险，风险；危险的人（或事物），隐患；（按风险大小评估的）被保险对象，受贷者；（保险业承保的）险；金融风险**{v.}++使遭受（失去、毁坏或伤害的）危险；冒......的危险，担......的风险；冒险做，（明知结果而）大胆做**{n.}++a source of danger; a possibility of incurring loss or misfortune																					   	同义词：								                                  				    hazard				    				    				      				    				      				    				                                      				    jeopardy				    				    				      				    				      				    				                                      				    peril				    				    				      				    				      				    				                                      				    endangerment**{n.}++风险；[保险]危险；冒险**{vt.}++冒…的危险**', '');
insert into TOEFLWordBook values ('820', 'ritual', '[ˈrɪtʃuəl]', 'http://dict.youdao.com/dictvoice?audio=ritual', '{n.}++（宗教等的）仪式，典礼；习惯，例行公事；（尤指某一宗教或教派特定的）程序，仪式**{adj.}++仪式上的，庆典上的；（行动）常规的，例行的**{n.}++any customary observance or practice																					   	同义词：								                                  				    rite**{n.}++仪式；惯例；礼制**{adj.}++仪式的；例行的；礼节性的**', '');
insert into TOEFLWordBook values ('821', 'rival', '[ˈraɪv(ə)l]', 'http://dict.youdao.com/dictvoice?audio=rival', '{n.}++竞争对手，敌手；可与之匹敌者，可与之相比的人（或物）**{v.}++与......相匹敌，比得上**{adj.}++竞争的，对抗的**{n.}++the contestant you hope to defeat																										        				&quot;he had respect for his rivals&quot;															   	同义词：								                                  				    challenger				    				    				      				    				      				    				                                      				    competitor				    				    				      				    				      				    				                                      				    competition				    				    				      				    				      				    				                                      				    contender**{v.}++be equal to in quality or ability																										        				&quot;Nothing can rival cotton for durability&quot;															   	同义词：								                                  				    equal				    				    				      				    				      				    				                                      				    touch				    				    				      				    				      				    				                                      				    match**{n.}++对手；[劳经]竞争者**{vt.}++与…竞争；比得上某人**{vi.}++[劳经]竞争**{adj.}++[劳经]竞争的**', '');
insert into TOEFLWordBook values ('822', 'roar', '[rɔːr]', 'http://dict.youdao.com/dictvoice?audio=roar', '{v.}++吼叫，咆哮；（人群）用欢呼声激励，为......喝彩，为加油；哄笑，大笑；（尤指车辆）轰鸣着疾驶，呼啸而过；果断行事，迅速发生；熊熊燃烧**{n.}++吼叫声， 咆哮声；（风或海的）呼啸声，（机器的）隆隆声；（狮等的）吼叫声；爆笑声**{n.}++a deep prolonged loud noise																					   	同义词：								                                  				    boom				    				    				      				    				      				    				                                      				    roaring				    				    				      				    				      				    				                                      				    thunder**{n.}++咆哮；吼；轰鸣**{vi.}++咆哮；吼叫；喧闹**{vt.}++咆哮；呼喊；使……轰鸣**', '');
insert into TOEFLWordBook values ('823', 'rocky', '[ˈrɑːki]', 'http://dict.youdao.com/dictvoice?audio=rocky', '{adj.}++岩石构成的，多岩石的；坚如岩石的；晃动的，不稳的；身体摇摇晃晃的，头晕目眩的；（局势、关系）不稳固的，困难重重的；与摇滚乐有关的**{adj.}++abounding in rocks or stones																										        				&quot;rocky fields&quot;															   	同义词：								                                  				    bouldery				    				    				      				    				      				    				                                      				    bouldered				    				    				      				    				      				    				                                      				    stony**{adj.}++岩石的，多岩石的；坚如岩石的；摇晃的；头晕目眩的**', '');
insert into TOEFLWordBook values ('824', 'roll', '[roʊl]', 'http://dict.youdao.com/dictvoice?audio=roll', '{v.}++（使）翻滚，滚动；（使）翻身，翻转；行驶，开动；（机器）转动，运转；（液体）滚落，滑落；使……成球状（或管状）；使平坦，压平；把（衣服的边）卷起来；（使）摇摆，摇晃；（使）原地转圈，翻白眼；摇（车窗），卷（窗帘等）；发出持续的声音；（时间）流逝；（产品）从（流水线，机器）产出；盗窃；连获成功**{n.}++卷，卷轴；卷状食品；赘肉，肥肉；名单，花名册；一管；滚动，翻滚；左右摇晃，振荡；隆隆声，轰轰响；掷骰子；压路机，辊轧机；（地形的）延绵起伏**{n.}++rotary motion of an object around its own axis																					   	同义词：								                                  				    axial rotation				    				    				      				    				      				    				                                      				    axial motion**{a roll of currency notes (often taken as the resources of a person or business etc.}++)																										        				&quot;he shot his roll on a bob-tailed nag&quot;															   	同义词：								                                  				    bankroll**{vt.}++卷；滚动，转动；辗**{vi.}++卷；滚动；转动；起伏，摇晃**{n.}++卷，卷形物；名单；摇晃**', '');
insert into TOEFLWordBook values ('825', 'roof', '[ruːf]', 'http://dict.youdao.com/dictvoice?audio=roof', '{n.}++屋顶，车顶；（洞穴、矿井等的）顶部；口腔顶部，上腭；住处，栖身之处；（价格或工资的）最高限度，上限**{v.}++给......盖上屋顶；覆遮，遮蔽**{n.}++a protective covering that covers or forms the top of a building**{n.}++[建]屋顶；最高处，顶部；最高限度**{vt.}++给…盖屋顶，覆盖**', '');
insert into TOEFLWordBook values ('826', 'rope', '[roʊp]', 'http://dict.youdao.com/dictvoice?audio=rope', '{n.}++粗绳，绳索；（球状物的）（一）串，（一）条；（套捕牛、马等的）套索；（拳击台、摔跤台的）围绳（the ropes）；绞刑（the rope）；办事的规矩，诀窍（the ropes）**{v.}++用绳子捆（或绑、系）；用绳套捕捉（动物）；用绳（或带子）围起（或隔开）（rope sth. off）；借绳爬下/借绳登山（rope down/up）；说服……参加（活动） (rope someone in/into)；拧成绳状**{n.}++a strong line**{n.}++绳，绳索**{vt.}++捆，绑**', '');
insert into TOEFLWordBook values ('827', 'rotor', '[ˈroʊtər]', 'http://dict.youdao.com/dictvoice?audio=rotor', '{n.}++转子；水平旋翼；旋转体**{n.}++the rotating armature of a motor or generator																					   	同义词：								                                  				    rotor coil**{n.}++[电][机][动力]转子；水平旋翼；旋转体**', '');
insert into TOEFLWordBook values ('828', 'rough', '[rʌf]', 'http://dict.youdao.com/dictvoice?audio=rough', '{adj.}++（表面）粗糙的，不平的；（网球或软式墙网球拍）粗面的；粗暴的，猛烈的；（地方）多暴力的，犯罪盛行的；汹涌的，风浪很大的；粗制的，不完善的；粗俗的，不讲究的；粗略的，大致的； 艰难的，不愉快的； 身体不适的；（声音）粗哑的，不悦耳的；（酒）涩味的；未经加工的；（文具）用以打草稿的**{n.}++（高尔夫球场的）深草区（the rough）；草稿，草图； 粗野的人，暴徒；未加工的宝石；高低不平的地面；粗糙的部分；艰苦，不愉快**{v.}++粗制，对……粗加工；草拟，画……的轮廓；使不平，把……弄毛糙； 因陋就简地生活；粗暴地对待；（在美式橄榄球、冰球等比赛中对对手）动粗**{adv.}++粗糙地，粗暴地； 风餐露宿**{n.}++the part of a golf course bordering the fairway where the grass is not cut short**{v.}++prepare in preliminary or sketchy form																					   	同义词：								                                  				    rough in				    				    				      				    				      				    				                                      				    rough out**{adj.}++having or caused by an irregular surface																										        													        													        													        				&quot;trees with rough bark&quot;; &quot;rough ground&quot;; &quot;rough skin&quot;; &quot;rough blankets&quot;															   	同义词：								                                  				    unsmooth**{adj.}++[机]粗糙的；粗略的；粗野的；艰苦的；未经加工的**{vt.}++[机]使粗糙；粗暴对待；草拟**{n.}++艰苦；高低不平的地面；未经加工的材料；粗糙的部分**{adv.}++[机]粗糙地；粗略地；粗暴地**', '');
insert into TOEFLWordBook values ('829', 'rounded', '[ˈraʊndɪd]', 'http://dict.youdao.com/dictvoice?audio=rounded', '{adj.}++圆形的；全面的；丰满的**{adj.}++curving and somewhat round in shape rather than jagged																										        													        				&quot;low rounded hills&quot;; &quot;rounded shoulders&quot;**{adj.}++圆形的；全面的；丰满的**', '');
insert into TOEFLWordBook values ('830', 'routine', '[ruːˈtiːn]', 'http://dict.youdao.com/dictvoice?audio=routine', '{n.}++常规，惯例；生活乏味，无聊；（演出中的）一套动作，一系列笑话（等）；（为达到特定目的的）老一套，俗套；（计算机）例行程序**{adj.}++常规的，例行的；平常的，毫不特别的；平淡乏味的**{v.}++按惯例安排**{n.}++an unvarying or habitual method or procedure																					   	同义词：								                                  				    modus operandi**{n.}++[计]程序；日常工作；例行公事**{adj.}++日常的；例行的**', '');
insert into TOEFLWordBook values ('831', 'row', '[roʊ]', 'http://dict.youdao.com/dictvoice?audio=row', '{n.}++一排，一行；（剧院、体育场等的）一排座位；街（用于某些道路名称）；（表格的）横线，横栏；（编织中的）针行；划船（时间）； 严重分歧，纠纷； 吵架，争吵； （持续时间长的）喧闹声，吵嚷声； 严厉斥责**{v.}++划（船）；划船送（某人或某物）；参加划船比赛； 争吵，吵架； 痛斥，责骂；使……成排**{n.}++an arrangement of objects or people side by side in a line																										        				&quot;a row of chairs&quot;**{n.}++行，排；划船；街道；吵闹**{vi.}++划船；争吵**', '');
insert into TOEFLWordBook values ('832', 'rub', '[rʌb]', 'http://dict.youdao.com/dictvoice?audio=rub', '{v.}++擦，磨擦；揉擦，按摩（尤指疼痛部位）；擦痛，磨损；涂，抹；摹拓，拓印（黄铜碑或墓石的）碑文；（滚木球）（球）受阻，转向；（使）相互摩擦，搓；把（配料）揉擦进（混合物）（rub sth. in/into/through）**{n.}++（用手或物体）擦，揉；按摩膏，面膜；困难，问题（the rub）；（烹饪肉之前涂抹在肉表面的）混合香料；（球）受阻，转向；磨损处**{n.}++an unforeseen obstacle																					   	同义词：								                                  				    hang-up				    				    				      				    				      				    				                                      				    hitch				    				    				      				    				      				    				                                      				    snag**{vt.}++擦；摩擦；惹怒**{vi.}++擦；摩擦；擦破**{n.}++摩擦；障碍；磨损处**', '');
insert into TOEFLWordBook values ('833', 'rule', '[ruːl]', 'http://dict.youdao.com/dictvoice?audio=rule', '{n.}++规章，条例；（语言、科学等的）规则，法则；行事准则，指导方针；常规，惯常做法；统治，管辖；尺，直尺；铅线印出的线，破折号； 澳大利亚式橄榄球规则（两队各18人参赛）**{v.}++统治，管辖；支配，控制；占首要地位；（尤指对法律问题）判定，裁定；（用尺等）划（线）； 好极了，非常棒；（行星）对（黄道十二宫图的宫，房子，生活等）有影响；（价格或贸易商品的价格）普遍处于某一水平（或坚挺趋势）**{n.}++a principle or condition that customarily governs behavior																										        				&quot;it was his rule to take a walk before breakfast&quot;															   	同义词：								                                  				    regulation**{any one of a systematic body of regulations defining the way of life of members of a religious order																										        				&quot;the rule of St.}++Dominic&quot;**{vi.}++统治；管辖；裁定**{n.}++统治；[数]规则**{vt.}++统治；规定；管理；裁决；支配**', '');
insert into TOEFLWordBook values ('834', 'rumor', '[ˈruːmər]', 'http://dict.youdao.com/dictvoice?audio=rumor', '{n.}++谣言；传闻**{vt.}++谣传；传说**{n.}++（Rumor）人名；（意、葡）鲁莫尔**{n.}++gossip (usually a mixture of truth and untruth) passed around by word of mouth																					   	同义词：								                                  				    rumour				    				    				      				    				      				    				                                      				    hearsay**{v.}++tell or spread rumors																										        				&quot;It was rumored that the next president would be a woman&quot;															   	同义词：								                                  				    rumour				    				    				      				    				      				    				                                      				    bruit**{n.}++谣言；传闻**{vt.}++谣传；传说**', '');
insert into TOEFLWordBook values ('835', 'runout', '[ˈrʌnˌaʊt]', 'http://dict.youdao.com/dictvoice?audio=runout', '{n.}++避开；（板球）刺杀**{n.}++避开；（板球）刺杀**', '');
insert into TOEFLWordBook values ('836', 'rural', '[ˈrʊrəl]', 'http://dict.youdao.com/dictvoice?audio=rural', '{adj.}++农村的，乡村的；有乡村特色的，有乡土气息的**{adj.}++living in or characteristic of farming or country life																										        													        													        													        				&quot;rural people&quot;; &quot;large rural households&quot;; &quot;unpaved rural roads&quot;; &quot;an economy that is basically rural&quot;**{adj.}++农村的，乡下的；田园的，有乡村风味的**', '');
insert into TOEFLWordBook values ('837', 'rush', '[rʌʃ]', 'http://dict.youdao.com/dictvoice?audio=rush', '{v.}++冲，奔；把（某人或某物）迅速送往；赶紧做，仓促做；催促，使赶紧；（水、液体等）快速流动；（因感到尴尬）某人的脸/面颊涨红；向……猛冲，猛攻；（大学生联谊会通过举办聚会等）招纳，招收（新会员）；办理手续加入（大学生联谊会）；（美橄）突袭（对方队员，尤指枢纽前卫）；（美式橄榄中）跑动带（球）；仓促生产并分发，匆匆出售（rush something out）**{n.}++（尤指一群人的）冲，奔；（空气、水等）湍流；匆忙，赶紧；（人流或交通的）高峰时间（the rush）；（很多人）争做，急需；迸发的情绪，情绪迸发；（因吸食毒品或因兴奋事物产生的）一阵激动；工作样片（rushes）；灯心草（常用来编筐）；（美橄）突袭对方队员（尤指枢纽前卫）；（美式橄榄球中的）跑动带球；（大学生联谊会的）招新活动；（美国大学生联谊会的）纳新活动（时间）**{n.}++the act of moving hurriedly and in a careless manner																					   	同义词：								                                  				    haste				    				    				      				    				      				    				                                      				    hurry				    				    				      				    				      				    				                                      				    rushing**{n.}++冲进；匆促；急流；[植]灯心草**{vt.}++使冲；突袭；匆忙地做；飞跃**{vi.}++冲；奔；闯；赶紧；涌现**', '');
insert into TOEFLWordBook values ('838', 'rust', '[rʌst]', 'http://dict.youdao.com/dictvoice?audio=rust', '{n.}++锈，铁锈；（植物的）锈病，锈菌；铁锈色，赭色**{v.}++（使）生锈；成铁锈色；（因疏忽或不用而）衰退，变迟钝；（因长时间不用或有害使用而）损害，腐蚀**{n.}++a red or brown oxide coating on iron or steel caused by the action of oxygen and moisture**{n.}++[材][化工]锈；生锈；[植保]锈病**{vt.}++使生锈；腐蚀**{vi.}++生锈；成铁锈色；变迟钝**', '');
insert into TOEFLWordBook values ('839', 'sail', '[seɪl]', 'http://dict.youdao.com/dictvoice?audio=sail', '{v.}++（人）航行；（船）航行；启航；驾驶（船只）；飘过，（轻快地）移动**{n.}++帆；乘船航行；（用作交通工具的）帆船的使用；（潜艇的）瞭望塔；油布，篷帆布；帆状物，功能似帆的物体；（风车的）翼板；（旗鱼或一些史前爬行动物的）脊鳍；（僧帽水母等的）帆器**{n.}++a large piece of fabric (usually canvas fabric) by means of which wind is used to propel a sailing vessel																					   	同义词：								                                  				    canvas				    				    				      				    				      				    				                                      				    canvass				    				    				      				    				      				    				                                      				    sheet**{vi.}++航行；启航，开船**{n.}++[船]帆，篷；航行**{vt.}++航行**', '');
insert into TOEFLWordBook values ('840', 'satisfy', '[ˈsætɪsfaɪ]', 'http://dict.youdao.com/dictvoice?audio=satisfy', '{v.}++使满意，使满足；满足（要求、需要等）；符合（规定、条件或标准）；使确信，使信服；清偿，偿付；解，符合（方程式）；令人满意，令人满足**{v.}++fulfil the requirements or expectations of																					   	同义词：								                                  				    fulfill				    				    				      				    				      				    				                                      				    fulfil				    				    				      				    				      				    				                                      				    live up to**{vi.}++令人满意；令人满足**{vt.}++满足；说服，使相信；使满意，使高兴**', '');
insert into TOEFLWordBook values ('841', 'saturated', '[ˈsætʃəreɪtɪd]', 'http://dict.youdao.com/dictvoice?audio=saturated', '{adj.}++湿透的；（溶液）饱和的，（有机分子）饱和的；充满的；（颜色）深的**{v.}++使湿透；使充满；使（化学溶液）饱和（saturate的过去式和过去分词）**{adj.}++being the most concentrated solution possible at a given temperature; unable to dissolve still more of a substance																										        				&quot;a saturated solution&quot;															   	同义词：								                                  				    concentrated**{adj.}++饱和的；渗透的；深颜色的**', '');
insert into TOEFLWordBook values ('842', 'scar', '[skɑːr]', 'http://dict.youdao.com/dictvoice?audio=scar', '{n.}++伤疤，疤痕；（精神上的）创伤；损伤痕迹，污点；（植物的）叶柄疤；（尤指石灰岩的）峭壁，露出地表的岩层**{v.}++结疤，留下伤疤；给……留下精神创伤；损害……的外观，破坏……的景致**{n.}++a mark left (usually on the skin) by the healing of injured tissue																					   	同义词：								                                  				    cicatrix				    				    				      				    				      				    				                                      				    cicatrice**{vt.}++伤害；给留下伤痕**{vi.}++结疤；痊愈**{n.}++创伤；伤痕**', '');
insert into TOEFLWordBook values ('843', 'scent', '[sent]', 'http://dict.youdao.com/dictvoice?audio=scent', '{n.}++香味，芳香；（动物或人的）气味，臭迹；香水；察觉，预示；线索，踪迹；嗅觉**{v.}++使……带有某种香味；（动物）嗅出，闻到；预感，觉察**{n.}++a distinctive odor that is pleasant																					   	同义词：								                                  				    aroma				    				    				      				    				      				    				                                      				    fragrance				    				    				      				    				      				    				                                      				    perfume**{n.}++气味；嗅觉；痕迹；察觉能力**{vt.}++闻到；发觉；使充满…的气味；循着遗臭追踪**{vi.}++发出…的气味；有…的迹象；嗅着气味追赶**', '');
insert into TOEFLWordBook values ('844', 'schedule', '[ˈskedʒuːl]', 'http://dict.youdao.com/dictvoice?audio=schedule', '{n.}++计划（表），进度表；（公共汽车、火车等的）时间表；（价目、费用等的）清单，一览表；（电视或电台的）节目表；（学校的）课程表； 附件（尤指表格、单据等）；（英国所得税制的）报税单**{v.}++安排，预定；列入，收进（正式目录、清单等中）； 把（建筑物）列为文物保护单位**{n.}++a temporally organized plan for matters to be attended to																					   	同义词：								                                  				    agenda				    				    				      				    				      				    				                                      				    docket**{vt.}++安排，[计划]计划；编制目录；将……列入计划表**{n.}++[交]时间表；[计划]计划表；一览表**', '');
insert into TOEFLWordBook values ('845', 'scholar', '[ˈskɑːlər]', 'http://dict.youdao.com/dictvoice?audio=scholar', '{n.}++学者；有学问的人；奖学金获得者；聪颖勤奋的学生**{n.}++a learned person (especially in the humanities); someone who by long study has gained mastery in one or more disciplines																					   	同义词：								                                  				    scholarly person				    				    				      				    				      				    				                                      				    bookman				    				    				      				    				      				    				                                      				    student**{n.}++学者；奖学金获得者**', '');
insert into TOEFLWordBook values ('846', 'score', '[skɔːr]', 'http://dict.youdao.com/dictvoice?audio=score', '{n.}++（游戏或比赛中的）得分，比分；（测验的）评分，分数；实情，真相（the score）；毒品到手；犯罪所得；二十，约二十个（复数 score）；很多，大量（scores）；（一首乐曲的）总谱；（电影或戏剧的）配乐；刻痕，划痕；宿怨；（尤指酒馆中有对应顾客名字刻痕的）往来账户**{v.}++（在运动、比赛或考试中）得（分）；评分，打分数；（在游戏或比赛中）记分；（棒球）使（队友）得分；（使）成功，赢得； （尤指在辩论等活动中机灵地）驳倒，挫败（score off）；购买，弄到（毒品）；得到（某事物）；（通常指与新认识的人）发生性关系；为……写总谱，为……配乐；（在表面上）刻痕，画线；画掉，删去（score sth. out/through）；检测（实验细胞、菌落等），并记录有某种特征的数量**{n.}++a number or letter indicating quality (especially of a students performance)																										        				&quot;what was your score on your homework?&quot;															   	同义词：								                                  				    mark				    				    				      				    				      				    				                                      				    grade**{n.}++分数；二十；配乐；[木]刻痕**{vt.}++获得；评价；划线，刻划；把…记下**{vi.}++得分；记分；[木]刻痕**', '');
insert into TOEFLWordBook values ('847', 'scratch', '[skrætʃ]', 'http://dict.youdao.com/dictvoice?audio=scratch', '{v.}++（用指甲）挠，轻抓；（用指甲或利器）抓破，划破；划出，刮出（痕迹）；（用爪子）抓，刨；（鸟、哺乳动物，尤指鸡）用嘴（或爪子）扒地找食物；寻觅（难找的人或物）（scratch for）；艰难生活（scratch along）；勾掉，划去（写下的字）； 仓促写下；（用尖利物）刮擦出声音； 取消，撤销（想法或计划）；（使）退出比赛；（用刮擦技法）播放唱片**{n.}++（某人皮肤上的）划痕，划伤；刮痕，划痕；抓，挠；刮擦声；唱片的嚓嚓声（指唱片纹道与唱针的摩擦噪声）；刮擦（多用于快板乐中，用手制止唱片转动，使其来回移动发出有节奏的嚓嚓声的技巧）；（高尔夫）零让步（表明选手不弱，能在场上达到规定击球的次数）； 钱**{adj.}++（球队或一群人等）仓促拼凑的，匆匆组成的；（高尔夫球员）无让杆的，无让步优待的；碰巧的；打草稿用的**{n.}++an abraded area where the skin is torn or worn off																					   	同义词：								                                  				    abrasion				    				    				      				    				      				    				                                      				    scrape				    				    				      				    				      				    				                                      				    excoriation**{n.}++擦伤；抓痕；刮擦声；乱写**{adj.}++打草稿用的；凑合的；碰巧的**{vt.}++抓；刮；挖出；乱涂**{vi.}++抓；搔；发刮擦声；勉强糊口；退出比赛**', '');
insert into TOEFLWordBook values ('848', 'seal', '[siːl]', 'http://dict.youdao.com/dictvoice?audio=seal', '{n.}++印章，图章；表示确认的事物；密封装置，密封物；密封，密封状态；水止，水封（根据排污管道深度U形管中防止臭气上升的存水）；封蜡，火漆；封蜡模（印），封铅模（印）；海豹；海豹皮；装饰性的背面涂胶水的邮票（印花）；（美国海军）海豹特种部队士兵（SEAL）**{v.}++封上（信封）；密封（容器）；确定，使成定局；给……涂上保护层；（给文件）加封，盖印；封锁；（为避免烹调时失去过多水分，将食物放在热油中）快速煎炸；猎捕海豹**{n.}++fastener consisting of a resinous composition that is plastic when warm; used for sealing documents and parcels and letters																					   	同义词：								                                  				    sealing wax**{n.}++[机]密封；印章；[皮革][脊椎]海豹；封条；标志**{vt.}++[机]密封；盖章**', '');
insert into TOEFLWordBook values ('849', 'search', '[sɜːrtʃ]', 'http://dict.youdao.com/dictvoice?audio=search', '{v.}++搜查，搜寻；搜查（地方，车辆），搜……的身；思索，细想（问题答案等）；细察，细查；（用计算机）搜索，检索**{n.}++搜寻，搜查；探索，寻求；（计算机的）搜索，检索；调查地产负担**{n.}++the activity of looking thoroughly in order to find something or someone																					   	同义词：								                                  				    hunt				    				    				      				    				      				    				                                      				    hunting**{vi.}++搜寻；调查；探求**{vt.}++[计][航][水运]搜索；搜寻；调查；搜查；探求**{n.}++搜寻；探究，查究**', '');
insert into TOEFLWordBook values ('850', 'seasonal', '[ˈsiːzən(ə)l]', 'http://dict.youdao.com/dictvoice?audio=seasonal', '{adj.}++季节性的，随季节变化的；节令性的，适应节日需要的**{n.}++a worker who finds employment only in certain seasons																					   	同义词：								                                  				    seasonal worker**{adj.}++occurring at or dependent on a particular season																										        													        				&quot;seasonal labor&quot;; &quot;a seasonal rise in unemployment&quot;**{adj.}++[天]季节的；周期性的；依照季节的**', '');
insert into TOEFLWordBook values ('851', 'secondary', '[ˈsekənderi]', 'http://dict.youdao.com/dictvoice?audio=secondary', '{adj.}++（教育）中等的，中学的；次要的， 第二位的；（疾病、感染）继发性的，第二期的；间接的；（化学反应）副的；（有机化合物）二代的；（主要指胺）仲的；（电）次级的；（地质）中生代的（Secondary）**{n.}++副手，下属；第二防线；中学（secondary school 的简称）；（鸟）次级飞羽（secondary feather 的简称）；（变压器中的）次级线圈；（地质）中生代（the Secondary）**{n.}++the defensive football players who line up behind the linemen**{adj.}++[数][地质]第二的；中等的；[电]次要的；中级的**{n.}++副手；代理人**', '');
insert into TOEFLWordBook values ('852', 'secret', '[ˈsiːkrət]', 'http://dict.youdao.com/dictvoice?audio=secret', '{adj.}++秘密的，保密的；（感情、担心、行动）不公开的，暗自的；（某人的行为）诡秘的，神秘的；善于掩饰自己的，严守秘密的**{n.}++秘密，内情；神秘，奥秘；秘诀，诀窍；（罗马天主教弥撒捐献仪式后牧师的）默祷**{n.}++something that should remain hidden from others (especially information that is not to be passed on)																										        													        				&quot;the combination to the safe was a secret&quot;; &quot;he tried to keep his drinking a secret&quot;**{n.}++秘密；秘诀；机密**{adj.}++秘密的；机密的**', '');
insert into TOEFLWordBook values ('853', 'sector', '[ˈsektər]', 'http://dict.youdao.com/dictvoice?audio=sector', '{n.}++区域，部分；（尤指商业、贸易等的）部门，行业；小群体；（尤指军队控制的）分区，防区；（磁盘上的）扇区； 扇形，扇形面；函数尺，象限仪**{v.}++把……分成扇形**{n.}++a plane figure bounded by two radii and the included arc of a circle**{n.}++部门；扇形，扇区；象限仪；函数尺**', '');
insert into TOEFLWordBook values ('854', 'seemingly', '[ˈsiːmɪŋli]', 'http://dict.youdao.com/dictvoice?audio=seemingly', '{adv.}++貌似，看似（但可能并非如此）；似乎，好像（是事实）**{adv.}++from appearances alone																										        				&quot;the child is seemingly healthy but the doctor is concerned&quot;															   	同义词：								                                  				    apparently				    				    				      				    				      				    				                                      				    ostensibly				    				    				      				    				      				    				                                      				    on the face of it**', '');
insert into TOEFLWordBook values ('855', 'seep', '[siːp]', 'http://dict.youdao.com/dictvoice?audio=seep', '{v.}++（液体）渗漏，渗透；逐渐移动，渐渐散开**{n.}++（油、水）渗出地表的地方**{v.}++pass gradually or leak through or as if through small openings																					   	同义词：								                                  				    ooze**{vi.}++漏；渗出**{n.}++小泉；水陆两用的吉普车**', '');
insert into TOEFLWordBook values ('856', 'segment', '[ˈseɡmənt]', 'http://dict.youdao.com/dictvoice?audio=segment', '{n.}++部分，片段；（市场）细分的部分；（水果或花自然形成的）瓣，（昆虫的）节； 球缺，弓形；（直线或弧线上两点间的）段；（特定广播或电视节目的）时间段；某一时段单独播放的节目；音段**{v.}++分割，划分；（细胞）分裂**{n.}++one of several parts or pieces that fit with others to constitute a whole object																										        				&quot;finished the final segment of the road&quot;															   	同义词：								                                  				    section**{vi.}++分割**{n.}++[计]段；部分**{vt.}++分割**', '');
insert into TOEFLWordBook values ('857', 'segregate', '[ˈseɡrɪɡeɪt]', 'http://dict.youdao.com/dictvoice?audio=segregate', '{v.}++（尤指因种族、性别、宗教不同而）使隔离，使分开；实行种族隔离；（使）分开，分离；（成对的等位基因）分离**{n.}++（遗传）分离子；（植物学）集合物种中的一种**{n.}++someone who is or has been segregated**{v.}++separate by race or religion; practice a policy of racial segregation																										        													        				&quot;This neighborhood is segregated&quot;; &quot;We dont segregate in this county&quot;**{vt.}++使隔离；[生物]使分离；在…实行种族隔离**', '');
