insert into TOEFLWordBook values ('859', 'select', '[sɪˈlekt]', 'http://dict.youdao.com/dictvoice?audio=select', '{v.}++选择，挑选；（在计算机屏幕上）选定；（进化）决定（特征，生物）是否继续存在**{adj.}++精选的，优等的；高级的，奢华的**{v.}++pick out, select, or choose from a number of alternatives																										        				&quot;She selected a pair of shoes from among the dozen the salesgirl had shown her&quot;															   	同义词：								                                  				    choose				    				    				      				    				      				    				                                      				    take				    				    				      				    				      				    				                                      				    pick out**{adj.}++of superior grade																										        				&quot;select peaches&quot;															   	同义词：								                                  				    choice				    				    				      				    				      				    				                                      				    prime(a)				    				    				      				    				      				    				                                      				    prize				    				    				      				    				      				    				                                      				    quality**{vt.}++挑选；选拔**{adj.}++精选的；挑选出来的；极好的**{vi.}++挑选**', '');
insert into TOEFLWordBook values ('860', 'sensational', '[senˈseɪʃən(ə)l]', 'http://dict.youdao.com/dictvoice?audio=sensational', '{adj.}++轰动的，激动人心的；夸张的，耸人听闻的；非常好的，吸引人的**{adj.}++causing intense interest, curiosity, or emotion**{adj.}++轰动的；耸人听闻的；非常好的；使人感动的**', '');
insert into TOEFLWordBook values ('861', 'sensitive', '[ˈsensətɪv]', 'http://dict.youdao.com/dictvoice?audio=sensitive', '{adj.}++过敏的，易受影响的；灵敏的；善解人意的，体恤的；（问题、话题）敏感的，须谨慎对待的；机密的，保密的；理解的，意识到的；（对艺术、音乐、文学等）感受力强的，有悟性的；需保护的；小心谨慎的；（照相材料）感光的；（市场）脆弱的；神经过敏的，敏感的**{n.}++具有超自然通灵能力的人**{n.}++someone who serves as an intermediary between the living and the dead																					   	同义词：								                                  				    medium				    				    				      				    				      				    				                                      				    spiritualist**{adj.}++responsive to physical stimuli																										        													        													        													        				&quot;a mimosas leaves are sensitive to touch&quot;; &quot;a sensitive voltmeter&quot;; &quot;sensitive skin&quot;; &quot;sensitive to light&quot;**{adj.}++[仪]敏感的；灵敏的；感光的；易受伤害的**', '');
insert into TOEFLWordBook values ('862', 'sensory', '[ˈsensəri]', 'http://dict.youdao.com/dictvoice?audio=sensory', '{adj.}++感觉的，感官的**{adj.}++of a nerve fiber or impulse originating outside and passing toward the central nervous system																										        				&quot;sensory neurons&quot;															   	同义词：								                                  				    centripetal				    				    				      				    				      				    				                                      				    receptive**{adj.}++[生理]感觉的；知觉的；传递感觉的**', '');
insert into TOEFLWordBook values ('863', 'sentimental', '[ˌsentɪˈment(ə)l]', 'http://dict.youdao.com/dictvoice?audio=sentimental', '{adj.}++情感的（而非理性的）；多愁善感的，柔情的；（故事、电影、书等）感伤的，故作伤感的**{adj.}++given to or marked by sentiment or sentimentality**{adj.}++感伤的；感情脆弱的**', '');
insert into TOEFLWordBook values ('864', 'separately', '[ˈseprətli]', 'http://dict.youdao.com/dictvoice?audio=separately', '{adv.}++单独地，分别地**{adv.}++apart from others																					   	同义词：								                                  				    individually				    				    				      				    				      				    				                                      				    singly				    				    				      				    				      				    				                                      				    severally				    				    				      				    				      				    				                                      				    one by one				    				    				      				    				      				    				                                      				    on an individual basis**{adv.}++分别地；分离地；个别地**', '');
insert into TOEFLWordBook values ('865', 'sequence', '[ˈsiːkwəns]', 'http://dict.youdao.com/dictvoice?audio=sequence', '{n.}++顺序，次序；连续事件（或动作、事物）；（电影中表现同一主题或场面的）一组镜头；（生物学中分子或基因的排列）顺序；模进；（纸牌的）同花顺；序列；（天主教弥撒中圣歌与福音之间的）继续经**{v.}++按顺序排列；测定（整套基因或分子成分的）序列；用音序器播放（或录制）音乐**{n.}++serial arrangement in which things follow in logical order or a recurrent pattern																										        													        				&quot;the sequence of names was alphabetical&quot;; &quot;he invented a technique to determine the sequence of base pairs in DNA&quot;**{n.}++[数][计]序列；顺序；续发事件**', '');
insert into TOEFLWordBook values ('866', 'seriously', '[ˈsɪriəsli]', 'http://dict.youdao.com/dictvoice?audio=seriously', '{adv.}++严重地，恶劣地；严肃地，认真地；说正经的，说实在的；真的，当真；非常，极其**{adv.}++in a serious manner																										        				&quot;a play dealing seriously with the question of divorce&quot;															   	同义词：								                                  				    earnestly				    				    				      				    				      				    				                                      				    in earnest**{adv.}++认真地；严重地，严肃地**', '');
insert into TOEFLWordBook values ('867', 'session', '[ˈseʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=session', '{n.}++（某项活动的）一段时间，一场；（议会等的）会议，（法庭的）开庭；学年，上课时间；（酒吧中）演奏会（尤指演奏爱尔兰音乐）；（尤指录音师的）灌录音乐时间；酗酒期；基督教长老会的管理机构**{adj.}++（音乐家）伴奏的**{n.}++a meeting for execution of a groups functions																										        				&quot;it was the opening session of the legislature&quot;**{n.}++会议；（法庭的）[法]开庭；（议会等的）开会；学期；讲习会**', '');
insert into TOEFLWordBook values ('868', 'setting', '[ˈsetɪŋ]', 'http://dict.youdao.com/dictvoice?audio=setting', '{n.}++（某事发生的）环境，场合；（戏剧、小说或电影的）场景，背景；舞台布景；（设备的）档位；（宝石的）镶嵌底座；（为诗、祷文等谱写的）乐曲；（供一人用的）一副餐具**{v.}++（小心地）放置；嵌入（表面）；（电影、戏剧、故事等）以……为背景（set 的现在分词形式）**{n.}++the context and environment in which something is set																										        				&quot;the perfect setting for a ghost story&quot;															   	同义词：								                                  				    scene**{n.}++环境；安装；布置；[天]沉落**{v.}++放置；沉没；使…处于某位置（set的ing形式）**', '');
insert into TOEFLWordBook values ('869', 'severe', '[sɪˈvɪr]', 'http://dict.youdao.com/dictvoice?audio=severe', '{adj.}++十分严重的，极为恶劣的；艰巨的，严峻的；（惩罚、批评）严厉的，重的；严厉的，苛刻的；不加装饰的，朴素的**{adj.}++intensely or extremely bad or unpleasant in degree or quality																										        													        				&quot;severe pain&quot;; &quot;a severe case of flu&quot;															   	同义词：								                                  				    terrible				    				    				      				    				      				    				                                      				    wicked**{adj.}++严峻的；严厉的；剧烈的；苛刻的**', '');
insert into TOEFLWordBook values ('870', 'sew', '[soʊ]', 'http://dict.youdao.com/dictvoice?audio=sew', '{v.}++缝，缝纫，缝补**{v.}++fasten by sewing; do needlework																					   	同义词：								                                  				    run up				    				    				      				    				      				    				                                      				    sew together				    				    				      				    				      				    				                                      				    stitch**{vt.}++缝合，缝上；缝纫**{vi.}++缝纫，缝**', '');
insert into TOEFLWordBook values ('871', 'shade', '[ʃeɪd]', 'http://dict.youdao.com/dictvoice?audio=shade', '{n.}++背阴处，阴凉处；（图画中的）暗处；遮光物，灯罩；（能上下卷叠的）窗帘，百叶窗；太阳镜，墨镜（shades）；（色彩的）浓淡深浅，色度；差别，不同；略微，少量（a shade）；让人想起……的事物（shades of）；次要地位，不显眼；鬼，幽灵；地狱，冥府（the Shades）；剪影**{v.}++为……遮阳（挡光），遮蔽（光线）；（用铅笔或加色）描黑，描影；使阴暗，使阴郁；（色彩）渐变；（比赛）稍胜一筹，略占优势；（数量、速度或价格）略降；细微改动以掩盖事实**{n.}++relative darkness caused by light rays being intercepted by an opaque body																										        				&quot;it is much cooler in the shade&quot;															   	同义词：								                                  				    shadiness				    				    				      				    				      				    				                                      				    shadowiness**{n.}++树荫；阴影；阴凉处；遮阳物；（照片等的）明暗度；少量、些微；细微的差别**{vt.}++使阴暗；使渐变；为…遮阳；使阴郁；掩盖**{vi.}++（颜色、色彩等）渐变**', '');
insert into TOEFLWordBook values ('872', 'shake', '[ʃeɪk]', 'http://dict.youdao.com/dictvoice?audio=shake', '{v.}++摇动，抖动；削弱，动摇；发抖，哆嗦；握手；使震惊，使烦乱；使改变（态度、信念）；摆脱，克服；舞动（拳头、棍子等）；抖掉，抖出；使劲甩动，急剧晃动；摇头（以示否定）；（声音）颤抖**{n.}++摇动，摇晃；奶昔；（摇动容器后的）撒出物；哆嗦，颤抖（the shakes）；木制墙面板；地震；（乐）颤音**{n.}++building material used as siding or roofing																					   	同义词：								                                  				    shingle**{vt.}++动摇；摇动；震动**{vi.}++动摇；摇动；发抖**{n.}++摇动；哆嗦**', '');
insert into TOEFLWordBook values ('873', 'shallow', '[ˈʃæloʊ]', 'http://dict.youdao.com/dictvoice?audio=shallow', '{adj.}++浅的，不深的；肤浅的，浅薄的；（呼吸）浅的，微弱的；平缓的；靠近内线的**{n.}++（海、湖或河的）浅水处，浅滩（shallows）**{v.}++（使）变浅**{n.}++a stretch of shallow water																					   	同义词：								                                  				    shoal**{v.}++make shallow																										        				&quot;The silt shallowed the canal&quot;															   	同义词：								                                  				    shoal**{adj.}++浅的；肤浅的**{n.}++[地理]浅滩**{vt.}++使变浅**{vi.}++变浅**', '');
insert into TOEFLWordBook values ('874', 'sharp', '[ʃɑːrp]', 'http://dict.youdao.com/dictvoice?audio=sharp', '{adj.}++锋利的，尖的；急转弯的；（变化）急剧的；清晰的，鲜明的；剧烈的，强烈的；（语言）尖锐的；刺耳的；聪明的，敏锐的；（味道）浓烈的，辛辣的；时髦的；（风或霜）刺骨的；狡诈的；（音）偏高（的），升半音（的）；瘦削的，不丰满的**{adv.}++正点，准时；突然地，急剧地；音调偏高地**{n.}++升半音，升半音号；锐利的东西；骗子**{v.}++升音演奏**{n.}++a musical notation indicating one half step higher than the note named**{adj.}++急剧的；锋利的；强烈的；敏捷的；刺耳的**{adv.}++急剧地；锐利地；突然地**{n.}++尖头；骗子；内行**{vt.}++磨快；把音调升高**{vi.}++打扮；升音演奏**', '');
insert into TOEFLWordBook values ('875', 'shed', '[ʃed]', 'http://dict.youdao.com/dictvoice?audio=shed', '{v.}++去除，摆脱；（植物）落（叶），（动物）蜕（皮），脱（毛）；脱掉（所穿衣物）；掉落（货物）；挡水，防水；射出，发出（光）；流，洒，落（泪）；（尤指在战争中）造成伤亡，使流（血）；把（车）停在库棚内；（分区）切断（电力载荷）**{n.}++棚屋，小屋；（工业上用于生产或存放设备的）厂房，工棚；剪羊棚，挤奶棚**{n.}++an outbuilding with a single story; used for shelter or storage**{v.}++get rid of																										        													        				&quot;he shed his image as a pushy boss&quot;; &quot;shed your clothes&quot;															   	同义词：								                                  				    cast				    				    				      				    				      				    				                                      				    cast off				    				    				      				    				      				    				                                      				    shake off				    				    				      				    				      				    				                                      				    throw				    				    				      				    				      				    				                                      				    throw off				    				    				      				    				      				    				                                      				    throw away				    				    				      				    				      				    				                                      				    drop**{vt.}++流出；摆脱；散发；倾吐**{vi.}++流出；脱落；散布**{n.}++小屋，棚；分水岭**', '');
insert into TOEFLWordBook values ('876', 'sheer', '[ʃɪr]', 'http://dict.youdao.com/dictvoice?audio=sheer', '{adj.}++（用于强调）纯粹的，完全的；程度深的，数量大的；陡峭的，垂直的；（织物等）极薄的，透明的**{adv.}++垂直地，陡峭地；彻底地，完全地**{v.}++急转弯，突然转向；避开（不愉快的话题）**{n.}++精纺（或透明）织物（或物品）；（尤指船）突然偏航，突然转向；（船首及船尾处的）舷弧**{v.}++turn sharply; change direction abruptly																					   	同义词：								                                  				    swerve				    				    				      				    				      				    				                                      				    curve				    				    				      				    				      				    				                                      				    trend				    				    				      				    				      				    				                                      				    veer				    				    				      				    				      				    				                                      				    slue				    				    				      				    				      				    				                                      				    slew				    				    				      				    				      				    				                                      				    cut**{adj.}++绝对的；透明的；峻峭的**{adv.}++完全；陡峭地**{vi.}++偏航**{vt.}++使偏航；使急转向**{n.}++偏航；[纺]透明薄织物**', '');
insert into TOEFLWordBook values ('877', 'sheet', '[ʃiːt]', 'http://dict.youdao.com/dictvoice?audio=sheet', '{n.}++床单，被单；布罩，盖布；纸片，纸张；（Excel 中的）工作表；简要记录，纪要；一整版邮票；（尤指大地区系列地图的一部分的）一张地图；薄板，薄片；（冰或水的）一大片；（雨或火）一大片；拉帆绳，帆脚索；敞舱船的首尾区域**{v.}++（用布）盖上，裹上；把（帆）扣紧（或放松）；（雨）倾盆（或瓢泼）而下**{n.}++any broad thin expanse or surface																										        				&quot;a sheet of ice&quot;**{n.}++薄片，纸张；[材]薄板；床单**{vt.}++覆盖；盖上被单；使成大片**{adj.}++片状的**', '');
insert into TOEFLWordBook values ('878', 'shift', '[ʃɪft]', 'http://dict.youdao.com/dictvoice?audio=shift', '{v.}++（使）移动，（使）转移；（使）转换到（另一个人或另一事物）；（使）改变意见（或信仰等）；赶快；换（挡）；（计算机）移位；按（计算机键盘上的）Shift 键；摆脱，消除；（尤指大量）销售，出售；狼吞虎咽地吃；含糊其辞，拐弯抹角**{n.}++改变，转变；轮班工作时间；轮班工作的人；（计算机键盘上的）Shift 键；（计算机）移位；（机动车的）换挡装置；宽松直筒连衣裙（=shift dress）；长而宽松的内衣；（建筑）错位；（美橄）（开赛前）球员位置的变换；（天文）（光谱线的）偏移；语音演变（sound shift 的简称）；计谋，诡计**{n.}++an event in which something is displaced without rotation																					   	同义词：								                                  				    displacement**{n.}++移动；变化；手段；轮班**{vi.}++移动；转变；[遗]转换**{vt.}++转移；改变；替换**', '');
insert into TOEFLWordBook values ('879', 'shine', '[ʃaɪn]', 'http://dict.youdao.com/dictvoice?audio=shine', '{v.}++（太阳或其他光源）发光，照耀；（用电筒等）照射；（表面）发亮；磨光，擦亮；（眼睛或脸上因快乐而）放光；表现突出，出众**{n.}++光亮，光泽；擦亮**{n.}++the quality of being bright and sending out rays of light																					   	同义词：								                                  				    radiance				    				    				      				    				      				    				                                      				    radiancy				    				    				      				    				      				    				                                      				    effulgence				    				    				      				    				      				    				                                      				    refulgence				    				    				      				    				      				    				                                      				    refulgency**{v.}++be bright by reflecting or casting light																					   	同义词：								                                  				    reflect**{vi.}++照耀；显露；出众**{n.}++光泽；擦亮；晴天**{vt.}++擦亮；把…的光投向**', '');
insert into TOEFLWordBook values ('880', 'shock', '[ʃɑːk]', 'http://dict.youdao.com/dictvoice?audio=shock', '{n.}++令人震惊的事；吃惊，震惊；休克；电击，触电；减震器；（对经济、传统、生活方式的）冲击，撞击；（爆炸、地震等引起的）剧烈震动；浓密的头发；愤怒，生气；冲击力 ；（竖放在地里促使谷物更快晒干和成熟的）禾束堆**{v.}++使震惊，使难以置信；（言语或行为）（使）愤慨，（使）生气；使触电，使遭电击；使恐惧（或厌恶）；使生理休克；把......堆成禾束堆**{adj.}++令人震惊的，令人大感意外的（尤用于新闻报道）；浓密的，蓬乱的**{n.}++the feeling of distress and disbelief that you have when something bad happens accidentally																										        				&quot;he was numb with shock&quot;															   	同义词：								                                  				    daze				    				    				      				    				      				    				                                      				    stupor**{n.}++[临床]休克；震惊；震动；打击；禾束堆**{vt.}++[临床]使休克；使震惊；使震动；使受电击；把…堆成禾束堆**{adj.}++浓密的；蓬乱的**', '');
insert into TOEFLWordBook values ('881', 'shortage', '[ˈʃɔːrtɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=shortage', '{n.}++短缺，不足**{n.}++the property of being an amount by which something is less than expected or required																					   	同义词：								                                  				    deficit				    				    				      				    				      				    				                                      				    shortfall**{n.}++缺乏，缺少；不足**', '');
insert into TOEFLWordBook values ('882', 'shut', '[ʃʌt]', 'http://dict.youdao.com/dictvoice?audio=shut', '{v.}++关闭，合上；把……关在；（使）停止运作，（使）停止营业；禁止通行，封闭**{adj.}++关闭的，关上的；打烊的，停止营业的**{n.}++关闭**{v.}++move so that an opening or passage is obstructed; make shut																										        				&quot;shut the window&quot;															   	同义词：								                                  				    close**{vt.}++关闭；停业；幽禁**{n.}++关闭**{adj.}++关闭的；围绕的**', '');
insert into TOEFLWordBook values ('883', 'sight', '[saɪt]', 'http://dict.youdao.com/dictvoice?audio=sight', '{n.}++视力，视觉；看见，见到；视野，视域；景物，景象；名胜，景点（sights）；志向，目标；（枪或炮上的）瞄准器，（光学仪器的）观测器； 奇怪的人，滑稽的人（或事物）； 许多，大量； 观点，见解**{v.}++（突然）看到，（远远）看见；把（枪）瞄准；（用观测器）观测；调整（火器）的瞄准器，调整（光学仪器）的观测器**{adj.}++见票即付的；即席的**{n.}++an instance of visual perception																										        													        				&quot;the sight of his wife brought him back to reality&quot;; &quot;the train was an unexpected sight&quot;**{n.}++视力；景象；眼界；见解**{vt.}++看见；瞄准**{vi.}++瞄准；观看**{adj.}++见票即付的；即席的**', '');
insert into TOEFLWordBook values ('884', 'signature', '[ˈsɪɡnətʃər]', 'http://dict.youdao.com/dictvoice?audio=signature', '{n.}++签名，署名；签字，签署；鲜明特色，明显特征；（印刷）折标；书贴；标记，用法签（处方上说明药的用法的部分）；（音乐的）拍号；（音乐的）调号**{adj.}++标志性的，惯有的**{n.}++your name written in your own handwriting**{n.}++署名；签名；信号**', '');
insert into TOEFLWordBook values ('885', 'silence', '[ˈsaɪləns]', 'http://dict.youdao.com/dictvoice?audio=silence', '{n.}++寂静，无声；沉默，默不作声:；保持沉默，拒绝回答；无音信，失去联系；默哀，静默**{v.}++使安静，使不说话；压制，使不再发表（反对意见）；杀……灭口；给（枪，排气系统）装消音器**{int.}++（用以让人们安静）安静，静下来**{n.}++the state of being silent (as when no one is speaking)																										        													        				&quot;there was a shocked silence&quot;; &quot;he gestured for silence&quot;**{n.}++沉默；寂静；缄默；不谈；无声状态**{vt.}++使沉默；使安静；压制；消除噪音**', '');
insert into TOEFLWordBook values ('886', 'silt', '[sɪlt]', 'http://dict.youdao.com/dictvoice?audio=silt', '{n.}++淤泥，泥沙；粉砂尘，泥沙层；（技）粉砂**{v.}++（使）淤塞**{n.}++mud or clay or small rocks deposited by a river or lake**{v.}++become chocked with silt																										        				&quot;The river silted up&quot;															   	同义词：								                                  				    silt up**{n.}++淤泥，[地质]泥沙；煤粉；残渣**{vi.}++淤塞，充塞；为淤泥堵塞**{vt.}++使淤塞；充塞**', '');
insert into TOEFLWordBook values ('887', 'sink', '[sɪŋk]', 'http://dict.youdao.com/dictvoice?audio=sink', '{v.}++下沉，沉没；使失败，受挫；下降，下陷；倒下，坐下；衰退，恶化；渗透，渐渐陷入；减少，降低；（声音）变低，变小；堕落，沉沦；挖掘；插入，打入；投进，滚进；投资；喝（酒）**{adj.}++贫困的，贫民窟的**{n.}++水槽，水池；洼地，渗坑；位于社会贫困地区的学校或房产；藏垢的场所；汇，壑**{n.}++plumbing fixture consisting of a water basin fixed to a wall or floor and having a drainpipe**{vi.}++下沉；消沉；渗透**{vt.}++使下沉；挖掘；使低落**{n.}++[化工]水槽；洗涤槽；污水坑**', '');
insert into TOEFLWordBook values ('888', 'skeleton', '[ˈskelɪt(ə)n]', 'http://dict.youdao.com/dictvoice?audio=skeleton', '{n.}++骨骼，骨架；梗概，提纲；骨瘦如柴的人（或动物）；（建筑物、桥梁等的）框架，骨架；（维持运转所需的）最少人员，基干人员；钢架雪车**{adj.}++（员工）最基本的，基干的**{n.}++something reduced to its minimal form																										        													        				&quot;the battalion was a mere skeleton of its former self&quot;; &quot;the bare skeleton of a novel&quot;**{n.}++[测][建]骨架，[解剖]骨骼；纲要；骨瘦如柴的人**{adj.}++[解剖]骨骼的；骨瘦如柴的；概略的**', '');
insert into TOEFLWordBook values ('889', 'sketch', '[sketʃ]', 'http://dict.youdao.com/dictvoice?audio=sketch', '{n.}++素描，速写，草图；（任何作品的）粗样，初稿；简述，概述；幽默短剧，滑稽小品；滑稽的人（或物）**{v.}++（给……）画速写，（给……）画素描；简述，概述；（用手或身体）做（姿势）**{n.}++preliminary drawing for later elaboration																					   	同义词：								                                  				    study**{n.}++素描；略图；梗概**', '');
