insert into TOEFLWordBook values ('891', 'slice', '[slaɪs]', 'http://dict.youdao.com/dictvoice?audio=slice', '{n.}++（切下的食物）薄片，片；（蛋糕等的）小块 ；水果切块；部分，份；例子；（体育运动中的）斜切球，削球，侧旋球；（切片用的）薄刀，（铲食物用的）铲子**{v.}++把……切成薄片；切，割，划；轻易快速穿过（空气或水等）；削（球），斜切打；（无意中）打出弧线球；减少（时间、钱等）**{n.}++a share of something																										        				&quot;a slice of the companys revenue&quot;															   	同义词：								                                  				    piece**{n.}++薄片；部分；菜刀，火铲**{vt.}++切下；把…分成部分；将…切成薄片**{vi.}++切开；割破**', '');
insert into TOEFLWordBook values ('892', 'slightly', '[ˈslaɪtli]', 'http://dict.youdao.com/dictvoice?audio=slightly', '{adv.}++稍微，轻微地；（指某人身材）纤弱地，瘦小地**{adv.}++to a small degree or extent																										        				&quot;the children argued because one slice of cake was slightly larger than the other&quot;															   	同义词：								                                  				    somewhat**', '');
insert into TOEFLWordBook values ('893', 'slip', '[slɪp]', 'http://dict.youdao.com/dictvoice?audio=slip', '{v.}++滑倒，失足；滑落，脱落；溜走，悄悄地走；偷偷塞进；滑行，打滑；下降，变差；陷入；迅速穿上，迅速脱下；摆脱，挣脱；飞逝，过得飞快；被（某人）忘记；放出（动物，尤指猎狗）；（身体部分）移位，脱臼；（编织）挑过一针不结；略微松动（汽车离合器）；（动物）流产**{n.}++疏漏，差错；小纸条；滑，滑倒；滑动；衬裙；（击球员后侧的）守场员；（制陶器用的）泥浆，泥釉；（飞机飞行中的）侧滑；牵狗皮带；（两个码头之间）泊位；（编织）挑针；变糟，下跌；接枝，插枝；瘦小的年轻人**{n.}++a socially awkward or tactless act																					   	同义词：								                                  				    faux pas				    				    				      				    				      				    				                                      				    gaffe				    				    				      				    				      				    				                                      				    solecism				    				    				      				    				      				    				                                      				    gaucherie**{a minor inadvertent mistake usually observed in speech or writing or in small accidents or memory lapses etc.}++同义词：								                                  				    slip-up				    				    				      				    				      				    				                                      				    miscue				    				    				      				    				      				    				                                      				    parapraxis**{vi.}++[地质]滑动；滑倒；犯错；失足；减退**{vt.}++[地质]使滑动；滑过；摆脱；塞入；闪开**{n.}++滑，滑倒；片，纸片；错误；下跌；事故**{adj.}++[地质]滑动的；有活结的；活络的**', '');
insert into TOEFLWordBook values ('894', 'slope', '[sloʊp]', 'http://dict.youdao.com/dictvoice?audio=slope', '{n.}++斜坡，斜面；山坡；滑雪斜坡；斜度，坡度；（电子）斜率；扛枪姿势； 东方人（尤指越南人）**{v.}++倾斜，成斜坡；歪斜；悄悄地走，溜； 逛，随意走动**{n.}++an elevated geological formation																										        				&quot;he climbed the steep slope&quot;															   	同义词：								                                  				    incline				    				    				      				    				      				    				                                      				    side**{n.}++斜坡；倾斜；[数]斜率；扛枪姿势**{vi.}++倾斜；逃走**{vt.}++倾斜；使倾斜；扛**', '');
insert into TOEFLWordBook values ('895', 'smell', '[smel]', 'http://dict.youdao.com/dictvoice?audio=smell', '{n.}++气味；臭味；嗅觉；嗅，闻**{v.}++有……气味，发出......的气味；闻出，闻到；（用鼻子凑过去）闻，嗅；有嗅觉，能闻出（smell sth. out）；散发异味，有难闻的气味；觉察出，感觉到；看起来像，有……意味**{n.}++the sensation that results when olfactory receptors in the nose are stimulated by particular chemicals in gaseous form																										        				&quot;she loved the smell of roses&quot;															   	同义词：								                                  				    odor				    				    				      				    				      				    				                                      				    odour				    				    				      				    				      				    				                                      				    olfactory sensation				    				    				      				    				      				    				                                      				    olfactory perception**{vi.}++[生理]嗅，闻；有…气味**{vt.}++[生理]嗅，闻；察觉到；发出…的气味**{n.}++气味，[生理]嗅觉；臭味**', '');
insert into TOEFLWordBook values ('896', 'smoke', '[smoʊk]', 'http://dict.youdao.com/dictvoice?audio=smoke', '{n.}++（燃烧所产生的）烟，烟雾；吸烟，抽烟；（抽的）香烟，（吸的）毒品； （伦敦之类的）大城市（the Smoke）；无常的事物**{v.}++吸烟，吸毒品；（作为习惯）抽烟；冒烟，冒气；用烟熏制；（战斗或竞赛中）彻底击败；开枪杀死（某人）；用力快击（球）；弥漫**{n.}++a cloud of fine particles suspended in a gas																					   	同义词：								                                  				    fume**{n.}++[环境]烟；抽烟；无常的事物**{vi.}++冒烟，吸烟；抽烟；弥漫**{vt.}++吸烟；抽**', '');
insert into TOEFLWordBook values ('897', 'smooth', '[smuːð]', 'http://dict.youdao.com/dictvoice?audio=smooth', '{adj.}++（表面）光滑的，平坦的，平整的；顺利的，无困难的；（动作等）流畅的，（骑马、航行等）平稳的；（人）圆滑的，八面玲珑的；（液体混合物）均匀的，不结块的；（声音）圆润的，悦耳的；（味道、气味等）醇和的，不烈的；（网球拍或软式壁球拍无线结的一面）光面，滑面**{v.}++抚平，弄平滑；轻轻地涂擦（液体、面霜等）；解决问题，消除困难；修改（图表、曲线等）以减少不规则现象；缓和；使优雅**{n.}++平滑部分**{adv.}++光滑地，平稳地，流畅地**{n.}++the act of smoothing																										        				&quot;he gave his hair a quick smooth&quot;**{v.}++make smooth or smoother, as if by rubbing																										        				&quot;smooth the surface of the wood&quot;															   	同义词：								                                  				    smoothen**{adj.}++顺利的；光滑的；平稳的**{vt.}++使光滑；消除（障碍等）；使优雅；缓和**{adv.}++光滑地；平稳地；流畅地**', '');
