insert into TOEFLWordBook values ('900', 'soaring', '[sɔːrɪŋ]', 'http://dict.youdao.com/dictvoice?audio=soaring', '{adj.}++翱翔的；高耸的；猛增的**{n.}++高耸；高飞；猛增**{v.}++高耸；高飞；猛增（soar 的现在分词）**{n.}++the activity of flying a glider																					   	同义词：								                                  				    glide				    				    				      				    				      				    				                                      				    gliding				    				    				      				    				      				    				                                      				    sailplaning				    				    				      				    				      				    				                                      				    sailing**{adj.}++ascending to a level markedly higher than the usual																										        				&quot;soaring prices&quot;**{adj.}++[航]翱翔的；高耸的；猛增的**{v.}++高耸（soar的现在分词形式）；高飞；猛增**', '');
insert into TOEFLWordBook values ('901', 'soldier', '[ˈsoʊldʒər]', 'http://dict.youdao.com/dictvoice?audio=soldier', '{n.}++士兵，军人；（昆） 兵蚁；垂直的砖（或木头等建筑材料）；面包条，土司条；懒汉**{v.}++当兵；坚持不懈，迎难而上（~ on）；假称害病；磨洋工**{n.}++an enlisted man or woman who serves in an army																										        				&quot;the soldiers stood at attention&quot;**{n.}++军人；[昆]兵蚁；懒汉；一片烤面包**{vi.}++当兵；磨洋工；坚持干；假称害病**', '');
