insert into TOEFLWordBook values ('903', 'solitary', '[ˈsɑːləteri]', 'http://dict.youdao.com/dictvoice?audio=solitary', '{adj.}++独自的，单独的；偏僻的，孤立的；独自完成的；（人或动物）独处的，独居的；（花或其他部分）单生的；唯一的，仅有的**{n.}++单独监禁；独居者，隐士**{n.}++confinement of a prisoner in isolation from other prisoners																										        				&quot;he was held in solitary&quot;															   	同义词：								                                  				    solitary confinement**{adj.}++[动]孤独的；独居的**{n.}++[动]独居者；隐士**', '');
