insert into TOEFLWordBook values ('905', 'sophisticated', '[səˈfɪstɪkeɪtɪd]', 'http://dict.youdao.com/dictvoice?audio=sophisticated', '{adj.}++见多识广的，老练的，见过世面的；复杂巧妙的，先进的，精密的；水平高的，在行的；时尚的，精致的**{v.}++使老于世故；使（设备、技术等）更复杂先进；（老练地）讲话（或推理）（sophisticate 的过去式和过去分词形式）**{adj.}++having or appealing to those having worldly knowledge and refinement and savoir-faire																										        													        													        													        				&quot;sophisticated young socialites&quot;; &quot;a sophisticated audience&quot;; &quot;a sophisticated lifestyle&quot;; &quot;a sophisticated book&quot;**{adj.}++复杂的；精致的；久经世故的；富有经验的**{v.}++使变得世故；使迷惑；篡改（sophisticate的过去分词形式）**', '');
insert into TOEFLWordBook values ('906', 'sort', '[sɔːrt]', 'http://dict.youdao.com/dictvoice?audio=sort', '{n.}++种类，品种；某一种（或某一类）人；（计算机对信息的）分类，排序；程度，方式**{v.}++整理，把……分类，拣选；妥善处理，安排妥当；交往；协调**{n.}++a category of things distinguished by some common characteristic or quality																					   	同义词：								                                  				    kind				    				    				      				    				      				    				                                      				    form				    				    				      				    				      				    				                                      				    variety**{n.}++种类；方式；品质**{vi.}++[计]分类；协调；交往**{vt.}++将…分类；将…排序；挑选出某物**', '');
insert into TOEFLWordBook values ('907', 'soul', '[soʊl]', 'http://dict.youdao.com/dictvoice?audio=soul', '{n.}++灵魂；心灵；某种人；（用于否定句中）一个人（也没有）；灵乐；感受强烈感情的能力；（艺术、音乐作品或文章中的）热情，气魄；精神，精髓；（某地的）人们，人口（souls）；（人类整体的）精神状况，道德品质；（某种品质的）典范，化身；美国黑人文化（或种族尊严）；鬼魂**{adj.}++激情黑人的，黑人文化的**{n.}++the immaterial part of a person; the actuating cause of an individual life																					   	同义词：								                                  				    psyche**{n.}++灵魂；心灵；精神；鬼魂**', '');
