insert into TOEFLWordBook values ('909', 'spacious', '[ˈspeɪʃəs]', 'http://dict.youdao.com/dictvoice?audio=spacious', '{adj.}++（房间或建筑物）宽敞的；无边无际的**{adj.}++very large in expanse or scope																										        													        				&quot;a spacious view&quot;; &quot;spacious skies&quot;															   	同义词：								                                  				    broad				    				    				      				    				      				    				                                      				    wide**{adj.}++宽敞的，广阔的；无边无际的**', '');
insert into TOEFLWordBook values ('910', 'spare', '[sper]', 'http://dict.youdao.com/dictvoice?audio=spare', '{adj.}++备用的，外加的；不用的，闲置的；空闲的，空余的；多余的；简单的，简朴的；瘦的，瘦高的；少量的；节约的**{v.}++抽出，拿出（时间、金钱等）；饶恕，赦免；省得，免去；节约，吝惜；保证（或满足）自己的需要（spare oneself）；剩余，剩下（时间、金钱或空间）；分让；删节**{n.}++备用品；（车辆或机器的）零件，备件；（十柱保龄球戏中的）二击全倒**{n.}++an extra component of a machine or other apparatus																					   	同义词：								                                  				    spare part**{vt.}++节约，吝惜；饶恕；分出，分让**{vi.}++饶恕，宽恕；节约**{adj.}++多余的；瘦的；少量的**{n.}++剩余；备用零件**', '');
insert into TOEFLWordBook values ('911', 'specialty', '[ˈspeʃəlti]', 'http://dict.youdao.com/dictvoice?audio=specialty', '{n.}++专业，专长；特色食品，特产；特产， 专卖店；（律）盖印的书面合同**{n.}++an asset of special worth or utility																					   	同义词：								                                  				    forte				    				    				      				    				      				    				                                      				    strong suit				    				    				      				    				      				    				                                      				    long suit				    				    				      				    				      				    				                                      				    metier				    				    				      				    				      				    				                                      				    speciality				    				    				      				    				      				    				                                      				    strong point				    				    				      				    				      				    				                                      				    strength**{n.}++专业，专长；特产；特性；招牌菜**{adj.}++特色的；专门的；独立的**', '');
insert into TOEFLWordBook values ('912', 'species', '[ˈspiːʃiːz]', 'http://dict.youdao.com/dictvoice?audio=species', '{n.}++（动植物的）种，物种；种类；（具有相同特征的）一类人；（化学，物理）核素；（圣餐中用的）面包和圣酒**{adj.}++原种的**{n.}++(biology) taxonomic group whose members can interbreed**{n.}++[生物]物种；种类**', '');
insert into TOEFLWordBook values ('913', 'specify', '[ˈspesɪfaɪ]', 'http://dict.youdao.com/dictvoice?audio=specify', '{v.}++明确指出；具体说明；把……列入说明书**{v.}++specify as a condition or requirement in a contract or agreement; make an express demand or provision in an agreement																					   	同义词：								                                  				    stipulate				    				    				      				    				      				    				                                      				    qualify				    				    				      				    				      				    				                                      				    condition**{vt.}++指定；详细说明；列举；把…列入说明书**', '');
insert into TOEFLWordBook values ('914', 'specimen', '[ˈspesɪmən]', 'http://dict.youdao.com/dictvoice?audio=specimen', '{n.}++样品，标本；（尤指动植物的）实例；（化验的）抽样，血样，尿样；具有……特性的人（幽默用法）**{n.}++an example regarded as typical of its class**{n.}++样品，[图情]样本；标本**', '');
insert into TOEFLWordBook values ('915', 'spectacle', '[ˈspektək(ə)l]', 'http://dict.youdao.com/dictvoice?audio=spectacle', '{n.}++精彩的表演，壮观的场面；壮观的景象；不寻常的事，出人意料的情况；眼镜（spectacles）**{n.}++something or someone seen (especially a notable or unusual sight)																										        				&quot;the tragic spectacle of cripples trying to escape&quot;**{n.}++景象，奇观；眼镜；引人羡慕的人**', '');
insert into TOEFLWordBook values ('916', 'sphere', '[sfɪr]', 'http://dict.youdao.com/dictvoice?audio=sphere', '{n.}++（活动、兴趣、专业知识的）范围，领域；球体，球，球形；社会阶层；势力范围；苍穹，天，天空；天体；天体外壳；地球仪**{vt.}++使……成球形；包围；放入球内**{n.}++a particular environment or walk of life																										        				&quot;his social sphere is limited&quot;															   	同义词：								                                  				    domain				    				    				      				    				      				    				                                      				    area				    				    				      				    				      				    				                                      				    orbit				    				    				      				    				      				    				                                      				    field				    				    				      				    				      				    				                                      				    arena**{n.}++范围；[数]球体**{vt.}++包围；放入球内；使…成球形**', '');
insert into TOEFLWordBook values ('917', 'spin', '[spɪn]', 'http://dict.youdao.com/dictvoice?audio=spin', '{v.}++（使）快速旋转；（使）急转身；（头感到）眩晕；纺纱，纺织；飞驰，疾驰；编故事；有倾向性地陈述；（用甩干机或洗衣机）甩干（衣服）；（昆虫）吐（丝），结（网）；（用旋式诱饵）钓鱼；播放（唱片）；抛（硬币）；（球）旋转；（用车床将金属薄板）旋压成形**{n.}++高速旋转；兜风；带倾向性的解释（或说法）；（政治上的）倾向性报道；（尤指板球、网球、斯诺克球中的）旋转球；（飞机的）旋冲，螺旋下降；晕头转向，焦虑不安；（物理）核素总角动量**{n.}++a swift whirling motion (usually of a missile)**{vi.}++[物]旋转；纺纱；吐丝；晕眩**{vt.}++[物]使旋转；纺纱；编造；结网**{n.}++[物]旋转；疾驰**', '');
insert into TOEFLWordBook values ('918', 'spine', '[spaɪn]', 'http://dict.youdao.com/dictvoice?audio=spine', '{n.}++脊髓，脊柱；书脊；（动植物的）刺，刺毛；中心力量，中流砥柱；骨气，勇气；直线型薪酬级别制；（地质）火山栓，熔岩塔**{n.}++the series of vertebrae forming the axis of the skeleton and protecting the spinal cord																					   	同义词：								                                  				    spinal column				    				    				      				    				      				    				                                      				    vertebral column				    				    				      				    				      				    				                                      				    backbone				    				    				      				    				      				    				                                      				    back				    				    				      				    				      				    				                                      				    rachis**{n.}++[解剖]脊柱，脊椎；[生物]刺；[印刷][图情]书脊**', '');
insert into TOEFLWordBook values ('919', 'spiral', '[ˈspaɪrəl]', 'http://dict.youdao.com/dictvoice?audio=spiral', '{n.}++螺旋形，螺旋形之物；持续加剧的上升（或下降、恶化）；旋球**{v.}++螺旋式上升（或下降），盘旋上升（或下降）；持续下降，持续恶化；急剧上升**{adj.}++螺旋形的；（医）扭折（骨折的一种）；spiral-bound的简称**{n.}++a plane curve traced by a point circling about the center but at increasing distances from the center**{n.}++[机]螺旋；旋涡；螺旋形之物**{adj.}++螺旋形的；盘旋的**', '');
insert into TOEFLWordBook values ('920', 'spirit', '[ˈspɪrɪt]', 'http://dict.youdao.com/dictvoice?audio=spirit', '{n.}++精神，心灵；情绪，心境；勇气，意志，活力；（对团体、队伍、社会的）忠心，（群体中的）态度，精神；心态，态度；本质，精髓，基本精神；真实意义，实质；灵魂，鬼魂；具有特别品质的人物，在群体或活动中发挥特殊作用的人物；烈酒；挥发性液体（尤指用蒸馏法提炼的燃料）；神灵；圣灵（Spirit，Holy Spirit 的简称）**{v.}++偷偷带走，秘密弄走；鼓励，鼓舞**{n.}++the vital principle or animating force within living things**{n.}++精神；心灵；情绪；志气；烈酒**{vt.}++鼓励；鼓舞；诱拐**', '');
insert into TOEFLWordBook values ('921', 'splendid', '[ˈsplendɪd]', 'http://dict.youdao.com/dictvoice?audio=splendid', '{adj.}++极佳的，非常好的；壮丽的，灿烂的，辉煌的；（一段时光）令人愉快的**{int.}++（表示赞许或满意）好极了，痛快**{adj.}++having great beauty and splendor																										        				&quot;splendid costumes&quot;															   	同义词：								                                  				    glorious				    				    				      				    				      				    				                                      				    resplendent				    				    				      				    				      				    				                                      				    splendiferous**{adj.}++辉煌的；灿烂的；极好的；杰出的**', '');
insert into TOEFLWordBook values ('922', 'spoil', '[spɔɪl]', 'http://dict.youdao.com/dictvoice?audio=spoil', '{v.}++破坏，糟蹋；溺爱，宠坏；善待，格外关照；（食物）变质，腐败；使（选票）作废；极度渴望，跃跃欲试；抢劫（人，地方），掠夺**{n.}++赃物，战利品（the spoils）；成功所带来的好处（spoils）；（开掘时挖出的）废土，废泥土**{n.}++(usually plural) valuables taken by violence (especially in war)																										        				&quot;to the victor belong the spoils of the enemy&quot;**{vt.}++溺爱；糟蹋；掠夺**{vi.}++掠夺；变坏；腐败**{n.}++次品；奖品**', '');
insert into TOEFLWordBook values ('923', 'sponge', '[spʌndʒ]', 'http://dict.youdao.com/dictvoice?audio=sponge', '{n.}++（擦洗用的天然或人造的）海绵块；（用海绵或布）擦拭，擦洗；海绵蛋糕，松软布丁；依赖他人生活的寄生虫，揩油者；海绵（一种海洋软体动物）；（女用）避孕海绵；海绵填料；金属绵**{v.}++用海绵擦洗；用湿布（或海绵）擦掉，揩去；白吃，揩油；用海绵抹（漆）**{n.}++a porous mass of interlacing fibers the forms the internal skeleton of various marine animals and usable to absorb water or any porous rubber or cellulose product similarly used**{vt.}++抹掉；用海绵擦拭；讨得**{vi.}++采集海绵；过寄生生活；海绵般地吸收**{n.}++[橡胶][无脊椎]海绵；海绵状物**', '');
insert into TOEFLWordBook values ('924', 'sponsor', '[ˈspɑːnsər]', 'http://dict.youdao.com/dictvoice?audio=sponsor', '{n.}++赞助者，赞助商；（培训或教育的）资助者；（慈善活动的）捐款者，捐资机构；法案的倡议者；担保人，保证人；（宗教事宜中的）引领人**{v.}++赞助（活动、节目等）； 为慈善活动捐资，为义赛捐款；倡议，提交（法案等）；主办，促成；纵容；为……担保**{n.}++someone who supports or champions something																					   	同义词：								                                  				    patron				    				    				      				    				      				    				                                      				    supporter**{an advocate who presents a person (as for an award or a degree or an introduction etc.}++)																					   	同义词：								                                  				    presenter**{n.}++赞助者；主办者；保证人**{vt.}++赞助；发起**', '');
insert into TOEFLWordBook values ('925', 'spoon', '[spuːn]', 'http://dict.youdao.com/dictvoice?audio=spoon', '{n.}++匙，勺子；（作打击乐器用的）调羹对；一匙的量；调羹状物品**{vt.}++用匙舀，使成匙状；高挑球**{n.}++a piece of cutlery with a shallow bowl-shaped container and a handle; used to stir or serve or take up food**{n.}++匙，勺子；一杓的量**', '');
insert into TOEFLWordBook values ('926', 'spur', '[spɜːr]', 'http://dict.youdao.com/dictvoice?audio=spur', '{n.}++一时冲动之下，心血来潮；刺激，激励；山嘴，尖坡；（公路或铁路的）支线，岔线；马刺，靴刺**{v.}++激励，鼓励；促进，加速，刺激（某事发生）；用马刺策（马）前进；紧贴主干剪短（副梢）**{n.}++a verbalization that encourages you to attempt something																					   	同义词：								                                  				    goad				    				    				      				    				      				    				                                      				    goading				    				    				      				    				      				    				                                      				    prod				    				    				      				    				      				    				                                      				    prodding				    				    				      				    				      				    				                                      				    urging				    				    				      				    				      				    				                                      				    spurring**{n.}++鼓舞，刺激；马刺；山坡**{vt.}++激励，鞭策；给…装踢马刺**', '');
insert into TOEFLWordBook values ('927', 'squeeze', '[skwiːz]', 'http://dict.youdao.com/dictvoice?audio=squeeze', '{v.}++挤压，捏；挤出，榨出（液体等）；（使）挤入，塞入；为……挤出时间（squeeze someone/something in）；排挤出（squeeze someone/something out）；敲诈勒索，榨取；严格限制，紧缩（资金）；好不容易取得，勉强成功；紧紧闭上双眼；扣扳机射击，打一整发（子弹）；拍照；（桥牌）逼（对方）放弃一张赢墩牌，逼牌**{n.}++挤压，捏；拥挤，塞满；挤出来的少量事物；紧缩，拮据； 男朋友，女朋友； 勒索（或敲诈）的钱；拥抱；（桥牌）紧逼打法（逼对手扔掉一张重要的牌）；压模，拓印；（棒球）抢分战术；  拥挤的社交舞会**{n.}++the act of gripping and pressing firmly																										        				&quot;he gave her cheek a playful squeeze&quot;															   	同义词：								                                  				    squeezing**{vt.}++挤；紧握；勒索**{n.}++压榨；紧握；拥挤；佣金**', '');
insert into TOEFLWordBook values ('928', 'staircase', '[ˈsterkeɪs]', 'http://dict.youdao.com/dictvoice?audio=staircase', '{n.}++楼梯；（尤指中小学和大学建筑物中的）楼梯间**{n.}++a way of access (upward and downward) consisting of a set of steps																					   	同义词：								                                  				    stairway**{n.}++楼梯**', '');
insert into TOEFLWordBook values ('929', 'stake', '[steɪk]', 'http://dict.youdao.com/dictvoice?audio=stake', '{n.}++股本，股份；桩，标桩，篱笆桩；赌注；赛马奖金（stakes）；比赛，竞赛（stakes）；利害关系；火刑柱；（制作篮子的）纵向基杆，经条；（铁匠用的）小铁砧；摩门主教管辖区**{v.}++拿…...冒险，以…...打赌；用桩支撑；资助，帮助**{n.}++(law) a right or legal share of something; a financial involvement with something																										        				&quot;a stake in the companys future&quot;															   	同义词：								                                  				    interest**{n.}++桩，棍子；赌注；火刑；奖金**{vt.}++资助，支持；系…于桩上；把…押下打赌**{vi.}++打赌**', '');
insert into TOEFLWordBook values ('930', 'stamp', '[stæmp]', 'http://dict.youdao.com/dictvoice?audio=stamp', '{n.}++邮票；印记，戳记；印，章，戳；跺脚（声），跺蹄（声）；特征，痕迹，烙印；类型，种类，类别；表明，表示；重要影响，持久影响；（捣矿机中用于捣碎矿石的）铁砧；购物券，购买券**{vt.}++跺（脚），重踩，重踏；迈着重步走，跺着脚走；在……上面印盖（图案、记号、字母等）；显示出（感情）；表明（某人）是……；（用印模）冲压；对…有重要（永久性）的影响；在……上贴邮票；捣碎（矿石），压碎（矿石）**{n.}++a token that postal fees have been paid																					   	同义词：								                                  				    postage				    				    				      				    				      				    				                                      				    postage stamp**{n.}++[邮]邮票；印记；标志；跺脚**{vt.}++铭记；标出；盖章于…；贴邮票于…；用脚踩踏**{vi.}++跺脚；捣碎；毁掉**', '');
insert into TOEFLWordBook values ('931', 'startling', '[ˈstɑːrtlɪŋ]', 'http://dict.youdao.com/dictvoice?audio=startling', '{adj.}++令人吃惊的，不寻常的；极鲜亮的**{v.}++使吓一跳，使惊奇（startle 的现在分词）**{adj.}++so remarkably different or sudden as to cause momentary shock or alarm																										        													        													        				&quot;Sydneys startling new Opera House&quot;; &quot;startling news&quot;; &quot;startling earthquake shocks&quot;**{adj.}++令人吃惊的**', '');
insert into TOEFLWordBook values ('932', 'starve', '[stɑːrv]', 'http://dict.youdao.com/dictvoice?audio=starve', '{v.}++（使）挨饿，饿死；使极其缺乏，需要**{v.}++be hungry; go without food																					   	同义词：								                                  				    hunger				    				    				      				    				      				    				                                      				    famish**{vi.}++饿死；挨饿；渴望**{vt.}++使饿死；使挨饿**', '');
insert into TOEFLWordBook values ('933', 'stationary', '[ˈsteɪʃəneri]', 'http://dict.youdao.com/dictvoice?audio=stationary', '{adj.}++不动的，静止的；不变的，稳定的；（行星）经度无明显移动的；定居的**{n.}++不动的人或物**{adj.}++standing still																										        				&quot;the car remained stationary with the engine running&quot;**{adj.}++固定的；静止的；定居的；常备军的**', '');
insert into TOEFLWordBook values ('934', 'statistics', '[stəˈtɪstɪks]', 'http://dict.youdao.com/dictvoice?audio=statistics', '{n.}++统计学；统计数字（statistic 的复数形式）**{n.}++a branch of applied mathematics concerned with the collection and interpretation of quantitative data and the use of probability theory to estimate population parameters**{n.}++[统计]统计；统计学；统计资料**', '');
insert into TOEFLWordBook values ('935', 'status', '[ˈsteɪtəs; ˈstætəs]', 'http://dict.youdao.com/dictvoice?audio=status', '{n.}++法律地位（或身份）；（尤指在社会中的）地位，身份；高级职位，社会上层地位；重视（或崇尚）程度；状况，情形**{n.}++the relative position or standing of things or especially persons in a society																										        													        				&quot;he had the status of a minor&quot;; &quot;the novel attained the status of a classic&quot;															   	同义词：								                                  				    position**{n.}++地位；状态；情形；重要身分**', '');
insert into TOEFLWordBook values ('936', 'steady', '[ˈstedi]', 'http://dict.youdao.com/dictvoice?audio=steady', '{adj.}++平稳的，稳步的，持续的；稳定的，恒定的；稳固的，牢固的；沉着的，冷静的；（人）稳重的，可靠的**{v.}++使平稳，稳住；（使）稳定，（使）固定（一段时间）；（使）镇定，（使）冷静**{n.}++关系确定的情侣；（支撑大篷车或其他车辆的）支架，撑竿**{int.}++当心，冷静点**{adv.}++稳定地，持续地，稳固地**{n.}++a person loved by another person																					   	同义词：								                                  				    sweetheart				    				    				      				    				      				    				                                      				    sweetie				    				    				      				    				      				    				                                      				    truelove**{v.}++make steady																										        				&quot;steady yourself&quot;															   	同义词：								                                  				    calm				    				    				      				    				      				    				                                      				    becalm**{adj.}++稳定的；不变的；沉着的**{vt.}++使稳定；稳固；使坚定**{adv.}++稳定地；稳固地**{n.}++关系固定的情侣；固定支架**', '');
insert into TOEFLWordBook values ('937', 'steal', '[stiːl]', 'http://dict.youdao.com/dictvoice?audio=steal', '{v.}++偷窃，盗窃；剽窃，窃取（观点）；悄悄地移动；（在棒球比赛中）偷（垒）；（在篮球或冰球比赛中）断（球），截（球）；偷偷做；偷拿，私自拿；抢（镜头、戏等）；（体育运动中）意外赢得；骗走**{n.}++极廉价的物品，低价；（尤指篮球比赛中的）断球；（棒球比赛中的）偷垒；偷窃，行窃；剽窃**{n.}++an advantageous purchase																					   	同义词：								                                  				    bargain				    				    				      				    				      				    				                                      				    buy**{vt.}++[法]偷窃；剽窃；偷偷地做**{n.}++[法]偷窃；便宜货；偷垒**', '');
insert into TOEFLWordBook values ('938', 'steam', '[stiːm]', 'http://dict.youdao.com/dictvoice?audio=steam', '{n.}++蒸汽，水蒸气；水汽，雾气；蒸汽动力（压力）；力量，势头；蒸汽机车**{v.}++散发蒸汽，冒热气；蒸（食物）；（以蒸汽为动力）行驶；快速行走，疾行；（使）蒙上水汽；蒸汽洗涤，蒸汽处理；用蒸汽软化（尤指胶水）；开始战斗，投入战斗；（一群贼）（在匆忙通过公共场所时）顺路盗窃（或抢劫）；用蒸汽开动（机车）**{adj.}++蒸汽的**{n.}++water at boiling temperature diffused in the atmosphere**{v.}++travel by means of steam power																										        				&quot;The ship steamed off into the Pacific&quot;															   	同义词：								                                  				    steamer**{vt.}++蒸，散发；用蒸汽处理**{n.}++蒸汽；精力**', '');
insert into TOEFLWordBook values ('939', 'steep', '[stiːp]', 'http://dict.youdao.com/dictvoice?audio=steep', '{adj.}++（路、山等）陡峭的；（价格，需求）难以接受的，过高的；（增加或减少）急剧的，大幅度的**{v.}++浸泡（食物）；使沉浸，使沉湎**{n.}++悬崖，陡坡；用于浸泡的溶液**{n.}++a steep place (as on a hill)**{v.}++engross (oneself) fully																					   	同义词：								                                  				    immerse				    				    				      				    				      				    				                                      				    engulf				    				    				      				    				      				    				                                      				    plunge				    				    				      				    				      				    				                                      				    engross				    				    				      				    				      				    				                                      				    absorb				    				    				      				    				      				    				                                      				    soak up**{adj.}++陡峭的；不合理的；夸大的；急剧升降的**{vt.}++泡；浸；使…充满**{n.}++峭壁；浸渍**', '');
insert into TOEFLWordBook values ('940', 'stick', '[stɪk]', 'http://dict.youdao.com/dictvoice?audio=stick', '{v.}++粘，贴；刺，戳，插；（随便）摆放，放置；伸出，突出；卡住，钉住；容忍，忍受；被接受，被众人采用；（牌戏中）不再要牌；停顿下来，没有进展；（生气地）放弃（和打发）；使支付，导致损失**{n.}++枯枝，枝条；条状物，棍状物；（用于某特定用途的）棍，条，签；球棍，球棒；变速杆，操纵杆；批评，惩罚；边远地区（the sticks）；（家具的）件；非常瘦的人（或四肢）；画着短细直线的；球门柱（the sticks）；（股票）大宗死股**{n.}++an implement consisting of a length of wood																										        													        				&quot;he collected dry sticks for a campfire&quot;; &quot;the kid had a candied apple on a stick&quot;**{vt.}++刺，戳；伸出；粘贴**{vi.}++坚持；伸出；粘住**{n.}++棍；手杖；呆头呆脑的人**', '');
insert into TOEFLWordBook values ('941', 'stiff', '[stɪf]', 'http://dict.youdao.com/dictvoice?audio=stiff', '{adj.}++（肌肉或关节）酸痛的，僵硬的；不易弯曲的，硬的；艰难的，严厉的；无礼的，生硬的；（酒）烈性的；稠的，难搅拌的；难移动的，不顺滑的；昂贵的；（风）强劲的，猛烈的；过于正式的**{n.}++死尸；……的人；无趣的人，令人讨厌的人；（体育俱乐部的）后备队，候补队 (the stiffs)**{v.}++诈骗，不还钱，（尤指）不给小费；（新产品、电影、节目等）不畅销，彻底失败；冷落，怠慢；杀害某人**{adv.}++非常，彻底地**{n.}++an ordinary man																										        													        				&quot;a lucky stiff&quot;; &quot;a working stiff&quot;**{adj.}++呆板的；坚硬的；严厉的；拘谨的；拘谨的**{adv.}++僵硬地；彻底地**{n.}++死尸；令人讨厌者；[金融]流通票据；劳动者**', '');
insert into TOEFLWordBook values ('942', 'stimulus', '[ˈstɪmjələs]', 'http://dict.youdao.com/dictvoice?audio=stimulus', '{n.}++刺激（物）, 促进因素；（使生物产生反应的）刺激，刺激物；刺激性，趣味性**{n.}++any stimulating information or event; acts to arouse action																					   	同义词：								                                  				    stimulation				    				    				      				    				      				    				                                      				    stimulant				    				    				      				    				      				    				                                      				    input**{n.}++[医]刺激；[电子]激励；刺激物**', '');
insert into TOEFLWordBook values ('943', 'sting', '[stɪŋ]', 'http://dict.youdao.com/dictvoice?audio=sting', '{v.}++（昆虫、动植物）叮，刺，蜇；（使）刺痛，（使）产生剧痛；向……索要惊人高价，敲诈；（使）生气，（使）心烦；刺激**{n.}++刺伤处，蜇伤处；（植物、水母等的）刺毛； 刺痛，灼痛；（身体或心灵的）剧痛，痛苦；（警察为抓住罪犯而设计的）圈套，骗局；（罪犯诈骗钱财的）骗局，诡计**{n.}++a kind of pain; something as sudden and painful as being stung																										        													        				&quot;the sting of death&quot;; &quot;he felt the stinging of nettles&quot;															   	同义词：								                                  				    stinging**{n.}++刺痛；讽刺，刺激；刺毛**{vt.}++刺；驱使；使…苦恼；使…疼痛**{vi.}++刺痛；被刺痛；感到剧痛**', '');
insert into TOEFLWordBook values ('944', 'stock', '[stɑːk]', 'http://dict.youdao.com/dictvoice?audio=stock', '{n.}++现货，存货；储备物，备用物；股本，资本；股份，股票；公债，公债券；家畜，牲畜；种族，家系；高汤，原汤；手足枷（stocks）；柄，枪托；名声，声望；紫罗兰；接穗，砧木；根茎，根状茎；保留剧目轮演剧团；信任，相信；铁路上使用的所有车辆；（胶卷）原片；发剩下的牌；（商品的）原材料；锚杆；主轴台，主轴箱（headstock 的简写）；尾架，尾座（tailstock 的简写）；白色领结，白色领带；（牧师衣领下系的）黑色领带；船台（stocks）**{v.}++备有，存有；摆满，供应；为（枪等火器）装枪托；出新芽**{adj.}++老一套的，陈腐的；（商店）库存的，常备的；（有关）电影资料镜头的**{n.}++the capital raised by a corporation through the issue of shares entitling holders to an ownership interest (equity)																										        				&quot;he owns a controlling share of the companys stock&quot;**{liquid in which meat and vegetables are simmered; used as a basis for e.}++g. soups or sauces																										        				&quot;she made gravy with a base of beef stock&quot;															   	同义词：								                                  				    broth**{n.}++[金融]股份，股票；[贸易]库存；血统；树干**{adj.}++[贸易]存货的，常备的；平凡的**{vt.}++进货；备有；装把手于…**{vi.}++囤积；办货；出新芽**', '');
insert into TOEFLWordBook values ('945', 'stomach', '[ˈstʌmək]', 'http://dict.youdao.com/dictvoice?audio=stomach', '{n.}++胃；腹部；（低级动物的）类胃器官；（反刍动物的）四胃之一；心窝，内脏； 食欲，胃口；（对有冲突、困难或不快之事的）欲望，倾向；（做困难或不愉快的事所需的）意愿，勇气，决心；（对令人反胃的东西的）承受能力**{v.}++忍受，承受；吃得下**{n.}++an enlarged and muscular saclike organ of the alimentary canal; the principal organ of digestion																					   	同义词：								                                  				    tummy				    				    				      				    				      				    				                                      				    tum				    				    				      				    				      				    				                                      				    breadbasket**{n.}++胃；[解剖]腹部；胃口**{vt.}++忍受；吃下**{vi.}++忍受**', '');
insert into TOEFLWordBook values ('946', 'stony', '[ˈstoʊni]', 'http://dict.youdao.com/dictvoice?audio=stony', '{adj.}++石头覆盖的，多石的；石制的，石头一样的；（表情或态度）冷冰冰的，冷漠的；（陨星） 石质的**{adj.}++abounding in rocks or stones																										        				&quot;stony ground&quot;															   	同义词：								                                  				    rocky				    				    				      				    				      				    				                                      				    bouldery				    				    				      				    				      				    				                                      				    bouldered**{adj.}++无情的；多石的；石头的**', '');
insert into TOEFLWordBook values ('947', 'storage', '[ˈstɔːrɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=storage', '{n.}++储存，贮藏；（信息的）存储，存储空间；（家具等的）存放，保管；储存空间，储藏场所；仓库费，仓租**{adj.}++储存的**{n.}++the act of storing something**{n.}++[计]存储；[建][经]仓库；[贸易]贮藏所**', '');
insert into TOEFLWordBook values ('948', 'storm', '[stɔːrm]', 'http://dict.youdao.com/dictvoice?audio=storm', '{n.}++暴风雨，暴风雪，风暴；（感情或反应的）爆发，迸发；强低气压天气，旋风；暴雨般的飞弹（或打击）；（军队的）强击，猛攻；（防雨雪寒风的）外重窗**{v.}++猛烈攻击，突然袭击；气冲冲地走；非常生气地说，怒骂；暴风雨来临；迅速获得成功；（游戏或竞赛中）强有力并且胸有成竹地行动**{n.}++a violent weather condition with winds 64-72 knots (11 on the Beaufort scale) and precipitation and thunder and lightening																					   	同义词：								                                  				    violent storm**{n.}++[气象]暴风雨；大动荡**{vi.}++[气象]起风暴；横冲直撞；狂怒咆哮**{vt.}++猛攻；怒骂**', '');
insert into TOEFLWordBook values ('949', 'stout', '[staʊt]', 'http://dict.youdao.com/dictvoice?audio=stout', '{adj.}++（人）肥胖的，壮实的；厚而结实的；不屈不挠的，顽强的**{n.}++烈性黑啤酒；特大号衣服；胖子**{n.}++a strong very dark heavy-bodied ale made from pale malt and roasted unmalted barley and (often) caramel malt with hops**{adj.}++结实的；矮胖的；勇敢的；激烈的**{n.}++矮胖子；[食品]烈性啤酒**', '');
insert into TOEFLWordBook values ('950', 'stove', '[stoʊv]', 'http://dict.youdao.com/dictvoice?audio=stove', '{n.}++（取暖或烹饪用的）炉子，火炉；厨灶，炉头；窑；温室**{v.}++（为了喷涂表层而）在炉中对（物体）进行热处理；（用硫磺等烟雾）烟熏，消毒（房屋）；在温室中加速（植物）生长，培植（植物）**{v.}++击穿；挡开，延缓（stave 的过去式和过去分词）**{n.}++a kitchen appliance used for cooking food																										        				&quot;dinner was already on the stove&quot;															   	同义词：								                                  				    kitchen stove				    				    				      				    				      				    				                                      				    range				    				    				      				    				      				    				                                      				    kitchen range				    				    				      				    				      				    				                                      				    cooking stove**{n.}++火炉；[炉窑]窑；温室**', '');
insert into TOEFLWordBook values ('951', 'straight', '[streɪt]', 'http://dict.youdao.com/dictvoice?audio=straight', '{adj.}++直的，笔直的；端正的，竖直的；（裙、裤等）直筒型的；坦诚的，直率的；简单的，非此即彼的；正中目标的；整洁的；连续的；（消息）正确的，可靠的；互不欠债的；不吸毒的，不酗酒的；（酒）纯的；纯正的，纯粹的；正统的，严肃的；正经的；异性恋的；（神态）从容的；（思维）清晰的**{adv.}++直线地，径直地；竖直地，直立地；立即，马上；诚实地，坦率地；连续地；准确地，清晰地**{n.}++异性恋者；直线跑道；（扑克牌的）顺子；750毫升瓶装酒；老实人；直立形态；直线**{v.}++使变直**{n.}++a heterosexual person; someone having a sexual orientation to persons of the opposite sex																					   	同义词：								                                  				    heterosexual				    				    				      				    				      				    				                                      				    heterosexual person				    				    				      				    				      				    				                                      				    straight person**{adj.}++直的；连续的；笔直的；正直的；整齐的**{adv.}++直接地；不断地；立即；坦率地**{n.}++直；直线**', '');
insert into TOEFLWordBook values ('952', 'strand', '[strænd]', 'http://dict.youdao.com/dictvoice?audio=strand', '{n.}++（绳、线、毛发等的）股，缕；串；（故事、观点、计划等的）部分；（海洋、湖或河的）岸，滨**{v.}++使滞留，使困在（某处）；使（船，船员，海洋生物）搁浅；使（跑垒员）残留垒上**{n.}++a pattern forming a unity within a larger structural whole																										        													        				&quot;he tried to pick up the strands of his former life&quot;; &quot;I could hear several melodic strands simultaneously&quot;**{n.}++线；串；海滨**{vt.}++使搁浅；使陷于困境；弄断；使落后**{vi.}++搁浅**', '');
insert into TOEFLWordBook values ('953', 'strategy', '[ˈstrætədʒi]', 'http://dict.youdao.com/dictvoice?audio=strategy', '{n.}++（尤指为获得某物制定长期的）策略，行动计划；战略，战略学**{n.}++an elaborate and systematic plan of action																					   	同义词：								                                  				    scheme**{n.}++[军]战略，策略**', '');
insert into TOEFLWordBook values ('954', 'streamline', '[ˈstriːmlaɪn]', 'http://dict.youdao.com/dictvoice?audio=streamline', '{v.}++精简（工商企业、组织、流程等）使效率更高；使……成为流线型**{n.}++（流动液体的）流线**{adj.}++（液体的流动）顺畅的，畅流的；流线型的**{v.}++contour economically or efficiently**{n.}++[流]流线；流线型**{adj.}++[流]流线型的**', '');
insert into TOEFLWordBook values ('955', 'strength', '[streŋθ]', 'http://dict.youdao.com/dictvoice?audio=strength', '{n.}++体力，力量；实力，影响力；长处，优势；意志力，毅力；（情感或意见的）强烈程度；（物体或物质的）强度；（食物、药等的）浓度，（酒的）烈度；（风等的）速度，力度；人数，人力；（货币的）价值，坚挺程度；球队的板凳深度，替补队员的水平；力量源泉；（手中所持好牌数目和花色的）牌力**{n.}++the property of being physically or mentally strong																										        				&quot;fatigue sapped his strength&quot;**{n.}++力量；力气；兵力；长处**', '');
insert into TOEFLWordBook values ('956', 'stretch', '[stretʃ]', 'http://dict.youdao.com/dictvoice?audio=stretch', '{v.}++（使）变大，拉长；（布料）可伸缩，有弹性；伸展肢体；伸出，伸长（胳膊或腿）；拉紧，拽紧；（时间上）延续；（空间上）延伸，绵延；使竭尽所能，使施展本领；耗尽，竭尽（财力或物力）；（使）延长使用，节俭地使用；（资金，资源）足够，够用；放宽，放松；夸大，夸张；涉及，囊括**{n.}++（土地或水域的）一片，一段；（时间）连续的一段，持续；（肢体）伸展，伸开；弹性，伸缩性；服刑期；（终点前的）直线跑道；言过其实的话；困难的任务，苛求的任务；加长轿车；抢风航行的距离**{adj.}++（织物）有弹性的，有弹力的**{n.}++a large and unbroken expanse or distance																										        													        				&quot;a stretch of highway&quot;; &quot;a stretch of clear water&quot;**', '');
insert into TOEFLWordBook values ('957', 'stroll', '[stroʊl]', 'http://dict.youdao.com/dictvoice?audio=stroll', '{v.}++散步，闲逛；（体育比赛）轻而易举地获胜**{n.}++散步，溜达；（竞赛中）轻易的胜利**{n.}++a leisurely walk (usually in some public place)																					   	同义词：								                                  				    amble				    				    				      				    				      				    				                                      				    promenade				    				    				      				    				      				    				                                      				    saunter				    				    				      				    				      				    				                                      				    perambulation**{v.}++walk leisurely and with no apparent aim																					   	同义词：								                                  				    saunter**{n.}++漫步；闲逛；巡回演出**{vi.}++散步；闲逛；巡回演出**{vt.}++散步；闲逛**', '');
insert into TOEFLWordBook values ('958', 'structural', '[ˈstrʌktʃərəl]', 'http://dict.youdao.com/dictvoice?audio=structural', '{adj.}++建筑结构的；建筑用的；结构（或构造）上的**{adj.}++relating to or caused by structure, especially political or economic structure																										        				&quot;structural unemployment in a technological society&quot;**{adj.}++结构的；建筑的**', '');
insert into TOEFLWordBook values ('959', 'studio', '[ˈstuːdioʊ]', 'http://dict.youdao.com/dictvoice?audio=studio', '{n.}++录音室，播音室，演播室；（电影）摄影棚，电影公司，电影制片厂；（画家、摄影师、雕塑家等的）工作室；（舞蹈）练习室；单室公寓房；（公司新产品的）设计室，工作室**{n.}++workplace for the teaching or practice of an art																										        													        													        				&quot;she ran a dance studio&quot;; &quot;the music department provided studios for their students&quot;; &quot;you dont need a studio to make a passport photograph&quot;**{n.}++工作室；[电视][广播]演播室；画室；电影制片厂**', '');
insert into TOEFLWordBook values ('960', 'stylized', '[ˈstaɪlaɪzd]', 'http://dict.youdao.com/dictvoice?audio=stylized', '{adj.}++非写实的；程式化的；有艺术效果的；按固定格式的**{v.}++风格化；仿效…的风格（stylize的过去式和过去分词）**{adj.}++using artistic forms and conventions to create effects; not natural or spontaneous																										        				&quot;a stylized mode of theater production&quot;															   	同义词：								                                  				    conventionalized				    				    				      				    				      				    				                                      				    conventionalised				    				    				      				    				      				    				                                      				    stylised**{adj.}++程式化的；按固定格式的**', '');
