insert into TOEFLWordBook values ('962', 'submerge', '[səbˈmɜːrdʒ]', 'http://dict.youdao.com/dictvoice?audio=submerge', '{v.}++（使）潜入水中，（使）没入水中，浸没；湮没，掩盖（思想、感情等）；使（自己）集中精力于，使（自己）沉浸于**{v.}++sink below the surface; go under or as if under water																					   	同义词：								                                  				    submerse**{vt.}++淹没；把…浸入；沉浸**{vi.}++淹没；潜入水中；湮没**', '');
insert into TOEFLWordBook values ('963', 'submit', '[səbˈmɪt]', 'http://dict.youdao.com/dictvoice?audio=submit', '{v.}++呈递，提交；屈服，不得已接受；建议，主张；使经受，使受到**{v.}++refer for judgment or consideration																										        				&quot;She submitted a proposal to the agency&quot;															   	同义词：								                                  				    subject**{vt.}++使服从；主张；呈递**{vi.}++[计]提交；服从**', '');
insert into TOEFLWordBook values ('964', 'subsidize', '[ˈsʌbsɪdaɪz]', 'http://dict.youdao.com/dictvoice?audio=subsidize', '{v.}++资助，补助，给……发津贴；（政府）资助，出资支持；向……行贿**{v.}++support through subsidies																										        				&quot;The arts in Europe are heavily subsidized&quot;															   	同义词：								                                  				    subsidise**{vt.}++资助；给与奖助金；向…行贿**', '');
insert into TOEFLWordBook values ('965', 'substantial', '[səbˈstænʃ(ə)l]', 'http://dict.youdao.com/dictvoice?audio=substantial', '{adj.}++大量的，价值巨大的；牢固的，结实的；基本的，实质性的；（饭菜）丰盛的；重要的，真实的；有地位的，富有的**{n.}++重要材料**{adj.}++fairly large																										        				&quot;won by a substantial margin&quot;															   	同义词：								                                  				    significant**{adj.}++大量的；实质的；内容充实的**{n.}++本质；重要材料**', '');
insert into TOEFLWordBook values ('966', 'substitute', '[ˈsʌbstɪtuːt]', 'http://dict.youdao.com/dictvoice?audio=substitute', '{n.}++替代品，代替物；（体育比赛中的）替补队员；令人满意的替代物，与之媲美的事物；副职**{v.}++用……代替；（比赛中）替换（运动员）；代替（某人的工作）；（化）取代（分子中的一个或一组原子，尤指氢原子）**{adj.}++替代性的**{n.}++a person or thing that takes or can take the place of another																					   	同义词：								                                  				    replacement**{n.}++代用品；代替者**{vi.}++[计]替代**{vt.}++代替**', '');
