insert into TOEFLWordBook values ('968', 'subtle', '[ˈsʌt(ə)l]', 'http://dict.youdao.com/dictvoice?audio=subtle', '{adj.}++不易察觉的，微妙的；敏锐的，有洞察力的；灵活的，巧妙的；含蓄的，隐晦的；狡猾的**{adj.}++be difficult to detect or grasp by the mind																										        													        				&quot;his whole attitude had undergone a subtle change&quot;; &quot;a subtle difference&quot;															   	同义词：								                                  				    elusive**{adj.}++微妙的；精细的；敏感的；狡猾的；稀薄的**', '');
