insert into TOEFLWordBook values ('971', 'subway', '[ˈsʌbweɪ]', 'http://dict.youdao.com/dictvoice?audio=subway', '{n.}++地铁；地下通道**{v.}++乘地铁**{n.}++an electric railway operating below the surface of the ground (usually in a city)																										        				&quot;in Paris the subway system is called the `metro and in London it is called the `tube or the `underground&quot;															   	同义词：								                                  				    metro				    				    				      				    				      				    				                                      				    tube				    				    				      				    				      				    				                                      				    underground				    				    				      				    				      				    				                                      				    subway system**{n.}++[铁路]地铁；地道**{vi.}++[铁路]乘地铁**', '');
insert into TOEFLWordBook values ('972', 'succeed', '[səkˈsiːd]', 'http://dict.youdao.com/dictvoice?audio=succeed', '{v.}++成功，达成；（学业、事业或其他活动）表现出色，有作为；取得预期效果，表现良好；继任，接任；接替，随后出现；结果却是……；若一次不成功，要再接再厉**{v.}++attain success or reach a desired goal																										        													        				&quot;The enterprise succeeded&quot;; &quot;We succeeded in getting tickets to the show&quot;															   	同义词：								                                  				    win				    				    				      				    				      				    				                                      				    come through				    				    				      				    				      				    				                                      				    bring home the bacon				    				    				      				    				      				    				                                      				    deliver the goods**{vi.}++成功；继承；继任；兴旺**{vt.}++继承；接替；继…之后**', '');
insert into TOEFLWordBook values ('973', 'suffer', '[ˈsʌfər]', 'http://dict.youdao.com/dictvoice?audio=suffer', '{v.}++（因疾病、痛苦、悲伤等）受苦，受折磨；经受，遭受（坏事）；变差，变糟；容许，允许；受处决**{v.}++undergo or be subjected to																										        													        				&quot;He suffered the penalty&quot;; &quot;Many saints suffered martyrdom&quot;															   	同义词：								                                  				    endure**{vt.}++遭受；忍受；经历**{vi.}++遭受，忍受；受痛苦；经验；受损害**', '');
insert into TOEFLWordBook values ('974', 'suit', '[suːt]', 'http://dict.youdao.com/dictvoice?audio=suit', '{n.}++套装，西装；（从事特定活动时穿的）成套服装；诉讼；同花色的一组纸牌；（企业或机构中的）高级管理人员；一套蓬帆；追求（常指求婚）；（向当权者提出的）请愿，请求**{v.}++（服装、风格、颜色）使显得漂亮，与……相配；对（某人）方便，满足（某人）需要，合（某人）心意；适合，适宜；随自己的意愿，随性子；（尤指为特定的活动）穿衣**{n.}++a comprehensive term for any proceeding in a court of law whereby an individual seeks a legal remedy																										        				&quot;the family brought suit against the landlord&quot;															   	同义词：								                                  				    lawsuit				    				    				      				    				      				    				                                      				    case				    				    				      				    				      				    				                                      				    cause				    				    				      				    				      				    				                                      				    causa**{vt.}++适合；使适应**{n.}++诉讼；组；套装；恳求**{vi.}++合适；相称**', '');
insert into TOEFLWordBook values ('975', 'sum', '[sʌm; səm]', 'http://dict.youdao.com/dictvoice?audio=sum', '{n.}++金额，款项；算术，简单计算；总数，总和；全部，一切（尤指数量不大）；计算失误；计算费用**{v.}++概括，总结；求……的和，计算……的总数**{n.}++a quantity of money																										        				&quot;he borrowed a large sum&quot;															   	同义词：								                                  				    sum of money				    				    				      				    				      				    				                                      				    amount				    				    				      				    				      				    				                                      				    amount of money**{n.}++金额；[数]总数**{vi.}++概括**{vt.}++总结；合计**', '');
