insert into TOEFLWordBook values ('977', 'superb', '[suːˈpɜːrb]', 'http://dict.youdao.com/dictvoice?audio=superb', '{adj.}++极佳的，质量极高的；（信心、控制力、技巧）非同一般的，超凡的；壮丽的，辉煌的；羽毛鲜艳夺目的**{adj.}++of surpassing excellence																										        				&quot;a superb actor&quot;															   	同义词：								                                  				    brilliant**{adj.}++极好的；华丽的；宏伟的**', '');
insert into TOEFLWordBook values ('978', 'superior', '[suːˈpɪriər]', 'http://dict.youdao.com/dictvoice?audio=superior', '{adj.}++（规模或实力）更大的，更强的，(在品质上)更好的；（尤用于广告中指产品或服务）高质量的，优质的；上级的，（在级别、重要性或职位上）更高的；有优越感的，高傲的，傲慢的；在其他器官之上的；（字母，数字，符号）上标的；（花的子房）上位的，（子房）在萼上的**{n.}++上级，上司；优胜者，高手；修道院院长（或其他宗教机构的负责人）；（印刷）上标字母（或数字、符号）**{n.}++one of greater rank or station or quality																					   	同义词：								                                  				    higher-up				    				    				      				    				      				    				                                      				    superordinate**{adj.}++上级的；优秀的，出众的；高傲的**{n.}++上级，长官；优胜者，高手；长者**', '');
insert into TOEFLWordBook values ('979', 'supernatural', '[ˌsuːpərˈnætʃrəl]', 'http://dict.youdao.com/dictvoice?audio=supernatural', '{adj.}++超自然的；神奇的，不可思议的**{n.}++超自然现象；不可思议的事**{n.}++supernatural forces and events and beings collectively																										        				&quot;She doesnt believe in the supernatural&quot;															   	同义词：								                                  				    occult**{adj.}++not existing in nature or subject to explanation according to natural laws; not physical or material																										        				&quot;supernatural forces and occurrences and beings&quot;**{adj.}++超自然的；神奇的，不可思议的**{n.}++超自然现象；不可思议的事**', '');
insert into TOEFLWordBook values ('980', 'supervise', '[ˈsuːpərvaɪz]', 'http://dict.youdao.com/dictvoice?audio=supervise', '{v.}++指导（某人）的工作；监督（任务，计划，活动）**{v.}++watch and direct																					   	同义词：								                                  				    oversee				    				    				      				    				      				    				                                      				    superintend				    				    				      				    				      				    				                                      				    manage**{vt.}++监督，管理；指导**{vi.}++监督，管理；指导**', '');
insert into TOEFLWordBook values ('981', 'suppose', '[səˈpoʊz]', 'http://dict.youdao.com/dictvoice?audio=suppose', '{v.}++推断，料想，猜想；假设，假定，设想；预期，需要，以……为条件；相信，认为（某事物是可能的）；（婉转表达）我看，要我说，要不；（因处于某种境地或因约定）必须做（be supposed to do sth.）；我看（用于生气地表示预料某事属实）**{v.}++express a supposition																					   	同义词：								                                  				    say**{vt.}++假设；认为；让（虚拟语气）；推想**{vi.}++猜想；料想**', '');
insert into TOEFLWordBook values ('982', 'surplus', '[ˈsɜːrplʌs]', 'http://dict.youdao.com/dictvoice?audio=surplus', '{n.}++过剩，剩余，过剩量；盈余，顺差；超净资产**{adj.}++过剩的，剩余的，多余的；（商店）出售剩余（或过时的）军用品的**{v.}++甩卖，变卖**{n.}++a quantity much larger than is needed																					   	同义词：								                                  				    excess				    				    				      				    				      				    				                                      				    surplusage				    				    				      				    				      				    				                                      				    nimiety**{adj.}++more than is needed, desired, or required																										        				&quot;surplus cheese distributed to the needy&quot;															   	同义词：								                                  				    excess				    				    				      				    				      				    				                                      				    extra				    				    				      				    				      				    				                                      				    redundant				    				    				      				    				      				    				                                      				    spare				    				    				      				    				      				    				                                      				    supererogatory				    				    				      				    				      				    				                                      				    superfluous				    				    				      				    				      				    				                                      				    supernumerary**{n.}++[数]剩余；[贸易]顺差；[会计]盈余；[电子][经]过剩**{adj.}++[数][电子]剩余的；[经]过剩的**', '');
insert into TOEFLWordBook values ('983', 'survey', '[ˈsɜːrveɪ]', 'http://dict.youdao.com/dictvoice?audio=survey', '{n.}++民意调查，民意测验；考察，调查；（对课题或情况的）全面考察，概述；测量，勘测；测绘图，勘测记录；测量部门； （尤指为欲购房者所做的）房屋鉴定；查勘报告**{v.}++做民意测验，做民意调查；（尤指认真地）审视，检查；测量，勘测； （尤指为可能的买家）查勘，检视（建筑物的状况）；全面评述，概述**{n.}++a detailed critical inspection																					   	同义词：								                                  				    study**{n.}++调查；测量；审视；纵览**{vt.}++调查；[测][油气]勘测；俯瞰**', '');
insert into TOEFLWordBook values ('984', 'survival', '[sərˈvaɪv(ə)l]', 'http://dict.youdao.com/dictvoice?audio=survival', '{n.}++继续生存，存活，幸存；遗留物，幸存物，残存物**{adj.}++幸存的，赖以生存的，救生用的**{n.}++a state of surviving; remaining alive																					   	同义词：								                                  				    endurance**{n.}++幸存，残存；幸存者，残存物**', '');
insert into TOEFLWordBook values ('985', 'suspect', '[səˈspekt]', 'http://dict.youdao.com/dictvoice?audio=suspect', '{v.}++猜想，认为（某事有可能）；怀疑……有罪，认为……有嫌疑；不信任，怀疑……的真实性**{n.}++嫌疑犯，可疑分子；（某坏事物的）可能导致者**{adj.}++不可靠的，不可信的；可疑的，可能有危险的；有问题的，运转不好的**{n.}++someone who is under suspicion**{n.}++[法]嫌疑犯**{adj.}++可疑的；不可信的**{vt.}++怀疑；猜想**{vi.}++怀疑；猜想**', '');
