insert into TOEFLWordBook values ('987', 'swallow', '[ˈswɑːloʊ]', 'http://dict.youdao.com/dictvoice?audio=swallow', '{v.}++吞下，咽下；（由于紧张等）做吞咽动作，咽口水；吞没，淹没；耗尽（金钱，资源）；完全相信，信以为真；抑制（感情、言语）；默默忍受（侮辱、批评等）**{n.}++吞，一口；燕子**{n.}++a small amount of liquid food																					   	同义词：								                                  				    sup**{vt.}++忍受；吞没**{vi.}++吞下；咽下**', '');
insert into TOEFLWordBook values ('988', 'sweat', '[swet]', 'http://dict.youdao.com/dictvoice?audio=sweat', '{v.}++流汗，出汗，冒汗；通过出汗排除；（通过运动或费力）使（人，动物）出汗；（食品，物体）渗出水分；辛苦工作，拼命干活；（人）（多指长时间的）处于极度焦虑中； 担心，焦虑，紧张；熔焊（金属）；用文火炖（肉或蔬菜）**{n.}++汗水，汗液；一身汗，满身大汗； 艰难的工作，累活，繁重的工作； 田径服，运动服，运动裤（sweats）；（用羊毛似的厚棉布做的）宽松休闲服装**{n.}++salty fluid secreted by sweat glands																										        				&quot;sweat poured off his brow&quot;															   	同义词：								                                  				    perspiration				    				    				      				    				      				    				                                      				    sudor**{vt.}++使出汗；流出；使干苦活；剥削；藉出汗减轻；焦急地期待**{n.}++汗；水珠；焦急；苦差使**{vi.}++出汗；辛苦工作；懊恼；结水珠**', '');
insert into TOEFLWordBook values ('989', 'sweep', '[swiːp]', 'http://dict.youdao.com/dictvoice?audio=sweep', '{v.}++打扫，清除；（迅猛地）带走，卷走；（风浪等）席卷，横扫；风行，迅速蔓延；（阔步或轻盈地）走；挥动，摆动；（情感）突然袭来；扫视，搜寻；（使）轻轻擦过；延伸，蜿蜒； 大获全胜；梳，拢（头发）；扫射；彻底删除；（板球）半跪挥棒**{n.}++打扫，清扫；挥动；巡行，扫荡；绵延弯曲的地带； 广度，范围；车道的弧形部分； 收视率调查时段； （系列比赛中）全胜； 赌金全赢制；烟囱清洁工；（用以操舵的）大桨；（板球）以半跪姿势击球；风车的翼板；水井的长杆**{n.}++a wide scope																										        				&quot;the sweep of the plains&quot;															   	同义词：								                                  				    expanse**{vt.}++扫除；猛拉；掸去**{vi.}++扫，打扫；席卷；扫视；袭击**{n.}++打扫，扫除；范围；全胜**', '');
insert into TOEFLWordBook values ('990', 'swift', '[swɪft]', 'http://dict.youdao.com/dictvoice?audio=swift', '{adj.}++迅速的，立刻的；快速移动的，速度非常快的；机灵的，聪明的**{n.}++雨燕；蝙蝠蛾；绷架**{adv.}++（在组合形式以外为诗歌或文学用于）迅速**{n.}++United States meat-packer who began the use of refrigerated railroad cars (1839-1903)																					   	同义词：								                                  				    Gustavus Franklin Swift**{adj.}++快的；迅速的；敏捷的；立刻的**{adv.}++迅速地**', '');
insert into TOEFLWordBook values ('991', 'swing', '[swɪŋ]', 'http://dict.youdao.com/dictvoice?audio=swing', '{v.}++（使）摆动，摇荡；（使）改变（意见、情绪等）；做弧线运动，转弯；（挥动某物）朝……打去；热闹，令人开心；（使）突然转向，突然转身；以强劲的节奏演奏；（迈着有节奏的步伐）行进；（有时略微不正当地）获得；荡秋千；纵身跃向；绞死；男女乱交；移转（船，飞机）至各方位点**{n.}++摇摆，摆动；挥舞，挥动；挥杆动作；改变，变化；秋千；摇摆乐；以强劲的节奏演奏；巡游，竞选旅行；（板球）侧飞球；（音乐剧）替补**{adj.}++摇摆乐的；（在投票选举中）摇摆不定的**{n.}++a state of steady vigorous action that is characteristic of an activity																										        													        				&quot;the party went with a swing&quot;; &quot;it took time to get into the swing of things&quot;**{n.}++摇摆；摆动；秋千；音律；涨落**{vi.}++摇摆；转向；悬挂；大摇大摆地行走**{vt.}++使旋转；挥舞；悬挂**{adj.}++旋转的；悬挂的；强节奏爵士音乐的**', '');
insert into TOEFLWordBook values ('992', 'switch', '[swɪtʃ]', 'http://dict.youdao.com/dictvoice?audio=switch', '{n.}++开关，电闸；骤变，突变；交换机；（计算机）切换； （铁路的）转辙器，道岔；（细软的）枝条，鞭子；假发；（在英国使用借记卡付账的一种）转换系统（Switch）**{v.}++（用开关）打开，关闭；（使）改变，转变；交换，调换；转移（注意力）；（与某人）交换工作，调班； 用枝条击打，轻拂**{n.}++control consisting of a mechanical or electrical or electronic device for making or breaking or changing the connections in a circuit																					   	同义词：								                                  				    electric switch				    				    				      				    				      				    				                                      				    electrical switch**', '');
insert into TOEFLWordBook values ('993', 'symbol', '[ˈsɪmb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=symbol', '{n.}++象征，标志；符号；代表性的人（物）**{n.}++an arbitrary sign (written or printed) that has acquired a conventional significance**{n.}++象征；符号；标志**', '');
