insert into TOEFLWordBook values ('995', 'symptom', '[ˈsɪmptəm]', 'http://dict.youdao.com/dictvoice?audio=symptom', '{n.}++（医） 症状；（大问题的）迹象，征兆，征候**{n.}++(medicine) any sensation or change in bodily function that is experienced by a patient and is associated with a particular disease**{n.}++[临床]症状；征兆**', '');
insert into TOEFLWordBook values ('996', 'systematic', '[ˌsɪstəˈmætɪk]', 'http://dict.youdao.com/dictvoice?audio=systematic', '{adj.}++有系统的，有条理的，仔细周到的；一贯的，惯常的；分类的**{adj.}++characterized by order and planning																										        													        				&quot;the investigation was very systematic&quot;; &quot;a systematic administrator&quot;**{adj.}++系统的；体系的；有系统的；[图情]分类的**', '');
