insert into TOEFLWordBook values ('998', 'tail', '[teɪl]', 'http://dict.youdao.com/dictvoice?audio=tail', '{n.}++（动物的）尾巴；（一些蝴蝶的）狭翅须；（物体的）尾状物，尾部；（离去事物的）末尾部分；盯梢人，跟踪者；（男子）燕尾服；硬币的反面（tails）；（水池的）浅水端，（河流的）下游；（屋瓦的）叠余外露部分；（板球）最弱的击球手；（数）截尾；（男子）燕尾服（tails）**{v.}++跟踪，盯梢；（飞行物体）曲线移动； 拉紧（绞索）；除去（水果或蔬菜的）梗**{n.}++the posterior part of the body of a vertebrate especially when elongated and extending beyond the trunk or main part of the body**{n.}++尾部；辫子；踪迹；燕尾服**{vt.}++尾随；装上尾巴**{vi.}++跟踪；变少或缩小**{adj.}++尾部的；从后面而来的**', '');
insert into TOEFLWordBook values ('999', 'tailor', '[ˈteɪlər]', 'http://dict.youdao.com/dictvoice?audio=tailor', '{n.}++（尤指男装）裁缝；蓝鱼（Tailorfish 的简称）**{v.}++定做（衣服）；迎合，使适应**{n.}++a person whose occupation is making and altering garments																					   	同义词：								                                  				    seamster				    				    				      				    				      				    				                                      				    sartor**{v.}++make fit for a specific purpose																					   	同义词：								                                  				    shoehorn**{n.}++[服装]裁缝**', '');
insert into TOEFLWordBook values ('1000', 'tale', '[teɪl]', 'http://dict.youdao.com/dictvoice?audio=tale', '{n.}++故事，传说；（对真人真事精彩的或夸张的）描述，讲述；谎言；流言蜚语**{n.}++a message that tells the particulars of an act or occurrence or course of events; presented in writing or drama or cinema or as a radio or television program																					   	同义词：								                                  				    narrative				    				    				      				    				      				    				                                      				    narration				    				    				      				    				      				    				                                      				    story**{n.}++故事；传说；叙述；流言蜚语**', '');
insert into TOEFLWordBook values ('1001', 'talent', '[ˈtælənt]', 'http://dict.youdao.com/dictvoice?audio=talent', '{n.}++天赋，才能；天才，人才；性感的人；（尤指古罗马人和古希腊人使用的重量和货币单位）塔兰特**{n.}++natural abilities or qualities																					   	同义词：								                                  				    endowment				    				    				      				    				      				    				                                      				    gift				    				    				      				    				      				    				                                      				    natural endowment**{n.}++才能；天才；天资**', '');
insert into TOEFLWordBook values ('1002', 'tame', '[teɪm]', 'http://dict.youdao.com/dictvoice?audio=tame', '{adj.}++驯服的，不怕人的；平淡无奇的，枯燥乏味的；听使唤的，温顺的； （植物）经栽培的；（土地）经开垦的**{v.}++驯化，驯服；制服，控制；开垦，开辟；使变得平淡**{v.}++correct by punishment or discipline																					   	同义词：								                                  				    chasten				    				    				      				    				      				    				                                      				    subdue**{adj.}++驯服的；平淡的；乏味的；顺从的**{vt.}++驯养；使变得平淡；制服**', '');
insert into TOEFLWordBook values ('1003', 'tank', '[tæŋk]', 'http://dict.youdao.com/dictvoice?audio=tank', '{n.}++（储存液体或气体的）箱，罐，缸；一箱，一罐（的量）；坦克；人工蓄水池； （警察局或监狱的）牢房；（养鱼、蛇等用的）玻璃容器，玻璃缸；水柜机车（tank engine 的简称）；紧身背心（多为羊毛的外罩）（tank top 的简称）**{v.}++彻底失败，破产；故意输掉比赛；给车辆加油； 喝醉； 使惨败；把······贮放在柜（或箱，缸，罐）内；乘车快速行进**{n.}++[军]坦克；水槽；池塘**{vt.}++把…贮放在柜内；打败**', '');
insert into TOEFLWordBook values ('1004', 'target', '[ˈtɑːrɡɪt]', 'http://dict.youdao.com/dictvoice?audio=target', '{n.}++目标，指标；（攻击的）目标；（批评、嘲笑等的）对象；靶子；目标受众，受影响的人（或群体）； 圆形小盾；（语音）目标**{v.}++把……作为攻击目标，把……作为批评的对象；面向，把……对准（某群体）；将（钱款或援助）用于**{n.}++a reference point to shoot at																					   	同义词：								                                  				    mark**{n.}++目标；靶子**', '');
insert into TOEFLWordBook values ('1005', 'tariff', '[ˈtærɪf]', 'http://dict.youdao.com/dictvoice?audio=tariff', '{n.}++（政府对进出口货物征收的）关税，关税表；（旅馆、饭店或服务公司的）价目表，收费表；量刑标准**{v.}++按税率定……的价格；征收关税**{n.}++a government tax on imports or exports																					   	同义词：								                                  				    duty**{v.}++charge a tariff																										        				&quot;tariff imported goods&quot;**', '');
insert into TOEFLWordBook values ('1006', 'taste', '[teɪst]', 'http://dict.youdao.com/dictvoice?audio=taste', '{n.}++味道，滋味；味觉；爱好，兴趣；（个人）喜欢的事物（tastes）；鉴赏力，品味；体验，尝试；（某段经历造成的）感觉，感受；（用来品尝的）一点儿，少量，一口；（用于短语，表示某人的言行举止等）得当，不得当**{v.}++尝起来；尝出……的味道；尝，品尝；（短暂地）体验，领略，经历；意识到，感觉到**{n.}++the sensation that results when taste buds in the tongue and throat convey information about the chemical composition of a soluble stimulus																										        													        				&quot;the candy left him with a bad taste&quot;; &quot;the melon had a delicious taste&quot;															   	同义词：								                                  				    taste sensation				    				    				      				    				      				    				                                      				    gustatory sensation				    				    				      				    				      				    				                                      				    taste perception				    				    				      				    				      				    				                                      				    gustatory perception**{n.}++[食品]味道；品味；审美**{vt.}++尝；体验**', '');
insert into TOEFLWordBook values ('1007', 'technical', '[ˈteknɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=technical', '{adj.}++工艺的，技术的；专业的，专门的；严格按照法律意义的，严格按字面解释的；（尤指体育或艺术等活动）技巧（上）的；与机器（或系统）运行相关的，技术性的**{n.}++（车后架设有机枪的）小卡车**{n.}++a pickup truck with a gun mounted on it**{adj.}++工艺的，科技的；技术上的；专门的**', '');
insert into TOEFLWordBook values ('1008', 'tectonics', '[tekˈtɑːnɪks]', 'http://dict.youdao.com/dictvoice?audio=tectonics', '{n.}++[建] 构造学，[地质] 构造地质学**{n.}++the science of architecture																					   	同义词：								                                  				    architectonics**{n.}++[建][地质]构造学，构造地质学**', '');
insert into TOEFLWordBook values ('1009', 'telegraph', '[ˈtelɪɡræf]', 'http://dict.youdao.com/dictvoice?audio=telegraph', '{n.}++电报（指通信方式）；电报机；（运动比赛得分或其他信息的）显示板**{v.}++发电报，用电报发送（信息）；流露，透露（计划或意图）**{n.}++apparatus used to communicate at a distance over a wire (usually in Morse code)																					   	同义词：								                                  				    telegraphy**{v.}++send cables, wires, or telegrams																					   	同义词：								                                  				    cable				    				    				      				    				      				    				                                      				    wire**{n.}++[通信]电报机，电报**{vt.}++电汇；流露出；打电报给…**{vi.}++[通信]打电报**', '');
insert into TOEFLWordBook values ('1010', 'televise', '[ˈtelɪvaɪz]', 'http://dict.youdao.com/dictvoice?audio=televise', '{vt.}++用电视播放**{vi.}++电视播放**{v.}++broadcast via television																										        				&quot;The Royal wedding was televised&quot;															   	同义词：								                                  				    telecast**', '');
insert into TOEFLWordBook values ('1011', 'tenant', '[ˈtenənt]', 'http://dict.youdao.com/dictvoice?audio=tenant', '{n.}++房客，租户；业主**{v.}++（作为租赁者）居住，工作**{n.}++someone who pays rent to use land or a building or a car that is owned by someone else																										        				&quot;the landlord can evict a tenant who doesnt pay the rent&quot;															   	同义词：								                                  				    renter**{n.}++[租赁]承租人；房客；佃户；居住者**{vt.}++租借（常用于被动语态）**', '');
