insert into TOEFLWordBook values ('1013', 'tension', '[ˈtenʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=tension', '{n.}++紧张，焦虑；紧张关系，紧张局势；矛盾，冲突；（电线、绳子、肌肉等的）拉紧，绷紧；拉力，张力；（电影、书籍中的）紧张情绪，恐怖气氛；（编织的）针织密度；电压**{v.}++使拉紧，使紧张**{n.}++feelings of hostility that are not manifest																										        				&quot;the diplomats first concern was to reduce international tensions&quot;															   	同义词：								                                  				    latent hostility**{n.}++张力，拉力；紧张，不安；电压**{vt.}++使紧张；使拉紧**', '');
insert into TOEFLWordBook values ('1014', 'terminal', '[ˈtɜːrmɪn(ə)l]', 'http://dict.youdao.com/dictvoice?audio=terminal', '{n.}++（火车、公共汽车或船的）终点站；航空终点站，航站楼；电脑终端；（电路的）端子，线接头；晚期病人；（石油，天然气的）集散站；（建筑）界标，端饰，胸像柱**{adj.}++（疾病） 致命的，不治的，晚期的；（病状）已达晚期的；逐步衰亡的，越来越糟的；终端的，末端的；极度的，极其的；学期的，期末的，按期的；（运输）终点（站）的；（动）末端的，远端的；（植）（花朵等）顶生的**{n.}++station where transport vehicles load or unload passengers or goods																					   	同义词：								                                  				    terminus				    				    				      				    				      				    				                                      				    depot**{n.}++末端；[交]终点；[计]终端机；极限**{adj.}++[动]末端的；[交]终点的；晚期的**', '');
insert into TOEFLWordBook values ('1015', 'terrace', '[ˈterəs]', 'http://dict.youdao.com/dictvoice?audio=terrace', '{n.}++（风格相同、互相连接的）排屋；（尤指房屋或餐馆外的）露天平台，阳台；（足球场的）阶梯看台；梯田，阶地；排屋中的一栋房屋；（地质）沿岸阶地，阶面**{v.}++使成阶地（或梯田）**{n.}++usually paved outdoor area adjoining a residence																					   	同义词：								                                  				    patio**{n.}++平台；[农]梯田；[建]阳台**', '');
insert into TOEFLWordBook values ('1016', 'terrible', '[ˈterəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=terrible', '{adj.}++糟糕的，令人极为不快的；极度的，极其严重的；劣质的，很差劲的；可怕的，骇人的；生病的，不高兴的；危害极大的，造成极大伤害的**{adj.}++causing fear or dread or terror																										        				&quot;a terrible curse&quot;															   	同义词：								                                  				    awful				    				    				      				    				      				    				                                      				    dire				    				    				      				    				      				    				                                      				    direful				    				    				      				    				      				    				                                      				    dread(a)				    				    				      				    				      				    				                                      				    dreaded				    				    				      				    				      				    				                                      				    dreadful				    				    				      				    				      				    				                                      				    fearful				    				    				      				    				      				    				                                      				    fearsome				    				    				      				    				      				    				                                      				    frightening				    				    				      				    				      				    				                                      				    horrendous				    				    				      				    				      				    				                                      				    horrific**{adj.}++可怕的；很糟的；令人讨厌的**{adv.}++很，非常**', '');
insert into TOEFLWordBook values ('1017', 'territory', '[ˈterətɔːri]', 'http://dict.youdao.com/dictvoice?audio=territory', '{n.}++领土，版图，领地；（美国、加拿大等的）准州；（某些国家划分的）地区；（某一动物或人想控制的）领地，地盘；（某人负责的）区域，地区；（具有某种特性的）地区，地方；（知识等的）领域，范围；（体育运动中的）防守区**{n.}++a region marked off for administrative or other purposes																					   	同义词：								                                  				    district				    				    				      				    				      				    				                                      				    territorial dominion				    				    				      				    				      				    				                                      				    dominion**{n.}++领土，领域；范围；地域；[地理]版图**', '');
insert into TOEFLWordBook values ('1018', 'testify', '[ˈtestɪfaɪ]', 'http://dict.youdao.com/dictvoice?audio=testify', '{v.}++（通常指在法庭上）作证；证明，证实；（尤指做礼拜时）见证（上帝存在）**{v.}++give testimony in a court of law																					   	同义词：								                                  				    attest				    				    				      				    				      				    				                                      				    take the stand				    				    				      				    				      				    				                                      				    bear witness**{vt.}++证明，证实；作证**{vi.}++作证；证明**', '');
insert into TOEFLWordBook values ('1019', 'textile', '[ˈtekstaɪl]', 'http://dict.youdao.com/dictvoice?audio=textile', '{n.}++纺织物，织物；纺织业（textiles）；着衣者，非自然主义者**{adj.}++纺织的；非自然主义者的，限于着衣者的（裸体主义者用语）**{n.}++artifact made by weaving or felting or knitting or crocheting natural or synthetic fibers																					   	同义词：								                                  				    fabric				    				    				      				    				      				    				                                      				    cloth				    				    				      				    				      				    				                                      				    material**{adj.}++of or relating to fabrics or fabric making																										        				&quot;textile research&quot;**{n.}++[纺]纺织品，织物**{adj.}++[纺]纺织的**', '');
insert into TOEFLWordBook values ('1020', 'texture', '[ˈtekstʃər]', 'http://dict.youdao.com/dictvoice?audio=texture', '{n.}++质地，纹理；口感；（音乐或文学的）谐和统一感，神韵**{v.}++使（织物、墙面等）具浮凸结构（或特征）**{n.}++the feel of a surface or a fabric																										        				&quot;the wall had a smooth texture&quot;**{n.}++质地；纹理；结构；本质，实质**', '');
insert into TOEFLWordBook values ('1021', 'theme', '[θiːm]', 'http://dict.youdao.com/dictvoice?audio=theme', '{n.}++（谈话、书籍、电影等的）题目，主题；（音乐的）主旋律；（电影、电视节目、广播节目的）主题音乐，主题曲；（学生的）作文；（聚会、房间等的）风格；（句子的）主位；（名词、动词等的）词干；（拜占庭帝国的）行政区**{adj.}++以奇想主题布置的**{v.}++（休闲场所、活动）以……主题**{n.}++the subject matter of a conversation or discussion																										        				&quot;his letters were always on the theme of love&quot;															   	同义词：								                                  				    subject				    				    				      				    				      				    				                                      				    topic**{n.}++主题；主旋律；题目**', '');
