insert into TOEFLWordBook values ('1023', 'thought', '[θɔːt]', 'http://dict.youdao.com/dictvoice?audio=thought', '{n.}++想法，看法，主意；考虑，深思；关心，顾虑；意图，希望，念头；思想，思潮；思考，思维；心思，思想（thoughts）**{v.}++认为，觉得；思考，考虑；想做，打算做（think 的过去式和过去分词形式）**{n.}++the content of cognition; the main thing you are thinking about																										        				&quot;the thought never entered my mind&quot;															   	同义词：								                                  				    idea**{n.}++思想；思考；想法；关心**{v.}++想，思考；认为（think的过去式和过去分词）**', '');
insert into TOEFLWordBook values ('1024', 'threat', '[θret]', 'http://dict.youdao.com/dictvoice?audio=threat', '{n.}++威胁，恐吓；构成威胁的人（或事物）；凶兆，征兆；（律）恐吓，威胁**{n.}++something that is a source of danger																										        				&quot;earthquakes are a constant threat in Japan&quot;															   	同义词：								                                  				    menace**{n.}++威胁，恐吓；凶兆**', '');
insert into TOEFLWordBook values ('1025', 'thrive', '[θraɪv]', 'http://dict.youdao.com/dictvoice?audio=thrive', '{v.}++茁壮成长，兴旺，繁荣；（尤指在别人觉得困难的时候）以……为乐，可以出色应对**{v.}++grow stronger																					   	同义词：								                                  				    boom				    				    				      				    				      				    				                                      				    prosper				    				    				      				    				      				    				                                      				    get ahead				    				    				      				    				      				    				                                      				    flourish				    				    				      				    				      				    				                                      				    expand**{vi.}++繁荣，兴旺；茁壮成长**', '');
insert into TOEFLWordBook values ('1026', 'throw', '[θroʊ]', 'http://dict.youdao.com/dictvoice?audio=throw', '{v.}++投，掷，抛，扔；掷（色子），掷出（色子的点数）；随手扔下（某物）；猛推，使劲撞；急伸，猛动（身体部位）；使迅猛地摔倒在地；使突然陷入；使困惑，使惊奇；把……拉成坯；投射（光或影子）；使嗓音听起来像来自他人（或别处）；故意输掉（比赛）；扳动（开关、操作杆等）；将……关进（监狱等）；大发脾气；（挥拳）猛击；举办（聚会）；投入，投身（于）；将……投向（某人）；（车辆）突然换挡；成功完成；迅速放置（或立起）；（马）脱落（蹄铁）；（动物）下仔；（在车床上）车（木料等）；捻（丝等）成线**{n.}++投，掷；投射距离；套，罩；摔倒对手；每一份（花费）；（地质）落差，位移；速转装置，旋转工具；摆动；（指针的）行程；冒险**{n.}++the act of throwing (propelling something through the air with a rapid movement of the arm and wrist)																										        				&quot;the catcher made a good throw to second base&quot;**{vt.}++投；抛；掷**{vi.}++抛；投掷**{n.}++投掷；冒险**', '');
insert into TOEFLWordBook values ('1027', 'thrust', '[θrʌst]', 'http://dict.youdao.com/dictvoice?audio=thrust', '{v.}++猛推，猛塞；刺，扎；（人）推进，挤过；上伸，伸出；强使接受**{n.}++要点，要旨；猛推，刺；（飞机、火箭等的）驱动力，推力；强攻，挺进；（拱、椽的）侧向压力；（地质）冲断层，逆断层；苛评**{n.}++the force used in pushing																										        				&quot;the thrust of the jet engines&quot;															   	同义词：								                                  				    push**{n.}++[力]推力；刺**{vt.}++插；插入；推挤**{vi.}++插入；用向某人刺去；猛然或用力推**', '');
insert into TOEFLWordBook values ('1028', 'thumb', '[θʌm]', 'http://dict.youdao.com/dictvoice?audio=thumb', '{n.}++拇指；（手套的）拇指部分；（灵长目动物或其他哺乳动物的）第一指；竖起大拇指，翘起大拇指（以表示赞成或说明没问题）；将拇指指向（所谈论的对象）**{v.}++竖起大拇指请求搭便车；用拇指摸，用拇指捋；用拇指示意；用拇指翻动，翻阅**{n.}++the thick short innermost digit of the forelimb																					   	同义词：								                                  				    pollex**{vt.}++翻阅；以拇指拨弄；作搭车手势；笨拙地摆弄**', '');
insert into TOEFLWordBook values ('1029', 'thunder', '[ˈθʌndər]', 'http://dict.youdao.com/dictvoice?audio=thunder', '{n.}++雷，雷声；雷鸣般的响声，轰隆声；怒容满面，（雷鸣般的）怒吼**{v.}++打雷；发出雷鸣般的响声，轰隆地响；轰隆隆地快速移动，使快速移动；愤怒地大叫，怒吼；砰然重击**{n.}++a deep prolonged loud noise																					   	同义词：								                                  				    boom				    				    				      				    				      				    				                                      				    roar				    				    				      				    				      				    				                                      				    roaring**{n.}++[气象]雷；轰隆声；恐吓**{vi.}++打雷；怒喝**{vt.}++轰隆地发出；大声喊出**', '');
insert into TOEFLWordBook values ('1030', 'ticket', '[ˈtɪkɪt]', 'http://dict.youdao.com/dictvoice?audio=ticket', '{n.}++票，入场券；（交通违章）通知单，罚款单；（政党在选举中支持的）候选人名单；（竞选时所支持的）纲领，政见；（商店中标明货物价格、尺码等的）标签；彩票，奖券；途径；（货物）收条；（船员、飞行员等的）执照；工单；退役证书；……人，……家伙**{v.}++售票；给（违章停车、超速行驶的人）开罚单；（为显示价格、尺寸等）贴标签于；给定目标；注定**{n.}++a commercial document showing that the holder is entitled to something (as to ride on public transportation or to enter a public entertainment)**{n.}++票；[经]入场券，标签；（美）候选人名单；证明书；交通罚款单**{vt.}++加标签于；指派；对…开出交通违规罚单**', '');
insert into TOEFLWordBook values ('1031', 'tight', '[taɪt]', 'http://dict.youdao.com/dictvoice?audio=tight', '{adj.}++牢固的，不松动的；紧身的；拉紧的，绷紧的；严厉的，严格的；紧的，拮据的；密集的，挤满的；亲密的，紧密的；急转的，陡的；憋闷的，不适的；紧张的，生气的；势均力敌的；困难的，棘手的；准确的，紧凑的；吝啬的；醉醺醺的；结实的**{adv.}++紧紧地，牢固地**{adj.}++closely constrained or constricted or constricting																										        													        													        													        				&quot;tight skirts&quot;; &quot;he hated tight starched collars&quot;; &quot;fingers closed in a tight fist&quot;; &quot;a tight feeling in his chest&quot;**{adj.}++[服装][贸易]紧的；[机]密封的；绷紧的；麻烦的；严厉的；没空的；吝啬的**{adv.}++紧紧地；彻底地**', '');
insert into TOEFLWordBook values ('1032', 'timber', '[ˈtɪmbər]', 'http://dict.youdao.com/dictvoice?audio=timber', '{n.}++木材，原木；（用于生产木材的）林木，树林；（造屋或造船用的）大木料，栋木；（砍伐树木时说）倒啦，小心大树倒下；（尤指人适于某角色的）素质，性格，才干**{v.}++用木料支撑或建造**{n.}++the wood of trees cut and prepared for use as building material																					   	同义词：								                                  				    lumber**{n.}++[木]木材；木料**', '');
insert into TOEFLWordBook values ('1033', 'tissue', '[ˈtɪʃuː]', 'http://dict.youdao.com/dictvoice?audio=tissue', '{n.}++纸巾，面巾纸；（动物或植物的细胞）组织；（用于包装易碎物品的）薄纸，绵纸；薄纱，薄织物；（罗织编造的）一套，一系列**{v.}++用化妆纸揩去；饰以薄纱**{n.}++part of an organism consisting of an aggregate of cells having a similar structure and function**{n.}++纸巾；[纺]薄纱；一套**', '');
insert into TOEFLWordBook values ('1034', 'tobacco', '[təˈbækoʊ]', 'http://dict.youdao.com/dictvoice?audio=tobacco', '{n.}++烟草，烟叶；烟草制品；烟草植株；抽烟**{n.}++leaves of the tobacco plant dried and prepared for smoking or ingestion																					   	同义词：								                                  				    baccy**{n.}++[作物]烟草，烟叶；[轻]烟草制品；抽烟**', '');
insert into TOEFLWordBook values ('1035', 'toe', '[toʊ]', 'http://dict.youdao.com/dictvoice?audio=toe', '{n.}++（人的）脚趾，（兽、鸟的）趾；（袜、鞋等的）足尖部；端部，尖部；（高尔夫球的）球棒尖；坡脚，基脚，堤脚；（曲线的）趾区；肉质根部**{v.}++用脚尖推（或触碰、踢、踩）；足尖朝内（或外）行走；（一对车轮）前束（或反前束，后束）；（高尔夫）用球棒尖击（球）**{n.}++one of the digits of the foot**{n.}++[解剖]脚趾；足尖**', '');
insert into TOEFLWordBook values ('1036', 'tolerance', '[ˈtɑːlərəns]', 'http://dict.youdao.com/dictvoice?audio=tolerance', '{n.}++忍受，容忍；（痛苦、困难等的）忍受程度，忍耐力；耐药力，耐受性；公差，容许偏差**{n.}++the power or capacity of an organism to tolerate unfavorable environmental conditions**{n.}++[机]公差；宽容；容忍；公差**', '');
insert into TOEFLWordBook values ('1037', 'tongue', '[tʌŋ]', 'http://dict.youdao.com/dictvoice?audio=tongue', '{n.}++舌，舌头；（供食用的动物的）舌头，口条；语言，方言；说话方式，写作风格；鞋舌；舌状物；（延伸入湖、海等中的）长条状陆地，舌状陆地；榫舌，雄榫；（脊椎动物的）齿舌；（昆虫的）喙；钟锤；（乐器、风琴管的）簧片；搭扣销**{v.}++用运舌法吹奏（管乐器）；用舌头触碰，舔；说话；斥责**{n.}++a mobile mass of muscular tissue covered with mucous membrane and located in the oral cavity																					   	同义词：								                                  				    lingua				    				    				      				    				      				    				                                      				    glossa				    				    				      				    				      				    				                                      				    clapper**{a human written or spoken language used by a community; opposed to e.}++g. a computer language																					   	同义词：								                                  				    natural language**{n.}++舌头；语言**{vt.}++舔；斥责；用舌吹**{vi.}++说话；吹管乐器**', '');
insert into TOEFLWordBook values ('1038', 'touch', '[tʌtʃ]', 'http://dict.youdao.com/dictvoice?audio=touch', '{v.}++触摸，碰；接触，触及；损坏，伤害；吃，喝，使用；感动，触动；影响，与……有关；与……媲美，比得上；达到（某一水平等）；参与，涉及；处理，做（某事）；（在脸上）闪现，掠过；轻轻击（球）；具有……特性；向（某人）讨要（物品）；跑垒得分；（几何）与（曲线，表面）切触；（用画笔、铅笔）轻轻勾勒**{n.}++触觉，触感；触摸，碰；触摸时的感觉；润色，装点；作风，风格，手法；一点儿，少许；略微，稍微；边线以外的区域；触球，控球；（音乐家的）触键法，弹奏法；（乐器键、弦的）弹性，弹力；（钢笔、铅笔等的）轻触；转调较少的钟乐**{n.}++the event of something coming in contact with the body																										        													        				&quot;he longed for the touch of her hand&quot;; &quot;the cooling touch of the night air&quot;															   	同义词：								                                  				    touching**{vt.}++接触；触动；使轻度受害**{vi.}++触摸；涉及；接近；提到**{n.}++接触；[生理]触觉；格调；少许**', '');
insert into TOEFLWordBook values ('1039', 'tough', '[tʌf]', 'http://dict.youdao.com/dictvoice?audio=tough', '{adj.}++（物质，物体）坚韧的，坚固的；（政策或行动）强硬的，严厉的；吃苦耐劳的，坚韧不拔的；顽固的，固执的；困难的，棘手的；艰难的，困苦的，难熬的；（食物）老的，不易切开的，嚼不动的；（人）粗暴的，粗鲁的；（地区）充满暴力与犯罪的；不幸的，倒霉的，活该（表示不同情）**{n.}++恶棍**{v.}++坚持，忍受，忍耐**{adv.}++坚强地，坚定地**{n.}++someone who learned to fight in the streets rather than being formally trained in the sport of boxing																					   	同义词：								                                  				    street fighter**{adj.}++艰苦的，困难的；坚强的，不屈不挠的；坚韧的，牢固的；强壮的，结实的**{n.}++恶棍**{vt.}++坚持；忍受，忍耐**{adv.}++强硬地，顽强地**', '');
insert into TOEFLWordBook values ('1040', 'tow', '[toʊ]', 'http://dict.youdao.com/dictvoice?audio=tow', '{v.}++拖，牵引（车、船等）；（人）牵引，拖带（某人，某物）**{n.}++（对车船等的）牵引，拖；牵引绳，拖链**{n.}++the act of hauling something (as a vehicle) by means of a hitch or rope																										        				&quot;the truck gave him a tow to the garage&quot;															   	同义词：								                                  				    towage**{v.}++drag behind																										        				&quot;Horses used to tow barges along the canal&quot;**{n.}++拖；[纺]麻的粗纤维；拖曳所用之绳**{vt.}++拖；牵引；曳**', '');
insert into TOEFLWordBook values ('1041', 'towel', '[ˈtaʊəl]', 'http://dict.youdao.com/dictvoice?audio=towel', '{n.}++毛巾，抹布，纸巾；卫生巾**{v.}++用毛巾擦，用毛巾擦干；鞭打**{n.}++a rectangular piece of absorbent cloth (or paper) for drying or wiping**{v.}++wipe with a towel																										        				&quot;towel your hair dry&quot;**{n.}++[纺]毛巾，手巾；[纸]纸巾**', '');
insert into TOEFLWordBook values ('1042', 'toxic', '[ˈtɑːksɪk]', 'http://dict.youdao.com/dictvoice?audio=toxic', '{adj.}++有毒的，引起中毒的；令人极不愉快的，极其有害的，恶毒的；中毒的，中毒性的；（财政）（债务）有毒的，风险高的；（证券）有毒的**{n.}++有毒物质，毒药（toxics）**{adj.}++of or relating to or caused by a toxin or poison																										        				&quot;suffering from exposure to toxic substances&quot;**{adj.}++[内科][毒物]有毒的；中毒的**', '');
insert into TOEFLWordBook values ('1043', 'tract', '[trækt]', 'http://dict.youdao.com/dictvoice?audio=tract', '{n.}++（尤指宣扬宗教、伦理或政治的）短文，传单，小册子；大片土地，地带；（身体的）道，束；大量，许多；咏唱（原在罗马天主教某些忏悔或安魂弥撒时用以代替阿利路亚赞美诗所唱的《圣经》韵文圣歌）**{n.}++an extended area of land																					   	同义词：								                                  				    piece of land				    				    				      				    				      				    				                                      				    piece of ground				    				    				      				    				      				    				                                      				    parcel of land				    				    				      				    				      				    				                                      				    parcel**{n.}++束；大片土地，地带；小册子**', '');
insert into TOEFLWordBook values ('1044', 'traditional', '[trəˈdɪʃən(ə)l]', 'http://dict.youdao.com/dictvoice?audio=traditional', '{adj.}++传统的；根据传统而制造（或使用）的；因袭的，守旧的；（活动）惯例的，经常从事的；典型的；（爵士乐）具20世纪早期风格的**{adj.}++consisting of or derived from tradition																										        													        				&quot;traditional history&quot;; &quot;traditional morality&quot;**{adj.}++传统的；惯例的**', '');
insert into TOEFLWordBook values ('1045', 'traffic', '[ˈtræfɪk]', 'http://dict.youdao.com/dictvoice?audio=traffic', '{n.}++路上行驶的车辆，交通；（沿固定路线的）航行，行驶，飞行；运输量；非法交易；信息流量，通信（量）**{v.}++（非法）进行……交易，做……买卖；在……通行**{n.}++the aggregation of things (pedestrians or vehicles) coming and going in a particular locality during a specified period of time**{n.}++[交]交通；运输；贸易；[通信]通信量**{vi.}++交易，买卖**', '');
insert into TOEFLWordBook values ('1046', 'trail', '[treɪl]', 'http://dict.youdao.com/dictvoice?audio=trail', '{n.}++痕迹，踪迹；（人或动物的）足迹，嗅迹；（乡间的）小路，小径；（特定）路线，路径；一系列（坏事或有害事件）；（尤指细长）一缕，一串；滑雪坡，滑雪道，越野滑雪路线；电影或广播的预告片；（炮架的）架尾**{v.}++拖，拉；没精打采地走，拖沓地走；（在竞赛或选举中）落后，输；跟踪，追踪；蔓生，蔓延，被搁置；垂下；慢慢移动，缓缓流动；（声音，喇叭）渐弱；事先宣传，预告（影片，节目等）；喷注（泥釉）**{n.}++a track or mark left by something that has passed																										        													        				&quot;there as a trail of blood&quot;; &quot;a tear left its trail on her cheek&quot;**{vt.}++追踪；拖；蔓延；落后于**{n.}++小径；痕迹；尾部；踪迹**{vi.}++飘出；[植]蔓生；垂下；[古生]拖曳**', '');
insert into TOEFLWordBook values ('1047', 'tranquil', '[ˈtræŋkwɪl]', 'http://dict.youdao.com/dictvoice?audio=tranquil', '{adj.}++平静的，宁静的**{adj.}++(of a body of water) free from disturbance by heavy waves																										        				&quot;a lake of tranquil blue water reflecting a tranquil blue sky&quot;															   	同义词：								                                  				    placid				    				    				      				    				      				    				                                      				    quiet				    				    				      				    				      				    				                                      				    still				    				    				      				    				      				    				                                      				    smooth				    				    				      				    				      				    				                                      				    unruffled**{adj.}++安静的，平静的；安宁的；稳定的**', '');
insert into TOEFLWordBook values ('1048', 'transfer', '[trænsˈfɜːr]', 'http://dict.youdao.com/dictvoice?audio=transfer', '{v.}++（使）转移，搬迁；转移（感情），传染（疾病），转让（权力等）；（使）调动，转职；转会，使转会（尤指职业足球队）；（将所得学分）转到（另一所学校）；转接（电话）；将（钱）转到（另一个账户上）；转让（财产，权利），移交（责任）；转用；转存，转录（资料、音乐等），改编；（旅途中）转乘，换乘；转印（图画，图案）；（通过延伸、隐喻）转变（词义，短语义）**{n.}++转移，转让，调动；（运动员）转会；转换，过渡；已调动的人，已转移的东西；（旅行中）转乘，转搭；转车票，换乘票；纸上可转印的图画或图案；迁移（将已习得的行为在新的情况下应用）**{n.}++the act of moving something from one location to another																					   	同义词：								                                  				    transportation				    				    				      				    				      				    				                                      				    transferral				    				    				      				    				      				    				                                      				    conveyance**{n.}++转让；[计]转移；传递；过户**{vi.}++转让；[计]转移；转学；换车**{vt.}++转让；[计]使转移；传递；调任**', '');
insert into TOEFLWordBook values ('1049', 'transit', '[ˈtrænzɪt]', 'http://dict.youdao.com/dictvoice?audio=transit', '{n.}++运输，运送；交通运输系统；通过，经过；（天文）凌日；（天文）中天；（占星）凌；（商标）（尤指用于运货的）“全顺”汽车（Transit）**{v.}++经过，穿过；（天文）（行星等天体）经过（另一天体、子午线）；（占星）（行星等天体）经过（黄道十二宫之一、住宅或星图区域）**{n.}++a surveying instrument for measuring horizontal and vertical angles, consisting of a small telescope mounted on a tripod																					   	同义词：								                                  				    theodolite**{n.}++运输；经过**{vt.}++运送**{vi.}++经过**', '');
insert into TOEFLWordBook values ('1050', 'translation', '[trænzˈleɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=translation', '{n.}++翻译；译文，译本；译词，译语；转变，转化；（生）转译；转移；（数）平移；调任**{n.}++a written communication in a second language having the same meaning as the written communication in a first language																					   	同义词：								                                  				    interlingual rendition				    				    				      				    				      				    				                                      				    rendering				    				    				      				    				      				    				                                      				    version**{n.}++[语][计]翻译；译文；转化；调任**', '');
insert into TOEFLWordBook values ('1051', 'transmission', '[trænzˈmɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=transmission', '{n.}++（无线电、电视等信号的）播送，发送；（电台或电视等的）信息，广播；传递，传播，传染；（车辆的）传动装置，变速器**{n.}++the act of sending a message; causing a message to be transmitted																					   	同义词：								                                  				    transmittal				    				    				      				    				      				    				                                      				    transmitting**{n.}++传动装置，[机]变速器；传递；[计][通信]传送；播送**', '');
insert into TOEFLWordBook values ('1052', 'transparent', '[trænsˈpærənt]', 'http://dict.youdao.com/dictvoice?audio=transparent', '{adj.}++透明的，清澈的；（过程、活动或组织）透明的，公开的；明显的，一目了然的；（谎言或借口）易识破的；（思想、情感、动机）易被人所知的；（计算机）（过程、界面）透明的；（物理）可穿透的，（热、电磁波）可通过的**{adj.}++transmitting light; able to be seen through with clarity																										        				&quot;transparent crystal&quot;															   	同义词：								                                  				    crystalline				    				    				      				    				      				    				                                      				    crystal clear				    				    				      				    				      				    				                                      				    limpid				    				    				      				    				      				    				                                      				    lucid				    				    				      				    				      				    				                                      				    pellucid**{adj.}++透明的；显然的；坦率的；易懂的**', '');
insert into TOEFLWordBook values ('1053', 'transplant', '[trænsˈplænt]', 'http://dict.youdao.com/dictvoice?audio=transplant', '{v.}++移植（器官、皮肤等）；（使）迁移，（使）移居；移栽，移植（植物）**{n.}++（器官、皮肤等的）移植（手术）；移植的器官，移植物；移居者，迁居者**{n.}++(surgery) tissue or organ transplanted from a donor to a recipient; in some cases the patient can be both donor and recipient																					   	同义词：								                                  				    graft**{vt.}++[林]移植；迁移；使移居**{n.}++[林]移植；移植器官；被移植物；移居者**{vi.}++[林]移植；迁移；移居**', '');
insert into TOEFLWordBook values ('1054', 'treasure', '[ˈtreʒər]', 'http://dict.youdao.com/dictvoice?audio=treasure', '{n.}++金银财宝，珠宝，财富；（尤指艺术或有历史价值的）珍品；得力帮手，心肝宝贝；珍藏品，珍贵之物**{v.}++珍爱，珍藏；珍惜，珍视**{n.}++accumulated wealth in the form of money or jewels etc.																										        				&quot;the pirates hid their treasure on a small island in the West Indies&quot;															   	同义词：								                                  				    hoarded wealth**{n.}++财富，财产；财宝；珍品**{vt.}++珍爱；珍藏**', '');
insert into TOEFLWordBook values ('1055', 'treat', '[triːt]', 'http://dict.youdao.com/dictvoice?audio=treat', '{v.}++对待，看待；治疗，医治；请客，招待；（利用化学物质或反应）处理，保护；把……看作，把……视为；处理，探讨，论述；做使自己快乐的事；把（某物）给某人以示好感；提供（娱乐）；（尤指与对手）商谈，谈判**{n.}++（不同一般的）乐事，享受；款待，招待；请客，做东；甜食；（尤指不经常吃的）美味佳肴**{n.}++something considered choice to eat																					   	同义词：								                                  				    dainty				    				    				      				    				      				    				                                      				    delicacy				    				    				      				    				      				    				                                      				    goody				    				    				      				    				      				    				                                      				    kickshaw**{vt.}++治疗；对待；探讨；视为**{vi.}++探讨；请客；协商**{n.}++请客；款待**', '');
insert into TOEFLWordBook values ('1056', 'tremendous', '[trəˈmendəs]', 'http://dict.youdao.com/dictvoice?audio=tremendous', '{adj.}++巨大的，极大的；极好的，精彩的；令人望而生畏的，可怕的**{adj.}++extraordinarily large in size or extent or amount or power or degree																										        													        													        													        				&quot;tremendous sweeping plains&quot;; &quot;a tremendous fact in human experience&quot;; &quot;that a whole civilization should be dependent on technology&quot;; &quot;a plane took off with a tremendous noise&quot;															   	同义词：								                                  				    enormous**{adj.}++极大的，巨大的；惊人的**', '');
insert into TOEFLWordBook values ('1057', 'trick', '[trɪk]', 'http://dict.youdao.com/dictvoice?audio=trick', '{n.}++花招，诡计，骗局；窍门，技巧；戏法，把戏；恶作剧，戏弄；引起错觉（或记忆紊乱）的事物；（纸牌的）一圈，一墩；（特别的）习惯，方式；舵手的一班（一般为二或四小时）；嫖客**{v.}++欺骗，哄骗；（纹章）（用由字母、符号标明的颜色）给（盾形徽章）勾勒轮廓**{adj.}++骗人的，使人产生错觉的；（身体部位）虚弱的，有毛病的；巧妙的，取乐的**{n.}++a cunning or deceitful action or device																										        				&quot;he played a trick on me&quot;															   	同义词：								                                  				    fast one**{n.}++诡计；恶作剧；窍门；花招；骗局；欺诈**{vt.}++欺骗；哄骗；装饰；打扮**{vi.}++哄骗；戏弄**{adj.}++[电影]特技的；欺诈的；有决窍的**', '');
insert into TOEFLWordBook values ('1058', 'trigger', '[ˈtrɪɡər]', 'http://dict.youdao.com/dictvoice?audio=trigger', '{n.}++（枪械等的）扳机；（尤指引发不良反应或发展的）起因，诱因；（炸弹的）引爆器，触发器**{v.}++引发，激发；起动，触发；引爆（炸弹）**{n.}++lever that activates the firing mechanism of a gun																					   	同义词：								                                  				    gun trigger**{vt.}++[物化]引发，引起；[电子]触发**{n.}++[军]扳机；[电子]触发器；制滑机**', '');
insert into TOEFLWordBook values ('1059', 'trillion', '[ˈtrɪljən]', 'http://dict.youdao.com/dictvoice?audio=trillion', '{num.}++万亿，兆；百万兆；大量，无数**{adj.}++万亿的**{n.}++a very large indefinite number (usually hyperbole)																					   	同义词：								                                  				    million				    				    				      				    				      				    				                                      				    billion				    				    				      				    				      				    				                                      				    zillion				    				    				      				    				      				    				                                      				    jillion**', '');
insert into TOEFLWordBook values ('1060', 'trip', '[trɪp]', 'http://dict.youdao.com/dictvoice?audio=trip', '{n.}++（尤指短程往返的）旅行，旅游；出门，出行；绊倒；（吸毒所致的）幻觉，迷幻感受；让人开心的奇人，奇妙有趣的经历；强烈的情感体验；（赛跑等比赛的）赛程；自我放纵的态度（或行动）；（机器、电路的）开关；轻捷的脚步；错误**{v.}++绊，绊倒；脚步轻快地走（或跑、跳舞）；（尤指意外地）触动（开关）；（部分电路）自动断开；（服用毒品后）产生幻觉；（字句）轻松自如地吐出；作短程旅行；竖起（帆桁等）；（航海）起（锚）**{n.}++a journey for some purpose (usually including the return)																										        				&quot;he took a trip to the shopping center&quot;**{vi.}++绊倒；远足；犯错误；轻快地走**{n.}++旅行；绊倒；差错**', '');
insert into TOEFLWordBook values ('1061', 'triumph', '[ˈtraɪʌmf]', 'http://dict.youdao.com/dictvoice?audio=triumph', '{n.}++巨大成功，重大胜利；（胜利或成功的）喜悦，狂喜；（成功的）典范，楷模；古罗马凯旋式**{v.}++获胜，成功；（因胜利或成功而）欣喜，欢跃；（古罗马将军）凯旋而归**{n.}++a successful ending of a struggle or contest																										        				&quot;the agreement was a triumph for common sense&quot;															   	同义词：								                                  				    victory**{n.}++胜利，凯旋；欢欣**{vi.}++获得胜利，成功**', '');
insert into TOEFLWordBook values ('1062', 'troop', '[truːp]', 'http://dict.youdao.com/dictvoice?audio=troop', '{n.}++军队，士兵；部队，（尤指）骑兵连，装甲连；童子军中队；一组，一群**{v.}++成群结队地走，列队行进；（孤身一人）缓步前行，稳步前行；（尤指被告知）成群前往**{adj.}++军队的，有关或涉及军队的**{n.}++a group of soldiers**{n.}++军队；组；群；多数**{vi.}++群集；成群而行；结队**', '');
insert into TOEFLWordBook values ('1063', 'trough', '[trɔːf]', 'http://dict.youdao.com/dictvoice?audio=trough', '{n.}++（喂家畜的）饲料槽，饮水槽； （商业活动等的）淡季，低谷； （波浪间的）波谷，（小山间的）低谷；低压槽，槽形低压；（用于培植植物、调配化学制品的）槽形容器；（运水的）沟槽；地表槽谷；钱槽，钱眼；（数）凹点**{v.}++狼吞虎咽**{n.}++a narrow depression (as in the earth or between ocean waves or in the ocean bed)**{n.}++水槽，水槽；[经]低谷期；饲料槽；[气象]低气压**', '');
insert into TOEFLWordBook values ('1064', 'trumpet', '[ˈtrʌmpɪt]', 'http://dict.youdao.com/dictvoice?audio=trumpet', '{n.}++小号，喇叭；喇叭形物（尤指黄水仙的管状冠）；喇叭似的响声（尤指大象的吼声）；（风琴的）小号音栓；北美黄瓶子草（trumpets）**{v.}++鼓吹，大肆宣扬；（尤指大象）吼叫；吹喇叭，吹小号**{n.}++a brass musical instrument with a brilliant tone; has a narrow tube and a flared bell and is played by means of valves																					   	同义词：								                                  				    cornet				    				    				      				    				      				    				                                      				    horn				    				    				      				    				      				    				                                      				    trump**{v.}++proclaim on, or as if on, a trumpet																										        				&quot;Liberals like to trumpet their opposition to the death penalty&quot;**{n.}++喇叭；喇叭声**{vt.}++吹喇叭；吹嘘**{vi.}++吹喇叭；发出喇叭般的声音**', '');
insert into TOEFLWordBook values ('1065', 'twine', '[twaɪn]', 'http://dict.youdao.com/dictvoice?audio=twine', '{n.}++（两股或多股的）线，绳**{v.}++使缠绕；（植物）盘绕；交织**{n.}++a lightweight cord																					   	同义词：								                                  				    string**{v.}++spin or twist together so as to form a cord																										        				&quot;intertwine the ribbons&quot;															   	同义词：								                                  				    intertwine				    				    				      				    				      				    				                                      				    entwine				    				    				      				    				      				    				                                      				    enlace				    				    				      				    				      				    				                                      				    interlace				    				    				      				    				      				    				                                      				    lace**{vt.}++使缠绕；使交织；编饰**{vi.}++缠绕；搓；交织；编饰**{n.}++麻线；细绳；搓；合股线**', '');
insert into TOEFLWordBook values ('1066', 'twig', '[twɪɡ]', 'http://dict.youdao.com/dictvoice?audio=twig', '{n.}++小枝，嫩枝；（剖）血管小支，神经小支**{v.}++顿悟，突然明白；察觉，观察**{n.}++a small branch or division of a branch (especially a terminal division); usually applied to branches of the current or preceding year																					   	同义词：								                                  				    branchlet				    				    				      				    				      				    				                                      				    sprig**{v.}++branch out in a twiglike manner																										        				&quot;The lightning bolt twigged in several directions&quot;**{vi.}++理解**{vt.}++理解**{n.}++小枝；嫩枝；末梢**', '');
insert into TOEFLWordBook values ('1067', 'twist', '[twɪst]', 'http://dict.youdao.com/dictvoice?audio=twist', '{v.}++使弯曲；（使）扭曲变形；扭动身体；扭伤（脚踝等）；旋转，转动；编织，捻在一起；缠绕；歪曲，曲解；蜿蜒，曲折；欺诈；牌面朝上**{n.}++扭动，转动；弯曲处，拐弯处；转折，变化；螺旋形物体；扭摆舞（the twist）；扭歪，（性格）反常；（棉，丝） 合股线；混合酒；欺诈；（棍棒或其他物体） 扭转度；扭转力，转矩；绕轴旋转前进**{n.}++an unforeseen development																					   	同义词：								                                  				    turn				    				    				      				    				      				    				                                      				    turn of events**{vt.}++捻；拧；扭伤；编织；使苦恼**{n.}++[力]扭曲；拧；扭伤**{vi.}++扭动；弯曲**', '');
insert into TOEFLWordBook values ('1068', 'typical', '[ˈtɪpɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=typical', '{adj.}++典型的，有代表性的；一贯的，平常的；不出所料，特有的；象征性的**{adj.}++exhibiting the qualities or characteristics that identify a group or kind or category																										        													        													        													        													        													        				&quot;a typical American girl&quot;; &quot;a typical suburban community&quot;; &quot;the typical car owner drives 10,000 miles a year&quot;; &quot;a painting typical of the Impressionist school&quot;; &quot;a typical romantic poem&quot;; &quot;a typical case of arteritis&quot;**{adj.}++[数]典型的；特有的；象征性的**', '');
insert into TOEFLWordBook values ('1069', 'tyrannical', '[təˈrænɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=tyrannical', '{adj.}++残暴的；暴君的；专横的**{adj.}++of or relating to or associated with or resembling a dictatorship																										        				&quot;tyrannical suppression of liberty&quot;															   	同义词：								                                  				    tyrannic**{adj.}++残暴的；暴君的；专横的**', '');
insert into TOEFLWordBook values ('1070', 'ultimate', '[ˈʌltɪmət]', 'http://dict.youdao.com/dictvoice?audio=ultimate', '{adj.}++最终的，最后的；最根本的，最基础的；极限的，终极的；首要的，决定性的；（太空或时空中）最遥远的；（物理）极限的**{n.}++最好的事物，最终的事物；最终（或最根本）的事实（或原则）；极限飞盘（Ultimate Frisbee 的简称）**{v.}++结束**{n.}++the finest or most superior quality of its kind																										        				&quot;the ultimate in luxury&quot;**{adj.}++furthest or highest in degree or order; utmost or extreme																										        													        													        													        													        				&quot;the ultimate achievement&quot;; &quot;the ultimate question&quot;; &quot;mans ultimate destiny&quot;; &quot;the ultimate insult&quot;; &quot;ones ultimate goal in life&quot;**{adj.}++最终的；[物]极限的；根本的**{n.}++终极；根本；基本原则**', '');
insert into TOEFLWordBook values ('1071', 'unaided', '[ʌnˈeɪdɪd]', 'http://dict.youdao.com/dictvoice?audio=unaided', '{adj.}++（通常用于动词后修饰主语）未受协助的；无助的**{adv.}++无外援地；独立地**{adj.}++carried out without aid or assistance																										        				&quot;his first unaided walk through the park&quot;**{adj.}++未受协助的；无助的**', '');
insert into TOEFLWordBook values ('1072', 'undergraduate', '[ˌʌndərˈɡrædʒuət]', 'http://dict.youdao.com/dictvoice?audio=undergraduate', '{n.}++大学本科生，大学肄业生**{adj.}++大学本科生的，大学肄业生的**{n.}++a university student who has not yet received a first degree																					   	同义词：								                                  				    undergrad**{n.}++大学生；大学肄业生**{adj.}++大学生的**', '');
insert into TOEFLWordBook values ('1073', 'underlie', '[ˌʌndərˈlaɪ]', 'http://dict.youdao.com/dictvoice?audio=underlie', '{vt.}++构成……的基础，为……的起因；位于……的下面**{v.}++be or form the base for**', '');
insert into TOEFLWordBook values ('1074', 'undermine', '[ˌʌndərˈmaɪn]', 'http://dict.youdao.com/dictvoice?audio=undermine', '{v.}++逐渐削弱（损害）；故意破坏（某人）的形象（或威信）；在……下面挖，（尤指）从根基处损坏**{v.}++destroy property or hinder normal operations																					   	同义词：								                                  				    sabotage				    				    				      				    				      				    				                                      				    countermine				    				    				      				    				      				    				                                      				    counteract				    				    				      				    				      				    				                                      				    subvert				    				    				      				    				      				    				                                      				    weaken**{vt.}++破坏，渐渐破坏；挖掘地基**', '');
insert into TOEFLWordBook values ('1075', 'undertake', '[ˌʌndərˈteɪk]', 'http://dict.youdao.com/dictvoice?audio=undertake', '{v.}++承担，从事；承诺，答应；在内侧行驶时赶上并超越（另一辆车）**{v.}++enter upon an activity or enterprise																					   	同义词：								                                  				    set about				    				    				      				    				      				    				                                      				    attempt**{vt.}++承担，保证；从事；同意；试图**', '');
insert into TOEFLWordBook values ('1076', 'union', '[ˈjuːniən]', 'http://dict.youdao.com/dictvoice?audio=union', '{n.}++工会；联邦，联盟；协会，俱乐部；联合，合并；结婚，婚姻；美利坚合众国（the Union）；（数）并，并集；联管节，接头；（印度次大陆）村落联合体；教区联合济贫组织；旗帜上象征国家统一的部分；混纺织物**{n.}++an organization of employees formed to bargain with the employer																										        				&quot;you have to join the union in order to get a job&quot;															   	同义词：								                                  				    labor union				    				    				      				    				      				    				                                      				    trade union				    				    				      				    				      				    				                                      				    trades union				    				    				      				    				      				    				                                      				    brotherhood**{n.}++联盟，协会；工会；联合**', '');
insert into TOEFLWordBook values ('1077', 'unity', '[ˈjuːnəti]', 'http://dict.youdao.com/dictvoice?audio=unity', '{n.}++团结，统一；整体性，统一性；三一律（指戏剧在时间、地点和情节三点上的统一性）；统一体；（数目或数字）一**{n.}++an undivided or unbroken completeness or totality with nothing wanting																										        				&quot;he took measures to insure the territorial unity of Croatia&quot;															   	同义词：								                                  				    integrity				    				    				      				    				      				    				                                      				    wholeness**{n.}++团结；一致；联合；个体**', '');
insert into TOEFLWordBook values ('1078', 'universal', '[ˌjuːnɪˈvɜːrs(ə)l]', 'http://dict.youdao.com/dictvoice?audio=universal', '{adj.}++普遍的，全体的，全世界的；通用的，万能的；（逻）全称的，总称的**{n.}++普遍原则，通用原理；普遍看法，普遍特征；（逻）全称命题；（哲）普遍，一般概念；（哲）共相；（语言学）普遍现象，通用规则**{n.}++(linguistics) a grammatical rule (or other linguistic feature) that is found in all languages																					   	同义词：								                                  				    linguistic universal**{adj.}++普遍的；通用的；[天]宇宙的；全世界的；全体的**{n.}++一般概念；普通性**', '');
insert into TOEFLWordBook values ('1079', 'urban', '[ˈɜːrbən]', 'http://dict.youdao.com/dictvoice?audio=urban', '{adj.}++城市的，城镇的；黑人音乐的；住在都市的**{adj.}++relating to or concerned with a city or densely populated area																										        													        				&quot;urban sociology&quot;; &quot;urban development&quot;**{adj.}++城市的；住在都市的**', '');
insert into TOEFLWordBook values ('1080', 'utility', '[juːˈtɪləti]', 'http://dict.youdao.com/dictvoice?audio=utility', '{n.}++（煤气、水、电等的）公共服务，公用事业；（供电、供水等的）公用事业单位；应用程序，实用程序；实用，有用；小卡车，轻型货车；（博弈论，经济学）效用**{adj.}++有用的，多功能的；（体育运动）多面手的；实用的**{n.}++a company that performs a public service; subject to government regulation																					   	同义词：								                                  				    public utility				    				    				      				    				      				    				                                      				    public utility company				    				    				      				    				      				    				                                      				    public-service corporation**{n.}++实用；效用；公共设施；功用**{adj.}++实用的；通用的；有多种用途的**', '');
insert into TOEFLWordBook values ('1081', 'utilize', '[ˈjuːtəlaɪz]', 'http://dict.youdao.com/dictvoice?audio=utilize', '{v.}++利用，使用**{v.}++put into service; make work or employ (something) for a particular purpose or for its inherent or natural purpose																										        				&quot;How do you utilize this tool?&quot;															   	同义词：								                                  				    use				    				    				      				    				      				    				                                      				    utilise				    				    				      				    				      				    				                                      				    apply				    				    				      				    				      				    				                                      				    employ**{vt.}++利用**', '');
