insert into TOEFLWordBook values ('1084', 'vacuum', '[ˈvækjuːm]', 'http://dict.youdao.com/dictvoice?audio=vacuum', '{n.}++真空，真空容器；真空吸尘器；空白，空虚；（用真空吸尘器所做的）清洁，清扫**{v.}++用真空吸尘器打扫**{adj.}++利用真空的；真空的；产生真空的**{n.}++the absence of matter																					   	同义词：								                                  				    vacuity**{n.}++[真空]真空；空间；真空吸尘器**', '');
insert into TOEFLWordBook values ('1085', 'vague', '[veɪɡ]', 'http://dict.youdao.com/dictvoice?audio=vague', '{adj.}++不明确的，不清楚的；（形状）模糊的；（感情、记忆等）不完整的，不清晰的；含糊其词的，闪烁其词的；茫然的，心不在焉的**{adj.}++not clearly understood or expressed																										        													        				&quot;their descriptions of human behavior become vague, dull, and unclear&quot;; &quot;vague...forms of speech...have so long passed for mysteries of science&quot;															   	同义词：								                                  				    obscure**{adj.}++模糊的；含糊的；不明确的；暧昧的**', '');
insert into TOEFLWordBook values ('1086', 'valid', '[ˈvælɪd]', 'http://dict.youdao.com/dictvoice?audio=valid', '{adj.}++（文件或票证）有效的；正当的，合理的；合法有效的；计算机系统接受的，被计算机系统认为有效的**{adj.}++well grounded in logic or truth or having legal force																										        													        													        													        				&quot;a valid inference&quot;; &quot;a valid argument&quot;; &quot;a valid contract&quot;; &quot;a valid license&quot;**{adj.}++有效的，有根据的；正当的**', '');
insert into TOEFLWordBook values ('1087', 'vanish', '[ˈvænɪʃ]', 'http://dict.youdao.com/dictvoice?audio=vanish', '{v.}++突然不见，消失；不复存在，灭绝；（数学）变为零；使不见，使消失**{n.}++弱化音**{v.}++get lost, as without warning or explanation																					   	同义词：								                                  				    disappear				    				    				      				    				      				    				                                      				    go away**{vi.}++[数]消失；突然不见；成为零**{vt.}++使不见，[数]使消失**', '');
insert into TOEFLWordBook values ('1088', 'variable', '[ˈveriəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=variable', '{adj.}++易变的，多变的；时好时坏的；可变的，可调节的；（数）（数字）变量的；（植，动）变异的，变型的；（齿轮）变速的**{n.}++可变性，可变因素；（数学中的）变量，变元；（计算机）变量（元）；（天文）变星的简称；（东北信风带以北或南半球的东南信风带与西风带之间的）变风区**{n.}++something that is likely to vary; something that is subject to variation																										        				&quot;the weather is one variable to be considered&quot;**{adj.}++[生物][数][光]变量的；可变的；易变的，多变的；变异的，畸变的**', '');
insert into TOEFLWordBook values ('1089', 'viable', '[ˈvaɪəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=viable', '{adj.}++可望成功的，切实可行的；能存活的，能生长发育的**{adj.}++capable of being done with means at hand and circumstances as they are																					   	同义词：								                                  				    feasible				    				    				      				    				      				    				                                      				    executable				    				    				      				    				      				    				                                      				    practicable				    				    				      				    				      				    				                                      				    workable**{adj.}++可行的；能养活的；能生育的**', '');
insert into TOEFLWordBook values ('1090', 'vibrant', '[ˈvaɪbrənt]', 'http://dict.youdao.com/dictvoice?audio=vibrant', '{adj.}++充满活力的，充满生机的，生气勃勃的；鲜艳的，醒目的；洪亮的，强劲的；颤抖的，震动的**{adj.}++vigorous and animated																										        				&quot;a vibrant group that challenged the system&quot;															   	同义词：								                                  				    vivacious**{adj.}++[力]振动的；充满生气的；响亮的；战栗的**', '');
insert into TOEFLWordBook values ('1091', 'vibrate', '[ˈvaɪbreɪt]', 'http://dict.youdao.com/dictvoice?audio=vibrate', '{v.}++（使）震动，（使）颤动；摇摆，踌躇**{v.}++shake, quiver, or throb; move back and forth rapidly, usually in an uncontrolled manner**{vi.}++振动；颤动；摇摆；踌躇**{vt.}++使振动；使颤动**', '');
