insert into TOEFLWordBook values ('1093', 'virtue', '[ˈvɜːrtʃuː]', 'http://dict.youdao.com/dictvoice?audio=virtue', '{n.}++高尚的道德，德行；美德，优秀品质；优点，长处；（尤指妇女的）贞操；功效；（传统基督教天使学）道德天使（天国九级制度的第七级）（virtues）**{n.}++the quality of doing what is right and avoiding what is wrong																					   	同义词：								                                  				    virtuousness				    				    				      				    				      				    				                                      				    moral excellence**{n.}++美德；优点；贞操；功效**', '');
insert into TOEFLWordBook values ('1094', 'vision', '[ˈvɪʒ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=vision', '{n.}++幻想，想象；幻觉，幻象；构想，展望；眼力，远见卓识；视力，视觉；视野；美好的人（或事物）；（电视或电影的）图像**{v.}++想像**{n.}++a vivid mental image																										        				&quot;he had a vision of his own death&quot;**{n.}++[生理][眼科]视力；美景；眼力；幻象；想象力**{vt.}++想象；显现；梦见**', '');
insert into TOEFLWordBook values ('1095', 'visual', '[ˈvɪʒuəl]', 'http://dict.youdao.com/dictvoice?audio=visual', '{adj.}++视觉的，视力的；栩栩如生的**{n.}++视觉资料（指说明性的图片、影片等）**{adj.}++relating to or using sight																										        													        				&quot;visual powers&quot;; &quot;visual navigation&quot;															   	同义词：								                                  				    ocular				    				    				      				    				      				    				                                      				    optic				    				    				      				    				      				    				                                      				    optical**{adj.}++[眼科][生理]视觉的，视力的；栩栩如生的**', '');
insert into TOEFLWordBook values ('1096', 'vital', '[ˈvaɪt(ə)l]', 'http://dict.youdao.com/dictvoice?audio=vital', '{adj.}++至关重要的，必不可少的；生机勃勃的，充满活力的；生命的，维持生命所必需的**{n.}++身体的重要内脏，维持生命的重要器官（vitals）**{adj.}++urgently needed; absolutely necessary																										        													        				&quot;vital for a healthy society&quot;; &quot;of vital interest&quot;															   	同义词：								                                  				    critical**{adj.}++至关重要的；生死攸关的；有活力的**', '');
insert into TOEFLWordBook values ('1097', 'vivid', '[ˈvɪvɪd]', 'http://dict.youdao.com/dictvoice?audio=vivid', '{adj.}++生动的，逼真的；（颜色）鲜艳的，明亮的；（人的想像）丰富的**{adj.}++evoking lifelike images within the mind																										        				&quot;a vivid description&quot;															   	同义词：								                                  				    graphic				    				    				      				    				      				    				                                      				    lifelike				    				    				      				    				      				    				                                      				    pictorial**{adj.}++生动的；鲜明的；鲜艳的**', '');
insert into TOEFLWordBook values ('1098', 'vocal', '[ˈvoʊk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=vocal', '{adj.}++嗓音的，发声的，歌唱的；直言不讳的，大声表达的**{n.}++（乐曲中的）歌唱部分，声乐部分**{n.}++music intended to be performed by one or more singers, usually with instrumental accompaniment																					   	同义词：								                                  				    vocal music**{adj.}++歌唱的；声音的，有声的**{n.}++声乐作品；元音**', '');
insert into TOEFLWordBook values ('1099', 'vocation', '[voʊˈkeɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=vocation', '{n.}++（认为某种职业适合自己的）使命感；（认为特别适合自己的）工作，职业，生活方式；神召，天命，（宗教）使命感**{n.}++the particular occupation for which you are trained																					   	同义词：								                                  				    career				    				    				      				    				      				    				                                      				    calling**{n.}++[劳经]职业；天职；天命；神召**', '');
insert into TOEFLWordBook values ('1100', 'volatile', '[ˈvɑːlət(ə)l]', 'http://dict.youdao.com/dictvoice?audio=volatile', '{adj.}++易变的，动荡不定的，反复无常的；（情绪）易变的，易怒的，突然发作的；（液体或固体）易挥发的，易气化的；（计算机内存）易失的**{n.}++挥发物；有翅的动物**{n.}++a volatile substance; a substance that changes readily from solid or liquid to a vapor																										        				&quot;it was heated to evaporate the volatiles&quot;**{adj.}++evaporating readily at normal temperatures and pressures																										        													        				&quot;volatile oils&quot;; &quot;volatile solvents&quot;**{adj.}++[化学]挥发性的；不稳定的；爆炸性的；反覆无常的**', '');
insert into TOEFLWordBook values ('1101', 'vulnerable', '[ˈvʌlnərəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=vulnerable', '{adj.}++（身体或精神）脆弱的，易受伤的；（事物、人或地方）易受攻击的，易受伤害的；易患病的；（桥牌）有局方的，有身价的**{adj.}++susceptible to attack																										        				&quot;a vulnerable bridge&quot;**{adj.}++易受攻击的，易受…的攻击；易受伤害的；有弱点的**', '');
insert into TOEFLWordBook values ('1102', 'wander', '[ˈwɑːndər]', 'http://dict.youdao.com/dictvoice?audio=wander', '{v.}++漫游，游荡，漫步，流浪；走神，开小差；偏离，走偏（道路、航线等）；（目光）游移，往别处看；（河流、道路等）蜿蜒曲折；离题；（因年老而）神志恍惚，精神错乱；在人的身上摸来摸去（尤指他人不情愿时）；（对固定的性伴侣）不忠**{n.}++游荡，漫步**{v.}++move about aimlessly or without any destination, often in search of food or employment																										        				&quot;the wandering Jew&quot;															   	同义词：								                                  				    roll				    				    				      				    				      				    				                                      				    swan				    				    				      				    				      				    				                                      				    stray				    				    				      				    				      				    				                                      				    tramp				    				    				      				    				      				    				                                      				    roam				    				    				      				    				      				    				                                      				    cast				    				    				      				    				      				    				                                      				    ramble				    				    				      				    				      				    				                                      				    rove				    				    				      				    				      				    				                                      				    range				    				    				      				    				      				    				                                      				    drift				    				    				      				    				      				    				                                      				    vagabond**{vi.}++徘徊；漫步；迷路；离题**{vt.}++游荡，漫游**', '');
insert into TOEFLWordBook values ('1103', 'wane', '[weɪn]', 'http://dict.youdao.com/dictvoice?audio=wane', '{v.}++（月亮）缺，亏；衰落，减少；消逝**{n.}++减弱，衰落（on the wane）；衰退期；（木板或木材的）缺棱，钝棱**{n.}++a gradual decline (in size or strength or power or number)																					   	同义词：								                                  				    ebb				    				    				      				    				      				    				                                      				    ebbing**{v.}++grow smaller																										        				&quot;Interest in the project waned&quot;															   	同义词：								                                  				    decline				    				    				      				    				      				    				                                      				    go down**{vi.}++衰落；变小；亏缺；[海洋]退潮；消逝**{n.}++[经]衰退；[天]月亏；衰退期；缺损**', '');
insert into TOEFLWordBook values ('1104', 'ward', '[wɔːrd]', 'http://dict.youdao.com/dictvoice?audio=ward', '{n.}++病房，病室；（城镇或村庄的）区，选区；被监护人（尤指儿童）；牢房；监视，看守；（锁内）齿凸（wards）；城堡内空地，堡场**{v.}++接受（病人）入病房；看守，保护**{n.}++a person who is under the protection or in the custody of another**{English writer of novels who was an active opponent of the womens suffrage movement (1851-1920)																					   	同义词：								                                  				    Mrs.}++Humphrey Ward				    				    				      				    				      				    				                                      				    Mary Augusta Arnold Ward**{n.}++[医]病房；保卫；监视**{vt.}++避开；保卫；守护**', '');
insert into TOEFLWordBook values ('1105', 'warfare', '[ˈwɔːrfer]', 'http://dict.youdao.com/dictvoice?audio=warfare', '{n.}++战争，作战；（团体、公司等之间的）斗争，竞争**{n.}++the waging of armed conflict against an enemy																					   	同义词：								                                  				    war**{n.}++战争；冲突**', '');
insert into TOEFLWordBook values ('1106', 'warp', '[wɔːrp]', 'http://dict.youdao.com/dictvoice?audio=warp', '{v.}++（使）扭曲，（使）变形；使反常，使有偏见；用绞船索牵曳（船）；（纺织用语）把（纱）排列成经；淤灌（土地）**{n.}++（织布中的）经纱，经线；变形，扭曲；（小说中或假想的空间旅行）靠扭曲时空实现，穿越时空；（喻）（性格）乖戾；绞船索**{n.}++a twist or aberration; especially a perverse or abnormal way of judging or acting																					   	同义词：								                                  				    deflection**{n.}++[物]弯曲，歪曲；偏见；乖戾**{vt.}++使变形；使有偏见；曲解**{vi.}++变歪，变弯；曲解**', '');
insert into TOEFLWordBook values ('1107', 'wary', '[ˈweri]', 'http://dict.youdao.com/dictvoice?audio=wary', '{adj.}++小心翼翼的，谨慎的，警戒的**{adj.}++marked by keen caution and watchful prudence																										        													        													        				&quot;they were wary in their movements&quot;; &quot;a wary glance at the black clouds&quot;; &quot;taught to be wary of strangers&quot;**{adj.}++谨慎的；机警的；惟恐的；考虑周到的**', '');
insert into TOEFLWordBook values ('1108', 'wax', '[wæks]', 'http://dict.youdao.com/dictvoice?audio=wax', '{n.}++蜡，蜂蜡；耳垢； 一阵愤怒；唱片；类似蜡的黏性物质（尤指液体或碳氢化合物）**{v.}++给……上（或打）蜡；用蜡除去（身体部位）的毛发；（月亮）渐圆，渐满；（带着某种情绪）说，写；（数量、规模等）增加，变大；把……灌制成唱片**{adj.}++蜡制的，似蜡的**{n.}++any of various substances of either mineral origin or plant or animal origin; they are solid at normal temperatures and insoluble in water**{v.}++cover with wax																										        				&quot;wax the car&quot;**{vi.}++月亮渐满；增大**{adj.}++[轻]蜡制的；似蜡的**', '');
insert into TOEFLWordBook values ('1109', 'wear', '[wer]', 'http://dict.youdao.com/dictvoice?audio=wear', '{v.}++穿（衣服），戴（首饰等）；蓄（须），留（发）；销蚀，磨损，踩出（路），磨出（洞）；流露，面带（某种表情）；使疲乏，使虚弱，使厌倦；经久耐用；不显老；允许，接受；（船）升，挂（旗）；消磨（时间） ；（航海）使（船头）转向下风**{n.}++（特定人群、场合或用途穿的）服装；穿，戴；（因长期使用而造成的）磨损，损坏；耐用性，经久性**{n.}++impairment resulting from long use																										        				&quot;the tires showed uneven wear&quot;**{vt.}++穿着，戴；[机]磨损**{vi.}++[机]磨损，变旧**{n.}++[服装]服装，穿着；耐用性，耐久性；损耗**', '');
insert into TOEFLWordBook values ('1110', 'weary', '[ˈwɪri]', 'http://dict.youdao.com/dictvoice?audio=weary', '{adj.}++疲劳的，疲倦的；使人疲劳的，令人厌烦的；厌倦的，厌烦的**{v.}++（使）疲倦，（使）厌烦；忧伤，烦恼**{v.}++exhaust or get tired through overuse or great strain or stress																					   	同义词：								                                  				    tire				    				    				      				    				      				    				                                      				    wear upon				    				    				      				    				      				    				                                      				    tire out				    				    				      				    				      				    				                                      				    wear				    				    				      				    				      				    				                                      				    jade				    				    				      				    				      				    				                                      				    wear out				    				    				      				    				      				    				                                      				    outwear				    				    				      				    				      				    				                                      				    wear down				    				    				      				    				      				    				                                      				    fag out				    				    				      				    				      				    				                                      				    fag				    				    				      				    				      				    				                                      				    fatigue**{adj.}++疲倦的；厌烦的；令人厌烦的**{vi.}++疲倦；厌烦**{vt.}++使疲倦；使厌烦**', '');
insert into TOEFLWordBook values ('1111', 'weave', '[wiːv]', 'http://dict.youdao.com/dictvoice?audio=weave', '{v.}++（用织布机）编，织；（用……）编成；编造（故事或计划）；将（素材等）编入（故事或设计中）；迂回行进，穿行（以避开障碍）；（蜘蛛）结网；（驾机）绕飞，作闪避动作；（马）不断左右摇晃头部和前身**{n.}++编法，织法，编织式样；编织图案；（使头发显得厚密或更长的）织发**{n.}++pattern of weaving or structure of a fabric**{v.}++interlace by or as it by weaving																					   	同义词：								                                  				    interweave**{vt.}++[纺]编织；编排；使迂回前进**{n.}++织物；[纺]织法；编织式样**', '');
insert into TOEFLWordBook values ('1112', 'welfare', '[ˈwelfer]', 'http://dict.youdao.com/dictvoice?audio=welfare', '{n.}++幸福，安康；福利救济，社会福利；（给失业者和穷人的）福利救济金**{adj.}++福利的；接受社会救济的**{n.}++governmental provision of economic assistance to persons in need																					   	同义词：								                                  				    social welfare**{n.}++福利；幸福；福利事业；安宁**', '');
insert into TOEFLWordBook values ('1113', 'whereas', '[ˌwerˈæz]', 'http://dict.youdao.com/dictvoice?audio=whereas', '{conj.}++（表示对比）但是，然而；鉴于（用于文件的开头）**{n.}++序言，开场白；条件语句**{conj.}++然而；鉴于；反之**', '');
insert into TOEFLWordBook values ('1114', 'whittle', '[ˈwɪt(ə)l]', 'http://dict.youdao.com/dictvoice?audio=whittle', '{vt.}++削；削减；切；削弱**{vi.}++削；削木头；弄坏身体**{n.}++屠刀**{n.}++（Whittle）人名；（英）惠特尔**{n.}++English aeronautical engineer who invented the jet aircraft engine (1907-1996)																					   	同义词：								                                  				    Frank Whittle				    				    				      				    				      				    				                                      				    Sir Frank Whittle**{v.}++cut small bits or pare shavings from																										        				&quot;whittle a piece of wood&quot;															   	同义词：								                                  				    pare**{vt.}++削；削减；切；削弱**{n.}++屠刀**', '');
insert into TOEFLWordBook values ('1115', 'windswept', '[ˈwɪndswept]', 'http://dict.youdao.com/dictvoice?audio=windswept', '{adj.}++被风吹的；暴露在风中的；风刮的**{adj.}++open to or swept by wind																										        				&quot;windswept headlands&quot;**', '');
insert into TOEFLWordBook values ('1116', 'wipe', '[waɪp]', 'http://dict.youdao.com/dictvoice?audio=wipe', '{v.}++（用布、手等）擦干净，抹掉；擦掉（液体、污垢、印迹）；把（某物）擦干净；消除，抹去（计算机、磁带或录像机上的信息等）；擦干（洗过的碟子、杯子）；抹去（旧事）；彻底去除（或消灭）（某物）；涂抹（液体）；拒绝（某人，观点），解雇（某人）；刷（卡）**{n.}++（湿）抹布，纸巾；擦，拭，擦净；划变**{n.}++the act of rubbing or wiping																					   	同义词：								                                  				    rub**{v.}++rub with a circular motion																										        				&quot;wipe the blackboard&quot;															   	同义词：								                                  				    pass over**{vt.}++擦；消除；涂上**{vi.}++擦；打**{n.}++擦拭；用力打**', '');
insert into TOEFLWordBook values ('1117', 'wispy', '[ˈwɪspi]', 'http://dict.youdao.com/dictvoice?audio=wispy', '{adj.}++象小束状的，纤细的；脆弱的**{adj.}++thin and weak																										        				&quot;a wispy little fellow with small hands and feet&quot;															   	同义词：								                                  				    wisplike**{adj.}++象小束状的，纤细的；脆弱的**', '');
insert into TOEFLWordBook values ('1118', 'wit', '[wɪt]', 'http://dict.youdao.com/dictvoice?audio=wit', '{n.}++（说话）风趣；说话风趣的人；机智；明智（the wit）；（不使用语言的）幽默机智**{v.}++知道；即，就是**{n.}++a message whose ingenuity or verbal skill or incongruity has the power to evoke laughter																					   	同义词：								                                  				    humor				    				    				      				    				      				    				                                      				    humour				    				    				      				    				      				    				                                      				    witticism				    				    				      				    				      				    				                                      				    wittiness**{n.}++智慧；才智；智力**', '');
insert into TOEFLWordBook values ('1119', 'withdraw', '[wɪðˈdrɔː]', 'http://dict.youdao.com/dictvoice?audio=withdraw', '{v.}++提，取（银行账户中的钱款）；停止提供，不再给予； 退出，不参加；（军队）撤离； 脱离（社会），不与人交往；离开；（将某物从某地或位置）抽回，移开；撤回，收回（前言）；（从某物中）拿出；停止提供，召回；退出，返回（至另一个房间）；（因对工作时间、报酬等不满意而）罢工；取消（许可、邀请或提议）；戒毒**{v.}++pull back or move away or backward																					   	同义词：								                                  				    retreat				    				    				      				    				      				    				                                      				    pull away				    				    				      				    				      				    				                                      				    draw back				    				    				      				    				      				    				                                      				    recede				    				    				      				    				      				    				                                      				    pull back				    				    				      				    				      				    				                                      				    retire				    				    				      				    				      				    				                                      				    move back**{vt.}++撤退；收回；撤消；拉开**{vi.}++撤退；离开**', '');
insert into TOEFLWordBook values ('1120', 'withstand', '[wɪðˈstænd]', 'http://dict.youdao.com/dictvoice?audio=withstand', '{v.}++顶住，抵住；经受住，承受住（攻击、批评等）；反抗**{v.}++resist or confront with resistance																										        				&quot;The new material withstands even the greatest wear and tear&quot;															   	同义词：								                                  				    defy				    				    				      				    				      				    				                                      				    hold				    				    				      				    				      				    				                                      				    hold up**{vt.}++抵挡；禁得起；反抗**{vi.}++反抗**', '');
insert into TOEFLWordBook values ('1121', 'wool', '[wʊl]', 'http://dict.youdao.com/dictvoice?audio=wool', '{n.}++羊毛，动物毛；毛线，绒线；毛料，毛织物；金属（或矿）丝**{n.}++a fabric made from the hair of sheep																					   	同义词：								                                  				    woolen				    				    				      				    				      				    				                                      				    woollen**{n.}++羊毛；毛线；[纺]绒线；毛织品；毛料衣物**', '');
insert into TOEFLWordBook values ('1122', 'wrap', '[ræp]', 'http://dict.youdao.com/dictvoice?audio=wrap', '{v.}++包，裹，包装；用（手臂、指头或腿）围紧，用……绕住；绕……走；完成拍摄，杀青 ；使（车辆）撞上（固定物体）；（使文字）换行**{n.}++披肩，围巾； 包裹（或包装）材料；宽松外套，浴衣；面卷饼（一种三明治，由薄面包包着肉、蔬菜等）；拍摄（或录音）结束，停机；（全身覆盖湿布或海草等进行的）皮肤护理；（喻）秘密；一小包白粉（毒品）**{n.}++cloak that is folded or wrapped around a person																					   	同义词：								                                  				    wrapper**{vt.}++包；缠绕；隐藏；掩护**{vi.}++包起来；缠绕；穿外衣**{n.}++外套；围巾**', '');
insert into TOEFLWordBook values ('1123', 'wreck', '[rek]', 'http://dict.youdao.com/dictvoice?audio=wreck', '{v.}++破坏，断送（计划、关系等）；（严重）破坏，毁坏（车辆或建筑物）；造成（船舶）失事，使遇难；毁船打劫；（为获取有用的零件、碎料而）拆，拆除（破汽车、旧建筑物等）；营救失事船只；失事**{n.}++沉船，遇难船；遭到严重破坏的东西（尤指建筑物、车辆）；健康（或精神）严重受损的人；（船舶的）失事，遇难，交通事故；杂乱的地方；（船舶失事后被冲上岸的）残货，沉船漂浮物**{n.}++something or someone that has suffered ruin or dilapidation																										        													        				&quot;the house was a wreck when they bought it&quot;; &quot;thanks to that quack I am a human wreck&quot;**{n.}++破坏；[水运]失事；残骸；失去健康的人**{vt.}++破坏；[水运]使失事；拆毁**', '');
insert into TOEFLWordBook values ('1124', 'intern', '[ˈɪntɜːrn]', 'http://dict.youdao.com/dictvoice?audio=intern', '{v.}++（由于政治原因或战时）拘留，扣押；做实习医生（或实习生）**{n.}++实习医生；实习生**{n.}++an advanced student or graduate in medicine gaining supervised practical experience (`houseman is a British term)																					   	同义词：								                                  				    interne				    				    				      				    				      				    				                                      				    houseman				    				    				      				    				      				    				                                      				    medical intern**{v.}++deprive of freedom																										        				&quot;During WW II, Japanese were interned in camps in the West&quot;**{n.}++实习生，实习医师**{vt.}++拘留，软禁**', '');
insert into TOEFLWordBook values ('1125', 'incredible', '[ɪnˈkredəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=incredible', '{adj.}++不可思议的，难以置信的；惊人的，极大的，极多的；了不起的，极好的**{adj.}++beyond belief or understanding																										        													        				&quot;at incredible speed&quot;; &quot;the books plot is simply incredible&quot;															   	同义词：								                                  				    unbelievable**{adj.}++难以置信的，惊人的**', '');
insert into TOEFLWordBook values ('1126', 'speculation', '[ˌspekjuˈleɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=speculation', '{n.}++投机，投机买卖；猜测，推测，推断**{n.}++a message expressing an opinion based on incomplete evidence																					   	同义词：								                                  				    guess				    				    				      				    				      				    				                                      				    conjecture				    				    				      				    				      				    				                                      				    supposition				    				    				      				    				      				    				                                      				    surmise				    				    				      				    				      				    				                                      				    surmisal				    				    				      				    				      				    				                                      				    hypothesis**{n.}++投机；推测；思索；投机买卖**', '');
insert into TOEFLWordBook values ('1127', 'perceive', '[pərˈsiːv]', 'http://dict.youdao.com/dictvoice?audio=perceive', '{vt.}++认为，理解；察觉，注意到；意识到**{v.}++to become aware of through the senses																										        				&quot;I could perceive the ship coming over the horizon&quot;															   	同义词：								                                  				    comprehend**{vt.}++察觉，感觉；理解；认知**{vi.}++感到，感知；认识到**', '');
insert into TOEFLWordBook values ('1128', 'well-being', '[ˈwel biːɪŋ]', 'http://dict.youdao.com/dictvoice?audio=well-being', '{n.}++幸福，安康；（国家的）繁荣**{n.}++a contented state of being happy and healthy and prosperous																					   	同义词：								                                  				    wellbeing				    				    				      				    				      				    				                                      				    welfare				    				    				      				    				      				    				                                      				    upbeat				    				    				      				    				      				    				                                      				    eudaemonia				    				    				      				    				      				    				                                      				    eudaimonia**{n.}++幸福；康乐**', '');
insert into TOEFLWordBook values ('1129', 'formalize', '[ˈfɔːrməlaɪz]', 'http://dict.youdao.com/dictvoice?audio=formalize', '{vt.}++使形式化；使正式；拘泥礼仪**{vi.}++拘泥于形式**{v.}++make formal or official																										        				&quot;We formalized the appointment and gave him a title&quot;															   	同义词：								                                  				    formalise**', '');
insert into TOEFLWordBook values ('1130', 'autonomous', '[ɔːˈtɑːnəməs]', 'http://dict.youdao.com/dictvoice?audio=autonomous', '{adj.}++自治的，有自治权的；自主的，有自主权的；自动的**{adj.}++(of political bodies) not controlled by outside forces																										        				&quot;an autonomous judiciary&quot;															   	同义词：								                                  				    independent				    				    				      				    				      				    				                                      				    self-governing				    				    				      				    				      				    				                                      				    sovereign**{(of persons) free from external control and constraint in e.}++g. action and judgment																					   	同义词：								                                  				    self-directed				    				    				      				    				      				    				                                      				    self-reliant**{adj.}++[生物][植]自治的；自主的；自发的**', '');
insert into TOEFLWordBook values ('1131', 'efficacious', '[ˌefɪˈkeɪʃəs]', 'http://dict.youdao.com/dictvoice?audio=efficacious', '{adj.}++有效的；灵验的**{adj.}++marked by qualities giving the power to produce an intended effect																										        													        				&quot;written propaganda is less efficacious than the habits and prejudices...of the readers&quot;; &quot;the medicine is efficacious in stopping a cough&quot;**{adj.}++有效的；灵验的**', '');
insert into TOEFLWordBook values ('1132', 'velocity', '[vəˈlɑːsəti]', 'http://dict.youdao.com/dictvoice?audio=velocity', '{n.}++速度，速率；高速，快速；（经济）周转率，流通速度**{n.}++distance travelled per unit time																					   	同义词：								                                  				    speed**{n.}++[力]速率；迅速；周转率**', '');
insert into TOEFLWordBook values ('1133', 'rigor', '[ˈrɪɡər]', 'http://dict.youdao.com/dictvoice?audio=rigor', '{n.}++（尤指发热之初或高潮时的）寒战；严密，严格（rigour的美式拼法）**{n.}++（Rigor）（菲、美）里戈尔（人名）**{n.}++something hard to endure																					   	同义词：								                                  				    asperity				    				    				      				    				      				    				                                      				    grimness				    				    				      				    				      				    				                                      				    hardship				    				    				      				    				      				    				                                      				    rigour				    				    				      				    				      				    				                                      				    severity				    				    				      				    				      				    				                                      				    severeness				    				    				      				    				      				    				                                      				    rigorousness				    				    				      				    				      				    				                                      				    rigourousness**{n.}++严厉；精确；苛刻；僵硬**', '');
insert into TOEFLWordBook values ('1134', 'insulation', '[ˌɪnsəˈleɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=insulation', '{n.}++隔热，绝缘，隔音；隔热（或绝缘、隔音）材料；隔绝状态**{n.}++the state of being isolated or detached																										        				&quot;the insulation of England was preserved by the English Channel&quot;															   	同义词：								                                  				    insularity				    				    				      				    				      				    				                                      				    insularism				    				    				      				    				      				    				                                      				    detachment**{n.}++[电]绝缘；隔离，孤立**', '');
insert into TOEFLWordBook values ('1135', 'feasible', '[ˈfiːzəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=feasible', '{adj.}++可行的，办得到的；很可能会发生的**{adj.}++capable of being done with means at hand and circumstances as they are																					   	同义词：								                                  				    executable				    				    				      				    				      				    				                                      				    practicable				    				    				      				    				      				    				                                      				    viable				    				    				      				    				      				    				                                      				    workable**{adj.}++可行的；可能的；可实行的**', '');
