insert into TOEFLWordBook values ('1178', 'crude', '[kruːd]', 'http://dict.youdao.com/dictvoice?audio=crude', '{adj.}++粗略的，大概的；粗糙的，粗制的；冒犯的，粗俗的；天然的，自然的**{n.}++原油；天然的物质**{n.}++a dark oil consisting mainly of hydrocarbons																					   	同义词：								                                  				    petroleum				    				    				      				    				      				    				                                      				    crude oil				    				    				      				    				      				    				                                      				    rock oil				    				    				      				    				      				    				                                      				    fossil oil**{adj.}++not carefully or expertly made																										        													        				&quot;managed to make a crude splint&quot;; &quot;a crude cabin of logs with bark still on them&quot;															   	同义词：								                                  				    rough**{adj.}++粗糙的；天然的，未加工的；粗鲁的**', '');
