insert into TOEFLWordBook values ('1185', 'slick', '[slɪk]', 'http://dict.youdao.com/dictvoice?audio=slick', '{adj.}++熟练的，灵巧的；光滑的，滑溜的；花言巧语的；华而不实的；很棒的，最好的；聪明的**{n.}++浮油，油膜；一小片湿而亮的地方；（赛车的）磨光轮胎；外表华丽内容肤浅的刊物；机灵鬼，滑头；平滑器；修光工具**{adv.}++灵活地，聪明地**{v.}++使（头发）光滑，使亮滑；打扮整洁**{n.}++a slippery smoothness																										        				&quot;he could feel the slickness of the tiller&quot;															   	同义词：								                                  				    slickness				    				    				      				    				      				    				                                      				    slipperiness				    				    				      				    				      				    				                                      				    slip**{adj.}++光滑的；华而不实的；聪明的；熟练的；老套的**{n.}++[机]平滑器；修光工具；通俗杂志**{adv.}++灵活地；聪明地**{vt.}++使光滑；使漂亮**{vi.}++打扮整洁**', '');
