insert into TOEFLWordBook values ('1190', 'tentative', '[ˈtentətɪv]', 'http://dict.youdao.com/dictvoice?audio=tentative', '{adj.}++试探性的，暂定的；踌躇的，犹豫不定的**{n.}++不确定的事物**{adj.}++under terms not final or fully worked out or agreed upon																										        				&quot;just a tentative schedule&quot;															   	同义词：								                                  				    probationary				    				    				      				    				      				    				                                      				    provisional				    				    				      				    				      				    				                                      				    provisionary**{adj.}++[试验]试验性的，暂定的；踌躇的**{n.}++假设，试验**', '');
