insert into TOEFLWordBook values ('1194', 'serpentine', '[ˈsɜːrpəntiːn]', 'http://dict.youdao.com/dictvoice?audio=serpentine', '{adj.}++蜿蜒的，弯弯曲曲的；复杂的，阴险的**{n.}++蛇纹石；蛇形之物；（骑术的）蜿蜒跑动训练；（15至16世纪使用的）一种加农炮**{v.}++使迂回曲折地行进；蛇形排列**{n.}++蛇形湖（伦敦海德公园中的湖，the Serpentine）**{adj.}++resembling a serpent in form																										        				&quot;a serpentine wall&quot;															   	同义词：								                                  				    snaky				    				    				      				    				      				    				                                      				    snakelike**{adj.}++蜿蜒的；阴险的；弯弯曲曲的**{n.}++[矿物]蛇纹石**', '');
