insert into TOEFLWordBook values ('1207', 'rotary', '[ˈroʊtəri]', 'http://dict.youdao.com/dictvoice?audio=rotary', '{adj.}++绕轴转动的；（机器）有旋转部件的，旋转式的**{n.}++环岛，环形交通枢纽；旋转式装置**{n.}++a road junction at which traffic streams circularly around a central island																										        				&quot;the accident blocked all traffic at the rotary&quot;															   	同义词：								                                  				    traffic circle				    				    				      				    				      				    				                                      				    circle				    				    				      				    				      				    				                                      				    roundabout**{adj.}++[机]旋转的，转动的；轮流的**', '');
insert into TOEFLWordBook values ('1208', 'flicker', '[ˈflɪkər]', 'http://dict.youdao.com/dictvoice?audio=flicker', '{v.}++闪烁，摇曳；闪现，一闪而过；（表情）掠过；（眼睛）瞟过；颤动，快速抖动；扑动翅膀；使……突然动一下**{n.}++（火焰，光的）闪烁，摇曳；（感觉或情绪的）闪现，一闪而过；（身体部位的）小而快的动作；（电影或电视每秒帧数过少时的）图像闪烁；（鸟）扑翅䴕属**{n.}++a momentary flash of light																					   	同义词：								                                  				    spark				    				    				      				    				      				    				                                      				    glint**{vi.}++[电子][光]闪烁；摇曳；颤动；扑动翅膀；假装昏倒**{vt.}++[电子][光]使闪烁；使摇曳**{n.}++[电子][光]闪烁；闪光；电影**', '');
