insert into TOEFLWordBook values ('1211', 'laden', '[ˈleɪdn]', 'http://dict.youdao.com/dictvoice?audio=laden', '{adj.}++负载的；装满的；苦恼的**{v.}++装载（同 lade）；装载（lade 的过去分词）**{n.}++（Laden）（阿拉伯）拉丹；（德、罗）拉登；（法）拉当（人名）**{v.}++remove with or as if with a ladle																					   	同义词：								                                  				    ladle				    				    				      				    				      				    				                                      				    lade**{adj.}++负载的；装满的；苦恼的**{vt.}++装载（等于lade）**{vi.}++装载（等于lade）**', '');
