insert into TOEFLWordBook values ('1214', 'roam', '[roʊm]', 'http://dict.youdao.com/dictvoice?audio=roam', '{v.}++漫步，闲逛；（眼睛）扫视，（手）扫过；（思绪，想象力）遨游**{n.}++漫步**{v.}++move about aimlessly or without any destination, often in search of food or employment																										        													        				&quot;The gypsies roamed the woods&quot;; &quot;The cattle roam across the prairie&quot;															   	同义词：								                                  				    roll				    				    				      				    				      				    				                                      				    wander				    				    				      				    				      				    				                                      				    swan				    				    				      				    				      				    				                                      				    stray				    				    				      				    				      				    				                                      				    tramp				    				    				      				    				      				    				                                      				    cast				    				    				      				    				      				    				                                      				    ramble				    				    				      				    				      				    				                                      				    rove				    				    				      				    				      				    				                                      				    range				    				    				      				    				      				    				                                      				    drift				    				    				      				    				      				    				                                      				    vagabond**{vi.}++漫游，漫步；流浪**{vt.}++在…漫步，漫游；在…流浪**{n.}++漫步，漫游；流浪**', '');
insert into TOEFLWordBook values ('1215', 'ubiquitous', '[juːˈbɪkwɪtəs]', 'http://dict.youdao.com/dictvoice?audio=ubiquitous', '{adj.}++普遍存在的，无所不在的**{adj.}++being present everywhere at once																					   	同义词：								                                  				    omnipresent**{adj.}++普遍存在的；无所不在的**', '');
insert into TOEFLWordBook values ('1216', 'scanty', '[ˈskænti]', 'http://dict.youdao.com/dictvoice?audio=scanty', '{adj.}++少量的，不足的；（衣服）暴露的，紧（身）的**{n.}++女式小短裤（或衬裤）（scanties）**{n.}++short underpants for women or children (usually used in the plural)																					   	同义词：								                                  				    pantie				    				    				      				    				      				    				                                      				    panty				    				    				      				    				      				    				                                      				    step-in**{adj.}++lacking in amplitude or quantity																										        				&quot;a scanty harvest&quot;															   	同义词：								                                  				    bare(a)				    				    				      				    				      				    				                                      				    spare**{adj.}++缺乏的；吝啬的；仅有的；稀疏的**', '');
