insert into TOEFLWordBook values ('1223', 'encode', '[ɪnˈkoʊd]', 'http://dict.youdao.com/dictvoice?audio=encode', '{v.}++把……译成密码（或电码）；给（计算机程序）编码；用外语表达；（基因）对生成（某种物质或行为）负责，给……编码**{v.}++convert ordinary language into code																										        				&quot;We should encode the message for security reasons&quot;															   	同义词：								                                  				    code				    				    				      				    				      				    				                                      				    encipher				    				    				      				    				      				    				                                      				    cipher				    				    				      				    				      				    				                                      				    cypher				    				    				      				    				      				    				                                      				    encrypt				    				    				      				    				      				    				                                      				    inscribe				    				    				      				    				      				    				                                      				    write in code**{vt.}++[计]编码，译码**', '');
