insert into TOEFLWordBook values ('1242', 'demographic', '[ˌdeməˈɡræfɪk]', 'http://dict.youdao.com/dictvoice?audio=demographic', '{adj.}++人口的，人口统计的**{n.}++（具有某种特征的）群体；人口统计数据**{n.}++a statistic characterizing human populations (or segments of human populations broken down by age or sex or income etc.)**{adj.}++of or relating to demography																										        				&quot;demographic survaaaaaaaeys&quot;**{adj.}++人口统计学的；人口学的**', '');
insert into TOEFLWordBook values ('1243', 'shrine', '[ʃraɪn]', 'http://dict.youdao.com/dictvoice?audio=shrine', '{n.}++圣地；神殿；神龛；圣祠**{vt.}++将……置于神龛内；把……奉为神圣**{n.}++a place of worship hallowed by association with some sacred thing or person**{v.}++enclose in a shrine																										        				&quot;the saints bones were enshrined in the cathedral&quot;															   	同义词：								                                  				    enshrine**{n.}++圣地；神殿；神龛；圣祠**{vt.}++将…置于神龛内；把…奉为神圣**', '');
insert into TOEFLWordBook values ('1244', 'coerce', '[koʊˈɜːrs]', 'http://dict.youdao.com/dictvoice?audio=coerce', '{v.}++强制，迫使；通过胁迫获得**{v.}++to cause to do through pressure or necessity, by physical, moral or intellectual means :																					   	同义词：								                                  				    hale				    				    				      				    				      				    				                                      				    squeeze				    				    				      				    				      				    				                                      				    pressure				    				    				      				    				      				    				                                      				    force**{vt.}++强制，迫使**', '');
insert into TOEFLWordBook values ('1245', 'demise', '[dɪˈmaɪz]', 'http://dict.youdao.com/dictvoice?audio=demise', '{n.}++倒闭，败落；死亡，逝世；（律）（财产或所有权的）转让，遗赠**{v.}++（律）遗赠，转让（产业）；正式放弃，禅让（最高统治者的头衔）**{n.}++the time when something ends																					   	同义词：								                                  				    death				    				    				      				    				      				    				                                      				    dying**{n.}++死亡，终止；转让；传位**{vt.}++[法]遗赠；禅让**', '');
insert into TOEFLWordBook values ('1246', 'livable', '[ˈlɪvəbl]', 'http://dict.youdao.com/dictvoice?audio=livable', '{adj.}++适于居住的；生活过得有价值的；宜居的；值得一过的；可勉强在一起生活的；足够维持生活的；能对付，可处理（同 liveable）**{adj.}++fit or suitable to live in or with																										        				&quot;livable conditions&quot;															   	同义词：								                                  				    liveable**{adj.}++适于居住的；生活过得有价值的**', '');
