insert into TOEFLWordBook values ('1259', 'technician', '[tekˈnɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=technician', '{n.}++技师，技术人员；（体育、艺术等方面）技巧精湛者，精于技巧者**{n.}++someone whose occupation involves training in a specific technical process**{n.}++[劳经]技师，技术员；技巧纯熟的人**', '');
insert into TOEFLWordBook values ('1260', 'vicissitude', '[vɪˈsɪsɪtuːd]', 'http://dict.youdao.com/dictvoice?audio=vicissitude', '{n.}++变迁；盛衰；变化无常；变迁兴衰**{n.}++a variation in circumstances or fortune at different times in your life or in the development of something																										        				&quot;the project was subject to the usual vicissitudes of exploratory research&quot;**{n.}++变迁；盛衰；变化无常；变迁兴衰**', '');
