insert into TOEFLWordBook values ('1262', 'illusory', '[ɪˈluːsəri]', 'http://dict.youdao.com/dictvoice?audio=illusory', '{adj.}++虚假的，幻觉的**{adj.}++based on or having the nature of an illusion																										        				&quot;Secret activities offer presidents the alluring but often illusory promise that they can achieve foreign policy goals without the bothersome debate and open decision that are staples of democracy&quot;															   	同义词：								                                  				    illusive**{adj.}++错觉的；幻影的；虚假的；产生幻觉的**', '');
