insert into TOEFLWordBook values ('1265', 'tribute', '[ˈtrɪbjuːt]', 'http://dict.youdao.com/dictvoice?audio=tribute', '{n.}++（表示敬意的）礼物，颂辞，行为；（良好效果或影响的）体现，显示；（尤指旧时一国向他国交纳的）贡品，贡金；（用于支付矿工工资，或给矿厂主、出租人的）矿石份子**{adj.}++（尤指团体或音乐家）（通过模仿）表演著名乐曲的**{n.}++something given or done as an expression of esteem																					   	同义词：								                                  				    testimonial**{n.}++礼物；[税收]贡物；颂词**', '');
insert into TOEFLWordBook values ('1266', 'opaque', '[oʊˈpeɪk]', 'http://dict.youdao.com/dictvoice?audio=opaque', '{adj.}++（玻璃、液体等）不透明的，不透光的；难懂的，隐晦的；迟钝的**{n.}++不透明体；（用于底片）不透明颜料**{v.}++使不透明**{adj.}++not clear; not transmitting or reflecting light or radiant energy																										        													        				&quot;opaque windows of the jail&quot;; &quot;opaque to X-rays&quot;**{adj.}++[物]不透明的；不传热的；迟钝的**{vt.}++[物]使不透明；使不反光**', '');
